_THREEDWORLD_MOD = None
_THREEDWORLD_IMPORT_TRIED = False
_THREEDWORLD_LAST_PUSH_MS = 0


def _get_3dworld_module():
    global _THREEDWORLD_MOD, _THREEDWORLD_IMPORT_TRIED
    if _THREEDWORLD_MOD is not None:
        return _THREEDWORLD_MOD
    if _THREEDWORLD_IMPORT_TRIED:
        return None
    _THREEDWORLD_IMPORT_TRIED = True
    try:
        _THREEDWORLD_MOD = importlib.import_module("3DWorld")
    except Exception as exc:
        _THREEDWORLD_MOD = None
        try:
            print(f"[3DWORLD][IMPORT] failed in main: {exc}")
        except Exception:
            pass
    return _THREEDWORLD_MOD


def _push_pose_to_3dworld(now_ms: int, ins_gps_state: dict, active_portal_formats: Optional[List[object]] = None) -> None:
    global _THREEDWORLD_LAST_PUSH_MS
    # When a dedicated TFLIR/DAS format instance is actively pushing pose to
    # its worker, skip generic main-loop pushes to avoid camera/polarity races.
    try:
        direct_ms = int(getattr(formats, "_3DWORLD_DIRECT_POSE_PUSH_MS", 0) or 0)
    except Exception:
        direct_ms = 0
    if direct_ms > 0 and (int(now_ms) - int(direct_ms)) < 500:
        return
    if (int(now_ms) - int(_THREEDWORLD_LAST_PUSH_MS)) < 20:
        return
    mod = _get_3dworld_module()
    if mod is None:
        return
    # When TFLIR/DAS formats are active, those format classes push their own
    # camera-specific pose data. A parallel generic push here causes camera
    # flicker between two pose sources.
    try:
        pf_list = active_portal_formats if isinstance(active_portal_formats, list) else None
        if isinstance(pf_list, list):
            for _pf in pf_list:
                if _pf is None:
                    continue
                for _fmt in [getattr(_pf, "primary", None), *list(getattr(_pf, "subs", []) or [])]:
                    name = str(getattr(_fmt, "name", "")).upper().strip()
                    if name in {"TFLIR", "DAS"}:
                        return
    except Exception:
        pass
    lat = None
    lon = None
    try:
        if isinstance(ins_gps_state, dict):
            lat = ins_gps_state.get("position_lat", None)
            lon = ins_gps_state.get("position_lon", None)
        lat = float(lat) if lat is not None else None
        lon = float(lon) if lon is not None else None
    except Exception:
        lat = None
        lon = None
    if lat is None or lon is None:
        try:
            tsd = getattr(formats, "TSD_ADSB_STATE", {})
            if isinstance(tsd, dict):
                tlat = tsd.get("lat", None)
                tlon = tsd.get("lon", None)
                if (tlat is None) or (tlon is None):
                    geo = tsd.get("geo")
                    if isinstance(geo, dict):
                        tlat = geo.get("lat", tlat)
                        tlon = geo.get("lon", tlon)
                if (tlat is not None) and (tlon is not None):
                    lat = float(tlat)
                    lon = float(tlon)
        except Exception:
            pass
    if lat is None or lon is None:
        return
    heading_deg = 0.0
    pitch_deg = 0.0
    roll_deg = 0.0
    look_az_deg = 90.0
    look_el_deg = 0.0
    zoom_fov_deg = 45.0
    cam_rel_forward_m = 0.0
    cam_rel_right_m = 0.0
    cam_rel_up_m = 0.0
    cam_default_forward_m = 0.0
    cam_default_right_m = 2.79
    cam_default_up_m = -0.59
    cam_default_cube_size_m = 1.0
    cam_cube_forward_m = 0.0
    cam_cube_right_m = 2.79
    cam_cube_up_m = -0.59
    look_slew_active = False
    hold_point_enabled = True
    whot = True
    bhot = False
    das_camera_key = "DAS-BA"
    das_zoom_ratio = 2.9
    das_fov_v_deg = 29.0
    das_fov_h_deg = 29.0
    das_cam_forward_m = 0.0
    das_cam_right_m = 0.0
    das_cam_up_m = 0.0
    das_yaw_deg = 0.0
    das_pitch_deg = 0.0
    altitude_ft = 0.0
    quat = None
    try:
        heading_deg = float(getattr(formats, "TWD_STATE", {}).get("heading_deg", 0.0)) % 360.0
    except Exception:
        heading_deg = 0.0
    try:
        panel = _ensure_panel_button_states()
        aircraft = panel.get("AIRCRAFT", {}) if isinstance(panel, dict) else {}
        if isinstance(aircraft, dict):
            try:
                heading_deg = float(
                    aircraft.get(
                        "HEADING_DEG",
                        aircraft.get("HDG_DEG", aircraft.get("HEADING", heading_deg)),
                    )
                    or heading_deg
                ) % 360.0
            except Exception:
                pass
            altitude_ft = float(aircraft.get("ALTITUDE_FT", aircraft.get("ALTITUDE_TARGET_FT", 0.0)) or 0.0)
            pitch_deg = float(aircraft.get("ATT_PITCH_DEG", aircraft.get("PITCH", pitch_deg)) or pitch_deg)
            roll_deg = float(aircraft.get("ATT_ROLL_DEG", aircraft.get("ROLL", roll_deg)) or roll_deg)
            qw = aircraft.get("ATT_Q_W", None)
            qx = aircraft.get("ATT_Q_X", None)
            qy = aircraft.get("ATT_Q_Y", None)
            qz = aircraft.get("ATT_Q_Z", None)
            if (qw is not None) and (qx is not None) and (qy is not None) and (qz is not None):
                quat = {
                    "w": float(qw),
                    "x": float(qx),
                    "y": float(qy),
                    "z": float(qz),
                }
    except Exception:
        pass
    try:
        tflir_state = getattr(formats, "TFLIR3D_STATE", {})
        if isinstance(tflir_state, dict):
            look_az_deg = float(tflir_state.get("look_az_deg", 90.0) or 90.0)
            look_el_deg = float(tflir_state.get("look_el_deg", 0.0) or 0.0)
            zoom_fov_deg = float(tflir_state.get("zoom_fov_deg", 45.0) or 45.0)
            cam_rel_forward_m = float(tflir_state.get("cam_rel_forward_m", 0.0) or 0.0)
            cam_rel_right_m = float(tflir_state.get("cam_rel_right_m", 0.0) or 0.0)
            cam_rel_up_m = float(tflir_state.get("cam_rel_up_m", 0.0) or 0.0)
            cam_default_forward_m = float(tflir_state.get("cam_default_forward_m", 0.0) or 0.0)
            cam_default_right_m = float(tflir_state.get("cam_default_right_m", 2.79) or 2.79)
            cam_default_up_m = float(tflir_state.get("cam_default_up_m", -0.59) or -0.59)
            cam_default_cube_size_m = float(tflir_state.get("cam_default_cube_size_m", 1.0) or 1.0)
            cam_cube_forward_m = float(tflir_state.get("cam_cube_forward_m", cam_default_forward_m) or cam_default_forward_m)
            cam_cube_right_m = float(tflir_state.get("cam_cube_right_m", cam_default_right_m) or cam_default_right_m)
            cam_cube_up_m = float(tflir_state.get("cam_cube_up_m", cam_default_up_m) or cam_default_up_m)
            look_slew_active = bool(tflir_state.get("look_slew_active", False))
            hold_point_enabled = bool(tflir_state.get("hold_point_enabled", True))
            bhot = bool(tflir_state.get("bhot", False))
            if "bhot" in tflir_state:
                whot = not bool(bhot)
            else:
                whot = bool(tflir_state.get("whot", True))
    except Exception:
        look_az_deg = 90.0
        look_el_deg = 0.0
        zoom_fov_deg = 45.0
        cam_rel_forward_m = 0.0
        cam_rel_right_m = 0.0
        cam_rel_up_m = 0.0
        cam_default_forward_m = 0.0
        cam_default_right_m = 2.79
        cam_default_up_m = -0.59
        cam_default_cube_size_m = 1.0
        cam_cube_forward_m = 0.0
        cam_cube_right_m = 2.79
        cam_cube_up_m = -0.59
        look_slew_active = False
        hold_point_enabled = True
        whot = True
        bhot = False
    try:
        das_state = getattr(formats, "DAS3D_STATE", {})
        if isinstance(das_state, dict):
            camera_keys = das_state.get("camera_keys", [])
            if not isinstance(camera_keys, list) or len(camera_keys) == 0:
                camera_keys = ["DAS-BA", "DAS-BF", "DAS-L", "DAS-R", "DAS-TA", "DAS-TF"]
            try:
                cam_idx = int(das_state.get("camera_index", 0) or 0) % len(camera_keys)
            except Exception:
                cam_idx = 0
            das_camera_key = str(das_state.get("active_camera_key", camera_keys[cam_idx]) or camera_keys[cam_idx]).upper().strip()
            if das_camera_key not in camera_keys:
                das_camera_key = str(camera_keys[cam_idx]).upper().strip()
            das_zoom_ratio = float(das_state.get("zoom_ratio", 2.9) or 2.9)
            das_fov_v_deg = float(das_state.get("fov_v_deg", 29.0) or 29.0)
            das_fov_h_deg = float(das_state.get("fov_h_deg", 29.0) or 29.0)
            offsets_raw = das_state.get("camera_offsets_m", {})
            rots_raw = das_state.get("camera_rot_deg", {})
            if isinstance(offsets_raw, dict):
                off = offsets_raw.get(das_camera_key, {})
                if isinstance(off, dict):
                    das_cam_forward_m = float(off.get("forward", 0.0) or 0.0)
                    das_cam_right_m = float(off.get("right", 0.0) or 0.0)
                    das_cam_up_m = float(off.get("up", 0.0) or 0.0)
            if isinstance(rots_raw, dict):
                rot = rots_raw.get(das_camera_key, {})
                if isinstance(rot, dict):
                    das_yaw_deg = float(rot.get("yaw", 0.0) or 0.0)
                    das_pitch_deg = float(rot.get("pitch", 0.0) or 0.0)
    except Exception:
        pass
    try:
        update_fn = getattr(mod, "update_pose", None)
        if callable(update_fn):
            update_fn(
                float(lat),
                float(lon),
                float(max(0.0, altitude_ft)),
                float(heading_deg),
                quat,
                float(pitch_deg),
                float(roll_deg),
                float(look_az_deg),
                float(look_el_deg),
                float(zoom_fov_deg),
                float(cam_rel_forward_m),
                float(cam_rel_right_m),
                float(cam_rel_up_m),
                float(cam_default_forward_m),
                float(cam_default_right_m),
                float(cam_default_up_m),
                float(cam_default_cube_size_m),
                float(cam_cube_forward_m),
                float(cam_cube_right_m),
                float(cam_cube_up_m),
                bool(look_slew_active),
                str(das_camera_key),
                float(das_zoom_ratio),
                float(das_fov_v_deg),
                float(das_fov_h_deg),
                float(das_cam_forward_m),
                float(das_cam_right_m),
                float(das_cam_up_m),
                float(das_yaw_deg),
                float(das_pitch_deg),
                show_aircraft_model=True,
                hold_point_enabled=bool(hold_point_enabled),
                whot=bool(whot),
                level_roll_to_horizon=True,
            )
            _THREEDWORLD_LAST_PUSH_MS = int(now_ms)
    except Exception:
        pass

