def _build_phm_system_subsystem_map() -> Dict[str, List[str]]:
    out: Dict[str, List[str]] = {}
    raw = getattr(formats, "PHM_SYSTEM_SUBSYSTEMS", {})
    if not isinstance(raw, dict):
        return out
    for system_name, subs in raw.items():
        sys_key = str(system_name).upper().strip()
        if sys_key == "" or not isinstance(subs, list):
            continue
        cleaned: List[str] = []
        for sub in subs:
            sub_key = str(sub).upper().strip()
            if sub_key == "" or sub_key in cleaned:
                continue
            cleaned.append(sub_key)
        out[sys_key] = cleaned
    return out


def _apply_default_stores_loadout_once(
    pmd_state: Dict[str, object],
    stations: Dict[str, List[str]],
    idx_map: Dict[str, int],
) -> None:
    try:
        already_applied = bool(pmd_state.get("stores_defaults_applied", False))
    except Exception:
        already_applied = False
    if already_applied:
        return
    has_custom_selection = False
    for sta in PMD_STORES_STATION_ORDER:
        try:
            idx = int(idx_map.get(sta, 0))
        except Exception:
            idx = 0
        if idx != 0:
            has_custom_selection = True
            break
    if has_custom_selection:
        pmd_state["stores_defaults_applied"] = True
        return
    for sta in PMD_STORES_STATION_ORDER:
        idx_map[sta] = 0
    for sta, weapon_id in PMD_STORES_DEFAULT_LOADOUT.items():
        opts_raw = stations.get(sta, ["NONE"])
        opts = [str(v) for v in opts_raw] if isinstance(opts_raw, list) and len(opts_raw) > 0 else ["NONE"]
        if weapon_id in opts:
            idx_map[sta] = opts.index(weapon_id)
    pmd_state["stores_defaults_applied"] = True


PHM_SYSTEM_SUBSYSTEMS_MAP: Dict[str, List[str]] = _build_phm_system_subsystem_map()
PHM_SUBSYSTEM_SYSTEM_MAP: Dict[str, str] = {}
for _sys_key, _subs in PHM_SYSTEM_SUBSYSTEMS_MAP.items():
    for _sub_key in _subs:
        PHM_SUBSYSTEM_SYSTEM_MAP[str(_sub_key).upper().strip()] = str(_sys_key).upper().strip()


def _phm_related_event_keys_for_system(system_name: str) -> List[str]:
    sys_key = str(system_name).upper().strip()
    if sys_key == "":
        return []
    keys: List[str] = [sys_key]
    for sub_key in PHM_SYSTEM_SUBSYSTEMS_MAP.get(sys_key, []):
        if sub_key not in keys:
            keys.append(sub_key)
    return keys


def _phm_system_key_for_name(name: str) -> str:
    key = str(name).upper().strip()
    if key == "":
        return ""
    if key in PHM_SYSTEM_SUBSYSTEMS_MAP:
        return key
    owner = PHM_SUBSYSTEM_SYSTEM_MAP.get(key, "")
    if owner != "":
        return owner
    return key


def _phm_subsystems_for_system(system_name: str) -> List[str]:
    sys_key = _phm_system_key_for_name(system_name)
    if sys_key == "":
        return []
    subs = PHM_SYSTEM_SUBSYSTEMS_MAP.get(sys_key, [])
    out: List[str] = []
    for sub in subs:
        sub_key = str(sub).upper().strip()
        if sub_key == "" or sub_key in out:
            continue
        out.append(sub_key)
    if len(out) <= 0:
        out = [sys_key]
    return out
