# Random BOS generation range is tightened by 10% from each side of the real limits.
PMD_SVC_BOS_RANDOM_TRIM_PCT = 0.10
PMD_SVC_BOS_RANDOM_MIN = 290


def random_bos_qty_trimmed() -> int:
    span = max(1, PMD_SVC_BOS_HIGH_LIMIT - PMD_SVC_BOS_LOW_LIMIT)
    trim = max(1, int(round(span * PMD_SVC_BOS_RANDOM_TRIM_PCT)))
    lo = max(PMD_SVC_BOS_RANDOM_MIN, PMD_SVC_BOS_LOW_LIMIT + trim)
    hi = PMD_SVC_BOS_HIGH_LIMIT - trim
    if lo > hi:
        lo, hi = PMD_SVC_BOS_RANDOM_MIN, PMD_SVC_BOS_HIGH_LIMIT
    return random.randint(lo, hi)


# Keep the full session console capture so PMD/DR DATA PUMP can export the
# current terminal/cmd log on demand.
CONSOLE_CAPTURE_MAX_LINES = 0
_CONSOLE_CAPTURE_LINES: deque[str] = deque()
_CONSOLE_CAPTURE_LOCK = threading.Lock()
_CONSOLE_CAPTURE_INSTALLED = False
_CONSOLE_CAPTURE_SEQ = 0
_CRASH_LOG_HOOK_INSTALLED = False
_ORIGINAL_EXCEPTHOOK = sys.excepthook
_ORIGINAL_THREADING_EXCEPTHOOK = getattr(threading, "excepthook", None)

TERM_HISTORY_MAX = 200
TERM_SCROLL_STEP_LINES = 3
TERM_COLOR_NORMAL = LINE_COLOR
TERM_COLOR_INPUT = (180, 255, 180)
TERM_COLOR_ERROR = (255, 96, 96)
TERM_COLOR_STATUS = (255, 220, 120)


def _term_line_style(line: str) -> str:
    stripped = str(line).strip()
    lowered = stripped.lower()
    if stripped.startswith(">>>"):
        return "input"
    if stripped.startswith("TERM:"):
        return "status"
    if (
        "traceback" in lowered
        or "error" in lowered
        or "exception" in lowered
        or stripped.startswith('File "')
        or stripped.startswith("^")
    ):
        return "error"
    return "normal"


def _term_line_color(style: str) -> Tuple[int, int, int]:
    if style == "input":
        return TERM_COLOR_INPUT
    if style == "error":
        return TERM_COLOR_ERROR
    if style == "status":
        return TERM_COLOR_STATUS
    return TERM_COLOR_NORMAL


def _term_wrap_line(line: str, max_chars: int) -> List[str]:
    width = max(1, int(max_chars))
    parts = textwrap.wrap(
        str(line) if str(line) != "" else " ",
        width=width,
        break_long_words=True,
        break_on_hyphens=False,
        drop_whitespace=False,
        replace_whitespace=False,
    )
    if len(parts) <= 0:
        return [""]
    return [str(part) for part in parts]


def _term_wrapped_snapshot(pmd_state: Dict[str, object], max_chars: int) -> List[Tuple[str, str]]:
    width = max(1, int(max_chars))
    cache_raw = pmd_state.get("term_wrap_cache", {})
    cache = cache_raw if isinstance(cache_raw, dict) else {}
    try:
        cache_width = int(cache.get("max_chars", -1))
    except Exception:
        cache_width = -1
    try:
        cache_seq = int(cache.get("seq", -1))
    except Exception:
        cache_seq = -1
    try:
        cache_raw_count = int(cache.get("raw_count", -1))
    except Exception:
        cache_raw_count = -1
    wrapped_raw = cache.get("wrapped", [])
    wrapped: List[Tuple[str, str]] = []
    if isinstance(wrapped_raw, list):
        for item in wrapped_raw:
            if isinstance(item, (tuple, list)) and len(item) >= 2:
                wrapped.append((str(item[0]), str(item[1])))
    wrap_counts_raw = cache.get("wrap_counts", [])
    wrap_counts: List[int] = []
    if isinstance(wrap_counts_raw, list):
        for count in wrap_counts_raw:
            try:
                wrap_counts.append(max(0, int(count)))
            except Exception:
                wrap_counts.append(0)
    if cache_width == width and cache_seq >= 0:
        try:
            if _console_capture_sequence() == cache_seq:
                return wrapped
        except Exception:
            pass

    raw_lines, seq = _console_capture_snapshot_with_seq()

    rebuild = (cache_width != width) or (cache_seq < 0) or (cache_raw_count < 0)
    if not rebuild:
        if seq == cache_seq:
            return wrapped
        append_count = seq - cache_seq
        expected_before_drop = cache_raw_count + append_count
        dropped_count = max(0, expected_before_drop - len(raw_lines))
        can_incremental = (
            append_count > 0
            and append_count <= len(raw_lines)
            and dropped_count <= cache_raw_count
            and len(wrap_counts) == cache_raw_count
        )
        if can_incremental:
            if dropped_count > 0:
                dropped_wrapped = sum(max(0, int(v)) for v in wrap_counts[:dropped_count])
                wrapped = wrapped[dropped_wrapped:]
                wrap_counts = wrap_counts[dropped_count:]
            for raw in raw_lines[-append_count:]:
                line = str(raw)
                style = _term_line_style(line)
                parts = _term_wrap_line(line, width)
                wrap_counts.append(len(parts))
                for part in parts:
                    wrapped.append((part, style))
            if len(wrap_counts) != len(raw_lines):
                rebuild = True
        else:
            rebuild = True

    if rebuild:
        wrapped = []
        wrap_counts = []
        for raw in raw_lines:
            line = str(raw)
            style = _term_line_style(line)
            parts = _term_wrap_line(line, width)
            wrap_counts.append(len(parts))
            for part in parts:
                wrapped.append((part, style))

    pmd_state["term_wrap_cache"] = {
        "max_chars": width,
        "seq": int(seq),
        "raw_count": len(raw_lines),
        "wrapped": wrapped,
        "wrap_counts": wrap_counts,
    }
    return wrapped


def _console_capture_append_line(line: str) -> None:
    global _CONSOLE_CAPTURE_SEQ
    try:
        clean = str(line).replace("\r", "")
    except Exception:
        clean = ""
    with _CONSOLE_CAPTURE_LOCK:
        _CONSOLE_CAPTURE_LINES.append(clean)
        _CONSOLE_CAPTURE_SEQ += 1


def _console_capture_snapshot() -> List[str]:
    with _CONSOLE_CAPTURE_LOCK:
        return list(_CONSOLE_CAPTURE_LINES)


def _console_capture_sequence() -> int:
    with _CONSOLE_CAPTURE_LOCK:
        return int(_CONSOLE_CAPTURE_SEQ)


def _console_capture_snapshot_with_seq() -> Tuple[List[str], int]:
    with _CONSOLE_CAPTURE_LOCK:
        return list(_CONSOLE_CAPTURE_LINES), int(_CONSOLE_CAPTURE_SEQ)


def _save_console_capture_pmdlog(label: str = "") -> Optional[Path]:
    lines = _console_capture_snapshot()
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    suffix = "".join(ch for ch in str(label).strip().lower() if ch.isalnum() or ch in {"_", "-"})
    suffix_text = f"_{suffix}" if suffix != "" else ""
    logs_dir = writable_path("logs")
    out_path = logs_dir / f"{timestamp}{suffix_text}.pmdlog"
    try:
        logs_dir.mkdir(parents=True, exist_ok=True)
        with out_path.open("w", encoding="utf-8", errors="replace", newline="\n") as f:
            f.write(f"F-35 PCD PMD DATA PUMP LOG\n")
            f.write(f"Generated: {datetime.now().isoformat(timespec='seconds')}\n")
            f.write(f"Lines: {len(lines)}\n")
            f.write("=" * 80 + "\n")
            for line in lines:
                f.write(str(line).replace("\r", "") + "\n")
        print(f"[PMD/DR][DATA PUMP] saved console log: {out_path}")
        return out_path
    except Exception as exc:
        print(f"[PMD/DR][DATA PUMP] failed to save console log: {exc}")
        return None


def install_crash_log_hook() -> None:
    global _CRASH_LOG_HOOK_INSTALLED
    if _CRASH_LOG_HOOK_INSTALLED:
        return

    def _crash_excepthook(exc_type, exc_value, exc_tb) -> None:
        try:
            _console_capture_append_line("[CRASH] Uncaught exception; writing PMD log.")
            for line in traceback.format_exception(exc_type, exc_value, exc_tb):
                for subline in str(line).rstrip().splitlines():
                    _console_capture_append_line(subline)
            _save_console_capture_pmdlog("crash")
        except Exception:
            pass
        try:
            _ORIGINAL_EXCEPTHOOK(exc_type, exc_value, exc_tb)
        except Exception:
            sys.__excepthook__(exc_type, exc_value, exc_tb)

    sys.excepthook = _crash_excepthook
    if _ORIGINAL_THREADING_EXCEPTHOOK is not None:
        def _thread_crash_excepthook(args) -> None:
            try:
                thread_name = getattr(getattr(args, "thread", None), "name", "unknown")
                _console_capture_append_line(f"[CRASH] Uncaught thread exception in {thread_name}; writing PMD log.")
                for line in traceback.format_exception(args.exc_type, args.exc_value, args.exc_traceback):
                    for subline in str(line).rstrip().splitlines():
                        _console_capture_append_line(subline)
                _save_console_capture_pmdlog("thread_crash")
            except Exception:
                pass
            try:
                _ORIGINAL_THREADING_EXCEPTHOOK(args)
            except Exception:
                pass

        threading.excepthook = _thread_crash_excepthook
    _CRASH_LOG_HOOK_INSTALLED = True


class _ConsoleCaptureTee:
    def __init__(self, original) -> None:
        self._orig = original
        self._partial = ""
        self._lock = threading.Lock()

    def write(self, data) -> int:
        text = str(data)
        with self._lock:
            try:
                self._orig.write(text)
            except Exception:
                pass
            if text != "":
                self._partial += text.replace("\r\n", "\n").replace("\r", "\n")
                while "\n" in self._partial:
                    line, self._partial = self._partial.split("\n", 1)
                    _console_capture_append_line(line)
        return len(text)

    def flush(self) -> None:
        try:
            self._orig.flush()
        except Exception:
            pass

    def isatty(self) -> bool:
        try:
            return bool(self._orig.isatty())
        except Exception:
            return False

    @property
    def encoding(self):
        try:
            return self._orig.encoding
        except Exception:
            return "utf-8"

    def __getattr__(self, name):
        return getattr(self._orig, name)


def install_console_capture() -> None:
    global _CONSOLE_CAPTURE_INSTALLED
    if _CONSOLE_CAPTURE_INSTALLED:
        return
    try:
        sys.stdout = _ConsoleCaptureTee(sys.stdout)
        sys.stderr = _ConsoleCaptureTee(sys.stderr)
        _CONSOLE_CAPTURE_INSTALLED = True
    except Exception:
        _CONSOLE_CAPTURE_INSTALLED = False


