def _engine_dynamic_pitch_enabled() -> bool:
    mode = str(ENGINE_DYNAMIC_PITCH_MODE).strip().lower()
    if mode in {"0", "false", "off", "no"}:
        return False
    if mode in {"1", "true", "on", "yes"}:
        return True
    # Auto mode: only enable dynamic pitch when NumPy fast-path is available.
    return np is not None


def _sound_effect_paths(name: str) -> List[Path]:
    raw = str(name).strip()
    if raw == "":
        return []
    aliases = [raw]
    if ("BAT " in raw) and ("BATT " not in raw):
        aliases.append(raw.replace("BAT ", "BATT "))
    if ("BATT " in raw) and ("BAT " not in raw):
        aliases.append(raw.replace("BATT ", "BAT "))
    out: List[Path] = []
    for alias in aliases:
        for root in (
            resource_path("SFX"),
            resource_path("sounds"),
            writable_path("SFX"),
            writable_path("sounds"),
        ):
            for ext in (".mp3", ".wav", ".ogg"):
                out.append(root / f"{alias}{ext}")
    return out


def _next_web_audio_clip_id() -> int:
    global _WEB_AUDIO_CLIP_ID
    try:
        with _WEB_AUDIO_CLIP_ID_LOCK:
            _WEB_AUDIO_CLIP_ID += 1
            if _WEB_AUDIO_CLIP_ID >= 2_000_000_000:
                _WEB_AUDIO_CLIP_ID = 1
            return int(_WEB_AUDIO_CLIP_ID)
    except Exception:
        return int(time.time() * 1000)


def _web_audio_mode_enabled() -> bool:
    return bool(WEB_COMM_STREAM_ENABLED and AUDIO_STREAM_ENABLED)


def _effective_local_sfx_volume(volume: float) -> float:
    # In web mode, keep mixer playback muted locally but still running so
    # channel busy/position timing for crossfades remains valid.
    if _web_audio_mode_enabled():
        return 0.0
    return max(0.0, min(1.0, float(volume)))


def _to_mono_pcm16(raw: bytes, channels: int) -> bytes:
    if channels <= 1:
        return raw
    try:
        total = len(raw) // 2
        if total <= 0:
            return b""
        # Keep first channel from interleaved int16 frames.
        out = bytearray((total // channels) * 2)
        oi = 0
        stride = channels * 2
        for i in range(0, len(raw) - 1, stride):
            out[oi:oi + 2] = raw[i:i + 2]
            oi += 2
        return bytes(out[:oi])
    except Exception:
        return raw


def _enqueue_web_audio_pcm(raw: bytes, sample_rate: int, channels: int, radio_tag: str = "sfx") -> None:
    if not _web_audio_mode_enabled():
        return
    if not raw:
        return
    try:
        mono = _to_mono_pcm16(raw, max(1, int(channels)))
        if not mono:
            return
        sr = max(1, int(sample_rate))
        chunk_frames = max(1, int((sr * WEB_AUDIO_PCM_CHUNK_MS) / 1000))
        chunk_bytes = max(2, chunk_frames * 2)  # mono int16
        payloads: List[str] = []
        for off in range(0, len(mono), chunk_bytes):
            part = mono[off:off + chunk_bytes]
            if not part:
                continue
            payloads.append(base64.b64encode(part).decode("ascii"))
        if not payloads:
            return
        clip_id = _next_web_audio_clip_id()
        chunk_total = len(payloads)
        fs = globals().get("frame_state", None)
        if fs is None:
            return
        with fs.audio_lock:
            for idx, payload in enumerate(payloads):
                if len(fs.audio_rx_queue) >= fs.audio_rx_queue.maxlen:
                    fs.audio_rx_queue.popleft()
                fs.audio_rx_queue.append(
                    {
                        "radio": str(radio_tag),
                        "sample_rate": int(sr),
                        "payload": payload,
                        "clip_id": int(clip_id),
                        "chunk_index": int(idx),
                        "chunk_total": int(chunk_total),
                    }
                )
    except Exception:
        pass


def _enqueue_web_audio_stop(radio_tag: str) -> None:
    if not _web_audio_mode_enabled():
        return
    try:
        fs = globals().get("frame_state", None)
        if fs is None:
            return
        target = str(radio_tag)
        with fs.audio_lock:
            # Drop any queued PCM/stop items for this stream so the stop takes
            # effect immediately on web clients.
            kept = deque(maxlen=fs.audio_rx_queue.maxlen)
            for item in fs.audio_rx_queue:
                try:
                    if isinstance(item, dict) and str(item.get("radio", "")) == target:
                        continue
                except Exception:
                    pass
                kept.append(item)
            fs.audio_rx_queue = kept
            if len(fs.audio_rx_queue) >= fs.audio_rx_queue.maxlen:
                fs.audio_rx_queue.popleft()
            fs.audio_rx_queue.append({"kind": "stop", "radio": target})
    except Exception:
        pass


def _apply_pcm16_gain_fade(raw: bytes, sample_rate: int, channels: int, gain: float, fade_in_ms: int, fade_out_ms: int) -> bytes:
    try:
        ch = max(1, int(channels))
        if len(raw) < 2:
            return raw
        samples = array("h")
        samples.frombytes(raw)
        total_frames = len(samples) // ch
        if total_frames <= 0:
            return raw
        g_base = max(0.0, min(1.0, float(gain)))
        if g_base <= 0.0:
            return b"\x00" * len(raw)
        fi = max(0, int(round((max(0, int(fade_in_ms)) * int(sample_rate)) / 1000.0)))
        fo = max(0, int(round((max(0, int(fade_out_ms)) * int(sample_rate)) / 1000.0)))
        if fi > total_frames:
            fi = total_frames
        if fo > total_frames:
            fo = total_frames
        for frame_idx in range(total_frames):
            g = g_base
            if fi > 0 and frame_idx < fi:
                g *= (frame_idx / float(max(1, fi)))
            if fo > 0 and frame_idx >= (total_frames - fo):
                tail_pos = total_frames - frame_idx
                g *= (tail_pos / float(max(1, fo)))
            if g >= 0.999:
                continue
            base_i = frame_idx * ch
            for c in range(ch):
                v = int(samples[base_i + c])
                nv = int(round(v * g))
                if nv > 32767:
                    nv = 32767
                elif nv < -32768:
                    nv = -32768
                samples[base_i + c] = nv
        return samples.tobytes()
    except Exception:
        return raw


def _engine_pitch_ratio_from_thrust(thrust_pct: float) -> float:
    try:
        thrust = float(thrust_pct)
    except Exception:
        thrust = 0.0
    norm = max(0.0, min(1.0, thrust / 150.0))
    return float(ENGINE_LOOP_PITCH_MIN) + (float(ENGINE_LOOP_PITCH_MAX) - float(ENGINE_LOOP_PITCH_MIN)) * norm


def _engine_pitch_quantized_ratio(ratio: float) -> float:
    try:
        val = float(ratio)
    except Exception:
        val = float(ENGINE_LOOP_PITCH_MIN)
    val = max(float(ENGINE_LOOP_PITCH_MIN), min(float(ENGINE_LOOP_PITCH_MAX), val))
    step = float(ENGINE_PITCH_RESOLUTION)
    if step <= 0.0:
        return val
    return round(val / step) * step


def _engine_pitch_ratio_key(ratio: float) -> str:
    return f"{_ENGINE_PITCH_BASE_SOUND_KEY}|PITCH|{_engine_pitch_quantized_ratio(ratio):.6f}"


def _resample_sound_int16_for_pitch(
    snd: pygame.mixer.Sound,
    ratio: float,
) -> Optional[pygame.mixer.Sound]:
    if snd is None:
        return None
    try:
        ratio = float(ratio)
    except Exception:
        return None
    if ratio <= 0.0 or abs(ratio - 1.0) < 1e-6:
        return snd

    mix_cfg = pygame.mixer.get_init()
    if mix_cfg is None:
        return None
    sample_width = int(mix_cfg[1])
    channels = max(1, int(mix_cfg[2])) if len(mix_cfg) >= 3 else 1
    sample_rate = max(1, int(mix_cfg[0]))

    raw = snd.get_raw()
    if not raw:
        return None
    ratio = max(1e-6, ratio)

    # Preferred path for 16-bit PCM.
    if np is not None and abs(sample_width) in (16, -16):
        try:
            arr = np.frombuffer(raw, dtype=np.int16)
            if arr.size <= 0:
                return None
            frames = max(1, arr.size // channels)
            try:
                arr = arr[:frames * channels].reshape((frames, channels))
            except Exception:
                return None
            if frames <= 2:
                return None

            out_frames = max(1, int(round(frames / ratio)))
            src_idx = np.linspace(0.0, float(frames - 1), out_frames, dtype=np.float32)
            idx_lo = np.floor(src_idx).astype(np.int64)
            idx_hi = np.minimum(idx_lo + 1, frames - 1).astype(np.int64)
            frac = (src_idx - idx_lo.astype(np.float32)).reshape(-1, 1)
            lo = arr[idx_lo]
            hi = arr[idx_hi]
            interp = (lo.astype(np.float32) * (1.0 - frac) + hi.astype(np.float32) * frac).astype(np.float32)
            interp = np.rint(np.clip(interp, -32768.0, 32767.0)).astype(np.int16)

            # Prevent discontinuities at sample boundaries by applying a short edge fade.
            fade_frames = max(1, int(round(sample_rate * 0.001)))
            fade_frames = min(fade_frames, max(1, (arr.shape[0] // 2)))
            if fade_frames > 0:
                ramp = np.linspace(0.0, 1.0, fade_frames, dtype=np.float32).reshape(-1, 1)
                end_ramp = np.linspace(1.0, 0.0, fade_frames, dtype=np.float32).reshape(-1, 1)
                # If output is shorter than input (higher pitch), derive fade windows from output length too.
                if interp.shape[0] >= fade_frames:
                    interp[:fade_frames] = (interp[:fade_frames].astype(np.float32) * ramp).astype(np.float32)
                    interp[-fade_frames:] = (interp[-fade_frames:].astype(np.float32) * end_ramp).astype(np.float32)

            out_arr = interp
            if channels == 1:
                out_arr = np.asarray(out_arr[:, 0], dtype=np.int16)
            snd_out = pygame.mixer.Sound(buffer=out_arr.tobytes())
            snd_out.set_volume(1.0)
            return snd_out
        except Exception:
            pass

    # Fallback path (non-NumPy): simple linear PCM16 resampling.
    if abs(sample_width) not in (16, -16):
        return None
    try:
        src = array("h")
        src.frombytes(raw)
    except Exception:
        return None
    if len(src) <= 0:
        return None
    frames = max(1, len(src) // channels)
    if frames <= 2:
        return None
    src = src[: frames * channels]
    out_frames = max(1, int(round(frames / ratio)))
    dst = array("h", [0]) * max(1, out_frames * channels)

    for out_i in range(out_frames):
        src_pos = float(out_i) * ratio
        lo = int(src_pos)
        if lo < 0:
            lo = 0
        if lo >= (frames - 1):
            lo = frames - 1
            hi = lo
            frac = 0.0
        else:
            hi = lo + 1
            frac = src_pos - float(lo)
        base_lo = lo * channels
        base_hi = hi * channels
        base_out = out_i * channels
        for ch_i in range(channels):
            a = int(src[base_lo + ch_i])
            b = int(src[base_hi + ch_i])
            val = float(a) + (float(b) - float(a)) * frac
            ival = int(round(val))
            if ival > 32767:
                ival = 32767
            elif ival < -32768:
                ival = -32768
            dst[base_out + ch_i] = ival

    # Light edge fade to reduce click risk at splice boundaries.
    try:
        fade_frames = max(1, int(round(sample_rate * 0.001)))
        fade_frames = min(fade_frames, max(1, out_frames // 2))
        if fade_frames > 0:
            for i in range(fade_frames):
                g_in = float(i) / float(max(1, fade_frames))
                g_out = float(fade_frames - i) / float(max(1, fade_frames))
                in_base = i * channels
                out_base = (out_frames - 1 - i) * channels
                for ch_i in range(channels):
                    v0 = int(round(float(dst[in_base + ch_i]) * g_in))
                    v1 = int(round(float(dst[out_base + ch_i]) * g_out))
                    if v0 > 32767:
                        v0 = 32767
                    elif v0 < -32768:
                        v0 = -32768
                    if v1 > 32767:
                        v1 = 32767
                    elif v1 < -32768:
                        v1 = -32768
                    dst[in_base + ch_i] = v0
                    dst[out_base + ch_i] = v1
    except Exception:
        pass

    try:
        snd_out = pygame.mixer.Sound(buffer=dst.tobytes())
        snd_out.set_volume(1.0)
        return snd_out
    except Exception:
        return None


def _get_engine_pitch_sound_for_ratio(pitch_ratio: float) -> str:
    if not _engine_dynamic_pitch_enabled():
        return _ENGINE_PITCH_BASE_SOUND_KEY
    ratio = _engine_pitch_quantized_ratio(pitch_ratio)
    if ratio <= float(ENGINE_LOOP_PITCH_MIN):
        return _ENGINE_PITCH_BASE_SOUND_KEY
    key = _engine_pitch_ratio_key(ratio)
    if key in _SOUND_CACHE:
        return key
    if key in _ENGINE_LOOP_PITCH_CACHE and _ENGINE_LOOP_PITCH_CACHE.get(key) == key:
        return key
    base = load_sound_effect(_ENGINE_PITCH_BASE_SOUND_KEY)
    if base is None:
        return _ENGINE_PITCH_BASE_SOUND_KEY
    pitched = _resample_sound_int16_for_pitch(base, ratio)
    if pitched is None:
        return _ENGINE_PITCH_BASE_SOUND_KEY
    _SOUND_CACHE[key] = pitched
    _ENGINE_LOOP_PITCH_CACHE[key] = key
    return key


def _apply_engine_pitch_from_thrust(
    track: "Any",
    thrust_pct: float,
    now_ms: int,
) -> None:
    if not _engine_dynamic_pitch_enabled():
        return
    try:
        cmd = str(_ensure_panel_button_states().get("THROTTLE", {}).get("ENGINE", "OFF")).upper()
    except Exception:
        cmd = "OFF"
    if cmd != "RUN":
        return
    thrust_ratio = _engine_pitch_ratio_from_thrust(thrust_pct)
    current_ratio = float(getattr(track, "_engine_pitch_ratio", float(ENGINE_LOOP_PITCH_MIN)))
    target_ratio = float(getattr(track, "_engine_pitch_target_ratio", thrust_ratio))
    now_ms_i = int(now_ms)
    prev_ms = int(getattr(track, "_engine_pitch_last_ms", now_ms_i))
    last_apply_ms = int(getattr(track, "_engine_pitch_last_apply_ms", prev_ms))
    dt_ms = max(0, now_ms_i - prev_ms)
    smooth_ms = max(1, float(ENGINE_PITCH_SMOOTH_MS))
    alpha = 1.0 if dt_ms >= smooth_ms else (dt_ms / smooth_ms)
    target_ratio = max(float(ENGINE_LOOP_PITCH_MIN), min(float(ENGINE_LOOP_PITCH_MAX), float(thrust_ratio)))
    smooth_ratio = float(current_ratio) + (float(target_ratio) - float(current_ratio)) * float(alpha)
    smooth_ratio = float(_engine_pitch_quantized_ratio(smooth_ratio))
    applied_ratio = float(getattr(track, "_engine_pitch_applied_ratio", current_ratio)) if track is not None else smooth_ratio
    sound_key = _get_engine_pitch_sound_for_ratio(smooth_ratio)
    if track is not None:
        setattr(track, "_engine_pitch_target_ratio", target_ratio)
        setattr(track, "_engine_pitch_ratio", smooth_ratio)
        setattr(track, "_engine_pitch_last_ms", now_ms_i)
    if abs(float(smooth_ratio) - float(applied_ratio)) < float(ENGINE_PITCH_MIN_DELTA):
        if track is not None:
            setattr(track, "_engine_pitch_next_key", "")
        return
    current = str(getattr(track, "_engine_pitch_band", "")) if track is not None else ""
    if str(sound_key) == str(current):
        if track is not None:
            setattr(track, "_engine_pitch_next_key", "")
            setattr(track, "_engine_pitch_applied_ratio", smooth_ratio)
        return
    if (now_ms_i - last_apply_ms) < int(ENGINE_PITCH_APPLY_MS):
        if track is not None:
            setattr(track, "_engine_pitch_next_key", str(sound_key))
        return
    if track is not None:
        try:
            if not bool(track.loop_active):
                setattr(track, "_engine_pitch_band", sound_key)
                track.loop_name = sound_key
                setattr(track, "_engine_pitch_next_key", "")
                setattr(track, "_engine_pitch_applied_ratio", smooth_ratio)
                setattr(track, "_engine_pitch_last_apply_ms", now_ms_i)
                return
            if bool(track.start_active):
                track.loop_name = sound_key
                setattr(track, "_engine_pitch_band", sound_key)
                setattr(track, "_engine_pitch_next_key", "")
                setattr(track, "_engine_pitch_applied_ratio", smooth_ratio)
                setattr(track, "_engine_pitch_last_apply_ms", now_ms_i)
                return
            # Real-time pitch tracking: swap loop variant immediately instead of
            # waiting for the next natural loop boundary.
            if bool(track.loop_fade_active):
                setattr(track, "_engine_pitch_next_key", str(sound_key))
                return
            next_ch = int(track.loop_next_ch)
            played = play_sound_effect_on_channel(
                str(sound_key),
                next_ch,
                loops=0,
                volume=0.0,
                web_fade_in_ms=int(ENGINE_PITCH_CROSSFADE_MS),
                web_fade_out_ms=int(ENGINE_PITCH_CROSSFADE_MS),
            )
            if played:
                track.loop_name = str(sound_key)
                setattr(track, "_engine_pitch_band", str(sound_key))
                setattr(track, "_engine_pitch_next_key", "")
                setattr(track, "_engine_pitch_applied_ratio", smooth_ratio)
                track.loop_fade_ms = int(ENGINE_PITCH_CROSSFADE_MS)
                track.loop_fade_active = True
                track.loop_fade_start_ms = int(now_ms_i)
                new_len = int(get_sound_effect_length_ms(str(sound_key)))
                if new_len > 0:
                    track.loop_len_ms = int(new_len)
                setattr(track, "_engine_pitch_last_apply_ms", now_ms_i)
                return
            setattr(track, "_engine_pitch_next_key", str(sound_key))
            setattr(track, "_engine_pitch_last_apply_ms", now_ms_i)
            return
        except Exception:
            setattr(track, "_engine_pitch_band", sound_key)
            track.loop_name = sound_key
            setattr(track, "_engine_pitch_next_key", "")
            setattr(track, "_engine_pitch_applied_ratio", smooth_ratio)
            setattr(track, "_engine_pitch_last_apply_ms", now_ms_i)
            return


def _emit_sound_for_web_and_record(
    snd: pygame.mixer.Sound,
    gain: float,
    fade_in_ms: int = 0,
    fade_out_ms: int = 0,
    radio_tag: str = "sfx",
) -> None:
    try:
        raw = snd.get_raw()
        mix_cfg = pygame.mixer.get_init()
        if not raw or mix_cfg is None:
            return
        sr = int(mix_cfg[0])
        ch = int(mix_cfg[2]) if len(mix_cfg) >= 3 else 1
        processed = _apply_pcm16_gain_fade(raw, sr, ch, gain, fade_in_ms, fade_out_ms)
        _enqueue_web_audio_pcm(processed, sr, ch, radio_tag=radio_tag)
        sink = _RECORD_AUDIO_SINK
        if sink is not None:
            sink(processed, sr, max(1, ch))
    except Exception:
        pass


def _record_sound_to_sink(snd: pygame.mixer.Sound) -> None:
    try:
        raw = snd.get_raw()
        mix_cfg = pygame.mixer.get_init()
        if raw and mix_cfg is not None:
            sr = int(mix_cfg[0])
            ch = int(mix_cfg[2]) if len(mix_cfg) >= 3 else 1
            _enqueue_web_audio_pcm(raw, sr, ch, radio_tag="sfx_misc")
            sink = _RECORD_AUDIO_SINK
            if sink is not None:
                sink(raw, sr, max(1, ch))
    except Exception:
        pass


def load_sound_effect(name: str) -> Optional[pygame.mixer.Sound]:
    if not SOUND_ENABLED:
        return None
    cached = _SOUND_CACHE.get(name)
    if cached is not None:
        return cached
    for path in _sound_effect_paths(name):
        if not path.exists():
            continue
        try:
            snd = pygame.mixer.Sound(str(path))
            snd.set_volume(1.0)
            _SOUND_CACHE[name] = snd
            return snd
        except Exception:
            continue
    return None


def play_sound_effect(name: str) -> None:
    snd = load_sound_effect(name)
    if snd is None:
        return
    _record_sound_to_sink(snd)
    if _web_audio_mode_enabled():
        return
    try:
        target = _sound_effect_target_volume(name)
        ch = None
        try:
            if pygame.mixer.get_init() is not None:
                ch = pygame.mixer.find_channel(False)
        except Exception:
            ch = None
        if ch is not None:
            ch.set_volume(_effective_local_sfx_volume(float(target)))
            ch.play(snd)
        else:
            snd.play()
    except Exception:
        pass


def play_sound_effect_on_channel(
    name: str,
    channel_index: int,
    loops: int = 0,
    volume: Optional[float] = None,
    web_fade_in_ms: int = 0,
    web_fade_out_ms: int = 0,
) -> bool:
    snd = load_sound_effect(name)
    if snd is None:
        return False
    try:
        if pygame.mixer.get_init() is None:
            return False
        needed = max(1, int(channel_index) + 1)
        if pygame.mixer.get_num_channels() < needed:
            pygame.mixer.set_num_channels(needed)
        ch = pygame.mixer.Channel(int(channel_index))
        if volume is None:
            target_volume = float(_sound_effect_target_volume(name))
        else:
            target_volume = max(0.0, min(1.0, float(volume)))
        if _web_audio_mode_enabled():
            # Web mode receives pre-shaped chunks; bake crossfade envelopes
            # directly into emitted PCM.
            emit_gain = target_volume
            if int(web_fade_in_ms) > 0 and emit_gain <= 0.0001:
                emit_gain = float(SOUND_VOLUME)
            _emit_sound_for_web_and_record(
                snd,
                emit_gain,
                int(web_fade_in_ms),
                int(web_fade_out_ms),
                radio_tag=f"sfx_{int(channel_index)}",
            )
        else:
            _record_sound_to_sink(snd)
        if volume is None:
            ch.set_volume(_effective_local_sfx_volume(float(SOUND_VOLUME)))
        else:
            ch.set_volume(_effective_local_sfx_volume(float(volume)))
        ch.play(snd, loops=int(loops))
        return True
    except Exception:
        return False


def is_sound_channel_busy(channel_index: int) -> bool:
    try:
        if pygame.mixer.get_init() is None:
            return False
        if pygame.mixer.get_num_channels() <= int(channel_index):
            return False
        return bool(pygame.mixer.Channel(int(channel_index)).get_busy())
    except Exception:
        return False


def stop_sound_channel(channel_index: int) -> None:
    idx = int(channel_index)
    try:
        if pygame.mixer.get_init() is None:
            return
        if pygame.mixer.get_num_channels() > idx:
            pygame.mixer.Channel(idx).stop()
    except Exception:
        pass
    finally:
        _enqueue_web_audio_stop(f"sfx_{idx}")


def set_sound_channel_volume(channel_index: int, volume: float) -> None:
    try:
        if pygame.mixer.get_init() is None:
            return
        if pygame.mixer.get_num_channels() <= int(channel_index):
            return
        pygame.mixer.Channel(int(channel_index)).set_volume(_effective_local_sfx_volume(float(volume)))
    except Exception:
        pass


def set_master_sound_volume(volume: float) -> float:
    global SOUND_VOLUME
    try:
        v = max(0.0, min(1.0, float(volume)))
    except Exception:
        v = float(SOUND_VOLUME)
    SOUND_VOLUME = float(v)
    try:
        for snd in list(_SOUND_CACHE.values()):
            try:
                snd.set_volume(1.0)
            except Exception:
                continue
    except Exception:
        pass
    return float(SOUND_VOLUME)


def get_sound_effect_length_ms(name: str) -> int:
    snd = load_sound_effect(name)
    if snd is None:
        return 0
    try:
        return max(0, int(round(float(snd.get_length()) * 1000.0)))
    except Exception:
        return 0


def get_sound_length_or_default_ms(name: str, default_ms: int) -> int:
    try:
        length_ms = int(get_sound_effect_length_ms(name))
    except Exception:
        length_ms = 0
    if length_ms <= 0:
        return max(1, int(default_ms))
    return max(1, int(length_ms))


@dataclass
class CrossfadeLoopTrack:
    start_name: str
    loop_name: str
    start_channel: int
    loop_ch_a: int
    loop_ch_b: int
    desired_on: bool = False
    start_active: bool = False
    start_started_ms: int = 0
    start_len_ms: int = 0
    start_bridge_started: bool = False
    loop_active: bool = False
    loop_active_ch: int = 0
    loop_next_ch: int = 0
    loop_started_ms: int = 0
    loop_len_ms: int = 0
    loop_fade_active: bool = False
    loop_fade_start_ms: int = 0
    loop_fade_ms: int = SFX_CROSSFADE_MS
    volume_profile: str = "master"


def _engine_ipp_volume() -> float:
    try:
        return max(0.0, min(1.0, float(ENGINE_IPP_VOLUME)))
    except Exception:
        return 0.5


def _icaws_alert_volume() -> float:
    try:
        if not bool(ICAWS_ALERT_ENABLED):
            return 0.0
        return max(0.0, min(1.0, float(ICAWS_ALERT_VOLUME)))
    except Exception:
        return 0.0


def _track_target_volume(track: CrossfadeLoopTrack) -> float:
    if str(getattr(track, "volume_profile", "master")).strip().lower() == "engine_ipp":
        return _engine_ipp_volume()
    try:
        return max(0.0, min(1.0, float(SOUND_VOLUME)))
    except Exception:
        return 0.5


def _reset_crossfade_track(track: CrossfadeLoopTrack) -> None:
    stop_sound_channel(track.start_channel)
    stop_sound_channel(track.loop_ch_a)
    stop_sound_channel(track.loop_ch_b)
    track.start_active = False
    track.start_started_ms = 0
    track.start_len_ms = 0
    track.start_bridge_started = False
    track.loop_active = False
    track.loop_active_ch = track.loop_ch_a
    track.loop_next_ch = track.loop_ch_b
    track.loop_started_ms = 0
    track.loop_len_ms = 0
    track.loop_fade_active = False
    track.loop_fade_start_ms = 0
    track.loop_fade_ms = int(SFX_CROSSFADE_MS)


def _start_loop_cycle(track: CrossfadeLoopTrack, now_ms: int, channel_index: int, volume: float) -> bool:
    track.loop_name = str(track.loop_name)
    track.loop_fade_ms = int(SFX_CROSSFADE_MS)
    fade_in_ms = int(SFX_CROSSFADE_MS) if float(volume) < float(_track_target_volume(track)) else 0
    fade_out_ms = int(SFX_CROSSFADE_MS)
    if not play_sound_effect_on_channel(
        track.loop_name,
        channel_index,
        loops=0,
        volume=volume,
        web_fade_in_ms=fade_in_ms,
        web_fade_out_ms=fade_out_ms,
    ):
        return False
    track.loop_active = True
    track.loop_active_ch = int(channel_index)
    track.loop_next_ch = track.loop_ch_b if track.loop_active_ch == track.loop_ch_a else track.loop_ch_a
    track.loop_started_ms = int(now_ms)
    if track.loop_len_ms <= 0:
        track.loop_len_ms = get_sound_effect_length_ms(track.loop_name)
    return True


def _start_track_with_start_sound(track: CrossfadeLoopTrack, now_ms: int, start_volume: Optional[float] = None) -> None:
    _reset_crossfade_track(track)
    track.start_len_ms = get_sound_effect_length_ms(track.start_name)
    target_volume = float(_track_target_volume(track))
    if start_volume is None:
        start_volume = float(target_volume)
    fade_in_ms = int(SFX_CROSSFADE_MS) if float(start_volume) < float(target_volume) else 0
    fade_out_ms = int(SFX_CROSSFADE_MS)
    played = play_sound_effect_on_channel(
        track.start_name,
        track.start_channel,
        loops=0,
        volume=float(start_volume),
        web_fade_in_ms=fade_in_ms,
        web_fade_out_ms=fade_out_ms,
    )
    if played:
        track.start_active = True
        track.start_started_ms = int(now_ms)
        track.start_bridge_started = False
    else:
        # If start sound is unavailable, begin loop immediately.
        _start_loop_cycle(track, now_ms, track.loop_ch_a, float(target_volume))


def _start_track_with_loop_sound(track: CrossfadeLoopTrack, now_ms: int) -> None:
    _reset_crossfade_track(track)
    _start_loop_cycle(track, now_ms, track.loop_ch_a, float(_track_target_volume(track)))


def _update_crossfade_track(track: CrossfadeLoopTrack, now_ms: int) -> None:
    if not track.desired_on:
        if track.start_active or track.loop_active or track.loop_fade_active:
            _reset_crossfade_track(track)
        return

    target_volume = float(_track_target_volume(track))

    if (not track.start_active) and (not track.loop_active):
        _start_track_with_start_sound(track, now_ms)

    # Crossfade START -> LOOP near the end of START.
    if track.start_active:
        fade_ms = max(1, min(SFX_CROSSFADE_MS, track.start_len_ms if track.start_len_ms > 0 else SFX_CROSSFADE_MS))
        bridge_start_ms = track.start_started_ms + max(0, track.start_len_ms - fade_ms)
        if (not track.start_bridge_started) and now_ms >= bridge_start_ms:
            if not track.loop_active:
                _start_loop_cycle(track, now_ms, track.loop_ch_a, 0.0)
            track.start_bridge_started = True
        if track.start_bridge_started and track.loop_active:
            prog = max(0.0, min(1.0, (now_ms - bridge_start_ms) / float(max(1, fade_ms))))
            gain_out = math.cos(prog * (math.pi * 0.5))
            gain_in = math.sin(prog * (math.pi * 0.5))
            set_sound_channel_volume(track.start_channel, float(target_volume) * float(gain_out))
            set_sound_channel_volume(track.loop_active_ch, float(target_volume) * float(gain_in))
        start_done = (track.start_len_ms > 0 and now_ms >= (track.start_started_ms + track.start_len_ms)) or (not is_sound_channel_busy(track.start_channel))
        if start_done:
            stop_sound_channel(track.start_channel)
            track.start_active = False
            track.start_bridge_started = False
            if not track.loop_active:
                _start_loop_cycle(track, now_ms, track.loop_ch_a, float(target_volume))
            else:
                set_sound_channel_volume(track.loop_active_ch, float(target_volume))

    # Crossfade LOOP -> LOOP (seamless ping-pong one-shot cycles).
    if track.loop_active:
        if track.loop_len_ms <= 0:
            track.loop_len_ms = get_sound_effect_length_ms(track.loop_name)
        fade_ms = max(1, min(int(track.loop_fade_ms), track.loop_len_ms if track.loop_len_ms > 0 else int(track.loop_fade_ms)))
        next_cycle_ms = track.loop_started_ms + max(0, track.loop_len_ms - fade_ms)
        if (not track.loop_fade_active) and track.loop_len_ms > 0 and now_ms >= next_cycle_ms:
            pending_key = ""
            try:
                pending_key = str(getattr(track, "_engine_pitch_next_key", ""))
            except Exception:
                pending_key = ""
                pass
            next_loop_name = str(track.loop_name)
            if pending_key:
                next_loop_name = pending_key
                track.loop_name = pending_key
                setattr(track, "_engine_pitch_next_key", "")
                setattr(track, "_engine_pitch_band", pending_key)
                new_len = get_sound_effect_length_ms(pending_key)
                if int(new_len) > 0:
                    track.loop_len_ms = int(new_len)
                track.loop_fade_ms = int(ENGINE_PITCH_CROSSFADE_MS)
            if play_sound_effect_on_channel(
                next_loop_name,
                track.loop_next_ch,
                loops=0,
                volume=0.0,
                web_fade_in_ms=int(SFX_CROSSFADE_MS),
                web_fade_out_ms=int(SFX_CROSSFADE_MS),
            ):
                track.loop_fade_active = True
                track.loop_fade_start_ms = int(now_ms)
        if track.loop_fade_active:
            prog = max(0.0, min(1.0, (now_ms - track.loop_fade_start_ms) / float(max(1, fade_ms))))
            gain_out = math.cos(prog * (math.pi * 0.5))
            gain_in = math.sin(prog * (math.pi * 0.5))
            set_sound_channel_volume(track.loop_active_ch, float(target_volume) * float(gain_out))
            set_sound_channel_volume(track.loop_next_ch, float(target_volume) * float(gain_in))
            if prog >= 1.0:
                stop_sound_channel(track.loop_active_ch)
                old_active = track.loop_active_ch
                track.loop_active_ch = track.loop_next_ch
                track.loop_next_ch = track.loop_ch_b if track.loop_active_ch == track.loop_ch_a else track.loop_ch_a
                track.loop_started_ms = int(track.loop_fade_start_ms)
                track.loop_fade_active = False
                track.loop_fade_start_ms = 0
                set_sound_channel_volume(track.loop_active_ch, float(target_volume))
                if old_active not in {track.loop_ch_a, track.loop_ch_b}:
                    stop_sound_channel(old_active)
                # If pitch updated during the fade, retarget immediately to avoid
                # audible "stair step" holds between ratio changes.
                pending_key = ""
                try:
                    pending_key = str(getattr(track, "_engine_pitch_next_key", ""))
                except Exception:
                    pending_key = ""
                if pending_key:
                    if pending_key == str(track.loop_name):
                        setattr(track, "_engine_pitch_next_key", "")
                    else:
                        if play_sound_effect_on_channel(
                            pending_key,
                            track.loop_next_ch,
                            loops=0,
                            volume=0.0,
                            web_fade_in_ms=int(ENGINE_PITCH_CROSSFADE_MS),
                            web_fade_out_ms=int(ENGINE_PITCH_CROSSFADE_MS),
                        ):
                            track.loop_name = pending_key
                            setattr(track, "_engine_pitch_band", pending_key)
                            setattr(track, "_engine_pitch_next_key", "")
                            new_len = get_sound_effect_length_ms(pending_key)
                            if int(new_len) > 0:
                                track.loop_len_ms = int(new_len)
                            track.loop_fade_ms = int(ENGINE_PITCH_CROSSFADE_MS)
                            track.loop_fade_active = True
                            track.loop_fade_start_ms = int(now_ms)
        # Recovery: if active loop dropped unexpectedly (decoder hiccup), restart.
        if (not track.loop_fade_active) and (not is_sound_channel_busy(track.loop_active_ch)):
            _start_loop_cycle(track, now_ms, track.loop_active_ch, float(target_volume))


def set_engine_ipp_volume(volume: float) -> float:
    global ENGINE_IPP_VOLUME
    old_volume = _engine_ipp_volume()
    try:
        ENGINE_IPP_VOLUME = max(0.0, min(1.0, float(volume)))
    except Exception:
        pass
    new_volume = _engine_ipp_volume()
    # Apply new cockpit gain immediately to active engine/IPP/battery channels
    # so users hear changes without waiting for loop boundaries.
    try:
        if pygame.mixer.get_init() is not None:
            cockpit_channels = (
                SFX_CH_BATT_START,
                SFX_CH_BATT_LOOP_A,
                SFX_CH_BATT_LOOP_B,
                SFX_CH_IPP_START,
                SFX_CH_IPP_LOOP_A,
                SFX_CH_IPP_LOOP_B,
                SFX_CH_ENGINE_START,
                SFX_CH_ENGINE_LOOP_A,
                SFX_CH_ENGINE_LOOP_B,
                SFX_CH_ENGINE_OFF,
            )
            for ch_idx in cockpit_channels:
                try:
                    if pygame.mixer.get_num_channels() <= int(ch_idx):
                        continue
                    ch = pygame.mixer.Channel(int(ch_idx))
                    if not ch.get_busy():
                        continue
                    cur_vol = max(0.0, min(1.0, float(ch.get_volume())))
                    if old_volume > 0.00001:
                        rel = max(0.0, min(1.0, cur_vol / float(old_volume)))
                    else:
                        rel = 1.0 if cur_vol > 0.0 else 0.0
                    set_sound_channel_volume(int(ch_idx), float(new_volume) * float(rel))
                except Exception:
                    continue
    except Exception:
        pass
    return float(new_volume)


def set_icaws_alert_audio(enabled: bool, volume: float) -> float:
    global ICAWS_ALERT_ENABLED, ICAWS_ALERT_VOLUME
    try:
        ICAWS_ALERT_ENABLED = bool(enabled)
    except Exception:
        ICAWS_ALERT_ENABLED = True
    try:
        ICAWS_ALERT_VOLUME = max(0.0, min(1.0, float(volume)))
    except Exception:
        pass
    return _icaws_alert_volume()


def _is_cockpit_sound_effect(name: str) -> bool:
    token = str(name or "").strip().upper()
    if token == "":
        return False
    return token in {
        "SWITCH",
        "BATT START",
        "BATT ON",
        "IPP START",
        "IPP ON",
        "ENGINE START",
        "ENGINE ON",
        "ENGINE OFF",
    }


def _sound_effect_target_volume(name: str) -> float:
    token = str(name or "").strip().upper()
    if token in {"WARNING", "CAUTION"}:
        return float(_icaws_alert_volume())
    if _is_cockpit_sound_effect(name):
        return float(_engine_ipp_volume())
    return float(SOUND_VOLUME)


def set_record_audio_sink(sink: Optional[Callable[[bytes, int, int], None]]) -> None:
    global _RECORD_AUDIO_SINK
    _RECORD_AUDIO_SINK = sink


def cleanup_old_recordings(recordings_dir: Path, older_than_seconds: int = RECORDING_RETENTION_SECONDS) -> None:
    try:
        if not recordings_dir.exists():
            return
        now_ts = datetime.now().timestamp()
        for p in recordings_dir.glob("*.mp4"):
            try:
                age = now_ts - p.stat().st_mtime
                if age > older_than_seconds:
                    p.unlink(missing_ok=True)
            except Exception:
                continue
    except Exception:
        pass

def open_vded(portal_index: int, vded_name: str) -> None:
    if _REQUEST_VDED is None:
        return
    _REQUEST_VDED(portal_index, vded_name)


def load_settings() -> dict:
    defaults = {
        "master_volume": 0.5,
        "engine_ipp_volume": 0.3,
        "comm_vola": 5,
        "comm_volb": 5,
        "comm_volc": 5,
        "comm_vold": 5,
        "audio_thrt_on": True,
        "audio_wpn_on": True,
        "audio_navaid_on": True,
        "audio_icaws_on": True,
        "audio_ics_on": True,
        "audio_vox_on": True,
        "audio_ckpt_on": True,
        "audio_thrt_vol": 5,
        "audio_wpn_vol": 5,
        "audio_navaid_vol": 5,
        "audio_icaws_vol": 5,
        "audio_ics_vol": 5,
        "audio_vox_vol": 5,
        "audio_ckpt_vol": 3,
        "audio_icaws_volume": 5,
        "adsb_enabled": True,
        "adsb_radius_km": ADSB_DEFAULT_RADIUS_KM,
        "adsb_min_interval_s": ADSB_DEFAULT_MIN_INTERVAL_S,
        "cesium_ion_token": "",
        FLIGHT_KEYBINDS_SETTINGS_KEY: {},
        HOTAS_BINDINGS_SETTINGS_KEY: {},
        PMD_AUTOLOAD_SETTINGS_KEY: [],
        PMD_ENABLED_SETTINGS_KEY: [],
        WINDOW_STATE_SETTINGS_KEY: {},
    }
    if SETTINGS_PATH.exists():
        try:
            raw = json.loads(SETTINGS_PATH.read_text(encoding="utf-8"))
            if isinstance(raw, dict):
                out = dict(defaults)
                out.update(raw)
                # System mode is runtime-local and should not persist in settings.
                out.pop("aircraft_system_mode", None)
                try:
                    mv = float(out.get("master_volume", 0.5))
                except Exception:
                    mv = 0.5
                out["master_volume"] = max(0.0, min(1.0, mv))
                try:
                    out["cesium_ion_token"] = str(out.get("cesium_ion_token", "") or "").strip()
                except Exception:
                    out["cesium_ion_token"] = ""
                raw_autoload = out.get(PMD_AUTOLOAD_SETTINGS_KEY, [])
                if isinstance(raw_autoload, list):
                    out[PMD_AUTOLOAD_SETTINGS_KEY] = [
                        _sanitize_pmd_id(v) for v in raw_autoload if _sanitize_pmd_id(v) != ""
                    ]
                else:
                    out[PMD_AUTOLOAD_SETTINGS_KEY] = []
                raw_enabled = out.get(PMD_ENABLED_SETTINGS_KEY, [])
                if isinstance(raw_enabled, list):
                    out[PMD_ENABLED_SETTINGS_KEY] = [
                        _sanitize_pmd_id(v) for v in raw_enabled if _sanitize_pmd_id(v) != ""
                    ]
                else:
                    out[PMD_ENABLED_SETTINGS_KEY] = []
                raw_keybinds = out.get(FLIGHT_KEYBINDS_SETTINGS_KEY, {})
                keybinds_out: Dict[str, str] = {}
                if isinstance(raw_keybinds, dict):
                    for action, key_name in raw_keybinds.items():
                        action_name = str(action).strip().lower()
                        if action_name not in PMD_KEYBIND_ACTION_ORDER:
                            continue
                        ktxt = str(key_name).strip()
                        keybinds_out[action_name] = ktxt
                out[FLIGHT_KEYBINDS_SETTINGS_KEY] = keybinds_out
                raw_hotas = out.get(HOTAS_BINDINGS_SETTINGS_KEY, {})
                hotas_out: Dict[str, object] = {}
                if isinstance(raw_hotas, dict):
                    slew_mode = str(raw_hotas.get("slew_mode", "AXIS")).upper()
                    if slew_mode not in {"AXIS", "HAT"}:
                        slew_mode = "AXIS"
                    hotas_out["slew_mode"] = slew_mode
                    try:
                        slew_speed = float(raw_hotas.get("slew_speed", 1.0))
                    except Exception:
                        slew_speed = 1.0
                    hotas_out["slew_speed"] = max(0.0, min(1.0, slew_speed))
                    try:
                        pan_speed = float(raw_hotas.get("pan_speed", 1.0))
                    except Exception:
                        pan_speed = 1.0
                    hotas_out["pan_speed"] = max(0.0, min(1.0, pan_speed))
                    pan_mode = str(raw_hotas.get("pan_mode", "HAT")).upper()
                    if pan_mode not in {"AXIS", "HAT"}:
                        pan_mode = "HAT"
                    hotas_out["pan_mode"] = pan_mode
                    engine_run_mode = str(raw_hotas.get("engine_run_mode", "MOMENTARY")).upper()
                    if engine_run_mode not in {"MOMENTARY", "TOGGLE"}:
                        engine_run_mode = "MOMENTARY"
                    hotas_out["engine_run_mode"] = engine_run_mode
                    hotas_out["engine_run_invert"] = bool(raw_hotas.get("engine_run_invert", False))
                    ldg_gear_mode = str(raw_hotas.get("ldg_gear_mode", "TOGGLE")).upper()
                    if ldg_gear_mode not in {"MOMENTARY", "TOGGLE"}:
                        ldg_gear_mode = "TOGGLE"
                    hotas_out["ldg_gear_mode"] = ldg_gear_mode
                    brake_mode = str(raw_hotas.get("brake_mode", "TOGGLE")).upper()
                    if brake_mode not in {"MOMENTARY", "TOGGLE"}:
                        brake_mode = "TOGGLE"
                    hotas_out["brake_mode"] = brake_mode
                    bindings_raw = raw_hotas.get("bindings", {})
                    bindings_out: Dict[str, Dict[str, object]] = {}
                    if isinstance(bindings_raw, dict):
                        for action in HOTAS_ACTION_ORDER:
                            b = bindings_raw.get(action, {})
                            if not isinstance(b, dict):
                                continue
                            b_type = str(b.get("type", "")).strip().lower()
                            if b_type not in {"axis", "button", "hat"}:
                                continue
                            try:
                                joy_idx = int(b.get("joy", -1))
                            except Exception:
                                joy_idx = -1
                            if joy_idx < 0:
                                continue
                            entry: Dict[str, object] = {"type": b_type, "joy": joy_idx}
                            joy_guid = str(b.get("joy_guid", "") or "").strip()
                            joy_name = str(b.get("joy_name", "") or "").strip()
                            if joy_guid != "":
                                entry["joy_guid"] = joy_guid
                            if joy_name != "":
                                entry["joy_name"] = joy_name
                            if b_type == "axis":
                                try:
                                    axis_idx = int(b.get("id", -1))
                                except Exception:
                                    axis_idx = -1
                                if axis_idx < 0:
                                    continue
                                entry["id"] = axis_idx
                                entry["invert"] = bool(b.get("invert", False))
                            elif b_type == "button":
                                try:
                                    btn_idx = int(b.get("id", -1))
                                except Exception:
                                    btn_idx = -1
                                if btn_idx < 0:
                                    continue
                                entry["id"] = btn_idx
                            else:
                                try:
                                    hat_idx = int(b.get("id", -1))
                                except Exception:
                                    hat_idx = -1
                                hat_dir = str(b.get("dir", "")).upper()
                                if hat_idx < 0 or hat_dir not in {"UP", "DOWN", "LEFT", "RIGHT"}:
                                    continue
                                entry["id"] = hat_idx
                                entry["dir"] = hat_dir
                            bindings_out[action] = entry
                    hotas_out["bindings"] = bindings_out
                out[HOTAS_BINDINGS_SETTINGS_KEY] = hotas_out
                return out
        except json.JSONDecodeError:
            pass
    return dict(defaults)


