def _safe_read_json(path: Path, fallback: Optional[dict] = None) -> dict:
    out = dict(fallback) if isinstance(fallback, dict) else {}
    try:
        raw = json.loads(path.read_text(encoding="utf-8-sig"))
    except Exception:
        return out
    if not isinstance(raw, dict):
        return out
    out.update(raw)
    return out


def _safe_write_json(path: Path, payload: object) -> bool:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
        return True
    except Exception:
        return False


_ASYNC_JSON_WRITE_LOCK = threading.Lock()
_ASYNC_JSON_WRITE_EVENT = threading.Event()
_ASYNC_JSON_WRITE_PENDING: Dict[str, Tuple[Path, str]] = {}
_ASYNC_JSON_WRITE_THREAD: Optional[threading.Thread] = None
_PLUGIN_JSON_READ_CACHE_LOCK = threading.Lock()
_PLUGIN_JSON_READ_CACHE: Dict[str, Tuple[float, dict]] = {}


def _async_json_write_loop() -> None:
    while True:
        _ASYNC_JSON_WRITE_EVENT.wait()
        while True:
            with _ASYNC_JSON_WRITE_LOCK:
                if len(_ASYNC_JSON_WRITE_PENDING) <= 0:
                    _ASYNC_JSON_WRITE_EVENT.clear()
                    break
                _key, (path, text) = _ASYNC_JSON_WRITE_PENDING.popitem()
            try:
                path.parent.mkdir(parents=True, exist_ok=True)
                path.write_text(text, encoding="utf-8")
            except Exception as exc:
                print(f"[PMD][IO] async json write failed path={path}: {exc}")


def _enqueue_async_json_write(path: Path, payload: object) -> bool:
    global _ASYNC_JSON_WRITE_THREAD
    try:
        text = json.dumps(payload, indent=2)
    except Exception:
        return False
    try:
        key = os.path.normcase(os.path.abspath(str(path)))
    except Exception:
        key = str(path)
    with _ASYNC_JSON_WRITE_LOCK:
        _ASYNC_JSON_WRITE_PENDING[key] = (path, text)
        if _ASYNC_JSON_WRITE_THREAD is None or not _ASYNC_JSON_WRITE_THREAD.is_alive():
            _ASYNC_JSON_WRITE_THREAD = threading.Thread(
                target=_async_json_write_loop,
                name="PmdJsonWriter",
                daemon=True,
            )
            _ASYNC_JSON_WRITE_THREAD.start()
        _ASYNC_JSON_WRITE_EVENT.set()
    return True


def _cached_plugin_read_json(path: Path, fallback: Optional[dict] = None, ttl_s: float = 0.50) -> dict:
    try:
        key = os.path.normcase(os.path.abspath(str(path)))
    except Exception:
        key = str(path)
    now = time.perf_counter()
    with _PLUGIN_JSON_READ_CACHE_LOCK:
        cached = _PLUGIN_JSON_READ_CACHE.get(key)
        if cached is not None and now < float(cached[0]):
            return dict(cached[1])
    data = _safe_read_json(path, fallback)
    with _PLUGIN_JSON_READ_CACHE_LOCK:
        _PLUGIN_JSON_READ_CACHE[key] = (now + max(0.0, float(ttl_s)), dict(data))
    return data

def _seclvl_has_dist_credentials(seclvl_state: Dict[str, object]) -> bool:
    secrets_obj = _dist_get_secrets()
    if secrets_obj is None:
        return False
    if not bool(seclvl_state.get("logged_in", False)):
        return False
    user_committed = str(seclvl_state.get("user_committed", ""))
    pass_committed = str(seclvl_state.get("pass_committed", ""))
    if user_committed.strip() == "" or pass_committed.strip() == "":
        return False
    user_expected = str(secrets_obj.admin_username_hash).strip()
    pw_expected = str(secrets_obj.admin_password_hash).strip()
    cache_raw = seclvl_state.get("_dist_cred_cache", {})
    cache = cache_raw if isinstance(cache_raw, dict) else {}
    cache_key = (
        user_expected,
        pw_expected,
        user_committed,
        pass_committed,
    )
    if tuple(cache.get("key", ())) == cache_key:
        return bool(cache.get("ok", False))

    user_ok = _dist_admin_credential_matches(user_expected, user_committed)
    pw_ok = _dist_admin_credential_matches(pw_expected, pass_committed)
    ok = bool(user_ok) and bool(pw_ok)
    seclvl_state["_dist_cred_cache"] = {
        "key": cache_key,
        "ok": ok,
    }
    return ok


def _seclvl_pmd_file_state() -> Tuple[str, bool]:
    # Returns (display_state, fields_enabled)
    # display_state: "VALID" | "NO FILE" | "ERROR"
    try:
        panel = _ensure_panel_button_states()
        phm_state = panel.get("PHM STATUS", {}) if isinstance(panel, dict) else {}
        runtime_sub = phm_state.get("runtime_subsystem_status", {}) if isinstance(phm_state, dict) else {}
        pmd_status = str(runtime_sub.get("PMD", "")).upper().strip() if isinstance(runtime_sub, dict) else ""
    except Exception:
        pmd_status = ""
    if pmd_status in {"OFF", "OF"}:
        return ("ERROR", False)
    if pmd_status == "OK":
        return ("VALID", True)
    return ("NO FILE", False)


def _varipass_api_key() -> str:
    global _VARIPASS_API_KEY_CACHE
    if _VARIPASS_API_KEY_CACHE is not None:
        return _VARIPASS_API_KEY_CACHE
    secrets_obj = _dist_get_secrets()
    if secrets_obj is not None:
        key = str(getattr(secrets_obj, "varipass_api_key", "")).strip()
        if key != "":
            _VARIPASS_API_KEY_CACHE = key
            return _VARIPASS_API_KEY_CACHE
    env_key = str(os.environ.get("F35_VARIPASS_API_KEY", "")).strip()
    if env_key != "":
        _VARIPASS_API_KEY_CACHE = env_key
        return _VARIPASS_API_KEY_CACHE
    try:
        exe_hint: Optional[Path] = Path(sys.executable).resolve() if is_frozen() else None
    except Exception:
        exe_hint = None
    try:
        search_paths = default_dist_secret_paths(
            base_dir=Path(__file__).resolve().parent,
            exe_path=exe_hint,
        )
    except Exception:
        search_paths = []
    for raw in search_paths:
        try:
            path = Path(raw).resolve()
        except Exception:
            path = Path(raw)
        if not path.exists() or not path.is_file():
            continue
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(payload, dict):
            continue
        candidate = str(payload.get("varipass_api_key", "")).strip()
        if candidate != "":
            print(f"[VARIPASS] Loaded API key from: {path}")
            _VARIPASS_API_KEY_CACHE = candidate
            return _VARIPASS_API_KEY_CACHE
    _VARIPASS_API_KEY_CACHE = ""
    return _VARIPASS_API_KEY_CACHE


def _supabase_url() -> str:
    _ensure_supabase_config_cache()
    return str(_SUPABASE_URL_CACHE or "")


def _supabase_api_key() -> str:
    _ensure_supabase_config_cache()
    return str(_SUPABASE_API_KEY_CACHE or "")


def _supabase_table_name() -> str:
    _ensure_supabase_config_cache()
    return str(_SUPABASE_TABLE_CACHE or "pcd_link16_nets")


def _ensure_supabase_config_cache() -> None:
    global _SUPABASE_URL_CACHE, _SUPABASE_API_KEY_CACHE, _SUPABASE_TABLE_CACHE
    if _SUPABASE_URL_CACHE is not None and _SUPABASE_API_KEY_CACHE is not None and _SUPABASE_TABLE_CACHE is not None:
        return
    supa_url = ""
    supa_key = ""
    supa_table = "pcd_link16_nets"

    secrets_obj = _dist_get_secrets()
    if secrets_obj is not None:
        supa_url = str(getattr(secrets_obj, "supabase_url", "")).strip().rstrip("/")
        supa_key = str(getattr(secrets_obj, "supabase_api_key", "")).strip()
        table_val = str(getattr(secrets_obj, "supabase_table", "")).strip()
        if table_val != "":
            supa_table = table_val

    if supa_url == "":
        supa_url = str(os.environ.get("F35_SUPABASE_URL", "")).strip().rstrip("/")
    if supa_key == "":
        supa_key = str(os.environ.get("F35_SUPABASE_API_KEY", "")).strip()
    env_table = str(os.environ.get("F35_SUPABASE_TABLE", "")).strip()
    if env_table != "":
        supa_table = env_table

    if supa_url == "" or supa_key == "":
        try:
            exe_hint: Optional[Path] = Path(sys.executable).resolve() if is_frozen() else None
        except Exception:
            exe_hint = None
        try:
            search_paths = default_dist_secret_paths(
                base_dir=Path(__file__).resolve().parent,
                exe_path=exe_hint,
            )
        except Exception:
            search_paths = []
        for raw in search_paths:
            try:
                path = Path(raw).resolve()
            except Exception:
                path = Path(raw)
            if not path.exists() or not path.is_file():
                continue
            try:
                payload = json.loads(path.read_text(encoding="utf-8"))
            except Exception:
                continue
            if not isinstance(payload, dict):
                continue
            p_url = str(payload.get("supabase_url", "")).strip().rstrip("/")
            p_key = str(
                payload.get(
                    "supabase_api_key",
                    payload.get("supabase_key", payload.get("supabase_publishable_key", payload.get("supabase_anon_key", ""))),
                )
            ).strip()
            p_table = str(payload.get("supabase_table", "")).strip()
            if p_url != "" and p_key != "":
                if supa_url == "":
                    supa_url = p_url
                if supa_key == "":
                    supa_key = p_key
                if p_table != "":
                    supa_table = p_table
                print(f"[SUPABASE] Loaded config from: {path}")
                break

    _SUPABASE_URL_CACHE = supa_url
    _SUPABASE_API_KEY_CACHE = supa_key
    _SUPABASE_TABLE_CACHE = supa_table if supa_table != "" else "pcd_link16_nets"


def _data_link_backend_name() -> str:
    return "supabase"


def _supabase_request(
    method: str,
    path: str,
    query: Optional[Dict[str, object]] = None,
    payload: Optional[Dict[str, object]] = None,
    timeout_s: float = 8.0,
    log_io: bool = True,
) -> Tuple[Optional[object], str]:
    base_url = _supabase_url()
    api_key = _supabase_api_key()
    if base_url == "" or api_key == "":
        return None, "SUPABASE CONFIG MISSING"
    query_items: List[Tuple[str, str]] = []
    if isinstance(query, dict):
        for k, v in query.items():
            query_items.append((str(k), str(v)))
    query_text = urllib_parse.urlencode(query_items, doseq=True) if len(query_items) > 0 else ""
    url = f"{base_url}{path}"
    if query_text != "":
        url = f"{url}?{query_text}"
    body: Optional[bytes] = None
    if isinstance(payload, dict):
        try:
            body = json.dumps(payload, ensure_ascii=True).encode("utf-8")
        except Exception as exc:
            return None, f"JSON encode failed: {exc}"
    headers = {
        "apikey": api_key,
        "Authorization": f"Bearer {api_key}",
        "User-Agent": "F35-PCD/1.0",
    }
    if body is not None:
        headers["Content-Type"] = "application/json"
    req_method = str(method or "GET").upper()
    if req_method in {"POST", "PATCH", "DELETE"}:
        headers["Prefer"] = "return=representation"
    if bool(log_io):
        try:
            dbg_payload = ""
            if body is not None:
                txt = body.decode("utf-8", errors="replace")
                dbg_payload = txt if len(txt) <= 500 else f"{txt[:260]}...<{len(txt)} chars>...{txt[-120:]}"
            print(f"[SUPABASE] REQUEST {str(method or 'GET').upper()} {url} {dbg_payload}")
        except Exception:
            print(f"[SUPABASE] REQUEST {str(method or 'GET').upper()} {url}")
    req = urllib_request.Request(url, data=body, headers=headers, method=req_method)
    transient_http_codes = {408, 409, 425, 429, 500, 502, 503, 504}
    max_attempts = 2
    for attempt in range(max_attempts):
        try:
            with urllib_request.urlopen(req, timeout=max(1.0, float(timeout_s))) as resp:
                raw = resp.read().decode("utf-8", errors="replace")
            if bool(log_io):
                try:
                    print(f"[SUPABASE] RESPONSE {raw}")
                except Exception:
                    pass
            text = str(raw or "").strip()
            if text == "":
                return {}, ""
            try:
                return json.loads(text), ""
            except Exception:
                return {"raw": text}, ""
        except urllib_error.HTTPError as exc:
            try:
                detail = exc.read().decode("utf-8", errors="replace")
            except Exception:
                detail = ""
            detail_l = str(detail).lower()
            # Supabase edge may occasionally return 409 + "error code: 1001" transiently.
            transient = int(getattr(exc, "code", 0)) in transient_http_codes or ("error code: 1001" in detail_l)
            if transient and attempt < (max_attempts - 1):
                if bool(log_io):
                    print(
                        f"[SUPABASE] TRANSIENT HTTP {exc.code} on {req_method} {url} "
                        f"(attempt {attempt + 1}/{max_attempts})"
                    )
                time.sleep(0.35 * float(attempt + 1))
                continue
            print(f"[SUPABASE] ERROR HTTP {exc.code} on {req_method} {url}: {detail or exc.reason}")
            return None, f"HTTP {exc.code}: {detail or exc.reason}"
        except Exception as exc:
            err_txt = str(exc)
            err_l = err_txt.lower()
            transient = ("timed out" in err_l) or ("timeout" in err_l) or ("tempor" in err_l)
            if transient and attempt < (max_attempts - 1):
                if bool(log_io):
                    print(
                        f"[SUPABASE] TRANSIENT ERROR on {req_method} {url}: {err_txt} "
                        f"(attempt {attempt + 1}/{max_attempts})"
                    )
                time.sleep(0.35 * float(attempt + 1))
                continue
            print(f"[SUPABASE] ERROR on {req_method} {url}: {exc}")
            return None, err_txt
    return None, "Unknown Supabase request failure"


def _supabase_data_link_request(kind: str, payload: Dict[str, object]) -> Tuple[Optional[Dict[str, object]], str]:
    table = _supabase_table_name()
    req_kind = str(kind).strip().lower()
    log_io = bool(payload.get("_log_io", req_kind in {"create", "delete"}))
    def _json_obj(value: object) -> Dict[str, object]:
        raw = value
        if isinstance(raw, str):
            txt = raw.strip()
            if txt != "":
                try:
                    raw = json.loads(txt)
                except Exception:
                    raw = {}
        return dict(raw) if isinstance(raw, dict) else {}

    def _merge_str_lists(existing: object, local: object) -> List[str]:
        out: List[str] = []
        for src in (existing, local):
            if not isinstance(src, list):
                continue
            for item in src:
                token = str(item).strip()
                if token == "" or token in out:
                    continue
                out.append(token)
        return out

    def _merge_missions(existing: object, local: object) -> Dict[str, object]:
        ex = _json_obj(existing)
        lo = _json_obj(local)
        ex_store = _json_obj(ex.get("store", {}))
        lo_store = _json_obj(lo.get("store", {}))
        def _mission_deleted(raw: object) -> bool:
            if not isinstance(raw, dict):
                return False
            val = raw.get("deleted", False)
            if isinstance(val, bool):
                return val
            txt = str(val).strip().lower()
            return txt in {"1", "true", "yes", "y", "on"}

        def _mission_ms(raw: object) -> int:
            if not isinstance(raw, dict):
                return 0
            for key in ("updated_unix_ms", "deleted_unix_ms", "created_unix_ms"):
                try:
                    return int(raw.get(key, 0) or 0)
                except Exception:
                    continue
            return 0

        merged_store: Dict[str, object] = {}
        all_ids: List[str] = []
        for src in (ex_store, lo_store):
            for mid in src.keys():
                mk = str(mid).strip()
                if mk == "" or mk in all_ids:
                    continue
                all_ids.append(mk)
        for mk in all_ids:
            ex_m = ex_store.get(mk)
            lo_m = lo_store.get(mk)
            if isinstance(ex_m, dict) and isinstance(lo_m, dict):
                ex_del = _mission_deleted(ex_m)
                lo_del = _mission_deleted(lo_m)
                ex_ms = _mission_ms(ex_m)
                lo_ms = _mission_ms(lo_m)
                if lo_ms > ex_ms:
                    chosen = lo_m
                elif ex_ms > lo_ms:
                    chosen = ex_m
                else:
                    # Tie-break: prefer tombstone to prevent delete resurrection.
                    if ex_del and not lo_del:
                        chosen = ex_m
                    elif lo_del and not ex_del:
                        chosen = lo_m
                    else:
                        # Same state on tie -> prefer local copy.
                        chosen = lo_m
                merged_store[mk] = dict(chosen)
                continue
            if isinstance(lo_m, dict):
                merged_store[mk] = dict(lo_m)
                continue
            if isinstance(ex_m, dict):
                merged_store[mk] = dict(ex_m)
        out: Dict[str, object] = {
            "store": merged_store,
            "inbox_own_ids": _merge_str_lists(ex.get("inbox_own_ids", []), lo.get("inbox_own_ids", [])),
            "inbox_flt_ids": _merge_str_lists(ex.get("inbox_flt_ids", []), lo.get("inbox_flt_ids", [])),
            "outbox_ids": _merge_str_lists(ex.get("outbox_ids", []), lo.get("outbox_ids", [])),
        }
        return out

    def _roster_texts(aircraft_obj: Dict[str, object]) -> Tuple[str, str, str]:
        calls: List[str] = []
        flts: List[str] = []
        msns: List[str] = []
        for _sid, raw in aircraft_obj.items():
            if not isinstance(raw, dict):
                continue
            c = str(raw.get("callsign", "")).strip().upper()
            f = str(raw.get("flt_pos", "")).strip().upper()
            m = str(raw.get("msn_nbr", "")).strip().upper()
            if c != "" and c not in calls:
                calls.append(c)
            if f != "" and f not in flts:
                flts.append(f)
            if m != "" and m not in msns:
                msns.append(m)
        return (
            ",".join(calls)[:255],
            ",".join(flts)[:255],
            ",".join(msns)[:255],
        )

    if req_kind == "create":
        entry_id = str(payload.get("id", "")).strip()
        if entry_id == "":
            entry_id = str(uuid.uuid4())
        net_payload = payload.get("net_payload", payload.get("mission", {}))
        if not isinstance(net_payload, dict):
            net_payload = {}
        aircraft_obj = net_payload.get("aircraft", {})
        missions_obj = net_payload.get("missions", {})
        images_obj = net_payload.get("images", {})
        targets_obj = net_payload.get("targets", {})
        try:
            updated_unix_ms = int(net_payload.get("updated_unix_ms", int(time.time() * 1000)) or 0)
        except Exception:
            updated_unix_ms = int(time.time() * 1000)
        row = {
            "id": entry_id,
            "callsign": str(payload.get("callsign", "")).strip(),
            "flt_pos": str(payload.get("flt_pos", "")).strip(),
            "msn_nbr": str(payload.get("msn_nbr", "")).strip(),
            "net_name": str(payload.get("net_name", payload.get("image", ""))).strip(),
            "aircraft": aircraft_obj if isinstance(aircraft_obj, dict) else {},
            "missions": missions_obj if isinstance(missions_obj, dict) else {},
            "images": images_obj if isinstance(images_obj, dict) else {},
            "targets": targets_obj if isinstance(targets_obj, dict) else {},
            "updated_unix_ms": int(updated_unix_ms),
        }
        resp, err = _supabase_request(
            "POST",
            f"/rest/v1/{table}",
            query={"select": "id"},
            payload=row,
            timeout_s=8.0,
            log_io=log_io,
        )
        if err != "":
            return None, err
        if isinstance(resp, list) and len(resp) > 0 and isinstance(resp[0], dict):
            return {"result": "success", "id": str(resp[0].get("id", "")).strip()}, ""
        return {"result": "success", "id": entry_id}, ""
    if req_kind == "write":
        entry_id = str(payload.get("id", "")).strip()
        if entry_id == "":
            return {"result": "error_invalid_id"}, ""
        net_payload = payload.get("net_payload", payload.get("mission", {}))
        if not isinstance(net_payload, dict):
            net_payload = {}
        local_aircraft = _json_obj(net_payload.get("aircraft", {}))
        local_missions = _json_obj(net_payload.get("missions", {}))
        local_images = _json_obj(net_payload.get("images", {}))
        local_targets = _json_obj(net_payload.get("targets", {}))
        try:
            updated_unix_ms = int(net_payload.get("updated_unix_ms", int(time.time() * 1000)) or 0)
        except Exception:
            updated_unix_ms = int(time.time() * 1000)
        existing_row: Dict[str, object] = {}
        read_resp, read_err = _supabase_request(
            "GET",
            f"/rest/v1/{table}",
            query={
                "id": f"eq.{entry_id}",
                "select": "id,callsign,flt_pos,msn_nbr,net_name,aircraft,missions,images,targets,updated_unix_ms",
            },
            timeout_s=8.0,
            log_io=False,
        )
        if read_err == "" and isinstance(read_resp, list) and len(read_resp) > 0 and isinstance(read_resp[0], dict):
            existing_row = dict(read_resp[0])
        merged_aircraft = _json_obj(existing_row.get("aircraft", {}))
        for sid, raw in local_aircraft.items():
            sk = str(sid).strip()
            if sk == "":
                continue
            merged_aircraft[sk] = dict(raw) if isinstance(raw, dict) else raw
        merged_missions = _merge_missions(existing_row.get("missions", {}), local_missions)
        merged_images = _json_obj(existing_row.get("images", {}))
        for token, raw in local_images.items():
            tk = str(token).strip()
            if tk == "":
                continue
            merged_images[tk] = dict(raw) if isinstance(raw, dict) else raw
        merged_targets = _json_obj(existing_row.get("targets", {}))
        for key, raw in local_targets.items():
            kk = str(key).strip()
            if kk == "":
                continue
            merged_targets[kk] = dict(raw) if isinstance(raw, dict) else raw
        roster_callsign, roster_flt_pos, roster_msn_nbr = _roster_texts(merged_aircraft)
        row = {
            "callsign": roster_callsign or str(payload.get("callsign", "")).strip(),
            "flt_pos": roster_flt_pos or str(payload.get("flt_pos", "")).strip(),
            "msn_nbr": roster_msn_nbr or str(payload.get("msn_nbr", "")).strip(),
            "net_name": str(payload.get("net_name", payload.get("image", ""))).strip(),
            "aircraft": merged_aircraft,
            "missions": merged_missions,
            "images": merged_images,
            "targets": merged_targets,
            "updated_unix_ms": int(updated_unix_ms),
        }
        resp, err = _supabase_request(
            "PATCH",
            f"/rest/v1/{table}",
            query={"id": f"eq.{entry_id}", "select": "id"},
            payload=row,
            timeout_s=8.0,
            log_io=log_io,
        )
        if err != "":
            return None, err
        if isinstance(resp, list) and len(resp) > 0:
            return {"result": "success"}, ""
        return {"result": "error_invalid_id"}, ""
    if req_kind == "all":
        resp, err = _supabase_request(
            "GET",
            f"/rest/v1/{table}",
            query={
                "select": "id,callsign,flt_pos,msn_nbr,net_name,aircraft,missions,images,targets,updated_unix_ms"
            },
            timeout_s=8.0,
            log_io=log_io,
        )
        if err != "":
            return None, err
        rows: List[Dict[str, object]] = []
        if isinstance(resp, list):
            rows = [r for r in resp if isinstance(r, dict)]
        return {"result": "success", "rows": rows}, ""
    if req_kind == "delete":
        entry_id = str(payload.get("id", "")).strip()
        if entry_id == "":
            return {"result": "error_invalid_id"}, ""
        resp, err = _supabase_request(
            "DELETE",
            f"/rest/v1/{table}",
            query={"id": f"eq.{entry_id}", "select": "id"},
            timeout_s=8.0,
            log_io=log_io,
        )
        if err != "":
            return None, err
        if isinstance(resp, list) and len(resp) > 0:
            return {"result": "success"}, ""
        return {"result": "error_invalid_id"}, ""
    return None, f"Unsupported DATA LINK request kind: {req_kind}"


def _data_link_api_request(kind: str, payload: Dict[str, object], timeout_s: float = 8.0) -> Tuple[Optional[Dict[str, object]], str]:
    _ = timeout_s
    return _supabase_data_link_request(kind, payload)


def _varipass_post(payload: Dict[str, object], timeout_s: float = 6.0) -> Tuple[Optional[Dict[str, object]], str]:
    action = str(payload.get("action", "")).strip().lower()
    try:
        debug_payload = dict(payload)
        if "key" in debug_payload:
            raw_key = str(debug_payload.get("key", ""))
            if len(raw_key) > 8:
                debug_payload["key"] = f"{raw_key[:4]}...{raw_key[-4:]}"
            else:
                debug_payload["key"] = "***"
        action_label = action.upper() if action != "" else "UNKNOWN"
        print(f"[VARIPASS] REQUEST {action_label}: {json.dumps(debug_payload, ensure_ascii=True)}")
    except Exception:
        print("[VARIPASS] REQUEST <unserializable payload>")
    try:
        body = json.dumps(payload, ensure_ascii=True).encode("utf-8")
    except Exception as exc:
        return None, f"JSON encode failed: {exc}"
    req = urllib_request.Request(
        str(VARIPASS_API_URL),
        data=body,
        headers={
            "Content-Type": "application/json",
            "User-Agent": "F35-PCD/1.0",
        },
        method="POST",
    )
    try:
        with urllib_request.urlopen(req, timeout=max(1.0, float(timeout_s))) as resp:
            raw = resp.read().decode("utf-8", errors="replace")
        action_label = action.upper() if action != "" else "UNKNOWN"
        print(f"[VARIPASS] RESPONSE {action_label}: {raw}")
        data = json.loads(raw)
        if isinstance(data, dict):
            return data, ""
        return None, "Non-object API response."
    except urllib_error.HTTPError as exc:
        try:
            detail = exc.read().decode("utf-8", errors="replace")
        except Exception:
            detail = ""
        print(f"[VARIPASS] ERROR HTTP {exc.code}: {detail or exc.reason}")
        return None, f"HTTP {exc.code}: {detail or exc.reason}"
    except Exception as exc:
        print(f"[VARIPASS] ERROR {exc}")
        return None, str(exc)


def _faa_airac_date_token(dt: datetime) -> str:
    month = FAA_AIRAC_MONTH_ABBR[max(0, min(11, int(dt.month) - 1))]
    return f"{int(dt.day):02d}_{month}_{int(dt.year):04d}"


def _faa_airac_candidate_dates(now_dt: Optional[datetime] = None, window_cycles: int = FAA_AIRAC_SEARCH_WINDOW_CYCLES) -> List[datetime]:
    now = now_dt if isinstance(now_dt, datetime) else datetime.now()
    today = now.date()
    base = FAA_AIRAC_BASE_DATE
    delta_days = int((today - base.date()).days)
    approx_idx = int(round(float(delta_days) / float(max(1, FAA_AIRAC_CYCLE_DAYS))))
    dates: List[datetime] = []
    for idx in range(approx_idx - int(window_cycles), approx_idx + int(window_cycles) + 1):
        dates.append(base + timedelta(days=int(idx) * int(FAA_AIRAC_CYCLE_DAYS)))
    dates.sort(key=lambda d: (abs((d.date() - today).days), 0 if d.date() <= today else 1))
    return dates


def _faa_target_data_dir() -> Path:
    primary = Path(resource_path("DATA", "FAA"))
    try:
        primary.mkdir(parents=True, exist_ok=True)
    except Exception:
        pass
    if primary.exists() and os.access(str(primary), os.W_OK):
        return primary
    fallback = Path(writable_path("DATA", "FAA"))
    try:
        fallback.mkdir(parents=True, exist_ok=True)
    except Exception:
        pass
    return fallback


def _faa_download_cycle_zip(target_date: datetime, target_dir: Path, timeout_s: float = 30.0) -> Tuple[bool, str, str, str]:
    date_token = _faa_airac_date_token(target_date)
    url = FAA_AIRAC_CSV_ZIP_URL_TEMPLATE.format(date_token=date_token)
    tmp_zip_path: Optional[Path] = None
    try:
        with tempfile.NamedTemporaryFile(prefix="faa_airac_", suffix=".zip", delete=False) as tmpf:
            tmp_zip_path = Path(tmpf.name)
        req = urllib_request.Request(
            str(url),
            headers={
                "User-Agent": "F35-PCD/1.0",
                "Accept": "application/zip,*/*",
            },
        )
        with urllib_request.urlopen(req, timeout=max(5.0, float(timeout_s))) as resp:
            payload = resp.read()
        if len(payload) <= 0:
            return False, "Empty ZIP payload.", url, date_token
        if tmp_zip_path is None:
            return False, "Unable to create temporary ZIP path.", url, date_token
        tmp_zip_path.write_bytes(payload)
        if not _pmd_extract_archive(tmp_zip_path, target_dir):
            return False, f"Extract failed into {target_dir}.", url, date_token
        return True, "OK", url, date_token
    except urllib_error.HTTPError as exc:
        return False, f"HTTP {exc.code}", url, date_token
    except urllib_error.URLError as exc:
        return False, f"URL error: {exc.reason}", url, date_token
    except Exception as exc:
        return False, str(exc), url, date_token
    finally:
        if isinstance(tmp_zip_path, Path):
            try:
                tmp_zip_path.unlink(missing_ok=True)
            except Exception:
                pass


def _faa_download_nearest_cycle_data(now_dt: Optional[datetime] = None) -> Tuple[bool, str, str, str]:
    target_dir = _faa_target_data_dir()
    candidates = _faa_airac_candidate_dates(now_dt=now_dt, window_cycles=FAA_AIRAC_SEARCH_WINDOW_CYCLES)
    first_error = ""
    for cand in candidates:
        ok, msg, url, date_token = _faa_download_cycle_zip(cand, target_dir)
        if ok:
            status = f"FAA load complete: {date_token}"
            return True, status, url, date_token
        if first_error == "":
            first_error = f"{date_token} ({msg})"
    if first_error == "":
        first_error = "No candidate AIRAC cycle dates generated."
    return False, f"FAA load failed: {first_error}", "", ""


def _to_bw_surface_from_pil(img: Image.Image) -> pygame.Surface:
    rgba = img.convert("RGBA")
    alpha = rgba.getchannel("A")
    gray = rgba.convert("L")
    bw = gray.point(lambda p: 255 if int(p) >= 128 else 0).convert("L")
    merged = Image.merge("RGBA", (bw, bw, bw, alpha))
    try:
        raw = merged.tobytes()
        surf = pygame.image.frombuffer(raw, merged.size, "RGBA").convert_alpha()
    except Exception:
        raw = merged.tobytes()
        surf = pygame.image.fromstring(raw, merged.size, "RGBA").convert_alpha()
    return surf


@dataclass
class PmdVideoClip:
    path: Path
    frames: List[pygame.Surface] = field(default_factory=list)
    durations_ms: List[int] = field(default_factory=list)
    loop: bool = True
    playing: bool = True
    frame_index: int = 0
    frame_elapsed_ms: float = 0.0

    @classmethod
    def load(cls, path: Path, loop: bool = True) -> "PmdVideoClip":
        clip = cls(path=Path(path), loop=bool(loop))
        try:
            with Image.open(str(path)) as pil_img:
                frame_count = 0
                for frame in ImageSequence.Iterator(pil_img):
                    clip.frames.append(_to_bw_surface_from_pil(frame))
                    try:
                        duration = int(frame.info.get("duration", pil_img.info.get("duration", 66)))
                    except Exception:
                        duration = 66
                    clip.durations_ms.append(max(16, duration))
                    frame_count += 1
                    if frame_count >= PMD_MAX_VIDEO_FRAMES:
                        break
        except Exception:
            clip.frames = []
            clip.durations_ms = []
        return clip

    def is_ready(self) -> bool:
        return len(self.frames) > 0 and len(self.frames) == len(self.durations_ms)

    def play(self) -> None:
        self.playing = True

    def pause(self) -> None:
        self.playing = False

    def restart(self) -> None:
        self.frame_index = 0
        self.frame_elapsed_ms = 0.0
        self.playing = True

    def update(self, dt_seconds: float) -> None:
        if not self.playing or not self.is_ready():
            return
        dt_ms = max(0.0, float(dt_seconds) * 1000.0)
        self.frame_elapsed_ms += dt_ms
        while self.frame_elapsed_ms >= float(self.durations_ms[self.frame_index]):
            self.frame_elapsed_ms -= float(self.durations_ms[self.frame_index])
            self.frame_index += 1
            if self.frame_index >= len(self.frames):
                if self.loop:
                    self.frame_index = 0
                else:
                    self.frame_index = max(0, len(self.frames) - 1)
                    self.playing = False
                    break

    def blit(self, surface: pygame.Surface, dest_rect: pygame.Rect) -> None:
        if not self.is_ready():
            return
        frame = self.frames[self.frame_index]
        if frame.get_size() != (dest_rect.width, dest_rect.height):
            frame = pygame.transform.smoothscale(frame, (max(1, dest_rect.width), max(1, dest_rect.height)))
        surface.blit(frame, dest_rect.topleft)


