def draw_triangle(
    screen: pygame.Surface,
    rect: pygame.Rect,
    direction: str,
) -> pygame.Rect:
    if direction == "up":
        points = [
            (rect.centerx, rect.y),
            (rect.left, rect.bottom),
            (rect.right, rect.bottom),
        ]
    elif direction == "down":
        points = [
            (rect.centerx, rect.bottom),
            (rect.left, rect.y),
            (rect.right, rect.y),
        ]
    elif direction == "left":
        points = [
            (rect.x, rect.centery),
            (rect.right, rect.y),
            (rect.right, rect.bottom),
        ]
    else:
        points = [
            (rect.right, rect.centery),
            (rect.left, rect.y),
            (rect.left, rect.bottom),
        ]

    pygame.draw.polygon(screen, LINE_COLOR, points, 1)
    return rect

def triangle_rect(base_rect: pygame.Rect, side: str, direction: str) -> pygame.Rect:
    if direction in ("up", "down"):
        width = TRI_LONG
        height = TRI_POINT_LEN
    else:
        width = TRI_POINT_LEN
        height = TRI_LONG

    if side == "left":
        x = base_rect.x + TRI_MARGIN
    else:
        x = base_rect.right - TRI_MARGIN - width

    y = base_rect.bottom - TRI_MARGIN - height
    return pygame.Rect(x, y, width, height)


def draw_poi_markers(screen: pygame.Surface, rect: pygame.Rect) -> None:
    color = LABEL_COLOR
    margin = 2
    size = 17
    left = rect.left + margin
    right = rect.right - margin
    top = rect.top + margin
    bottom = rect.bottom - margin

    tl = [(left, top), (left + size, top), (left, top + size)]
    tr = [(right, top), (right - size, top), (right, top + size)]
    bl = [(left, bottom), (left + size, bottom), (left, bottom - size)]
    br = [(right, bottom), (right - size, bottom), (right, bottom - size)]

    for points in (tl, tr, bl, br):
        pygame.draw.polygon(screen, color, points, 0)

    # Inner POI border.
    inner = rect.inflate(-2, -2)
    if inner.width > 0 and inner.height > 0:
        pygame.draw.rect(screen, color, inner, 1)

def draw_dashed_polygon_stroke(
    screen: pygame.Surface,
    color: Tuple[int, int, int],
    points: List[Tuple[int, int]],
    dash_length: int = 6,
    gap_length: int = 4,
    width: int = 1,
) -> None:
    if len(points) < 2:
        return
    perimeter = []
    for i in range(len(points)):
        start = points[i]
        end = points[(i + 1) % len(points)]
        perimeter.append((start, end))

    dash_on = True
    remaining = dash_length
    for start, end in perimeter:
        dx = end[0] - start[0]
        dy = end[1] - start[1]
        length = (dx * dx + dy * dy) ** 0.5
        if length == 0:
            continue
        ux = dx / length
        uy = dy / length
        traveled = 0.0
        while traveled < length:
            seg_len = min(remaining, length - traveled)
            if dash_on:
                x1 = int(start[0] + ux * traveled)
                y1 = int(start[1] + uy * traveled)
                x2 = int(start[0] + ux * (traveled + seg_len))
                y2 = int(start[1] + uy * (traveled + seg_len))
                pygame.draw.line(screen, color, (x1, y1), (x2, y2), width)
            traveled += seg_len
            remaining -= seg_len
            if remaining <= 0:
                dash_on = not dash_on
                remaining = dash_length if dash_on else gap_length


def draw_dashed_line(
    screen: pygame.Surface,
    color: Tuple[int, int, int],
    start: Tuple[int, int],
    end: Tuple[int, int],
    dash_length: int = 6,
    gap_length: int = 4,
    width: int = 1,
) -> None:
    draw_dashed_polygon_stroke(
        screen,
        color,
        [start, end],
        dash_length=dash_length,
        gap_length=gap_length,
        width=width,
    )

def build_osb_zones(primary_rect: pygame.Rect, portal_index: int) -> List[OsbZone]:
    zones: List[OsbZone] = []
    wide = primary_rect.width >= PORTAL_WIDTH * 2 - 1
    tall = primary_rect.height >= PORTAL_HEIGHT - 1
    # 7-high windows (5x7/10x7) have top and 6 side OSBs.
    # 5-high windows (5x5/10x5) have top only and 5 side OSBs.
    if tall:
        top_count = 10 if wide else 5
        bottom_count = 0
        side_count = 6
    else:
        top_count = 10 if wide else 5
        bottom_count = 0
        side_count = 5
    osb_height = OSB_HEIGHT

    if top_count > 0:
        top_x = primary_rect.x
        cell = OSB_WIDTH
        for i in range(top_count):
            start = top_x + int(i * cell)
            zones.append(
                OsbZone(
                    label=f"T{i + 1}",
                    rect=pygame.Rect(start, primary_rect.y, OSB_WIDTH, osb_height),
                    portal_index=portal_index,
                )
            )

    if bottom_count > 0:
        bottom_x = primary_rect.x
        cell = OSB_WIDTH
        y = primary_rect.bottom - osb_height
        for i in range(bottom_count):
            start = bottom_x + int(i * cell)
            zones.append(
                OsbZone(
                    label=f"B{i + 1}",
                    rect=pygame.Rect(start, y, OSB_WIDTH, osb_height),
                    portal_index=portal_index,
                )
            )

    if side_count > 0:
        top_offset = osb_height
        left_y = primary_rect.y + top_offset - SIDE_OSB_Y_SHIFT
        cell = osb_height
        for i in range(side_count):
            start = left_y + int(i * cell)
            zones.append(
                OsbZone(
                    label=f"L{i + 1}",
                    rect=pygame.Rect(primary_rect.x, start, OSB_WIDTH, osb_height),
                    portal_index=portal_index,
                )
            )

        right_x = primary_rect.right - OSB_WIDTH
        for i in range(side_count):
            start = left_y + int(i * cell)
            zones.append(
                OsbZone(
                    label=f"R{i + 1}",
                    rect=pygame.Rect(right_x, start, OSB_WIDTH, osb_height),
                    portal_index=portal_index,
                )
            )

    return zones

def build_vded_zones(vded_rect: pygame.Rect, portal_index: int) -> List[VdedZone]:
    zones: List[VdedZone] = []
    cols = 5
    rows = 8
    cell_w = OSB_WIDTH
    cell_h = VDED_CELL_HEIGHT
    letters = "ABCDEFGH"
    for row in range(rows):
        for col in range(cols):
            x = vded_rect.x + int(col * cell_w)
            y = vded_rect.y + int(row * cell_h)
            label = f"{letters[row]}{col + 1}"
            zones.append(
                VdedZone(
                    label=label,
                    rect=pygame.Rect(x, y, cell_w, cell_h),
                    portal_index=portal_index,
                )
            )
    return zones

def draw_crosshair(screen: pygame.Surface, pos: Tuple[int, int]) -> None:
    x, y = pos
    size = CROSSHAIR_SIZE
    draw_dashed_line(screen, CROSSHAIR_COLOR, (x - size, y), (x + size, y))
    draw_dashed_line(screen, CROSSHAIR_COLOR, (x, y - size), (x, y + size))


def draw_hotas_slew_cursor_hsd(screen: pygame.Surface, pos: Tuple[int, int]) -> None:
    x = int(pos[0])
    y = int(pos[1])
    green = (0, 255, 0)
    size = max(3, int(round(float(CROSSHAIR_SIZE) * 0.75)))
    half_len = size
    y_off = size
    top_y = y - y_off
    bot_y = y + y_off
    pygame.draw.line(screen, green, (x - half_len, top_y), (x + half_len, top_y), 1)
    pygame.draw.line(screen, green, (x - half_len, bot_y), (x + half_len, bot_y), 1)
    pygame.draw.circle(screen, green, (x, y), max(1, int(round(size * 0.12))), 0)


def draw_hotas_slew_cursor(screen: pygame.Surface, pos: Tuple[int, int]) -> None:
    x = int(pos[0])
    y = int(pos[1])
    green = (0, 255, 0)
    arm = max(7, int(round(float(CROSSHAIR_SIZE) * 0.65)))
    gap = max(2, int(round(arm * 0.22)))
    pygame.draw.line(screen, green, (x - arm, y), (x - gap, y), 1)
    pygame.draw.line(screen, green, (x + gap, y), (x + arm, y), 1)
    pygame.draw.line(screen, green, (x, y - arm), (x, y - gap), 1)
    pygame.draw.line(screen, green, (x, y + gap), (x, y + arm), 1)
    pygame.draw.circle(screen, green, (x, y), 1, 0)

