def draw_backtick_popup(screen: pygame.Surface, page_index: int = 0) -> Tuple[pygame.Rect, int]:
    pad = 50
    popup = pygame.Rect(pad, pad, WINDOW_WIDTH - pad * 2, WINDOW_HEIGHT - pad * 2)
    dim = pygame.Surface((WINDOW_WIDTH, WINDOW_HEIGHT), pygame.SRCALPHA)
    dim.fill((0, 0, 0, 180))
    screen.blit(dim, (0, 0))
    pygame.draw.rect(screen, BG_COLOR, popup, 0)
    pygame.draw.rect(screen, (255, 255, 255), popup, 2)
    title_font = load_font(24)
    body_font = load_font(16)
    footer_font = load_font(8)
    title = title_font.render("COCKPIT PANELS", True, (0, 255, 255))
    pages = _discover_panel_pages()
    total_pages = max(1, len(pages))
    current_page = max(0, min(total_pages - 1, int(page_index)))
    _PANEL_RUNTIME_BUTTON_HITS.clear()
    _ensure_panel_button_states()
    hint = footer_font.render("TAB: toggle  LEFT/RIGHT: page", True, (0, 255, 0))
    page_txt = footer_font.render(f"PAGE {current_page + 1}/{total_pages}", True, (255, 255, 255))
    screen.blit(title, title.get_rect(midtop=(popup.centerx, popup.top + 4)))
    screen.blit(page_txt, page_txt.get_rect(midbottom=(popup.centerx, popup.bottom - 26)))
    screen.blit(hint, hint.get_rect(midbottom=(popup.centerx, popup.bottom - 6)))
    left_arrow_rect, right_arrow_rect = cockpit_panel_page_arrow_rects(popup)
    for arrow_rect, direction in ((left_arrow_rect, -1), (right_arrow_rect, 1)):
        pygame.draw.rect(screen, (0, 0, 0), arrow_rect)
        pygame.draw.rect(screen, (0, 255, 255), arrow_rect, 1)
        if direction < 0:
            points = [
                (arrow_rect.right - 9, arrow_rect.top + 6),
                (arrow_rect.left + 9, arrow_rect.centery),
                (arrow_rect.right - 9, arrow_rect.bottom - 6),
            ]
        else:
            points = [
                (arrow_rect.left + 9, arrow_rect.top + 6),
                (arrow_rect.right - 9, arrow_rect.centery),
                (arrow_rect.left + 9, arrow_rect.bottom - 6),
            ]
        pygame.draw.polygon(screen, (0, 255, 0), points, 0)

    # Panels use full popup height; title/hints are overlays and do not reserve space.
    content = pygame.Rect(popup.left + 4, popup.top + 4, popup.width - 8, popup.height - 8)
    panels = pages[current_page] if current_page < len(pages) else []
    if not panels:
        msg = body_font.render("No panel assets found in icons/PANELS.", True, (255, 255, 255))
        screen.blit(msg, msg.get_rect(center=content.center))
        return popup, total_pages

    def _draw_panel_buttons(panel_name: str, img_rect: pygame.Rect) -> None:
        if panel_name == "POWER PANEL":
            _draw_power_panel_buttons(screen, img_rect)
        elif panel_name == "THROTTLE":
            _draw_throttle_panel_buttons(screen, img_rect)
        elif panel_name == "DISPLAY CONTROL":
            _draw_display_control_panel_buttons(screen, img_rect)
        elif panel_name == "MASTER ARM":
            _draw_master_arm_panel_buttons(screen, img_rect)
        elif panel_name == "CONSOLE LEFT":
            _draw_console_left_panel_buttons(screen, img_rect)

    special_set = set(panels)
    special_order = [name for name in ("DISPLAY CONTROL", "MASTER ARM") if name in panels]
    special_quad = special_set == {"DISPLAY CONTROL", "MASTER ARM", "CONSOLE LEFT", "CONSOLE RIGHT"}
    special_vertical = len(special_order) == 2 and special_set == {"DISPLAY CONTROL", "MASTER ARM"}
    if special_quad:
        def _draw_panel_in_slot(panel_name: str, slot: pygame.Rect, mode: str, left_anchor: Optional[int] = None) -> Optional[pygame.Rect]:
            name_surf = body_font.render(panel_name, True, (0, 255, 0))
            name_h = name_surf.get_height()
            composite = _load_panel_composite(panel_name)
            if composite is None:
                missing = body_font.render("MISSING", True, (255, 255, 255))
                miss_rect = missing.get_rect(center=slot.center)
                pygame.draw.rect(screen, (0, 255, 255), slot, 1)
                screen.blit(missing, miss_rect)
                return None
            iw = max(1, composite.get_width())
            ih = max(1, composite.get_height())
            pad_px = 3
            max_h = max(1, slot.height - (name_h + 12 + pad_px * 2))
            scale = max_h / float(ih)
            sw = max(1, int(round(iw * scale)))
            sh = max(1, int(round(ih * scale)))
            max_w = max(1, slot.width - pad_px * 2 - 2)
            if sw > max_w:
                scale = max_w / float(iw)
                sw = max(1, int(round(iw * scale)))
                sh = max(1, int(round(ih * scale)))
            tile_w = sw + pad_px * 2
            tile_h = name_h + 8 + sh + pad_px * 2
            tile = pygame.Rect(0, 0, tile_w, tile_h)
            if mode == "left_top":
                tile.left = slot.left + 2
                tile.top = slot.top + 2
            elif mode == "right_center":
                tile.right = slot.right - 2
                tile.centery = slot.centery
            elif mode == "left_anchor_top" and left_anchor is not None:
                tile.left = left_anchor
                tile.top = slot.top + 2
            else:
                tile.centerx = slot.centerx
                tile.top = slot.top + 2
            pygame.draw.rect(screen, (0, 255, 255), tile, 1)
            name_rect = name_surf.get_rect(centerx=tile.centerx, y=tile.top + 4)
            screen.blit(name_surf, name_rect)
            scaled = pygame.transform.smoothscale(composite, (sw, sh))
            img_rect = scaled.get_rect()
            img_rect.x = tile.left + pad_px
            img_rect.y = name_rect.bottom + 4
            screen.blit(scaled, img_rect)
            _draw_panel_buttons(panel_name, img_rect)
            return tile

        # Keep CONSOLE LEFT/RIGHT placement behavior matching the old 2-panel page.
        old_gap = 24
        old_left_slot = pygame.Rect(content.left, content.top, (content.width - old_gap) // 2, content.height)
        old_right_slot = pygame.Rect(old_left_slot.right + old_gap, content.top, content.width - old_left_slot.width - old_gap, content.height)
        _draw_panel_in_slot("CONSOLE LEFT", old_left_slot, "left_top")
        _draw_panel_in_slot("CONSOLE RIGHT", old_right_slot, "right_center")

        # DISPLAY CONTROL top-center, MASTER ARM below and left-edge aligned to DISPLAY CONTROL.
        title_bottom = popup.top + 4 + title.get_height()
        center_top = title_bottom + 8
        center_bottom = popup.bottom - 44
        center_h = max(1, center_bottom - center_top)
        center_w = max(220, int(round(content.width * 0.32)))
        center_x = content.centerx - (center_w // 2)
        top_h = max(1, int(round((center_h - 8) * 0.52)))
        top_slot = pygame.Rect(center_x, center_top, center_w, top_h)
        bottom_slot = pygame.Rect(center_x, top_slot.bottom + 8, center_w, max(1, center_bottom - (top_slot.bottom + 8)))
        disp_tile = _draw_panel_in_slot("DISPLAY CONTROL", top_slot, "center_top")
        disp_left = disp_tile.left if disp_tile is not None else None
        _draw_panel_in_slot("MASTER ARM", bottom_slot, "left_anchor_top", left_anchor=disp_left)
    elif special_vertical:
        title_bottom = popup.top + 4 + title.get_height()
        special_top = title_bottom + 8
        special_bottom = popup.bottom - 44
        special = pygame.Rect(content.left, special_top, content.width, max(1, special_bottom - special_top))
        gap = 8
        top_h = max(1, int(round((special.height - gap) * 0.52)))
        top_slot = pygame.Rect(special.left, special.top, special.width, top_h)
        bot_slot = pygame.Rect(special.left, top_slot.bottom + gap, special.width, max(1, special.bottom - (top_slot.bottom + gap)))
        aligned_left = top_slot.left + 2
        for idx, panel_name in enumerate(special_order):
            slot = top_slot if idx == 0 else bot_slot
            name_surf = body_font.render(panel_name, True, (0, 255, 0))
            name_h = name_surf.get_height()
            composite = _load_panel_composite(panel_name)
            if composite is None:
                missing = body_font.render("MISSING", True, (255, 255, 255))
                miss_rect = missing.get_rect(center=slot.center)
                pygame.draw.rect(screen, (0, 255, 255), slot, 1)
                screen.blit(missing, miss_rect)
                continue
            iw = max(1, composite.get_width())
            ih = max(1, composite.get_height())
            pad_px = 3
            max_h = max(1, slot.height - (name_h + 12 + pad_px * 2))
            scale = max_h / float(ih)
            sw = max(1, int(round(iw * scale)))
            sh = max(1, int(round(ih * scale)))
            max_w = max(1, slot.width - pad_px * 2 - 2)
            if sw > max_w:
                scale = max_w / float(iw)
                sw = max(1, int(round(iw * scale)))
                sh = max(1, int(round(ih * scale)))
            tile_w = sw + pad_px * 2
            tile_h = name_h + 8 + sh + pad_px * 2
            tile = pygame.Rect(0, 0, tile_w, tile_h)
            if idx == 0:
                tile.centerx = slot.centerx
                tile.top = slot.top + 2
                aligned_left = tile.left
            else:
                tile.left = aligned_left
                tile.top = slot.top + 2
            pygame.draw.rect(screen, (0, 255, 255), tile, 1)
            name_rect = name_surf.get_rect(centerx=tile.centerx, y=tile.top + 4)
            screen.blit(name_surf, name_rect)
            scaled = pygame.transform.smoothscale(composite, (sw, sh))
            img_rect = scaled.get_rect()
            img_rect.x = tile.left + pad_px
            img_rect.y = name_rect.bottom + 4
            screen.blit(scaled, img_rect)
            _draw_panel_buttons(panel_name, img_rect)
    else:
        gap = 24
        if len(panels) >= 2:
            left_slot = pygame.Rect(content.left, content.top, (content.width - gap) // 2, content.height)
            right_slot = pygame.Rect(left_slot.right + gap, content.top, content.width - left_slot.width - gap, content.height)
            slots = [left_slot, right_slot]
        else:
            slots = [pygame.Rect(content.left, content.top, content.width, content.height)]

        for idx, panel_name in enumerate(panels[:2]):
            slot = slots[min(idx, len(slots) - 1)]
            name_surf = body_font.render(panel_name, True, (0, 255, 0))
            name_h = name_surf.get_height()
            composite = _load_panel_composite(panel_name)
            if composite is None:
                missing = body_font.render("MISSING", True, (255, 255, 255))
                miss_rect = missing.get_rect(center=slot.center)
                pygame.draw.rect(screen, (0, 255, 255), slot, 1)
                screen.blit(missing, miss_rect)
                continue

            iw = max(1, composite.get_width())
            ih = max(1, composite.get_height())
            pad_px = 3
            max_h = max(1, slot.height - (name_h + 12 + pad_px * 2))
            # Prefer vertical fit so narrow/tall panels are not undersized.
            scale = max_h / float(ih)
            sw = max(1, int(round(iw * scale)))
            sh = max(1, int(round(ih * scale)))
            max_w = max(1, slot.width - pad_px * 2)
            if sw > max_w:
                scale = max_w / float(iw)
                sw = max(1, int(round(iw * scale)))
                sh = max(1, int(round(ih * scale)))

            tile_w = sw + pad_px * 2
            tile_h = name_h + 8 + sh + pad_px * 2
            tile = pygame.Rect(0, 0, tile_w, tile_h)
            if len(panels) >= 2:
                if idx == 0:
                    tile.left = slot.left + 2  # POWER PANEL left-aligned.
                    tile.top = slot.top + 2
                else:
                    tile.right = slot.right - 2  # THROTTLE right-aligned.
                    tile.centery = slot.centery  # THROTTLE vertically centered.
            else:
                tile.centerx = slot.centerx
                tile.top = slot.top + 2
            pygame.draw.rect(screen, (0, 255, 255), tile, 1)

            name_rect = name_surf.get_rect(centerx=tile.centerx, y=tile.top + 4)
            screen.blit(name_surf, name_rect)
            scaled = pygame.transform.smoothscale(composite, (sw, sh))
            img_rect = scaled.get_rect()
            img_rect.x = tile.left + pad_px
            img_rect.y = name_rect.bottom + 4
            screen.blit(scaled, img_rect)
            _draw_panel_buttons(panel_name, img_rect)
    return popup, total_pages


def draw_start_mode_prompt(screen: pygame.Surface) -> Dict[str, pygame.Rect]:
    title_font = load_font(28)
    body_font = load_font(20)
    screen.fill(BG_COLOR)
    t1 = title_font.render("START CONDITION", True, (0, 255, 255))
    t2 = body_font.render("[H] HOT START", True, (0, 255, 0))
    t3 = body_font.render("[C] COLD START", True, (0, 255, 0))
    t4 = body_font.render("Use TAB to open cockpit panels menu", True, (0, 255, 255))
    t1_rect = t1.get_rect(center=(WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2 - 60))
    t2_rect = t2.get_rect(center=(WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2 - 10))
    t3_rect = t3.get_rect(center=(WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2 + 24))
    t4_rect = t4.get_rect(center=(WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2 + 64))
    screen.blit(t1, t1_rect)
    screen.blit(t2, t2_rect)
    screen.blit(t3, t3_rect)
    screen.blit(t4, t4_rect)

    return {
        "hot": t2_rect.inflate(36, 14),
        "cold": t3_rect.inflate(36, 14),
    }


def prompt_start_mode(screen: pygame.Surface, clock: pygame.time.Clock) -> str:
    title_font = load_font(28)
    body_font = load_font(20)
    while True:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return "hot"
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_c:
                    return "cold"
                if event.key == pygame.K_h:
                    return "hot"
                if event.key == pygame.K_ESCAPE:
                    return "hot"
        screen.fill(BG_COLOR)
        t1 = title_font.render("START CONDITION", True, (0, 255, 255))
        t2 = body_font.render("[H] HOT START", True, (0, 255, 0))
        t3 = body_font.render("[C] COLD START", True, (0, 255, 0))
        t4 = body_font.render("Select before loading sequence", True, (128, 128, 128))
        screen.blit(t1, t1.get_rect(center=(WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2 - 60)))
        screen.blit(t2, t2.get_rect(center=(WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2 - 10)))
        screen.blit(t3, t3.get_rect(center=(WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2 + 24)))
        screen.blit(t4, t4.get_rect(center=(WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2 + 64)))
        pygame.display.flip()
        clock.tick(60)

def draw_portal4_menu_popup(
    screen: pygame.Surface,
    active_submenu: Optional[str],
    item_flash_until: Dict[str, int],
    now_ms: int,
    crus_state: Dict[str, object],
    lites_state: Dict[str, object],
    data_link_state: Dict[str, object],
    ecs_state: Dict[str, object],
    seclvl_state: Dict[str, object],
    hmd_state: Dict[str, object],
    ins_gps_state: Dict[str, object],
    pmd_dr_state: Dict[str, object],
    dist_state: Dict[str, object],
    popup_portal_index: int,
    plugin_status_menu_buttons: Optional[List[Dict[str, object]]] = None,
) -> Dict[str, pygame.Rect]:
    zones: Dict[str, pygame.Rect] = {}
    popup_rect = get_portal_rect(popup_portal_index).copy()
    screen.fill(BG_COLOR, popup_rect)
    pygame.draw.rect(screen, LINE_COLOR, popup_rect, 1)

    cols = 5
    rows = 8
    cell_w = popup_rect.width // cols
    cell_h = popup_rect.height // rows
    draw_grid = active_submenu not in {"PMD_DR_TERM", "PMD_DR_CKLST_LEGACY"}
    if draw_grid:
        for i in range(1, cols):
            x = popup_rect.x + i * cell_w
            pygame.draw.line(screen, LINE_COLOR, (x, popup_rect.top), (x, popup_rect.bottom), 1)
        for j in range(1, rows):
            y = popup_rect.y + j * cell_h
            pygame.draw.line(screen, LINE_COLOR, (popup_rect.left, y), (popup_rect.right, y), 1)

    def cell_rect(row: int, col: int) -> pygame.Rect:
        return pygame.Rect(popup_rect.x + col * cell_w, popup_rect.y + row * cell_h, cell_w, cell_h)

    def cell_rect_by_name(name: str) -> pygame.Rect:
        col = ord(name[0].upper()) - ord("A")
        row = int(name[1:]) - 1
        return cell_rect(row, col)

    def draw_popup_button(box: pygame.Rect, state: ButtonState) -> None:
        render_button(screen, box, state, formats.get_font, now_ms)

    def merge_cells(cell_a: str, cell_b: str) -> pygame.Rect:
        rect_a = cell_rect_by_name(cell_a)
        rect_b = cell_rect_by_name(cell_b)
        merged = rect_a.union(rect_b)
        screen.fill(BG_COLOR, merged)
        pygame.draw.rect(screen, LINE_COLOR, merged, 1)
        return merged

    def line_slot_y(box: pygame.Rect, line_no: int, font: pygame.font.Font) -> int:
        slot_h = box.height / 3.0
        return int(box.top + (line_no - 1) * slot_h + (slot_h - font.get_height()) / 2)

    def draw_line(box: pygame.Rect, line_no: int, text: str, color: Tuple[int, int, int], flashing: bool, box_selected: bool = False) -> pygame.Rect:
        font = formats.get_font(14)
        surf = font.render(text, True, (0, 0, 0) if flashing else color)
        text_rect = surf.get_rect(centerx=box.centerx)
        text_rect.y = line_slot_y(box, line_no, font)
        if flashing:
            pygame.draw.rect(screen, (255, 255, 255), text_rect.inflate(4, 2))
        elif box_selected:
            pygame.draw.rect(screen, (255, 255, 255), text_rect.inflate(4, 2), 1)
        screen.blit(surf, text_rect)
        return text_rect

    def _remove_overlapping_popup_zones(overlay_rect: pygame.Rect) -> None:
        for zone_key, zone_rect in list(zones.items()):
            if isinstance(zone_rect, pygame.Rect) and zone_rect.colliderect(overlay_rect):
                zones.pop(zone_key, None)

    def draw_cni_style_gol_popup(option_key_prefix: str, options: List[str], selected_idx: int) -> None:
        option_cells = [
            "B3",
            "C3",
            "D3",
            "B4",
            "C4",
            "D4",
        ]
        used_cells = option_cells[: max(0, min(len(options), len(option_cells)))]
        for cell_name in used_cells:
            box = cell_rect_by_name(cell_name)
            _remove_overlapping_popup_zones(box)
            screen.fill(BG_COLOR, box)
            pygame.draw.rect(screen, LINE_COLOR, box, 1)

        font = formats.get_font(16)
        for idx, opt in enumerate(options):
            if idx >= len(used_cells):
                break
            cell_name = used_cells[idx]
            box = cell_rect_by_name(cell_name)
            key = f"{option_key_prefix}{idx}"
            zones[key] = box
            flashing = item_flash_until.get(key, 0) > now_ms
            is_selected = int(idx) == int(selected_idx)
            lines = str(opt).split("\n")
            rendered = [font.render(line, True, (0, 0, 0) if flashing else ((255, 255, 255) if is_selected else LINE_COLOR)) for line in lines]
            total_h = sum(s.get_height() for s in rendered) + max(0, len(rendered) - 1)
            y = box.centery - total_h // 2
            merged: Optional[pygame.Rect] = None
            for surf in rendered:
                rr = surf.get_rect(centerx=box.centerx, y=y)
                if flashing:
                    pygame.draw.rect(screen, (255, 255, 255), rr.inflate(4, 2))
                screen.blit(surf, rr)
                merged = rr if merged is None else merged.union(rr)
                y += surf.get_height() + 1
            if is_selected and (not flashing) and merged is not None:
                pygame.draw.rect(screen, (255, 255, 255), merged.inflate(6, 3), 1)

    def _normalize_popup_stores_state() -> Tuple[Dict[str, object], Dict[str, int]]:
        raw_cfg = pmd_dr_state.get("stores_cfg")
        cfg = raw_cfg if isinstance(raw_cfg, dict) else load_stores_config()
        weapons_raw = cfg.get("weapons", {})
        weapons = weapons_raw if isinstance(weapons_raw, dict) else {}
        stations: Dict[str, List[str]] = {}
        for sta in PMD_STORES_STATION_ORDER:
            required_mode = ""
            if sta in PMD_STORES_EXTERNAL_STATIONS:
                required_mode = "EXT"
            elif sta in PMD_STORES_INTERNAL_STATIONS:
                required_mode = "INT"
            opts: List[str] = ["NONE"]
            inv_opts = _stores_inventory_station_options(cfg, sta)
            if len(inv_opts) > 0:
                opts.extend([wid for wid in inv_opts if wid not in opts])
            else:
                for weapon_id, weapon_meta in weapons.items():
                    wid = str(weapon_id).strip()
                    if wid == "" or not isinstance(weapon_meta, dict):
                        continue
                    car_raw = weapon_meta.get("carriage", [])
                    carriage: List[str] = []
                    if isinstance(car_raw, list):
                        for mode in car_raw:
                            tag = str(mode).upper().strip()
                            if tag in {"INT", "EXT"} and tag not in carriage:
                                carriage.append(tag)
                    if len(carriage) <= 0:
                        carriage = ["INT", "EXT"]
                    wtype = str(weapon_meta.get("type", "AS")).upper().strip()
                    if wtype not in {"AS", "SRM", "MRM"}:
                        wtype = "AS"
                    if sta in PMD_STORES_AA_ONLY_STATIONS and wtype == "AS":
                        continue
                    if (required_mode == "" or required_mode in carriage) and wid not in opts:
                        opts.append(wid)
            stations[sta] = opts

        cfg["weapons"] = weapons
        cfg["stations"] = stations
        pmd_dr_state["stores_cfg"] = cfg

        idx_map_raw = pmd_dr_state.get("stores_sta_idx")
        idx_map = idx_map_raw if isinstance(idx_map_raw, dict) else {}
        if not isinstance(idx_map_raw, dict):
            pmd_dr_state["stores_sta_idx"] = idx_map
        _apply_default_stores_loadout_once(pmd_dr_state, stations, idx_map)
        for sta in PMD_STORES_STATION_ORDER:
            opts = stations.get(sta, ["NONE"])
            try:
                idx = int(idx_map.get(sta, 0))
            except Exception:
                idx = 0
            idx_map[sta] = max(0, min(len(opts) - 1, idx))
        pmd_dr_state["stores_sta_idx"] = idx_map
        try:
            pmd_dr_state["stores_gun_value"] = max(0, min(182, int(pmd_dr_state.get("stores_gun_value", 182))))
        except Exception:
            pmd_dr_state["stores_gun_value"] = 182
        try:
            pmd_dr_state["stores_chaff_value"] = max(0, min(30, int(pmd_dr_state.get("stores_chaff_value", 10))))
        except Exception:
            pmd_dr_state["stores_chaff_value"] = 10
        try:
            pmd_dr_state["stores_flare_value"] = max(0, min(30, int(pmd_dr_state.get("stores_flare_value", 10))))
        except Exception:
            pmd_dr_state["stores_flare_value"] = 10
        return cfg, idx_map

    def draw_scratchpad_line(
        box: pygame.Rect,
        input_text: str,
        selected: bool,
        flashing: bool,
    ) -> None:
        font = formats.get_font(14)
        slot_count = 3
        slot_text = "".join(ch for ch in str(input_text) if ch.isdigit())[-slot_count:].rjust(slot_count, " ")
        chars = list(slot_text)
        baseline_y = line_slot_y(box, 1, font)
        slot_w = max(10, int(font.size("0")[0]))
        slot_gap = 4
        total_w = (slot_count * slot_w) + ((slot_count - 1) * slot_gap)
        start_x = box.centerx - (total_w // 2)
        color = (255, 255, 255) if selected else (128, 128, 128)
        slot_rects: List[pygame.Rect] = []
        for idx, ch in enumerate(chars):
            draw_char = ch.strip() != ""
            surf = font.render(ch if draw_char else " ", True, (0, 0, 0) if flashing else color)
            text_rect = surf.get_rect()
            slot_x = start_x + idx * (slot_w + slot_gap)
            text_rect.x = slot_x + ((slot_w - text_rect.width) // 2)
            text_rect.y = baseline_y
            slot_rects.append(text_rect)
            if flashing and draw_char:
                pygame.draw.rect(screen, (255, 255, 255), text_rect.inflate(4, 2))
            if draw_char:
                screen.blit(surf, text_rect)
            underline_y = text_rect.bottom + 1
            pygame.draw.line(
                screen,
                (0, 0, 0) if flashing else color,
                (slot_x, underline_y),
                (slot_x + slot_w, underline_y),
                1,
            )
        if selected and not flashing and len(slot_rects) >= 1:
            top_box = slot_rects[0].unionall(slot_rects[1:]).inflate(6, 4)
            pygame.draw.rect(screen, (255, 255, 255), top_box, 1)

    def draw_data_entry_cell(
        box: pygame.Rect,
        key_prefix: str,
        line2: str,
        committed_value: int,
        selected: bool,
        input_text: str,
    ) -> None:
        flashing = item_flash_until.get(key_prefix, 0) > now_ms
        draw_scratchpad_line(box, input_text, selected, flashing)
        draw_line(box, 2, line2, (0, 255, 0), flashing)
        l3_rect = draw_line(box, 3, f"BRT {committed_value}", (255, 255, 255), flashing)
        tri_color = LINE_COLOR if selected else (128, 128, 128)
        if flashing:
            tri_color = (0, 0, 0)
        tx = l3_rect.left - 12
        up_points = [(tx + 4, l3_rect.centery - 6), (tx, l3_rect.centery - 1), (tx + 8, l3_rect.centery - 1)]
        dn_points = [(tx + 4, l3_rect.centery + 6), (tx, l3_rect.centery + 1), (tx + 8, l3_rect.centery + 1)]
        pygame.draw.polygon(screen, tri_color, up_points, 0)
        pygame.draw.polygon(screen, tri_color, dn_points, 0)

    def _popup_ensure_degrd_system_state() -> Tuple[List[str], int]:
        opts = pmd_dr_state.get("degrd_system_options", [])
        if not isinstance(opts, list) or len(opts) <= 0:
            names: List[str] = []
            try:
                rows = list(formats.PhmFormat._vehicle_systems()) + list(formats.PhmFormat._mission_systems())
                for row in rows:
                    if not isinstance(row, tuple) or len(row) < 1:
                        continue
                    name = str(row[0]).strip()
                    if name == "":
                        continue
                    names.append(name)
            except Exception:
                names = []
            if len(names) <= 0:
                names = [k for k in PHM_SYSTEM_LCN_PREFIX.keys()]
            opts = list(dict.fromkeys(names))
            pmd_dr_state["degrd_system_options"] = list(opts)
        idx = int(pmd_dr_state.get("degrd_system_idx", 0))
        idx = max(0, min(len(opts) - 1, idx))
        pmd_dr_state["degrd_system_idx"] = idx
        return opts, idx

    def _popup_ensure_degrd_subsystem_state() -> Tuple[List[str], int]:
        sys_opts, sys_idx = _popup_ensure_degrd_system_state()
        selected_system = str(sys_opts[sys_idx]) if len(sys_opts) > 0 else "VSP"
        selected_system_key = _phm_system_key_for_name(selected_system)

        opts = pmd_dr_state.get("degrd_subsystem_options", [])
        cached_system = _phm_system_key_for_name(str(pmd_dr_state.get("degrd_subsystem_system", "")))
        required = _phm_subsystems_for_system(selected_system_key)
        if not isinstance(opts, list):
            opts = []
        opts_norm = [str(x).upper().strip() for x in opts if str(x).strip() != ""]
        if cached_system != selected_system_key or len(opts_norm) <= 0 or opts_norm != required:
            opts_norm = list(required)
            pmd_dr_state["degrd_subsystem_options"] = list(opts_norm)
            pmd_dr_state["degrd_subsystem_system"] = selected_system_key
            pmd_dr_state["degrd_subsystem_idx"] = 0

        idx = int(pmd_dr_state.get("degrd_subsystem_idx", 0))
        idx = max(0, min(len(opts_norm) - 1, idx)) if len(opts_norm) > 0 else 0
        pmd_dr_state["degrd_subsystem_idx"] = idx
        return opts_norm, idx

    def _popup_degrd_selected_field() -> Optional[str]:
        raw = str(pmd_dr_state.get("degrd_selected_field", "")).upper()
        if raw in {"LCN", "FNA"}:
            return raw
        return None

    def _popup_degrd_lcn_formatted() -> str:
        opts, idx = _popup_ensure_degrd_system_state()
        selected = str(opts[idx]).upper() if len(opts) > 0 else "VSP"
        prefix = str(PHM_SYSTEM_LCN_PREFIX.get(selected, "00")).rjust(2, "0")[-2:]
        digits = "".join(ch for ch in str(pmd_dr_state.get("degrd_lcn_input", "")) if ch.isdigit())[:13]
        auto = bool(pmd_dr_state.get("degrd_lcn_autofill", True))
        if auto:
            suffix = digits[2:] if len(digits) > 2 else ""
            digits = (prefix + suffix)[:13]
        pmd_dr_state["degrd_lcn_input"] = digits
        full = digits.ljust(13, "_")
        return f"{full[:7]} {full[7:9]} {full[9:13]}"

    def _popup_ensure_fuel_degrd_state() -> Dict[str, object]:
        raw = pmd_dr_state.get("fuel_degrd", {})
        state = raw if isinstance(raw, dict) else {}
        defaults = _default_fuel_degrd_state()
        for key, default_val in defaults.items():
            if key not in state:
                state[key] = default_val
        for map_key in ("tank_degrd", "sensor_degrd"):
            raw_map = state.get(map_key, {})
            out_map = raw_map if isinstance(raw_map, dict) else {}
            for tank in PMD_FUEL_DEGRD_TANK_ORDER:
                out_map[tank] = bool(out_map.get(tank, False))
            state[map_key] = out_map
        for map_key in ("valve_state", "valve_degrd"):
            raw_outer = state.get(map_key, {})
            outer = raw_outer if isinstance(raw_outer, dict) else {}
            normalized_outer: Dict[str, Dict[str, bool]] = {}
            for tank, valves in PMD_FUEL_DEGRD_VALVE_LAYOUT.items():
                tank_raw = outer.get(tank, {})
                tank_map = tank_raw if isinstance(tank_raw, dict) else {}
                defaults_map = PMD_FUEL_DEGRD_VALVE_DEFAULTS.get(tank, {})
                normalized_outer[tank] = {}
                for valve in valves:
                    if map_key == "valve_state":
                        normalized_outer[tank][valve] = bool(tank_map.get(valve, defaults_map.get(valve, False)))
                    else:
                        normalized_outer[tank][valve] = bool(tank_map.get(valve, False))
            state[map_key] = normalized_outer
        page = str(state.get("page", "HOME")).upper().strip()
        if page not in {"HOME"} | set(PMD_FUEL_DEGRD_TANK_ORDER):
            page = "HOME"
        state["page"] = page
        state["stale_data"] = bool(state.get("stale_data", False))
        pmd_dr_state["fuel_degrd"] = state
        return state

    def _popup_pmd_keybind_selected_field() -> Optional[str]:
        raw = str(pmd_dr_state.get("keybind_selected", "")).strip().lower()
        return raw if raw in PMD_KEYBIND_ACTION_ORDER else None

    def _popup_pmd_keybind_current_char(action: str) -> str:
        action_key = str(action).strip().lower()
        if action_key in _FLIGHT_CTRL_MANUAL_KEYS:
            keys_tuple = _FLIGHT_CTRL_MANUAL_KEYS.get(action_key, ())
            if isinstance(keys_tuple, tuple) and len(keys_tuple) > 0:
                try:
                    key_name = pygame.key.name(int(keys_tuple[0])).strip()
                    if key_name != "":
                        display = _format_keybind_display_text(key_name)
                        if display != "":
                            return display
                except Exception:
                    pass
        values_raw = pmd_dr_state.get("keybind_values", {})
        values = values_raw if isinstance(values_raw, dict) else {}
        fallback = str(PMD_KEYBIND_DEFAULT_NAMES.get(action_key, "")).strip()
        if action_key in values:
            key_name = str(values.get(action_key, "")).strip()
            if key_name == "":
                return "?"
        else:
            key_name = fallback
        display = _format_keybind_display_text(key_name)
        return display if display != "" else "?"

    def _popup_hotas_bindings_dict() -> Dict[str, Dict[str, object]]:
        raw = pmd_dr_state.get("hotas_bindings", {})
        out: Dict[str, Dict[str, object]] = {}
        if isinstance(raw, dict):
            for action, binding in raw.items():
                action_key = str(action).strip().lower()
                if action_key not in HOTAS_ACTION_ORDER:
                    continue
                if isinstance(binding, dict):
                    out[action_key] = dict(binding)
        pmd_dr_state["hotas_bindings"] = out
        return out

    def _popup_hotas_get_binding(action: str) -> Optional[Dict[str, object]]:
        action_key = str(action).strip().lower()
        binding = _popup_hotas_bindings_dict().get(action_key)
        return dict(binding) if isinstance(binding, dict) else None

    def _popup_hotas_binding_is_connected(binding: Optional[Dict[str, object]]) -> bool:
        if not isinstance(binding, dict):
            return False
        try:
            saved_idx = int(binding.get("joy", -1))
        except Exception:
            saved_idx = -1
        saved_guid = str(binding.get("joy_guid", "") or "").strip().lower()
        saved_name = str(binding.get("joy_name", "") or "").strip().lower()
        devices_raw = pmd_dr_state.get("hotas_devices", [])
        devices = devices_raw if isinstance(devices_raw, list) else []
        if saved_guid != "" or saved_name != "":
            for dev_raw in devices:
                dev = dev_raw if isinstance(dev_raw, dict) else {}
                dev_guid = str(dev.get("guid", "") or "").strip().lower()
                dev_name = str(dev.get("name", "") or "").strip().lower()
                if saved_guid != "" and dev_guid != "" and dev_guid == saved_guid:
                    return True
                if saved_name != "" and dev_name != "" and dev_name == saved_name:
                    return True
            return False
        for dev_raw in devices:
            dev = dev_raw if isinstance(dev_raw, dict) else {}
            try:
                dev_idx = int(dev.get("index", -1))
            except Exception:
                dev_idx = -1
            if dev_idx == saved_idx and dev_idx >= 0:
                return True
        return False

    def _popup_hotas_binding_label(binding: Optional[Dict[str, object]]) -> str:
        if not isinstance(binding, dict):
            return ""
        b_type = str(binding.get("type", "")).strip().lower()
        try:
            joy_idx = int(binding.get("joy", -1))
        except Exception:
            joy_idx = -1
        if joy_idx < 0:
            return ""
        token = ""
        if b_type == "axis":
            try:
                axis_idx = int(binding.get("id", -1))
            except Exception:
                axis_idx = -1
            if axis_idx < 0:
                return ""
            token = f"AXIS{axis_idx + 1}"
            if bool(binding.get("invert", False)):
                token += " INV"
        elif b_type == "button":
            try:
                btn_idx = int(binding.get("id", -1))
            except Exception:
                btn_idx = -1
            if btn_idx < 0:
                return ""
            token = f"BTN{btn_idx + 1}"
        elif b_type == "hat":
            try:
                hat_idx = int(binding.get("id", -1))
            except Exception:
                hat_idx = -1
            hat_dir = str(binding.get("dir", "")).upper()
            dir_tag = {"UP": "U", "DOWN": "D", "LEFT": "L", "RIGHT": "R"}.get(hat_dir, "")
            if hat_idx < 0 or dir_tag == "":
                return ""
            token = f"HAT{hat_idx + 1}_{dir_tag}"
        else:
            return ""
        return f"{joy_idx + 1}; {token}"

    def _popup_hotas_slew_mode() -> str:
        mode = str(pmd_dr_state.get("hotas_slew_mode", "AXIS")).upper()
        if mode not in {"AXIS", "HAT"}:
            mode = "AXIS"
        pmd_dr_state["hotas_slew_mode"] = mode
        return mode

    def _popup_hotas_pan_mode() -> str:
        mode = str(pmd_dr_state.get("hotas_pan_mode", "HAT")).upper()
        if mode not in {"AXIS", "HAT"}:
            mode = "HAT"
        pmd_dr_state["hotas_pan_mode"] = mode
        return mode

    def _popup_hotas_allowed_types(action: str) -> Tuple[str, ...]:
        action_key = str(action).strip().lower()
        allowed = HOTAS_ALLOWED_INPUTS.get(action_key, tuple())
        return tuple(v for v in allowed if v in {"axis", "button", "hat"})

    def _popup_hotas_excluded_inputs_set() -> Set[str]:
        raw = pmd_dr_state.get("hotas_edit_excluded_inputs", [])
        out: Set[str] = set()
        if isinstance(raw, list):
            for item in raw:
                token = str(item).strip().lower()
                if token != "":
                    out.add(token)
        pmd_dr_state["hotas_edit_excluded_inputs"] = sorted(out)
        return out

    def _popup_hotas_set_excluded_inputs(values: Set[str]) -> None:
        out = sorted({str(v).strip().lower() for v in values if str(v).strip() != ""})
        pmd_dr_state["hotas_edit_excluded_inputs"] = out

    def _popup_hotas_binding_exclude_signature(binding: Optional[Dict[str, object]]) -> str:
        if not isinstance(binding, dict):
            return ""
        b_type = str(binding.get("type", "")).strip().lower()
        try:
            joy_idx = int(binding.get("joy", -1))
        except Exception:
            joy_idx = -1
        if joy_idx < 0:
            return ""
        if b_type == "button":
            try:
                btn_idx = int(binding.get("id", -1))
            except Exception:
                btn_idx = -1
            if btn_idx < 0:
                return ""
            return f"button:{joy_idx}:{btn_idx}"
        if b_type == "hat":
            try:
                hat_idx = int(binding.get("id", -1))
            except Exception:
                hat_idx = -1
            hat_dir = str(binding.get("dir", "")).upper().strip()
            if hat_idx < 0 or hat_dir not in {"UP", "DOWN", "LEFT", "RIGHT"}:
                return ""
            return f"hat:{joy_idx}:{hat_idx}:{hat_dir.lower()}"
        return ""

    def draw_data_link_cells() -> None:
        field_max_len = {
            "flt_pos": 3,
            "callsign": 9,
            "msn_nbr": 5,
            "net_key": 8,
        }

        def _field_has_value(field_name: str, value: object) -> bool:
            _ = field_name
            return str(value or "").strip().upper() != ""

        def _draft_or_committed(field_name: str) -> str:
            key = str(field_name).strip().lower()
            committed = str(data_link_state.get(f"{key}_value", "")).strip().upper()
            selected = str(data_link_state.get("selected_field", "")).strip().lower()
            if selected != key:
                return committed
            inputs = data_link_state.get("inputs", {})
            if not isinstance(inputs, dict):
                return committed
            draft = str(inputs.get(key, "")).strip().upper()
            return draft if draft != "" else committed

        def _entry_enabled(field_name: str) -> bool:
            if field_name == "msn_nbr":
                flt_pos_val = _draft_or_committed("flt_pos")
                callsign_val = _draft_or_committed("callsign")
                return _field_has_value("flt_pos", flt_pos_val) and _field_has_value("callsign", callsign_val)
            return True

        def _entry_value(field_name: str) -> str:
            key = f"{field_name}_value"
            return str(data_link_state.get(key, "")).strip().upper()

        def _draw_entry(box: pygame.Rect, zone_key: str, field_name: str, label: str) -> None:
            zones[zone_key] = box
            enabled = _entry_enabled(field_name)
            selected = str(data_link_state.get("selected_field", "")).strip().lower() == field_name
            flashing = item_flash_until.get(zone_key, 0) > now_ms
            label_col = (0, 255, 0) if enabled else (128, 128, 128)
            value_col = LINE_COLOR if enabled else (128, 128, 128)
            value_text = _entry_value(field_name)
            if value_text == "":
                value_text = "---"
            draw_line(box, 2, label, label_col, flashing)
            draw_line(box, 3, value_text, value_col, flashing)
            if selected and enabled:
                inputs = data_link_state.get("inputs", {})
                raw = str(inputs.get(field_name, "")) if isinstance(inputs, dict) else ""
                scratch_len = int(field_max_len.get(field_name, 12))
                scratch = raw[-scratch_len:].rjust(scratch_len, "_")
                draw_line(box, 1, f"{scratch}\u2190", (255, 255, 255), flashing, box_selected=(not flashing))

        a2 = cell_rect_by_name("A2")
        _draw_entry(a2, "DATA_LINK_A2", "flt_pos", "FLT POS")

        b2 = cell_rect_by_name("B2")
        _draw_entry(b2, "DATA_LINK_B2", "callsign", "CALLSGN")

        a3 = cell_rect_by_name("A3")
        _draw_entry(a3, "DATA_LINK_A3", "net_key", "NET KEY")

        b3c3 = merge_cells("B3", "C3")
        _draw_entry(b3c3, "DATA_LINK_B3_C3", "msn_nbr", "MSN NBR")

        d3 = cell_rect_by_name("D3")
        zones["DATA_LINK_D3"] = d3
        joined_net = str(data_link_state.get("entry_id", "")).strip().upper()
        d3_text = "ABORT" if joined_net != "" else "JOIN\nNET"
        draw_popup_button(
            d3,
            ButtonState(
                button_id="DATA_LINK_D3",
                button_type=ButtonType.MOMENTARY_SINGLE,
                text=d3_text,
                enabled=True,
            ),
        )

        for key, cell_name, text in (
            ("DATA_LINK_E1", "E1", "MADL>"),
            ("DATA_LINK_E2", "E2", "LINK16>"),
            ("DATA_LINK_E3", "E3", "VMF>"),
        ):
            box = cell_rect_by_name(cell_name)
            zones[key] = box
            e2_disabled = bool(data_link_state.get("cni_fail_l16_ipf_active", False))
            draw_popup_button(
                box,
                ButtonState(
                    button_id=key,
                    button_type=ButtonType.PAGE_ACCESS,
                    text=text,
                    enabled=not (key == "DATA_LINK_E2" and e2_disabled),
                    flash_until_ms=item_flash_until.get(key, 0),
                ),
            )

        keypad_cells = {
            "DATA_LINK_KP_A4": ("A4", "ABC\n2"),
            "DATA_LINK_KP_B4": ("B4", "DEF\n3"),
            "DATA_LINK_KP_C4": ("C4", "GHI\n4"),
            "DATA_LINK_KP_A5": ("A5", "JKL\n5"),
            "DATA_LINK_KP_B5": ("B5", "MNO\n6"),
            "DATA_LINK_KP_C5": ("C5", "PQRS\n7"),
            "DATA_LINK_KP_A6": ("A6", "TUV\n8"),
            "DATA_LINK_KP_B6": ("B6", "WXYZ\n9"),
            "DATA_LINK_KP_C6": ("C6", "1"),
            "DATA_LINK_KP_A7": ("A7", "â–²"),
            "DATA_LINK_KP_B7": ("B7", "SPACE"),
            "DATA_LINK_KP_C7": ("C7", "BACK"),
            "DATA_LINK_KP_A8": ("A8", "â–¼"),
        }
        selected_field = str(data_link_state.get("selected_field", "")).strip().lower()
        keypad_enabled = selected_field in {"flt_pos", "callsign", "msn_nbr", "net_key"}
        if selected_field == "msn_nbr":
            keypad_enabled = bool(_entry_enabled("msn_nbr"))
        if bool(keypad_enabled):
            for zone_key, (cell_name, text) in keypad_cells.items():
                box = cell_rect_by_name(cell_name)
                zones[zone_key] = box
                draw_popup_button(
                    box,
                    ButtonState(
                        button_id=zone_key,
                        button_type=ButtonType.MOMENTARY_SINGLE,
                        text=text,
                        enabled=True,
                        flash_until_ms=item_flash_until.get(zone_key, 0),
                    ),
                )

    def draw_lites_cells() -> None:
        def draw_single_function_cell(cell_name: str, zone_key: str, label: str, on: bool) -> None:
            box = cell_rect_by_name(cell_name)
            zones[zone_key] = box
            flashing = item_flash_until.get(zone_key, 0) > now_ms
            draw_line(
                box,
                1,
                label,
                (255, 255, 255) if on else LINE_COLOR,
                flashing,
                box_selected=on and not flashing,
            )

        def draw_double_function_cell(cell_name: str, zone_key: str, label: str, opt_a: str, opt_b: str, mode: int) -> None:
            box = cell_rect_by_name(cell_name)
            zones[zone_key] = box
            flashing = item_flash_until.get(zone_key, 0) > now_ms
            draw_line(box, 1, label, (0, 255, 0), flashing)
            draw_line(
                box,
                2,
                opt_a,
                (255, 255, 255) if mode == 0 else LINE_COLOR,
                flashing,
                box_selected=(mode == 0 and not flashing),
            )
            draw_line(
                box,
                3,
                opt_b,
                (255, 255, 255) if mode == 1 else LINE_COLOR,
                flashing,
                box_selected=(mode == 1 and not flashing),
            )

        def draw_gol_button_cell(cell_name: str, zone_key: str, label: str, current_option: str) -> None:
            box = cell_rect_by_name(cell_name)
            zones[zone_key] = box
            flashing = item_flash_until.get(zone_key, 0) > now_ms
            label_rect = draw_line(box, 1, label, (0, 255, 0), flashing)
            pygame.draw.line(screen, (0, 255, 0), (label_rect.left, label_rect.bottom + 1), (label_rect.right, label_rect.bottom + 1), 1)
            option_lines = current_option.split("\n")
            if len(option_lines) == 1:
                draw_line(box, 2, option_lines[0], (255, 255, 255), flashing)
            else:
                draw_line(box, 2, option_lines[0], (255, 255, 255), flashing)
                draw_line(box, 3, option_lines[1], (255, 255, 255), flashing)

        def draw_gol_option_list(source_key: str, options: List[str], selected_index: int) -> None:
            option_slots = [
                "A3", "B3", "C3", "D3", "E3",
                "A4", "B4", "C4", "D4", "E4",
                "A5", "B5", "C5", "D5", "E5",
                "A6", "B6", "C6", "D6", "E6",
            ]
            for idx, option in enumerate(options):
                if idx >= len(option_slots):
                    break
                cell_name = option_slots[idx]
                box = cell_rect_by_name(cell_name)
                zone_key = f"LITES_GOL_{source_key}_{idx}"
                zones[zone_key] = box
                flashing = item_flash_until.get(zone_key, 0) > now_ms
                if "\n" in option:
                    a, b = option.split("\n", 1)
                    draw_line(box, 2, a, (255, 255, 255) if idx == selected_index else LINE_COLOR, flashing, box_selected=False)
                    draw_line(box, 3, b, (255, 255, 255) if idx == selected_index else LINE_COLOR, flashing, box_selected=False)
                    if idx == selected_index and not flashing:
                        font = formats.get_font(14)
                        a_r = font.render(a, True, LINE_COLOR).get_rect(centerx=box.centerx)
                        b_r = font.render(b, True, LINE_COLOR).get_rect(centerx=box.centerx)
                        a_r.y = line_slot_y(box, 2, font)
                        b_r.y = line_slot_y(box, 3, font)
                        merged = a_r.union(b_r)
                        pygame.draw.rect(screen, (255, 255, 255), merged.inflate(4, 2), 1)
                else:
                    draw_line(
                        box,
                        2,
                        option,
                        (255, 255, 255) if idx == selected_index else LINE_COLOR,
                        flashing,
                        box_selected=(idx == selected_index and not flashing),
                    )

        a1 = cell_rect_by_name("A1")
        zones["LITES_A1"] = a1
        a1_flashing = item_flash_until.get("LITES_A1", 0) > now_ms
        a1_on = bool(lites_state["a1_on"])
        draw_line(a1, 1, "CONSL", (255, 255, 255) if a1_on else LINE_COLOR, a1_flashing, box_selected=a1_on and not a1_flashing)

        b1 = cell_rect_by_name("B1")
        zones["LITES_B1"] = b1
        b1_input = str(lites_state.get("b1_input", ""))
        draw_data_entry_cell(
            b1,
            "LITES_B1",
            "CONSL",
            int(lites_state["b1_brt"]),
            bool(lites_state["b1_selected"]),
            b1_input,
        )

        c1 = cell_rect_by_name("C1")
        zones["LITES_C1"] = c1
        c1_flashing = item_flash_until.get("LITES_C1", 0) > now_ms
        c1_mode = int(lites_state["c1_mode"])
        draw_line(c1, 1, "POSIT", (0, 255, 0), c1_flashing)
        draw_line(c1, 2, "FLASH", (255, 255, 255) if c1_mode == 0 else LINE_COLOR, c1_flashing, box_selected=(c1_mode == 0 and not c1_flashing))
        draw_line(c1, 3, "STDY", (255, 255, 255) if c1_mode == 1 else LINE_COLOR, c1_flashing, box_selected=(c1_mode == 1 and not c1_flashing))

        d1 = cell_rect_by_name("D1")
        zones["LITES_D1"] = d1
        d1_flashing = item_flash_until.get("LITES_D1", 0) > now_ms
        d1_on = bool(lites_state["d1_on"])
        draw_line(d1, 1, "POSIT", (255, 255, 255) if d1_on else LINE_COLOR, d1_flashing, box_selected=d1_on and not d1_flashing)

        e1 = cell_rect_by_name("E1")
        zones["LITES_E1"] = e1
        e1_input = str(lites_state.get("e1_input", ""))
        draw_data_entry_cell(
            e1,
            "LITES_E1",
            "POSIT",
            int(lites_state["e1_brt"]),
            bool(lites_state["e1_selected"]),
            e1_input,
        )

        draw_double_function_cell("A2", "LITES_A2", "INDLTS", "BRT", "DIM", int(lites_state["a2_mode"]))
        draw_gol_button_cell(
            "C2",
            "LITES_C2",
            "STROB",
            ["PROG A", "PROG B", "PROG C"][int(lites_state["c2_option"])],
        )
        draw_single_function_cell("D2", "LITES_D2", "STROB", bool(lites_state["d2_on"]))
        draw_double_function_cell("E2", "LITES_E2", "STROBE", "BRT", "DIM", int(lites_state["e2_mode"]))
        draw_single_function_cell("D4", "LITES_D4", "FORM", bool(lites_state["d4_on"]))

        e4 = cell_rect_by_name("E4")
        zones["LITES_E4"] = e4
        draw_data_entry_cell(e4, "LITES_E4", "FORM", int(lites_state["e4_brt"]), bool(lites_state["e4_selected"]), str(lites_state.get("e4_input", "")))

        d5 = cell_rect_by_name("D5")
        zones["LITES_D5"] = d5
        draw_data_entry_cell(d5, "LITES_D5", "FLOOD", int(lites_state["d5_brt"]), bool(lites_state["d5_selected"]), str(lites_state.get("d5_input", "")))

        e5 = cell_rect_by_name("E5")
        zones["LITES_E5"] = e5
        draw_data_entry_cell(e5, "LITES_E5", "REFUEL", int(lites_state["e5_brt"]), bool(lites_state["e5_selected"]), str(lites_state.get("e5_input", "")))

        draw_single_function_cell("E6", "LITES_E6", "WPN", bool(lites_state["e6_on"]))
        draw_gol_button_cell(
            "E7",
            "LITES_E7",
            "MASTER",
            ["OFF", "COVERT\nFORM"][int(lites_state["e7_option"])],
        )

        merged_box = zones.get("LITES_B8_C8")
        if merged_box is not None:
            flashing = item_flash_until.get("LITES_B8_C8", 0) > now_ms
            on = bool(lites_state["b8c8_on"])
            rect1 = draw_line(merged_box, 1, "MSTR SWITCH", (255, 255, 255) if on else LINE_COLOR, flashing, box_selected=False)
            rect2 = draw_line(merged_box, 2, "ENABLE", (255, 255, 255) if on else LINE_COLOR, flashing, box_selected=False)
            if on and not flashing:
                both = rect1.union(rect2).inflate(4, 2)
                pygame.draw.rect(screen, (255, 255, 255), both, 1)

    def draw_ecs_cells() -> None:
        # B1 Status Label (compact 3-line stack)
        b1 = cell_rect_by_name("B1")
        zones["ECS_B1"] = b1
        font = formats.get_font(14)
        b1_lines = ["CABIN", "ALT", str(int(ecs_state["b1_alt"]))]
        b1_rendered = [font.render(t, True, (0, 255, 0)) for t in b1_lines]
        b1_total_h = sum(r.get_height() for r in b1_rendered) + 1
        y = b1.centery - b1_total_h // 2
        for surf in b1_rendered:
            r = surf.get_rect(centerx=b1.centerx)
            r.y = y
            screen.blit(surf, r)
            y += surf.get_height()

        # C1 Status Label: BOS + value centered as a 2-line block.
        c1 = cell_rect_by_name("C1")
        zones["ECS_C1"] = c1
        lines = ["BOS", str(int(ecs_state["c1_bos"]))]
        rendered = [font.render(t, True, (0, 255, 0)) for t in lines]
        total_h = sum(r.get_height() for r in rendered) + 1
        y = c1.centery - total_h // 2
        for surf in rendered:
            r = surf.get_rect(centerx=c1.centerx)
            r.y = y
            screen.blit(surf, r)
            y += surf.get_height() + 1

        # D1 Data Entry (arrow + scratchpad only visible when selected)
        d1 = cell_rect_by_name("D1")
        zones["ECS_D1"] = d1
        d1_flashing = item_flash_until.get("ECS_D1", 0) > now_ms
        input_text = str(ecs_state.get("d1_input", ""))
        if bool(ecs_state["d1_selected"]):
            padded = input_text[-2:].rjust(2, "_")
            top_text = f"Ã¢â€ â€™{padded}"
            draw_line(d1, 1, top_text, (255, 255, 255), d1_flashing, box_selected=True)
        d1_value_text = "0" if bool(ecs_state.get("cabin_press_active", False)) else str(int(ecs_state["d1_value"]))
        draw_line(d1, 2, "CABIN", LINE_COLOR, d1_flashing)
        draw_line(d1, 3, d1_value_text, LINE_COLOR, d1_flashing)

        # C2 OBOGS RESET (disabled, non-interactive, centered like C1)
        c2 = cell_rect_by_name("C2")
        zones["ECS_C2"] = c2
        c2_lines = ["OBOGS", "RESET"]
        c2_rendered = [font.render(t, True, (128, 128, 128)) for t in c2_lines]
        c2_total_h = sum(r.get_height() for r in c2_rendered) + 1
        y2 = c2.centery - c2_total_h // 2
        for surf in c2_rendered:
            r = surf.get_rect(centerx=c2.centerx)
            r.y = y2
            screen.blit(surf, r)
            y2 += surf.get_height() + 1

        # E1/E2 slider (merged zone)
        slider_box = zones.get("ECS_E1_E2")
        if slider_box is not None:
            zones["ECS_E1"] = cell_rect_by_name("E1")
            zones["ECS_E2"] = cell_rect_by_name("E2")
            slider_w = int((1 / 3) * DPI)
            slider_h = int(1.5 * DPI)
            slider_rect = pygame.Rect(0, 0, slider_w, slider_h)
            slider_rect.center = slider_box.center
            slider_rect.x += slider_w // 2
            zones["ECS_SLIDER"] = slider_rect
            pygame.draw.rect(screen, LINE_COLOR, slider_rect, 1)
            pos = max(0.0, min(1.0, float(ecs_state["slider_pos"])))
            marker_y = slider_rect.bottom - int(pos * (slider_rect.height - 2)) - 1
            pygame.draw.line(screen, (255, 255, 255), (slider_rect.left + 2, marker_y), (slider_rect.right - 2, marker_y), 2)

    def draw_seclvl_cells() -> None:
        seclvl_mode_popup_open = active_submenu == "SECLVL_MODE_GOL"

        # A1 status label
        a1 = cell_rect_by_name("A1")
        zones["SECLVL_A1"] = a1
        pmd_file_state, seclvl_fields_enabled = _seclvl_pmd_file_state()
        level_text = ["UNCLAS", "TOPSCT"][int(seclvl_state["level_idx"])]
        font = formats.get_font(14)
        a1_lines = ["SECLVL", level_text]
        a1_rendered = [font.render(t, True, (0, 255, 0)) for t in a1_lines]
        a1_total_h = sum(r.get_height() for r in a1_rendered) + 1
        y = a1.centery - a1_total_h // 2
        for surf in a1_rendered:
            r = surf.get_rect(centerx=a1.centerx)
            r.y = y
            screen.blit(surf, r)
            y += surf.get_height() + 1

        # B1 status label
        b1 = cell_rect_by_name("B1")
        zones["SECLVL_B1"] = b1
        draw_line(b1, 1, "PMD", (0, 255, 0), False)
        draw_line(b1, 2, "ACV", (0, 255, 0), False)
        draw_line(b1, 3, "DFLT", (0, 255, 0), False)

        b2 = cell_rect_by_name("B2")
        zones["SECLVL_B2"] = b2
        draw_line(b2, 1, "PMD", (0, 255, 0), False)
        draw_line(b2, 2, "UAF", (0, 255, 0), False)

        b3 = cell_rect_by_name("B3")
        zones["SECLVL_B3"] = b3
        draw_line(b3, 1, "PMD", (0, 255, 0), False)
        draw_line(b3, 2, "TEKDF", (0, 255, 0), False)
        draw_line(b3, 3, pmd_file_state, (0, 255, 0), False)

        c3 = cell_rect_by_name("C3")
        zones["SECLVL_C3"] = c3
        draw_line(c3, 1, "PMD", (0, 255, 0), False)
        draw_line(c3, 2, "AVBKF", (0, 255, 0), False)
        draw_line(c3, 3, pmd_file_state, (0, 255, 0), False)

        def draw_seclvl_entry(
            merged_box: pygame.Rect,
            prefix: str,
            label: str,
            masked: bool,
            zone_key: str,
            enabled: bool = True,
        ) -> None:
            zones[zone_key] = merged_box
            selected = bool(seclvl_state[f"{prefix}_selected"]) and bool(enabled)
            flashing = item_flash_until.get(zone_key, 0) > now_ms
            visible_slots = 7
            chars = seclvl_state.get(f"{prefix}_chars", [])
            if isinstance(chars, list):
                live_text = "".join(ch for ch in chars if str(ch) != "")
            else:
                live_text = str(chars or "")
            shown_live = live_text[-visible_slots:]
            shown_live = ("*" * len(shown_live)) if masked else shown_live
            top = shown_live.rjust(visible_slots, "_") + " <-"
            if selected:
                draw_line(merged_box, 1, top, (255, 255, 255), flashing, box_selected=True)
            label_color = LINE_COLOR if enabled else (128, 128, 128)
            if (not enabled) and bool(seclvl_state.get(f"{prefix}_selected", False)):
                seclvl_state[f"{prefix}_selected"] = False
            draw_line(merged_box, 2, label, label_color, flashing)
            committed = str(seclvl_state[f"{prefix}_committed"])
            if committed != "":
                line3_text = ("*" * len(committed)) if masked else committed
                draw_line(merged_box, 3, line3_text, label_color, flashing)
        cde1 = zones.get("SECLVL_USER")
        if cde1 is not None:
            draw_seclvl_entry(
                cde1,
                "user",
                "USER ID",
                masked=False,
                zone_key="SECLVL_USER",
                enabled=bool(seclvl_fields_enabled),
            )
        cde2 = zones.get("SECLVL_PASS")
        if cde2 is not None:
            user_chars = seclvl_state.get("user_chars", [])
            user_live = ""
            if isinstance(user_chars, list):
                user_live = "".join(str(ch) for ch in user_chars if str(ch) != "")
            user_present = bool(str(seclvl_state.get("user_committed", "")).strip()) or bool(user_live.strip())
            if (not user_present) or (not seclvl_fields_enabled):
                seclvl_state["pass_selected"] = False
            draw_seclvl_entry(
                cde2,
                "pass",
                "PASSWORD",
                masked=True,
                zone_key="SECLVL_PASS",
                enabled=bool(user_present and seclvl_fields_enabled),
            )

        # A2 GOL
        a2 = cell_rect_by_name("A2")
        zones["SECLVL_A2"] = a2
        mode_text = ["TRNG", "MSSN"][int(seclvl_state["mode_idx"])]
        enabled = bool(seclvl_state["logged_in"])
        color = (0, 255, 0) if enabled else (128, 128, 128)
        a2_lines = ["MODE", mode_text]
        a2_rendered = [font.render(t, True, color if i == 0 else ((255, 255, 255) if enabled else (128, 128, 128))) for i, t in enumerate(a2_lines)]
        a2_total_h = sum(r.get_height() for r in a2_rendered) + 1
        y2 = a2.centery - a2_total_h // 2
        first_rect = None
        for surf in a2_rendered:
            r = surf.get_rect(centerx=a2.centerx)
            r.y = y2
            screen.blit(surf, r)
            if first_rect is None:
                first_rect = r
            y2 += surf.get_height() + 1
        r = first_rect if first_rect is not None else a2
        pygame.draw.line(screen, (0, 255, 0) if enabled else (128, 128, 128), (r.left, r.bottom + 1), (r.right, r.bottom + 1), 1)
        if seclvl_mode_popup_open:
            mode_opts = ["TRNG", "MSSN"]
            draw_cni_style_gol_popup("SECLVL_MODE_", mode_opts, int(seclvl_state["mode_idx"]))

