    def draw_hmd_onaxs_dcltr_cells() -> None:
        def draw_single_multiline(cell_name: str, zone_key: str, lines: List[str], on: bool) -> None:
            box = cell_rect_by_name(cell_name)
            zones[zone_key] = box
            flashing = item_flash_until.get(zone_key, 0) > now_ms
            font = formats.get_font(14)
            rendered = [font.render(txt, True, (0, 0, 0) if flashing else ((255, 255, 255) if on else LINE_COLOR)) for txt in lines[:3]]
            total_h = sum(s.get_height() for s in rendered) + max(0, len(rendered) - 1)
            y = box.centery - total_h // 2
            drawn: List[pygame.Rect] = []
            for surf in rendered:
                r = surf.get_rect(centerx=box.centerx)
                r.y = y
                if flashing:
                    pygame.draw.rect(screen, (255, 255, 255), r.inflate(4, 2))
                screen.blit(surf, r)
                drawn.append(r)
                y += surf.get_height() + 1
            if on and not flashing and drawn:
                merged = drawn[0]
                for r in drawn[1:]:
                    merged = merged.union(r)
                pygame.draw.rect(screen, (255, 255, 255), merged.inflate(4, 2), 1)

        ab1 = merge_cells("A1", "B1")
        left = pygame.Rect(ab1.left, ab1.top, ab1.width // 2, ab1.height)
        right = pygame.Rect(left.right, ab1.top, ab1.width - left.width, ab1.height)
        zones["HMD_ONAXS_A1"] = left
        zones["HMD_ONAXS_B1"] = right
        draw_line(left, 1, "ON AXIS", LINE_COLOR, False)
        draw_line(left, 2, "DCLTR", LINE_COLOR, False)
        draw_line(left, 3, "LEVEL", LINE_COLOR, False)
        b1_mode = int(hmd_state["b1_mode"])
        b1_flash = item_flash_until.get("HMD_ONAXS_B1", 0) > now_ms
        draw_line(right, 1, "D1", (255, 255, 255) if b1_mode == 0 else LINE_COLOR, b1_flash, box_selected=(b1_mode == 0 and not b1_flash))
        draw_line(right, 2, "D2", (255, 255, 255) if b1_mode == 1 else LINE_COLOR, b1_flash, box_selected=(b1_mode == 1 and not b1_flash))
        draw_line(right, 3, "D3", (255, 255, 255) if b1_mode == 2 else LINE_COLOR, b1_flash, box_selected=(b1_mode == 2 and not b1_flash))

        ab2 = merge_cells("A2", "B2")
        zones["HMD_ONAXS_A2B2"] = ab2
        on = bool(hmd_state["onaxs_a2b2_on"])
        flash = item_flash_until.get("HMD_ONAXS_A2B2", 0) > now_ms
        r1 = draw_line(ab2, 1, "RESET ON AXIS", (255, 255, 255) if on else LINE_COLOR, flash, box_selected=False)
        r2 = draw_line(ab2, 2, "DEFAULTS", (255, 255, 255) if on else LINE_COLOR, flash, box_selected=False)
        if on and not flash:
            pygame.draw.rect(screen, (255, 255, 255), r1.union(r2).inflate(4, 2), 1)

        draw_single_multiline("A3", "HMD_ONAXS_A3", ["ACCEL", "CUE  "], bool(hmd_state["onaxs_a3_on"]))
        draw_single_multiline("B3", "HMD_ONAXS_B3", ["AOA"], bool(hmd_state["onaxs_b3_on"]))
        draw_single_multiline("C3", "HMD_ONAXS_C3", ["0"], bool(hmd_state["onaxs_c3_on"]))
        draw_single_multiline("D3", "HMD_ONAXS_D3", ["0  ", "MAX"], bool(hmd_state["onaxs_d3_on"]))
        draw_single_multiline("E3", "HMD_ONAXS_E3", ["MACH"], bool(hmd_state["onaxs_e3_on"]))
        draw_single_multiline("A4", "HMD_ONAXS_A4", ["A/C  ", "HDG  ", "SCALE"], bool(hmd_state["onaxs_a4_on"]))
        draw_single_multiline("B4", "HMD_ONAXS_B4", ["A/S ", "DIAL"], bool(hmd_state["onaxs_b4_on"]))
        draw_single_multiline("C4", "HMD_ONAXS_C4", ["ALT ", "DIAL"], bool(hmd_state["onaxs_c4_on"]))
        draw_single_multiline("D4", "HMD_ONAXS_D4", ["VVI"], bool(hmd_state["onaxs_d4_on"]))
        draw_single_multiline("E4", "HMD_ONAXS_E4", ["VEIND"], bool(hmd_state["onaxs_e4_on"]))
        draw_single_multiline("A5", "HMD_ONAXS_A5", ["STPT"], bool(hmd_state["onaxs_a5_on"]))
        draw_single_multiline("B5", "HMD_ONAXS_B5", ["TAC ", "INFO"], bool(hmd_state["onaxs_b5_on"]))
        draw_single_multiline("C5", "HMD_ONAXS_C5", ["TGT  ", "B & R"], bool(hmd_state["onaxs_c5_on"]))

        d8 = cell_rect_by_name("D8")
        zones["HMD_ONAXS_D8"] = d8
        draw_line(d8, 1, "OFFAXS", LINE_COLOR, item_flash_until.get("HMD_ONAXS_D8", 0) > now_ms)
        draw_line(d8, 2, " DCLTR>", LINE_COLOR, item_flash_until.get("HMD_ONAXS_D8", 0) > now_ms)
        e8 = cell_rect_by_name("E8")
        zones["HMD_ONAXS_E8"] = e8
        draw_line(e8, 1, "<HMD", LINE_COLOR, item_flash_until.get("HMD_ONAXS_E8", 0) > now_ms)

    def draw_hmd_offaxs_dcltr_cells() -> None:
        def draw_single_multiline(cell_name: str, zone_key: str, lines: List[str], on: bool) -> None:
            box = cell_rect_by_name(cell_name)
            zones[zone_key] = box
            flashing = item_flash_until.get(zone_key, 0) > now_ms
            font = formats.get_font(14)
            rendered = [font.render(txt, True, (0, 0, 0) if flashing else ((255, 255, 255) if on else LINE_COLOR)) for txt in lines[:3]]
            total_h = sum(s.get_height() for s in rendered) + max(0, len(rendered) - 1)
            y = box.centery - total_h // 2
            drawn: List[pygame.Rect] = []
            for surf in rendered:
                r = surf.get_rect(centerx=box.centerx)
                r.y = y
                if flashing:
                    pygame.draw.rect(screen, (255, 255, 255), r.inflate(4, 2))
                screen.blit(surf, r)
                drawn.append(r)
                y += surf.get_height() + 1
            if on and not flashing and drawn:
                merged = drawn[0]
                for r in drawn[1:]:
                    merged = merged.union(r)
                pygame.draw.rect(screen, (255, 255, 255), merged.inflate(4, 2), 1)

        ab1 = merge_cells("A1", "B1")
        left = pygame.Rect(ab1.left, ab1.top, ab1.width // 2, ab1.height)
        right = pygame.Rect(left.right, ab1.top, ab1.width - left.width, ab1.height)
        zones["HMD_OFFAXS_A1"] = left
        zones["HMD_OFFAXS_B1"] = right
        draw_line(left, 1, "OFFAXIS", LINE_COLOR, False)
        draw_line(left, 2, "DCLTR", LINE_COLOR, False)
        draw_line(left, 3, "LEVEL", LINE_COLOR, False)
        b2_mode = int(hmd_state["b2_mode"])
        b2_flash = item_flash_until.get("HMD_OFFAXS_B1", 0) > now_ms
        draw_line(right, 1, "D1", (255, 255, 255) if b2_mode == 0 else LINE_COLOR, b2_flash, box_selected=(b2_mode == 0 and not b2_flash))
        draw_line(right, 2, "D2", (255, 255, 255) if b2_mode == 1 else LINE_COLOR, b2_flash, box_selected=(b2_mode == 1 and not b2_flash))
        draw_line(right, 3, "D3", (255, 255, 255) if b2_mode == 2 else LINE_COLOR, b2_flash, box_selected=(b2_mode == 2 and not b2_flash))

        ab2 = merge_cells("A2", "B2")
        zones["HMD_OFFAXS_A2B2"] = ab2
        on = bool(hmd_state["offaxs_a2b2_on"])
        flash = item_flash_until.get("HMD_OFFAXS_A2B2", 0) > now_ms
        r1 = draw_line(ab2, 1, "RESET ON AXIS", (255, 255, 255) if on else LINE_COLOR, flash, box_selected=False)
        r2 = draw_line(ab2, 2, "DEFAULTS", (255, 255, 255) if on else LINE_COLOR, flash, box_selected=False)
        if on and not flash:
            pygame.draw.rect(screen, (255, 255, 255), r1.union(r2).inflate(4, 2), 1)

        draw_single_multiline("A3", "HMD_OFFAXS_A3", ["HEAD ", "HDG  ", "SCALE"], bool(hmd_state["offaxs_a3_on"]))
        draw_single_multiline("A4", "HMD_OFFAXS_A4", ["DLZ", "A-A"], bool(hmd_state["offaxs_a4_on"]))
        draw_single_multiline("B4", "HMD_OFFAXS_B4", ["DLZ", "A-S"], bool(hmd_state["offaxs_b4_on"]))
        draw_single_multiline("C4", "HMD_OFFAXS_C4", ["RETICL", "AIM 9 "], bool(hmd_state["offaxs_c4_on"]))
        draw_single_multiline("D4", "HMD_OFFAXS_D4", ["SHOOT", "CUE  "], bool(hmd_state["offaxs_d4_on"]))
        draw_single_multiline("E4", "HMD_OFFAXS_E4", ["TTG"], bool(hmd_state["offaxs_e4_on"]))
        draw_single_multiline("A5", "HMD_OFFAXS_A5", ["STPT"], bool(hmd_state["offaxs_a5_on"]))
        draw_single_multiline("B5", "HMD_OFFAXS_B5", ["TAC ", "INFO"], bool(hmd_state["offaxs_b5_on"]))
        draw_single_multiline("C5", "HMD_OFFAXS_C5", ["TGT  ", "B & R"], bool(hmd_state["offaxs_c5_on"]))

        d8 = cell_rect_by_name("D8")
        zones["HMD_OFFAXS_D8"] = d8
        draw_line(d8, 1, "ONAXIS ", LINE_COLOR, item_flash_until.get("HMD_OFFAXS_D8", 0) > now_ms)
        draw_line(d8, 2, " DCLTR>", LINE_COLOR, item_flash_until.get("HMD_OFFAXS_D8", 0) > now_ms)
        e8 = cell_rect_by_name("E8")
        zones["HMD_OFFAXS_E8"] = e8
        draw_line(e8, 1, "<HMD", LINE_COLOR, item_flash_until.get("HMD_OFFAXS_E8", 0) > now_ms)

    def draw_hmd_video_cells() -> None:
        c1 = cell_rect_by_name("C1")
        zones["HMD_VIDEO_C1"] = c1
        c1_mode = int(hmd_state["video_c1_mode"])
        c1_flash = item_flash_until.get("HMD_VIDEO_C1", 0) > now_ms
        draw_line(c1, 1, "HMD VID", (255, 255, 255) if c1_mode == 0 else LINE_COLOR, c1_flash, box_selected=(c1_mode == 0 and not c1_flash))
        draw_line(c1, 2, "DAS VID", (255, 255, 255) if c1_mode == 1 else LINE_COLOR, c1_flash, box_selected=(c1_mode == 1 and not c1_flash))
        draw_line(c1, 3, "OFF", (255, 255, 255) if c1_mode == 2 else LINE_COLOR, c1_flash, box_selected=(c1_mode == 2 and not c1_flash))

        e3 = cell_rect_by_name("E3")
        zones["HMD_VIDEO_E3"] = e3
        e3_mode = int(hmd_state["video_e3_mode"])
        e3_flash = item_flash_until.get("HMD_VIDEO_E3", 0) > now_ms
        draw_line(e3, 1, "POLARTY", (0, 255, 0), e3_flash)
        draw_line(e3, 2, "WHOT", (255, 255, 255) if e3_mode == 0 else LINE_COLOR, e3_flash, box_selected=(e3_mode == 0 and not e3_flash))
        draw_line(e3, 3, "BHOT", (255, 255, 255) if e3_mode == 1 else LINE_COLOR, e3_flash, box_selected=(e3_mode == 1 and not e3_flash))

        d4 = cell_rect_by_name("D4")
        zones["HMD_VIDEO_D4"] = d4
        d4_mode = int(hmd_state["video_d4_mode"])
        d4_flash = item_flash_until.get("HMD_VIDEO_D4", 0) > now_ms
        draw_line(d4, 1, "DAS", (0, 255, 0), d4_flash)
        draw_line(d4, 2, "AGC", (255, 255, 255) if d4_mode == 0 else LINE_COLOR, d4_flash, box_selected=(d4_mode == 0 and not d4_flash))
        draw_line(d4, 3, "MGC", (255, 255, 255) if d4_mode == 1 else LINE_COLOR, d4_flash, box_selected=(d4_mode == 1 and not d4_flash))

        def draw_video_data_entry(cell_name: str, key_prefix: str, line2: str, selected: bool, input_text: str, value: int) -> None:
            box = cell_rect_by_name(cell_name)
            zones[key_prefix] = box
            flashing = item_flash_until.get(key_prefix, 0) > now_ms
            if selected:
                top_text = f"{input_text[-2:].rjust(2, '_')} \u2190"
                draw_line(box, 1, top_text, (255, 255, 255), flashing, box_selected=not flashing)
            draw_line(box, 2, line2, LINE_COLOR, flashing)
            draw_line(box, 3, str(value), LINE_COLOR, flashing)

        draw_video_data_entry(
            "E4",
            "HMD_VIDEO_E4",
            "GAIN",
            bool(hmd_state["video_e4_selected"]),
            str(hmd_state.get("video_e4_input", "")),
            int(hmd_state["video_e4_value"]),
        )
        draw_video_data_entry(
            "E5",
            "HMD_VIDEO_E5",
            "LEVEL",
            bool(hmd_state["video_e5_selected"]),
            str(hmd_state.get("video_e5_input", "")),
            int(hmd_state["video_e5_value"]),
        )

        e8 = cell_rect_by_name("E8")
        zones["HMD_VIDEO_E8"] = e8
        draw_line(e8, 1, "HMD  ", LINE_COLOR, item_flash_until.get("HMD_VIDEO_E8", 0) > now_ms)
        draw_line(e8, 2, "<CTRL", LINE_COLOR, item_flash_until.get("HMD_VIDEO_E8", 0) > now_ms)

    def draw_ins_gps_cells() -> None:
        ins_a1_popup_open = active_submenu == "INS_GPS_A1_GOL"
        ins_b8_popup_open = active_submenu == "INS_GPS_B8_GOL"
        ins_c8_popup_open = active_submenu == "INS_GPS_C8_GOL"
        ins_d8_popup_open = active_submenu == "INS_GPS_D8_GOL"
        ins_e3_popup_open = active_submenu == "INS_GPS_E3_GOL"
        ins_d4_popup_open = active_submenu == "INS_GPS_D4_GOL"
        ins_fix_submenu_open = active_submenu == "INS_GPS_FIX"
        ins_nav_filtr_submenu_open = active_submenu == "INS_GPS_NAV_FILTR"
        ins_gps_submenu_open = active_submenu == "INS_GPS_GPS"

        ins_fail_active = bool(ins_gps_state.get("ins_fail_active", False))
        ins_degd_active = bool(ins_gps_state.get("ins_degd_active", False))
        nav_degd_active = bool(ins_gps_state.get("nav_degd_active", False))
        gps_fail_active = bool(ins_gps_state.get("gps_fail_active", False))
        gps_degd_active = bool(ins_gps_state.get("gps_degd_active", False))
        gps_no_keys_active = bool(ins_gps_state.get("gps_no_keys_active", False))

        def _ins_opt_text(options: List[str], idx_value: object, fallback_idx: int = 0) -> str:
            opts = [str(v).strip().upper() for v in options if str(v).strip() != ""]
            if len(opts) <= 0:
                return ""
            try:
                idx = int(idx_value)
            except Exception:
                idx = int(fallback_idx)
            idx = max(0, min(len(opts) - 1, idx))
            return str(opts[idx])

        def _ins_master_mode() -> str:
            return _ins_opt_text(INS_GPS_MODE_OPTIONS, ins_gps_state.get("a1_mode_idx", 1), 1) or "NAV"

        def _ins_nav_allowed(master_mode: str, nav_output: str) -> bool:
            master = str(master_mode).upper().strip()
            output = str(nav_output).upper().strip()
            if output not in {"STBY", "ATT", "NAV"}:
                return False
            if master == "STBY":
                return output == "STBY"
            if master == "ALIGN":
                return output in {"STBY", "ATT"}
            if master in {"NAV", "COMP", "SEC"}:
                return output in {"STBY", "ATT", "NAV"}
            return output == "STBY"

        # Local normalization for renderer safety.
        try:
            mode_idx = int(ins_gps_state.get("a1_mode_idx", 1))
        except Exception:
            mode_idx = 1
        ins_gps_state["a1_mode_idx"] = max(0, min(len(INS_GPS_MODE_OPTIONS) - 1, mode_idx))
        for key, options in (
            ("align_profile_idx", INS_GPS_ALIGN_PROFILE_OPTIONS),
            ("gps_aiding_idx", INS_GPS_GPS_AIDING_OPTIONS),
            ("fix_source_idx", INS_GPS_FIX_SOURCE_OPTIONS),
            ("nav_filter_idx", INS_GPS_NAV_FILTER_OPTIONS),
            ("magvar_mode_idx", INS_GPS_MAGVAR_MODE_OPTIONS),
            ("wypt_source_idx", INS_GPS_WYPT_SOURCE_OPTIONS),
        ):
            try:
                idx = int(ins_gps_state.get(key, 0))
            except Exception:
                idx = 0
            ins_gps_state[key] = max(0, min(len(options) - 1, idx))

        master_mode = _ins_master_mode()
        nav_output_mode = str(ins_gps_state.get("nav_output_mode", "NAV")).upper().strip()
        gps_aiding_mode = _ins_opt_text(INS_GPS_GPS_AIDING_OPTIONS, ins_gps_state.get("gps_aiding_idx", 0), 0)
        nav_filter_mode = _ins_opt_text(INS_GPS_NAV_FILTER_OPTIONS, ins_gps_state.get("nav_filter_idx", 0), 0)
        align_profile = _ins_opt_text(INS_GPS_ALIGN_PROFILE_OPTIONS, ins_gps_state.get("align_profile_idx", 0), 0)
        fix_source = _ins_opt_text(INS_GPS_FIX_SOURCE_OPTIONS, ins_gps_state.get("fix_source_idx", 0), 0)
        magvar_mode = _ins_opt_text(INS_GPS_MAGVAR_MODE_OPTIONS, ins_gps_state.get("magvar_mode_idx", 0), 0)
        wypt_source = _ins_opt_text(INS_GPS_WYPT_SOURCE_OPTIONS, ins_gps_state.get("wypt_source_idx", 0), 0)
        align_quality = max(0.0, min(1.0, float(ins_gps_state.get("align_quality", 0.98))))
        align_time_sec = max(0.0, float(ins_gps_state.get("align_time_sec", 0.0)))
        align_time_min = int(align_time_sec // 60.0)
        align_time_sec_rem = align_time_sec - (float(align_time_min) * 60.0)
        nav_allowed = _ins_nav_allowed(master_mode, "NAV")
        att_allowed = _ins_nav_allowed(master_mode, "ATT")
        stby_allowed = _ins_nav_allowed(master_mode, "STBY")

        def draw_block_center(box: pygame.Rect, lines: List[str], color: Tuple[int, int, int], flashing: bool = False) -> List[pygame.Rect]:
            font = formats.get_font(14)
            rendered = [font.render(t, True, (0, 0, 0) if flashing else color) for t in lines]
            total_h = sum(s.get_height() for s in rendered) + max(0, len(rendered) - 1)
            y = box.centery - total_h // 2
            rects: List[pygame.Rect] = []
            for surf in rendered:
                r = surf.get_rect(centerx=box.centerx)
                r.y = y
                if flashing:
                    pygame.draw.rect(screen, (255, 255, 255), r.inflate(4, 2))
                screen.blit(surf, r)
                rects.append(r)
                y += surf.get_height() + 1
            return rects

        def draw_block_bottom(box: pygame.Rect, lines: List[str], color: Tuple[int, int, int], flashing: bool = False) -> List[pygame.Rect]:
            font = formats.get_font(14)
            rendered = [font.render(t, True, (0, 0, 0) if flashing else color) for t in lines]
            total_h = sum(s.get_height() for s in rendered) + max(0, len(rendered) - 1)
            y = box.bottom - total_h - 2
            rects: List[pygame.Rect] = []
            for surf in rendered:
                r = surf.get_rect(centerx=box.centerx)
                r.y = y
                if flashing:
                    pygame.draw.rect(screen, (255, 255, 255), r.inflate(4, 2))
                screen.blit(surf, r)
                rects.append(r)
                y += surf.get_height() + 1
            return rects

        def ins_coord_scratch(raw_digits: object, is_lat: bool) -> str:
            digits = "".join(ch for ch in str(raw_digits) if ch.isdigit())
            width = 8 if is_lat else 9
            digits = digits[-width:]
            slots = list("_" * width)
            for idx, ch in enumerate(digits):
                slots[idx] = ch
            if is_lat:
                return f"{slots[0]}{slots[1]} {slots[2]}{slots[3]}.{''.join(slots[4:])}"
            return f"{slots[0]}{slots[1]}{slots[2]} {slots[3]}{slots[4]}.{''.join(slots[5:])}"

        def draw_ins_option_gol(prefix: str, options: List[str], selected_idx: int) -> None:
            slots = ["A1", "B1", "C1", "D1", "E1"]
            used_slots = slots[: max(0, min(len(options), len(slots)))]
            if len(used_slots) > 0:
                overlay_box = cell_rect_by_name(used_slots[0]).copy()
                for slot_name in used_slots[1:]:
                    overlay_box = overlay_box.union(cell_rect_by_name(slot_name))
                _remove_overlapping_popup_zones(overlay_box)
            for idx, opt in enumerate(options):
                if idx >= len(slots):
                    break
                box = cell_rect_by_name(slots[idx])
                key = f"{prefix}_OPT_{idx}"
                zones[key] = box
                flashing = item_flash_until.get(key, 0) > now_ms
                selected = idx == int(selected_idx)
                draw_line(
                    box,
                    2,
                    opt,
                    (255, 255, 255) if selected else LINE_COLOR,
                    flashing,
                    box_selected=(selected and not flashing),
                )

        if ins_fix_submenu_open or ins_nav_filtr_submenu_open or ins_gps_submenu_open:
            title = "FIX"
            value = fix_source
            if ins_nav_filtr_submenu_open:
                title = "NAV FILTR"
                value = nav_filter_mode
            elif ins_gps_submenu_open:
                title = "GPS"
                value = gps_aiding_mode
            head = merge_cells("B1", "D1")
            zones["INS_GPS_SUBMENU_HEAD"] = head
            draw_line(head, 1, "INS GPS", LINE_COLOR, False)
            draw_line(head, 2, title, (0, 255, 0), False)
            draw_line(head, 3, str(value), LINE_COLOR, False)
            body = merge_cells("B3", "D6")
            zones["INS_GPS_SUBMENU_BODY"] = body
            draw_line(body, 2, "SUBMENU PAGE", LINE_COLOR, False)
            draw_line(body, 3, "NO OPTION LIST", (0, 255, 0), False)
            return

        # A1 GOL
        a1 = cell_rect_by_name("A1")
        zones["INS_GPS_A1"] = a1
        a1_flash = item_flash_until.get("INS_GPS_A1", 0) > now_ms
        ins_nav_text = str(master_mode)
        font = formats.get_font(14)
        a1_lines = [
            font.render("INS", True, (0, 0, 0) if a1_flash else ((128, 128, 128) if ins_fail_active else LINE_COLOR)),
            font.render(ins_nav_text, True, (0, 0, 0) if a1_flash else ((128, 128, 128) if ins_fail_active else (255, 255, 255))),
        ]
        a1_total_h = sum(s.get_height() for s in a1_lines) + 1
        a1_y = a1.centery - a1_total_h // 2
        ins_rect = None
        for surf in a1_lines:
            rr = surf.get_rect(centerx=a1.centerx)
            rr.y = a1_y
            if a1_flash:
                pygame.draw.rect(screen, (255, 255, 255), rr.inflate(4, 2))
            screen.blit(surf, rr)
            if ins_rect is None:
                ins_rect = rr
            a1_y += surf.get_height() + 1
        if ins_rect is not None:
            pygame.draw.line(
                screen,
                (128, 128, 128) if ins_fail_active else LINE_COLOR,
                (ins_rect.left, ins_rect.bottom + 1),
                (ins_rect.right, ins_rect.bottom + 1),
                1,
            )

        # Row 1 status
        b1 = cell_rect_by_name("B1")
        zones["INS_GPS_B1"] = b1
        nav_status_text = "HIGH"
        if ins_fail_active or master_mode == "STBY" or nav_output_mode == "STBY":
            nav_status_text = "OFF"
        elif ins_degd_active or nav_degd_active or align_quality < 0.80:
            nav_status_text = "LOW"
        draw_line(b1, 1, "NAV   ", (0, 255, 0), False)
        draw_line(b1, 2, "STATUS", (0, 255, 0), False)
        draw_line(b1, 3, nav_status_text.ljust(5), (0, 255, 0), False)

        c1 = cell_rect_by_name("C1")
        zones["INS_GPS_C1"] = c1
        gps_text = "HIGH"
        gps_color = (0, 255, 0)
        if gps_fail_active:
            gps_text = "OFF"
        elif gps_aiding_mode == "OFF":
            gps_text = "LOW"
        elif gps_degd_active:
            gps_text = "LOW"
        elif gps_no_keys_active:
            gps_text = "HIGH"
            gps_color = (128, 128, 128)
        draw_line(c1, 1, "GPS  ", gps_color, False)
        draw_line(c1, 2, "ACCUR", gps_color, False)
        draw_line(c1, 3, gps_text.ljust(5), gps_color, False)

        d1e1 = merge_cells("D1", "E1")
        zones["INS_GPS_D1_E1"] = d1e1
        # INS page coordinates are display-only; editing is available in PMD/DR GPS DEBUG.
        if bool(ins_gps_state.get("de1_selected", False)):
            ins_gps_state["de1_selected"] = False
            ins_gps_state["de1_n_input"] = ""
            ins_gps_state["de1_w_input"] = ""
        if bool(ins_gps_state.get("alt_selected", False)):
            ins_gps_state["alt_selected"] = False
            ins_gps_state["alt_input"] = ""
        de1_selected = False
        de1_line = str(ins_gps_state.get("de1_edit_line", "N")).upper()
        n_color = (255, 255, 255) if (de1_selected and de1_line == "N") else LINE_COLOR
        w_color = (255, 255, 255) if (de1_selected and de1_line == "W") else LINE_COLOR
        draw_line(d1e1, 2, str(ins_gps_state.get("lon", "N 00 00.0000")), n_color, False)
        draw_line(d1e1, 3, str(ins_gps_state.get("lat", "W 000 00.0000")), w_color, False)

        # Row 2 status
        a2 = cell_rect_by_name("A2")
        zones["INS_GPS_A2"] = a2
        draw_line(a2, 1, "TNS A ", (0, 255, 0), False)
        draw_line(a2, 2, "STATUS", (0, 255, 0), False)
        draw_line(a2, 3, "HIGH  ", (0, 255, 0), False)

        b2 = cell_rect_by_name("B2")
        zones["INS_GPS_B2"] = b2
        draw_line(b2, 1, "TNS B ", (0, 255, 0), False)
        draw_line(b2, 2, "STATUS", (0, 255, 0), False)
        draw_line(b2, 3, "HIGH  ", (0, 255, 0), False)

        c2 = cell_rect_by_name("C2")
        zones["INS_GPS_C2"] = c2
        draw_line(c2, 1, "TNS C ", (0, 255, 0), False)
        draw_line(c2, 2, "STATUS", (0, 255, 0), False)
        draw_line(c2, 3, "HIGH  ", (0, 255, 0), False)

        d2e2 = merge_cells("D2", "E2")
        zones["INS_GPS_D2_E2"] = d2e2
        font = formats.get_font(14)
        e2_lines = [font.render("ELEV", True, (0, 255, 0)), font.render(str(int(ins_gps_state["elev"])), True, (0, 255, 0))]
        e2_total = sum(s.get_height() for s in e2_lines) + 1
        e2_y = d2e2.centery - e2_total // 2
        e2_left = d2e2.centerx + 2
        for surf in e2_lines:
            rr = surf.get_rect()
            rr.left = e2_left
            rr.y = e2_y
            screen.blit(surf, rr)
            e2_y += surf.get_height() + 1

        e3 = cell_rect_by_name("E3")
        zones["INS_GPS_E3"] = e3
        draw_block_center(e3, ["MAGVAR", f"{magvar_mode}"], (0, 255, 0), False)

        # Single function and misc row 4/5/6/7/8
        def draw_single(cell_name: str, key: str, lines: List[str], on: bool) -> None:
            box = cell_rect_by_name(cell_name)
            zones[key] = box
            flashing = item_flash_until.get(key, 0) > now_ms
            rects = draw_block_center(box, lines[:3], (255, 255, 255) if on else LINE_COLOR, flashing)
            if on and not flashing and rects:
                u = rects[0]
                for rr in rects[1:]:
                    u = u.union(rr)
                pygame.draw.rect(screen, (255, 255, 255), u.inflate(4, 2), 1)

        draw_single("A4", "INS_GPS_A4", ["STBY"], bool(nav_output_mode == "STBY"))
        draw_single("B4", "INS_GPS_B4", ["ATT"], bool(nav_output_mode == "ATT"))

        c4 = cell_rect_by_name("C4")
        zones["INS_GPS_C4"] = c4
        c4_color = (255, 255, 255) if nav_output_mode == "NAV" else ((128, 128, 128) if (not nav_allowed or ins_fail_active) else LINE_COLOR)
        draw_line(c4, 2, "NAV", c4_color, False)
        if nav_output_mode == "NAV":
            nav_txt = formats.get_font(14).render("NAV", True, (255, 255, 255))
            nav_rr = nav_txt.get_rect(center=c4.center)
            pygame.draw.rect(screen, (255, 255, 255), nav_rr.inflate(4, 2), 1)
        if (not stby_allowed) or ins_fail_active:
            draw_line(cell_rect_by_name("A4"), 2, "STBY", (128, 128, 128), False)
        if (not att_allowed) or ins_fail_active:
            draw_line(cell_rect_by_name("B4"), 2, "ATT", (128, 128, 128), False)

        d4 = cell_rect_by_name("D4")
        zones["INS_GPS_D4"] = d4
        g = (128, 128, 128)
        draw_line(d4, 1, "PRES", g, False)
        gps_rect = draw_line(d4, 2, wypt_source.split(" ")[0][:5].ljust(5), g, False)
        draw_line(d4, 3, "WYPT", g, False)
        pygame.draw.rect(screen, g, gps_rect.inflate(4, 2), 1)

        e4 = cell_rect_by_name("E4")
        zones["INS_GPS_E4"] = e4
        draw_block_center(e4, ["WYPT", wypt_source[:7]], g, False)

        a5 = cell_rect_by_name("A5")
        zones["INS_GPS_A5"] = a5
        draw_block_center(a5, ["STR", "HDG"], g, False)

        b5 = cell_rect_by_name("B5")
        zones["INS_GPS_B5"] = b5
        draw_block_center(b5, [nav_filter_mode[:7]], g, False)

        draw_single("C5", "INS_GPS_C5", ["IMA"], bool(ins_gps_state["c5_on"]))

        d6e6 = merge_cells("D6", "E6")
        zones["INS_GPS_D6_E6"] = d6e6
        draw_block_bottom(d6e6, [f"PROF : {align_profile}", f"FIX : {fix_source}"], (0, 255, 0), False)
        d7e7 = merge_cells("D7", "E7")
        zones["INS_GPS_D7_E7"] = d7e7
        draw_block_bottom(
            d7e7,
            [f"QUAL : {align_quality:0.2f}", f"TIME : {align_time_min:02d}:{align_time_sec_rem:04.1f}"],
            (0, 255, 0),
            False,
        )

        b8 = cell_rect_by_name("B8")
        zones["INS_GPS_B8"] = b8
        draw_line(b8, 2, "FIX>", LINE_COLOR, item_flash_until.get("INS_GPS_B8", 0) > now_ms)

        c8 = cell_rect_by_name("C8")
        zones["INS_GPS_C8"] = c8
        draw_block_center(c8, ["NAV", "FILTR>"], LINE_COLOR, item_flash_until.get("INS_GPS_C8", 0) > now_ms)

        d8 = cell_rect_by_name("D8")
        zones["INS_GPS_D8"] = d8
        draw_line(d8, 2, "GPS>", (128, 128, 128) if gps_fail_active else LINE_COLOR, item_flash_until.get("INS_GPS_D8", 0) > now_ms)
        if ins_a1_popup_open:
            draw_cni_style_gol_popup("INS_GPS_A1_OPT_", INS_GPS_MODE_OPTIONS, int(ins_gps_state.get("a1_mode_idx", 1)))
        elif ins_b8_popup_open:
            draw_ins_option_gol("INS_GPS_B8", INS_GPS_FIX_SOURCE_OPTIONS, int(ins_gps_state.get("fix_source_idx", 0)))
        elif ins_c8_popup_open:
            draw_ins_option_gol("INS_GPS_C8", INS_GPS_NAV_FILTER_OPTIONS, int(ins_gps_state.get("nav_filter_idx", 0)))
        elif ins_d8_popup_open:
            draw_ins_option_gol("INS_GPS_D8", INS_GPS_GPS_AIDING_OPTIONS, int(ins_gps_state.get("gps_aiding_idx", 0)))
        elif ins_e3_popup_open:
            draw_ins_option_gol("INS_GPS_E3", INS_GPS_MAGVAR_MODE_OPTIONS, int(ins_gps_state.get("magvar_mode_idx", 0)))
        elif ins_d4_popup_open:
            draw_ins_option_gol("INS_GPS_D4", INS_GPS_WYPT_SOURCE_OPTIONS, int(ins_gps_state.get("wypt_source_idx", 0)))

    def draw_crus_cells() -> None:
        zulu = datetime.utcnow().strftime("%H:%M:%S")
        nav_state = getattr(formats, "NAV_STATE", {})

        def crus_rolex_display(selected: bool) -> str:
            if not selected:
                return str(crus_state.get("rolex_value", "00:00:00"))
            mode = str(crus_state.get("rolex_mode", "roll"))
            slots = list("______")
            if mode == "segment":
                base = "".join(ch for ch in str(crus_state.get("rolex_value", "00:00:00")) if ch.isdigit())[-6:].rjust(6, "0")
                slots = list(base)
                seg_idx = max(0, min(2, int(crus_state.get("rolex_seg", 2))))
                seg_input = "".join(ch for ch in str(crus_state.get("rolex_seg_input", "")) if ch.isdigit())[-2:]
                if seg_input == "":
                    seg_slots = ["0", "0"]
                elif len(seg_input) == 1:
                    seg_slots = ["0", seg_input[0]]
                else:
                    seg_slots = [seg_input[0], seg_input[1]]
                start = seg_idx * 2
                slots[start] = seg_slots[0]
                slots[start + 1] = seg_slots[1]
            else:
                raw = "".join(ch for ch in str(crus_state.get("rolex_raw", "")) if ch.isdigit())[-6:]
                start = 6 - len(raw)
                for i, ch in enumerate(raw):
                    slots[start + i] = ch
            return f"{slots[0]}{slots[1]}:{slots[2]}{slots[3]}:{slots[4]}{slots[5]}"

        a1 = cell_rect_by_name("A1")
        zones["CRUS_A1"] = a1
        tos_on = bool(crus_state.get("tos_on", False))
        a1_flash = item_flash_until.get("CRUS_A1", 0) > now_ms
        draw_line(a1, 2, "TOS", (255, 255, 255) if tos_on else LINE_COLOR, a1_flash, box_selected=(tos_on and not a1_flash))

        bc1 = merge_cells("B1", "C1")
        zones["CRUS_BC1"] = bc1
        draw_line(bc1, 1, "TIME", (0, 255, 0), item_flash_until.get("CRUS_BC1", 0) > now_ms)
        draw_line(bc1, 2, f"{zulu}Z", (0, 255, 0), item_flash_until.get("CRUS_BC1", 0) > now_ms)

        de1 = merge_cells("D1", "E1")
        zones["CRUS_DE1"] = de1
        de1_selected = bool(crus_state.get("de1_selected", False))
        de1_input = str(crus_state.get("de1_input", ""))
        if de1_selected:
            top_text = "".join(list("_" * (3 - len("".join(ch for ch in de1_input if ch.isdigit())[-3:]))) + list("".join(ch for ch in de1_input if ch.isdigit())[-3:]))
            draw_line(de1, 1, top_text, (255, 255, 255), item_flash_until.get("CRUS_DE1", 0) > now_ms, box_selected=True)
        de1_val = str(nav_state.get("de1_value", "000")).rjust(3, "0")
        try:
            de1_r = int(nav_state.get("de1_r_idx", 1))
        except Exception:
            de1_r = 1
        line2_rect = draw_line(de1, 2, f"{de1_val} R{max(1, de1_r)}", LINE_COLOR, item_flash_until.get("CRUS_DE1", 0) > now_ms)
        tx = de1.left + 8
        up_points = [(tx + 4, line2_rect.centery - 6), (tx, line2_rect.centery - 1), (tx + 8, line2_rect.centery - 1)]
        dn_points = [(tx + 4, line2_rect.centery + 6), (tx, line2_rect.centery + 1), (tx + 8, line2_rect.centery + 1)]
        pygame.draw.polygon(screen, LINE_COLOR, up_points, 0)
        pygame.draw.polygon(screen, LINE_COLOR, dn_points, 0)

        de2 = merge_cells("D2", "E2")
        zones["CRUS_DE2"] = de2
        draw_line(de2, 2, "STPT TOS", LINE_COLOR, item_flash_until.get("CRUS_DE2", 0) > now_ms)
        draw_line(de2, 3, f"{zulu} Z", LINE_COLOR, item_flash_until.get("CRUS_DE2", 0) > now_ms)

        d4 = cell_rect_by_name("D4")
        zones["CRUS_D4"] = d4
        flashing = item_flash_until.get("CRUS_D4", 0) > now_ms
        draw_line(d4, 1, "CLEAR", LINE_COLOR, flashing)
        draw_line(d4, 2, "TOS", LINE_COLOR, flashing)

        de5 = merge_cells("D5", "E5")
        zones["CRUS_DE5"] = de5
        draw_line(de5, 2, "WYPT TOS", (0, 255, 0), item_flash_until.get("CRUS_DE5", 0) > now_ms)
        draw_line(de5, 3, f"{zulu} Z", (0, 255, 0), item_flash_until.get("CRUS_DE5", 0) > now_ms)

        e6 = cell_rect_by_name("E6")
        zones["CRUS_E6"] = e6
        draw_line(e6, 2, "REQ GS", (0, 255, 0), item_flash_until.get("CRUS_E6", 0) > now_ms)
        draw_line(e6, 3, "0", (0, 255, 0), item_flash_until.get("CRUS_E6", 0) > now_ms)

        de7 = merge_cells("D7", "E7")
        zones["CRUS_DE7"] = de7
        rolex_flash = item_flash_until.get("CRUS_DE7", 0) > now_ms
        rolex_selected = bool(crus_state.get("rolex_selected", False))
        rolex_display = crus_rolex_display(rolex_selected)
        seg = int(crus_state.get("rolex_seg", 2))
        # L2 label
        draw_line(de7, 2, "ROLEX", LINE_COLOR, rolex_flash)
        # L1 scratch/value
        font = formats.get_font(14)
        rolex_surf = font.render(rolex_display, True, (0, 0, 0) if rolex_flash else ((255, 255, 255) if rolex_selected else LINE_COLOR))
        rolex_rect = rolex_surf.get_rect(centerx=de7.centerx)
        rolex_rect.y = line_slot_y(de7, 1, font)
        if rolex_flash:
            pygame.draw.rect(screen, (255, 255, 255), rolex_rect.inflate(4, 2))
        elif rolex_selected:
            pygame.draw.rect(screen, (255, 255, 255), rolex_rect.inflate(4, 2), 1)
        screen.blit(rolex_surf, rolex_rect)
        # Segment indicator underline (HH/MM/SS) for A7/A8 jump behavior.
        if rolex_selected and not rolex_flash:
            seg_w = font.size("00")[0]
            start_x = rolex_rect.left
            seg_x = [start_x, start_x + seg_w + font.size(":")[0], start_x + 2 * (seg_w + font.size(":")[0])][max(0, min(2, seg))]
            y = rolex_rect.bottom + 1
            pygame.draw.line(screen, (255, 255, 255), (seg_x, y), (seg_x + seg_w, y), 1)

