    def draw_pmd_dr_cesium_token_cells() -> None:
        info = merge_cells("A1", "E5")
        zones["PMD_CESIUM_INFO"] = info
        screen.fill(BG_COLOR, info)
        pygame.draw.rect(screen, LINE_COLOR, info, 1)
        info_lines = [
            "1. Create an account at:",
            "https://ion.cesium.com/",
            '2. Go to "Access Tokens"',
            '3. Click "Create Token"',
            "4. Copy Token",
            "5. Paste Token in token input box on simulator",
        ]
        font = formats.get_font(14)
        y = info.top + 6
        for line in info_lines:
            surf = font.render(str(line), True, LINE_COLOR)
            rr = surf.get_rect()
            rr.x = info.left + 6
            rr.y = y
            screen.blit(surf, rr)
            y += surf.get_height() + 2

        a6 = cell_rect_by_name("A6")
        zones["PMD_CESIUM_A6_GO"] = a6
        draw_popup_button(
            a6,
            ButtonState(
                button_id="PMD_CESIUM_A6_GO",
                button_type=ButtonType.MOMENTARY_SINGLE,
                text="Go to\nCesium",
                flash_until_ms=item_flash_until.get("PMD_CESIUM_A6_GO", 0),
            ),
        )

        token_box = merge_cells("B6", "D6")
        zones["PMD_CESIUM_TOKEN"] = token_box
        selected = bool(pmd_dr_state.get("cesium_token_selected", False))
        draft = str(pmd_dr_state.get("cesium_token_input", ""))
        committed = str(pmd_dr_state.get("cesium_token_value", "") or "")
        if selected:
            shown = draft
            if shown == "":
                shown = " "
        else:
            shown = "\u2022" * min(max(0, len(committed)), 24)
            if shown == "":
                shown = "----"
        draw_line(token_box, 1, shown, (255, 255, 255), False, box_selected=selected)
        draw_line(token_box, 2, "TOKEN", LINE_COLOR, False)
        draw_line(token_box, 3, "SET" if committed != "" else "NONE", LINE_COLOR, False)

        status_box = merge_cells("A7", "E7")
        zones["PMD_CESIUM_STATUS"] = status_box
        status_text = str(pmd_dr_state.get("cesium_token_status", "")).strip()
        if status_text == "":
            status_text = "Click token box, paste, click again to save"
        draw_line(status_box, 2, _pmd_wrap_text(status_text, 44, 1)[0], (255, 255, 255), False)

    def draw_pmd_dr_cklst_legacy_cells() -> None:
        cklst = _pmd_dr_cklst_legacy_instance()

        def _is_cklst_osb_flashing(label: str) -> bool:
            key = f"PMD_DR_CKLST_OSB_{str(label).upper().strip()}"
            return item_flash_until.get(key, 0) > now_ms

        ctx = FormatContext(
            0,
            lambda *_args: None,
            lambda *_args: None,
            lambda *_args: None,
            is_osb_flashing=_is_cklst_osb_flashing,
        )
        cklst.render(screen, popup_rect, True, ctx)

        for label in ("T2", "T3", "L1", "L2", "L3", "L4", "L5", "L6"):
            box = cklst._osb_box(popup_rect, label)
            if isinstance(box, pygame.Rect):
                zones[f"PMD_DR_CKLST_OSB_{label}"] = box

    def draw_pmd_dr_load_msn_cells() -> None:
        action_cells: Dict[str, Tuple[str, str]] = {
            "PMD_LOAD_MSN_D1_POS": ("D1", "POS\n1"),
            "PMD_LOAD_MSN_D2_NAV": ("D2", "NAV"),
            "PMD_LOAD_MSN_D3_COM": ("D3", "COM"),
            "PMD_LOAD_MSN_D4_SENSOR": ("D4", "SENSOR"),
            "PMD_LOAD_MSN_D5_WPNS": ("D5", "WPNS"),
            "PMD_LOAD_MSN_D6_PLAN_DATA": ("D6", "PLAN\nDATA"),
            "PMD_LOAD_MSN_E2_ELINT": ("E2", "ELINT"),
            "PMD_LOAD_MSN_E6_LOAD_ALL": ("E6", "LOAD\nALL"),
        }
        try:
            active_until = int(pmd_dr_state.get("load_msn_active_until_ms", 0))
        except Exception:
            active_until = 0
        active_key = str(pmd_dr_state.get("load_msn_active_key", "")).strip()
        if active_until <= now_ms:
            active_until = 0
            active_key = ""
            pmd_dr_state["load_msn_active_until_ms"] = 0
            pmd_dr_state["load_msn_active_key"] = ""

        def _draw_center_lines(box: pygame.Rect, lines: List[Tuple[str, Tuple[int, int, int], bool]]) -> None:
            font = formats.get_font(14)
            rendered = [(font.render(text, True, color), underline, color) for text, color, underline in lines]
            total_h = sum(s.get_height() for s, _underline, _color in rendered) + max(0, len(rendered) - 1)
            y = box.centery - (total_h // 2)
            for surf, underline, color in rendered:
                rect_line = surf.get_rect(centerx=box.centerx, y=y)
                screen.blit(surf, rect_line)
                if underline:
                    pygame.draw.line(screen, color, (rect_line.left, rect_line.bottom + 1), (rect_line.right, rect_line.bottom + 1), 1)
                y += surf.get_height() + 1

        a1 = cell_rect_by_name("A1")
        _draw_center_lines(a1, [("LOAD", (0, 255, 0), False), ("MSN", (0, 255, 0), False)])

        b1 = cell_rect_by_name("B1")
        zones["PMD_LOAD_MSN_B1_DELTA"] = b1
        _draw_center_lines(b1, [("MSN", (0, 255, 0), True), ("DELTA", LINE_COLOR, False)])

        c1 = cell_rect_by_name("C1")
        _draw_center_lines(c1, [("PMD", (0, 255, 0), False), ("ON", (0, 255, 0), False)])

        for key, (cell_name, text) in action_cells.items():
            box = cell_rect_by_name(cell_name)
            zones[key] = box
            disabled = bool(active_until > now_ms and active_key != "" and key != active_key)
            color = (128, 128, 128) if disabled else LINE_COLOR
            if key == "PMD_LOAD_MSN_D1_POS":
                label_color = (128, 128, 128) if disabled else (0, 255, 0)
                _draw_center_lines(box, [("POS", label_color, True), ("1", color, False)])
            else:
                _draw_center_lines(box, [(line, color, False) for line in str(text).split("\n")])

        d8 = cell_rect_by_name("D8")
        zones["PMD_LOAD_MSN_D8_BACK"] = d8
        draw_popup_button(
            d8,
            ButtonState(
                button_id="PMD_LOAD_MSN_D8_BACK",
                button_type=ButtonType.PAGE_ACCESS,
                text="<PMD/DR",
                flash_until_ms=item_flash_until.get("PMD_LOAD_MSN_D8_BACK", 0),
            ),
        )
        e8 = cell_rect_by_name("E8")
        zones["PMD_LOAD_MSN_E8_MENU"] = e8
        draw_popup_button(
            e8,
            ButtonState(
                button_id="PMD_LOAD_MSN_E8_MENU",
                button_type=ButtonType.PAGE_ACCESS,
                text="<MENU",
                flash_until_ms=item_flash_until.get("PMD_LOAD_MSN_E8_MENU", 0),
            ),
        )

    def draw_pmd_dr_gps_debug_cells() -> None:
        def _coord_scratch(raw_digits: object, is_lat: bool) -> str:
            raw_text = str(raw_digits or "").strip()
            if any(ch in raw_text for ch in {".", "-", "+", "N", "S", "E", "W", "n", "s", "e", "w"}):
                shown = raw_text[:12]
                return shown + ("_" * max(0, 12 - len(shown)))
            digits = "".join(ch for ch in raw_text if ch.isdigit())
            width = 8 if is_lat else 9
            digits = digits[-width:]
            slots = list("_" * width)
            for idx, ch in enumerate(digits):
                slots[idx] = ch
            if is_lat:
                return f"{slots[0]}{slots[1]} {slots[2]}{slots[3]}.{''.join(slots[4:])}"
            return f"{slots[0]}{slots[1]}{slots[2]} {slots[3]}{slots[4]}.{''.join(slots[5:])}"

        def _aircraft_altitude_ft() -> int:
            panel = _ensure_panel_button_states()
            aircraft = panel.get("AIRCRAFT", {}) if isinstance(panel, dict) else {}
            if not isinstance(aircraft, dict):
                return 0
            try:
                alt = float(aircraft.get("ALTITUDE_FT", 0.0))
            except Exception:
                alt = 0.0
            return int(round(max(0.0, alt)))

        box = merge_cells("A1", "B1")
        zones["PMD_GPSDBG_A1_B1"] = box
        selected = bool(ins_gps_state.get("de1_selected", False))
        line = str(ins_gps_state.get("de1_edit_line", "N")).upper()
        if selected:
            scratch = _coord_scratch(
                ins_gps_state.get("de1_n_input", "") if line == "N" else ins_gps_state.get("de1_w_input", ""),
                line == "N",
            )
            draw_line(box, 1, scratch, (255, 255, 255), False, box_selected=True)
        n_color = (255, 255, 255) if (selected and line == "N") else LINE_COLOR
        w_color = (255, 255, 255) if (selected and line == "W") else LINE_COLOR
        draw_line(box, 2, str(ins_gps_state.get("lon", "N 00 00.0000")), n_color, False)
        draw_line(box, 3, str(ins_gps_state.get("lat", "W 000 00.0000")), w_color, False)

        alt_box = cell_rect_by_name("A2")
        zones["PMD_GPSDBG_A2_ALT"] = alt_box
        alt_selected = bool(ins_gps_state.get("alt_selected", False))
        alt_input = "".join(ch for ch in str(ins_gps_state.get("alt_input", "")) if ch.isdigit())
        alt_scratch = alt_input[-6:].rjust(6, "_") if alt_selected else "______"
        draw_line(alt_box, 1, alt_scratch, (255, 255, 255), False, box_selected=alt_selected)
        draw_line(alt_box, 2, "ALT", LINE_COLOR, False)
        draw_line(alt_box, 3, str(_aircraft_altitude_ft()).rjust(6, "0"), LINE_COLOR, False)

