    def draw_pmd_dr_hotas_bind_cells() -> None:
        def _fit_cell_text(text: str, box: pygame.Rect, font: pygame.font.Font) -> str:
            raw = str(text)
            if raw == "":
                return ""
            max_w = max(8, int(box.width) - 8)
            if font.size(raw)[0] <= max_w:
                return raw
            out = raw
            while len(out) > 0 and font.size(out)[0] > max_w:
                out = out[:-1]
            return out

        def _draw_active_outline(rect: pygame.Rect) -> None:
            inner = rect.inflate(-2, -2)
            if inner.width > 0 and inner.height > 0:
                pygame.draw.rect(screen, (255, 0, 0), inner, 2)

        action = str(pmd_dr_state.get("hotas_edit_action", "")).strip().lower()
        if action not in HOTAS_ACTION_ORDER:
            action = "pitch"
            pmd_dr_state["hotas_edit_action"] = action
        title = str(HOTAS_ACTION_TITLES.get(action, action.upper()))
        title_box = merge_cells("A1", "E3")
        zones["PMD_HOTAS_BIND_TITLE"] = title_box
        wrapped = _pmd_wrap_text(title, 22, 3)
        for idx, line in enumerate(wrapped[:3]):
            draw_line(title_box, idx + 1, line, (0, 255, 0), False)
        if action == "mngmt":
            try:
                mngmt_pos = max(0, min(15, int(pmd_dr_state.get("hotas_mngmt_rotary_pos", 0))))
            except Exception:
                mngmt_pos = 0
            draw_line(title_box, 2, f"POS {mngmt_pos + 1:02d}/16", (255, 255, 255), False)

        dev_box = merge_cells("A4", "B4")
        zones["PMD_HOTAS_BIND_DEVICE"] = dev_box
        devices_raw = pmd_dr_state.get("hotas_devices", [])
        devices = devices_raw if isinstance(devices_raw, list) else []
        try:
            dev_idx = int(pmd_dr_state.get("hotas_edit_device", -1))
        except Exception:
            dev_idx = -1
        dev_name = "NONE"
        if dev_idx >= 0:
            for dev in devices:
                if not isinstance(dev, dict):
                    continue
                try:
                    if int(dev.get("index", -1)) == dev_idx:
                        dev_name = str(dev.get("name", "UNKNOWN"))
                        break
                except Exception:
                    continue
        draw_line(dev_box, 1, f"DEV {dev_idx + 1}" if dev_idx >= 0 else "DEV --", (255, 255, 255), False)
        draw_line(dev_box, 2, "DEVICE", LINE_COLOR, False)
        draw_line(dev_box, 3, _pmd_wrap_text(dev_name, 8, 1)[0], LINE_COLOR, False)

        input_box = merge_cells("C4", "D4")
        zones["PMD_HOTAS_BIND_INPUT"] = input_box
        capture_selected = bool(pmd_dr_state.get("hotas_edit_capture_selected", False))
        current_binding = _popup_hotas_get_binding(action)
        current_label = _popup_hotas_binding_label(current_binding)
        binding_missing = isinstance(current_binding, dict) and (not _popup_hotas_binding_is_connected(current_binding))
        input_label = str(pmd_dr_state.get("hotas_edit_input_text", "")).strip()
        shown = input_label if input_label != "" else current_label
        shown = _fit_cell_text(shown, input_box, formats.get_font(14))
        down_raw = pmd_dr_state.get("hotas_action_down_raw", {})
        down_map = down_raw if isinstance(down_raw, dict) else {}
        input_active = bool((not binding_missing) and down_map.get(action, False))
        draw_line(input_box, 1, shown, (255, 0, 0) if binding_missing else (255, 255, 255), False, box_selected=False)
        draw_line(input_box, 2, "INPUT", LINE_COLOR, False)
        if binding_missing and (not capture_selected):
            draw_line(input_box, 3, "MISSING", (255, 0, 0), False)
        else:
            draw_line(input_box, 3, "ARMED" if capture_selected else "SELECT", LINE_COLOR, False)
        if capture_selected or input_active:
            _draw_active_outline(input_box)

        e4 = cell_rect_by_name("E4")
        zones["PMD_HOTAS_BIND_INVERT"] = e4
        allowed_types = set(_popup_hotas_allowed_types(action))
        allow_axis = "axis" in allowed_types
        invert_on = bool(current_binding.get("invert", False)) if isinstance(current_binding, dict) else False
        draw_popup_button(
            e4,
            ButtonState(
                button_id="PMD_HOTAS_BIND_INVERT",
                button_type=ButtonType.MOMENTARY_SINGLE if allow_axis else ButtonType.STATUS_LABEL,
                text="INVERT" if allow_axis else "N/A",
                is_single_function=allow_axis,
                is_on=invert_on if allow_axis else False,
                flash_until_ms=item_flash_until.get("PMD_HOTAS_BIND_INVERT", 0),
            ),
        )

        allow_btn_hat = bool(("button" in allowed_types) or ("hat" in allowed_types))
        if allow_btn_hat:
            a5 = cell_rect_by_name("A5")
            zones["PMD_HOTAS_BIND_A5_EXCLUDE"] = a5
            excluded_set = _popup_hotas_excluded_inputs_set()
            current_sig = _popup_hotas_binding_exclude_signature(current_binding)
            excluded_on = bool(current_sig != "" and current_sig in excluded_set)
            draw_popup_button(
                a5,
                ButtonState(
                    button_id="PMD_HOTAS_BIND_A5_EXCLUDE",
                    button_type=ButtonType.MOMENTARY_SINGLE,
                    text="EXCLUDE",
                    is_single_function=True,
                    is_on=excluded_on,
                    flash_until_ms=item_flash_until.get("PMD_HOTAS_BIND_A5_EXCLUDE", 0),
                ),
            )

        slew_speed_actions = {"slew_lr", "slew_ud", "slew_up", "slew_down", "slew_left", "slew_right"}
        pan_speed_actions = {"pan_lr", "pan_ud", "pan_up", "pan_down", "pan_left", "pan_right"}
        speed_prefix = ""
        speed_value = 1.0
        if action in slew_speed_actions:
            speed_prefix = "SLEW"
            try:
                speed_value = float(pmd_dr_state.get("hotas_slew_speed", 1.0))
            except Exception:
                speed_value = 1.0
        elif action in pan_speed_actions:
            speed_prefix = "PAN"
            try:
                speed_value = float(pmd_dr_state.get("hotas_pan_speed", 1.0))
            except Exception:
                speed_value = 1.0
        if speed_prefix != "":
            speed_value = max(0.0, min(1.0, speed_value))
            speed_box = merge_cells("B5", "C5")
            zones[f"PMD_HOTAS_BIND_{speed_prefix}_SPEED"] = speed_box
            draw_line(speed_box, 1, "SPEED", LINE_COLOR, False)
            slider_w = int(1.5 * DPI)
            slider_h = int((1.0 / 3.0) * DPI)
            slider_rect = pygame.Rect(0, 0, max(12, slider_w), max(6, slider_h))
            slider_rect.centerx = speed_box.centerx
            slider_rect.centery = int(line_slot_y(speed_box, 2, formats.get_font(14)) + formats.get_font(14).get_height() + 2)
            zones[f"PMD_HOTAS_BIND_{speed_prefix}_SPEED_SLIDER"] = slider_rect
            pygame.draw.rect(screen, LINE_COLOR, slider_rect, 1)
            marker_x = slider_rect.left + 1 + int(round(speed_value * max(1, slider_rect.width - 2)))
            marker_x = max(slider_rect.left + 1, min(slider_rect.right - 2, marker_x))
            pygame.draw.line(
                screen,
                (255, 255, 255),
                (marker_x, slider_rect.top + 2),
                (marker_x, slider_rect.bottom - 3),
                2,
            )
            draw_line(speed_box, 3, f"{speed_value:.2f}", (255, 255, 255), False)

        if action == "engine_run":
            mode_now = str(pmd_dr_state.get("hotas_engine_run_mode", "MOMENTARY")).upper()
            if mode_now not in {"MOMENTARY", "TOGGLE"}:
                mode_now = "MOMENTARY"
            e5 = cell_rect_by_name("E5")
            zones["PMD_HOTAS_BIND_E5_ENGINE_MODE"] = e5
            draw_popup_button(
                e5,
                ButtonState(
                    button_id="PMD_HOTAS_BIND_E5_ENGINE_MODE",
                    button_type=ButtonType.MOMENTARY_SINGLE,
                    text="MODE\nMOMENT" if mode_now == "MOMENTARY" else "MODE\nTOGGLE",
                    flash_until_ms=item_flash_until.get("PMD_HOTAS_BIND_E5_ENGINE_MODE", 0),
                ),
            )
            e6 = cell_rect_by_name("E6")
            zones["PMD_HOTAS_BIND_E6_ENGINE_INVERT"] = e6
            inv_on = bool(pmd_dr_state.get("hotas_engine_run_invert", False))
            draw_popup_button(
                e6,
                ButtonState(
                    button_id="PMD_HOTAS_BIND_E6_ENGINE_INVERT",
                    button_type=ButtonType.MOMENTARY_SINGLE,
                    text="INVERT\nON" if inv_on else "INVERT\nOFF",
                    is_single_function=True,
                    is_on=inv_on,
                    flash_until_ms=item_flash_until.get("PMD_HOTAS_BIND_E6_ENGINE_INVERT", 0),
                ),
            )
        elif action == "ldg_gear":
            gear_mode = str(pmd_dr_state.get("hotas_ldg_gear_mode", "TOGGLE")).upper()
            if gear_mode not in {"MOMENTARY", "TOGGLE"}:
                gear_mode = "TOGGLE"
            e5 = cell_rect_by_name("E5")
            zones["PMD_HOTAS_BIND_E5_LDG_GEAR_MODE"] = e5
            draw_popup_button(
                e5,
                ButtonState(
                    button_id="PMD_HOTAS_BIND_E5_LDG_GEAR_MODE",
                    button_type=ButtonType.MOMENTARY_SINGLE,
                    text="MODE\nMOMENT" if gear_mode == "MOMENTARY" else "MODE\nTOGGLE",
                    flash_until_ms=item_flash_until.get("PMD_HOTAS_BIND_E5_LDG_GEAR_MODE", 0),
                ),
            )
        elif action == "brake":
            brake_mode = str(pmd_dr_state.get("hotas_brake_mode", "TOGGLE")).upper()
            if brake_mode not in {"MOMENTARY", "TOGGLE"}:
                brake_mode = "TOGGLE"
            e5 = cell_rect_by_name("E5")
            zones["PMD_HOTAS_BIND_E5_BRAKE_MODE"] = e5
            draw_popup_button(
                e5,
                ButtonState(
                    button_id="PMD_HOTAS_BIND_E5_BRAKE_MODE",
                    button_type=ButtonType.MOMENTARY_SINGLE,
                    text="MODE\nMOMENT" if brake_mode == "MOMENTARY" else "MODE\nTOGGLE",
                    flash_until_ms=item_flash_until.get("PMD_HOTAS_BIND_E5_BRAKE_MODE", 0),
                ),
            )

        e8 = cell_rect_by_name("E8")
        zones["PMD_HOTAS_BIND_E8_BACK"] = e8
        draw_popup_button(
            e8,
            ButtonState(
                button_id="PMD_HOTAS_BIND_E8_BACK",
                button_type=ButtonType.PAGE_ACCESS,
                text="<BACK",
                flash_until_ms=item_flash_until.get("PMD_HOTAS_BIND_E8_BACK", 0),
            ),
        )

    def _pmd_active_list_cache() -> List[Dict[str, object]]:
        raw = pmd_dr_state.get("pmd_active_list", [])
        if not isinstance(raw, list):
            return []
        out: List[Dict[str, object]] = []
        for item in raw:
            if isinstance(item, dict):
                out.append(item)
        return out

