    def draw_pmd_dr_term_cells() -> None:
        copy_box = cell_rect_by_name("E1")
        zones["PMD_TERM_COPY"] = copy_box
        draw_popup_button(
            copy_box,
            ButtonState(
                button_id="PMD_TERM_COPY",
                button_type=ButtonType.MOMENTARY_SINGLE,
                text="COPY",
                flash_until_ms=item_flash_until.get("PMD_TERM_COPY", 0),
            ),
        )

        input_box = merge_cells("A8", "D8")
        zones["PMD_TERM_INPUT"] = input_box
        input_flash = item_flash_until.get("PMD_TERM_INPUT", 0) > now_ms
        draw_line(input_box, 1, "INPUT PYTHON STRINGCODE", LINE_COLOR, input_flash)

        term_selected = bool(pmd_dr_state.get("term_input_selected", False))
        term_text = str(pmd_dr_state.get("term_input", ""))
        shown = term_text + ("_" if term_selected else "")
        value_font = formats.get_font(14)
        max_w = max(8, input_box.width - 12)
        while len(shown) > 0 and value_font.size(shown)[0] > max_w:
            shown = shown[1:]
        value_surf = value_font.render(shown, True, (0, 0, 0) if input_flash else (255, 255, 255))
        value_rect = value_surf.get_rect()
        value_rect.left = input_box.left + 6
        value_rect.y = line_slot_y(input_box, 3, value_font)
        if input_flash:
            pygame.draw.rect(screen, (255, 255, 255), value_rect.inflate(4, 2))
        elif term_selected:
            pygame.draw.rect(screen, (255, 255, 255), value_rect.inflate(4, 2), 1)
        screen.blit(value_surf, value_rect)

        e8 = cell_rect_by_name("E8")
        zones["BACK"] = e8
        draw_popup_button(
            e8,
            ButtonState(
                button_id="BACK",
                button_type=ButtonType.PAGE_ACCESS,
                text="<DEBUG",
                flash_until_ms=item_flash_until.get("BACK", 0),
            ),
        )
        log_area = pygame.Rect(
            popup_rect.left + 6,
            popup_rect.top + 6,
            popup_rect.width - 12,
            max(0, e8.top - popup_rect.top - 10),
        )
        if log_area.height <= 0 or log_area.width <= 0:
            return
        font = formats.get_font(14)
        line_h = max(1, font.get_height() + 1)
        max_lines = max(1, log_area.height // line_h)
        max_chars = max(1, int(log_area.width / max(1, font.size("M")[0])))
        pmd_dr_state["term_log_max_lines"] = int(max_lines)
        pmd_dr_state["term_log_max_chars"] = int(max_chars)
        zones["PMD_TERM_LOG"] = log_area.copy()
        wrapped = _term_wrapped_snapshot(pmd_dr_state, max_chars)
        try:
            scroll_lines = int(pmd_dr_state.get("term_scroll_lines", 0))
        except Exception:
            scroll_lines = 0
        max_scroll = max(0, len(wrapped) - max_lines)
        scroll_lines = max(0, min(max_scroll, scroll_lines))
        pmd_dr_state["term_scroll_lines"] = scroll_lines
        end_idx = max(0, len(wrapped) - scroll_lines)
        start_idx = max(0, end_idx - max_lines)
        visible_lines = wrapped[start_idx:end_idx]
        y = log_area.top
        for line_text, line_style in visible_lines:
            if y + line_h > log_area.bottom:
                break
            surf = font.render(str(line_text), True, _term_line_color(line_style))
            screen.blit(surf, (log_area.left, y))
            y += line_h

