        active_icaws = _active_icaw_names()
        hyd_fail_a_active = "HYD FAIL A" in active_icaws
        hyd_fail_b_active = "HYD FAIL B" in active_icaws
        hyd_fail_dual_active = "HYD FAIL DUAL" in active_icaws

        for zone_key, cell_name, label, vmin, vmax, default, is_float in specs:
            box = cell_rect_by_name(cell_name)
