    def _status_popup_group_portals(swapped: bool) -> Dict[str, int]:
        if not bool(swapped):
            return {"A": 0, "B": 1, "C": 2, "D": 3}
        # Flipped mapping:
        # A (ENG/FUEL/SMS/FCS) -> Portal 3
        # B (ICAWS/AP)         -> Portal 4
        # C (COMM/NAV)         -> Portal 1
        # D (IFF/ALT/WIND)     -> Portal 2
        return {"A": 2, "B": 3, "C": 0, "D": 1}

