    def start_recording_session(capture_rect: Optional[pygame.Rect] = None, source: str = "status") -> None:
        nonlocal recording_writer, recording_current_path, record_session_start_ms, record_active, record_started, recording_worker_thread
        nonlocal recording_audio_start_monotonic_ms, recording_audio_mix
        nonlocal record_capture_rect, record_capture_source
        nonlocal record_screen_dbg_area, record_screen_dbg_portal_idx, record_screen_dbg_pair_expanded_ever
        record_capture_source = str(source or "status")
        record_screen_dbg_area = ""
        record_screen_dbg_portal_idx = None
        record_screen_dbg_pair_expanded_ever = False
        if record_capture_source == "screen_debug":
            try:
                opts = _screen_dbg_area_options()
                idx = _screen_dbg_area_idx()
                area = str(opts[idx]).upper()
                record_screen_dbg_area = area
                if area in {"P1", "P2", "P3", "P4"}:
                    portal_idx = max(0, min(3, int(area[1]) - 1))
                    record_screen_dbg_portal_idx = portal_idx
                    pair_idx = portal_idx // 2
                    record_screen_dbg_pair_expanded_ever = bool(pair_owner[pair_idx] is not None)
            except Exception:
                record_screen_dbg_area = ""
                record_screen_dbg_portal_idx = None
                record_screen_dbg_pair_expanded_ever = False
        if isinstance(capture_rect, pygame.Rect):
            clipped = capture_rect.clip(pygame.Rect(0, 0, WINDOW_WIDTH, WINDOW_HEIGHT))
            if clipped.width > 0 and clipped.height > 0:
                record_capture_rect = clipped
            else:
                record_capture_rect = pygame.Rect(0, 0, WINDOW_WIDTH, WINDOW_HEIGHT)
        else:
            record_capture_rect = pygame.Rect(0, 0, WINDOW_WIDTH, WINDOW_HEIGHT)
        frame_w = int(max(1, record_capture_rect.width))
        frame_h = int(max(1, record_capture_rect.height))
        record_started = True
        record_active = True
        record_session_start_ms = pygame.time.get_ticks()
        with recording_audio_lock:
            recording_audio_start_monotonic_ms = int(time.monotonic() * 1000)
            recording_audio_mix = np.zeros(0, dtype=np.int32) if np is not None else None
        if not RECORDING_SUPPORTED:
            recording_writer = None
            recording_current_path = None
            return
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        recording_current_path = recordings_dir / f"Recording_{ts}.mp4"
        try:
            recording_writer = imageio.get_writer(str(recording_current_path), fps=30)
            # Drain stale frames from any previous session.
            while True:
                try:
                    recording_queue.get_nowait()
                except Empty:
                    break
            recording_stop_event.clear()

            def recording_worker(writer, rec_w: int, rec_h: int) -> None:
                while not recording_stop_event.is_set() or not recording_queue.empty():
                    try:
                        raw_frame = recording_queue.get(timeout=0.1)
                    except Empty:
                        continue
                    try:
                        if RECORDING_SUPPORTED and np is not None:
                            frame_np = np.frombuffer(raw_frame, dtype=np.uint8).reshape((int(rec_h), int(rec_w), 3))
                            writer.append_data(frame_np)
                    except Exception:
                        continue

            recording_worker_thread = threading.Thread(target=recording_worker, args=(recording_writer, frame_w, frame_h), daemon=True)
            recording_worker_thread.start()
        except Exception:
            recording_writer = None
            recording_current_path = None

    def _recording_audio_add_chunk(raw: bytes, sample_rate: int, channels: int = 1) -> None:
        nonlocal recording_audio_start_monotonic_ms, recording_audio_mix
        if not record_active or np is None:
            return
        if not raw:
            return
        sr = int(sample_rate) if sample_rate else recording_audio_sample_rate
        if sr <= 0:
            return
        ch = max(1, int(channels) if channels else 1)
        try:
            sample_count = len(raw) // 2
            if sample_count <= 0:
                return
            pcm = np.frombuffer(raw[: sample_count * 2], dtype=np.int16)
            if ch > 1:
                frame_count = len(pcm) // ch
                if frame_count <= 0:
                    return
                pcm = pcm[: frame_count * ch].reshape((-1, ch)).astype(np.int32).mean(axis=1).astype(np.int16)
            if sr != recording_audio_sample_rate:
                if len(pcm) <= 1:
                    return
                src_x = np.arange(len(pcm), dtype=np.float32)
                dst_len = max(1, int(round(len(pcm) * (recording_audio_sample_rate / float(sr)))))
                dst_x = np.linspace(0, len(pcm) - 1, dst_len, dtype=np.float32)
                pcm = np.interp(dst_x, src_x, pcm.astype(np.float32)).astype(np.int16)
            now_ms = int(time.monotonic() * 1000)
            with recording_audio_lock:
                if recording_audio_start_monotonic_ms is None:
                    recording_audio_start_monotonic_ms = now_ms
                if recording_audio_mix is None:
                    recording_audio_mix = np.zeros(0, dtype=np.int32)
                start_ms = recording_audio_start_monotonic_ms
                start_sample = max(0, int((now_ms - start_ms) * recording_audio_sample_rate / 1000))
                end_sample = start_sample + len(pcm)
                current_len = len(recording_audio_mix)
                if end_sample > current_len:
                    recording_audio_mix = np.pad(recording_audio_mix, (0, end_sample - current_len), mode="constant")
                recording_audio_mix[start_sample:end_sample] += pcm.astype(np.int32)
        except Exception:
            pass

    def _recording_finalize_mux(video_path: Path) -> None:
        if np is None:
            return
        with recording_audio_lock:
            mix = recording_audio_mix
        if mix is None or len(mix) == 0:
            return
        ffmpeg_path = shutil.which("ffmpeg")
        if not ffmpeg_path:
            try:
                import imageio_ffmpeg  # type: ignore
                ffmpeg_path = imageio_ffmpeg.get_ffmpeg_exe()
            except Exception:
                ffmpeg_path = None
        if not ffmpeg_path:
            local_candidates = [
                Path(os.environ.get("LOCALAPPDATA", "")) / "Programs" / "Python" / "Python311" / "Scripts" / "ffmpeg.exe",
                Path("C:/ffmpeg/bin/ffmpeg.exe"),
            ]
            for cand in local_candidates:
                try:
                    if cand.exists():
                        ffmpeg_path = str(cand)
                        break
                except Exception:
                    continue
        if not ffmpeg_path:
            print("Recording mux skipped: ffmpeg not found")
            return
        clipped = np.clip(mix, -32768, 32767).astype(np.int16)
        audio_path = video_path.with_suffix(".audio.wav")
        mux_path = video_path.with_name(f"{video_path.stem}_mux.mp4")
        try:
            with wave.open(str(audio_path), "wb") as wf:
                wf.setnchannels(1)
                wf.setsampwidth(2)
                wf.setframerate(recording_audio_sample_rate)
                wf.writeframes(clipped.tobytes())
        except Exception:
            return
        try:
            cmd = [
                ffmpeg_path,
                "-y",
                "-i",
                str(video_path),
                "-i",
                str(audio_path),
                "-map",
                "0:v:0",
                "-map",
                "1:a:0",
                "-c:v",
                "copy",
                "-c:a",
                "aac",
                "-movflags",
                "+faststart",
                "-shortest",
                str(mux_path),
            ]
            proc = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, check=False)
            if proc.returncode != 0 or not mux_path.exists():
                cmd_fallback = [
                    ffmpeg_path,
                    "-y",
                    "-i",
                    str(video_path),
                    "-i",
                    str(audio_path),
                    "-map",
                    "0:v:0",
                    "-map",
                    "1:a:0",
                    "-c:v",
                    "libx264",
                    "-preset",
                    "veryfast",
                    "-crf",
                    "18",
                    "-c:a",
                    "aac",
                    "-movflags",
                    "+faststart",
                    "-shortest",
                    str(mux_path),
                ]
                proc = subprocess.run(cmd_fallback, stdout=subprocess.PIPE, stderr=subprocess.PIPE, check=False)
            if proc.returncode == 0 and mux_path.exists():
                try:
                    video_path.unlink(missing_ok=True)
                except Exception:
                    pass
                os.replace(mux_path, video_path)
            else:
                print("Recording mux failed; leaving silent video")
        except Exception:
            pass
        finally:
            try:
                audio_path.unlink(missing_ok=True)
            except Exception:
                pass
            try:
                mux_path.unlink(missing_ok=True)
            except Exception:
                pass

    def _recording_finalize_screen_debug_p_crop(video_path: Path, portal_idx: int) -> None:
        ffmpeg_path = shutil.which("ffmpeg")
        if not ffmpeg_path:
            try:
                import imageio_ffmpeg  # type: ignore
                ffmpeg_path = imageio_ffmpeg.get_ffmpeg_exe()
            except Exception:
                ffmpeg_path = None
        if not ffmpeg_path:
            local_candidates = [
                Path(os.environ.get("LOCALAPPDATA", "")) / "Programs" / "Python" / "Python311" / "Scripts" / "ffmpeg.exe",
                Path("C:/ffmpeg/bin/ffmpeg.exe"),
            ]
            for cand in local_candidates:
                try:
                    if cand.exists():
                        ffmpeg_path = str(cand)
                        break
                except Exception:
                    continue

        x_expr = "0" if (int(portal_idx) % 2 == 0) else "iw/2"
        crop_path = video_path.with_name(f"{video_path.stem}_crop.mp4")
        ffmpeg_succeeded = False

        if ffmpeg_path:
            try:
                cmd = [
                    ffmpeg_path,
                    "-y",
                    "-i",
                    str(video_path),
                    "-map",
                    "0:v:0",
                    "-map",
                    "0:a:0",
                    "-vf",
                    f"crop=iw/2:ih:{x_expr}:0",
                    "-c:v",
                    "libx264",
                    "-preset",
                    "veryfast",
                    "-crf",
                    "18",
                    "-c:a",
                    "copy",
                    "-movflags",
                    "+faststart",
                    str(crop_path),
                ]
                proc = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, check=False)
                if proc.returncode != 0 or not crop_path.exists():
                    cmd_no_audio = [
                        ffmpeg_path,
                        "-y",
                        "-i",
                        str(video_path),
                        "-map",
                        "0:v:0",
                        "-vf",
                        f"crop=iw/2:ih:{x_expr}:0",
                        "-c:v",
                        "libx264",
                        "-preset",
                        "veryfast",
                        "-crf",
                        "18",
                        "-movflags",
                        "+faststart",
                        str(crop_path),
                    ]
                    proc = subprocess.run(cmd_no_audio, stdout=subprocess.PIPE, stderr=subprocess.PIPE, check=False)
                if proc.returncode == 0 and crop_path.exists():
                    try:
                        video_path.unlink(missing_ok=True)
                    except Exception:
                        pass
                    os.replace(crop_path, video_path)
                    ffmpeg_succeeded = True
                else:
                    try:
                        err_tail = proc.stderr.decode("utf-8", errors="ignore").strip().splitlines()
                        if err_tail:
                            print(f"Recording crop ffmpeg failed: {err_tail[-1]}")
                        else:
                            print("Recording crop ffmpeg failed")
                    except Exception:
                        print("Recording crop ffmpeg failed")
            except Exception:
                pass
            finally:
                try:
                    crop_path.unlink(missing_ok=True)
                except Exception:
                    pass
        else:
            print("Recording crop ffmpeg unavailable; using fallback")

        if ffmpeg_succeeded:
            return

        # Fallback path without ffmpeg: re-encode cropped video frames (no audio).
        fallback_path = video_path.with_name(f"{video_path.stem}_crop_fallback.mp4")
        try:
            if imageio is None or np is None:
                print("Recording crop fallback unavailable; leaving uncropped video")
                return
            reader = imageio.get_reader(str(video_path))
            meta = {}
            try:
                meta = reader.get_meta_data()
            except Exception:
                pass
            fps = float(meta.get("fps", 30.0)) if isinstance(meta, dict) else 30.0
            writer = imageio.get_writer(str(fallback_path), fps=max(1.0, fps))
            try:
                for frame in reader:
                    if frame is None:
                        continue
                    h = int(frame.shape[0]) if hasattr(frame, "shape") else 0
                    w = int(frame.shape[1]) if hasattr(frame, "shape") else 0
                    if h <= 0 or w <= 1:
                        continue
                    half = max(1, w // 2)
                    if int(portal_idx) % 2 == 0:
                        cropped = frame[:, :half, :]
                    else:
                        cropped = frame[:, (w - half):, :]
                    writer.append_data(cropped)
            finally:
                try:
                    writer.close()
                except Exception:
                    pass
                try:
                    reader.close()
                except Exception:
                    pass
            if fallback_path.exists():
                try:
                    video_path.unlink(missing_ok=True)
                except Exception:
                    pass
                os.replace(fallback_path, video_path)
            else:
                print("Recording crop fallback failed; leaving uncropped video")
        except Exception:
            print("Recording crop fallback failed; leaving uncropped video")
        finally:
            try:
                fallback_path.unlink(missing_ok=True)
            except Exception:
                pass

    set_record_audio_sink(_recording_audio_add_chunk)

    def stop_recording_session() -> None:
        nonlocal recording_writer, recording_current_path, record_active, record_session_start_ms, record_accumulated_seconds, recording_worker_thread
        nonlocal recording_audio_start_monotonic_ms, recording_audio_mix
        nonlocal record_capture_source
        nonlocal record_screen_dbg_area, record_screen_dbg_portal_idx, record_screen_dbg_pair_expanded_ever
        post_crop_portal_idx: Optional[int] = None
        if (
            record_capture_source == "screen_debug"
            and record_screen_dbg_area in {"P1", "P2", "P3", "P4"}
            and record_screen_dbg_portal_idx is not None
            and not bool(record_screen_dbg_pair_expanded_ever)
        ):
            post_crop_portal_idx = int(record_screen_dbg_portal_idx)
        if record_session_start_ms is not None:
            elapsed = max(0.0, (pygame.time.get_ticks() - record_session_start_ms) / 1000.0)
            record_accumulated_seconds += elapsed
        record_session_start_ms = None
        record_active = False
        record_capture_source = "status"
        if recording_writer is not None:
            try:
                recording_stop_event.set()
                if recording_worker_thread is not None:
                    recording_worker_thread.join(timeout=2.0)
                recording_writer.close()
                if recording_current_path is not None and recording_current_path.exists():
                    _recording_finalize_mux(recording_current_path)
                if (
                    post_crop_portal_idx is not None
                    and recording_current_path is not None
                    and recording_current_path.exists()
                ):
                    _recording_finalize_screen_debug_p_crop(recording_current_path, post_crop_portal_idx)
                if recording_current_path is not None and recording_current_path.exists():
                    with frame_state.recording_lock:
                        frame_state.pending_recording_path = str(recording_current_path)
            except Exception:
                pass
            finally:
                recording_writer = None
                recording_current_path = None
                recording_worker_thread = None
        with recording_audio_lock:
            recording_audio_start_monotonic_ms = None
            recording_audio_mix = np.zeros(0, dtype=np.int32) if np is not None else None
        record_screen_dbg_area = ""
        record_screen_dbg_portal_idx = None
        record_screen_dbg_pair_expanded_ever = False

    def get_status_fuel_values() -> Tuple[float, float, float]:
        # Prefer live values from any active FUEL format instance.
        for pf in portal_formats:
            candidates = [pf.primary, pf.subs[0], pf.subs[1]]
            for fmt in candidates:
                if fmt is None:
                    continue
                if getattr(fmt, "name", "").upper() != "FUEL":
                    continue
                qty = getattr(fmt, "fuel_qty", None)
                if isinstance(qty, dict):
                    total = sum(float(v) for v in qty.values())
                    return (total / 1000.0, total / 1000.0, 0.0)
        # Fallback: shared FUEL state so status bar remains correct even when
        # no FUEL format instance is currently mounted/rendered.
        try:
            shared_qty = getattr(formats.FuelFormat, "_shared_fuel_qty", None)
            if isinstance(shared_qty, dict) and len(shared_qty) > 0:
                total = sum(max(0.0, float(v)) for v in shared_qty.values())
                return (total / 1000.0, total / 1000.0, 0.0)
        except Exception:
            pass
        try:
            total = max(0.0, float(getattr(formats.FuelFormat, "_shared_total_lbs", 0.0)))
            return (total / 1000.0, total / 1000.0, 0.0)
        except Exception:
            return (0.0, 0.0, 0.0)

    def sync_shared_fuel_total() -> None:
        total = 0.0
        found = False
        for pf in portal_formats:
            candidates = [pf.primary, pf.subs[0], pf.subs[1]]
            for fmt in candidates:
                if fmt is None or getattr(fmt, "name", "").upper() != "FUEL":
                    continue
                qty = getattr(fmt, "fuel_qty", None)
                if isinstance(qty, dict):
                    try:
                        total = float(sum(float(v) for v in qty.values()))
                        found = True
                        break
                    except Exception:
                        pass
            if found:
                break
        if not found:
            try:
                shared_qty = getattr(formats.FuelFormat, "_shared_fuel_qty", None)
                if isinstance(shared_qty, dict) and len(shared_qty) > 0:
                    total = float(sum(max(0.0, float(v)) for v in shared_qty.values()))
                    found = True
            except Exception:
                pass
        if not found:
            try:
                total = max(0.0, float(getattr(formats.FuelFormat, "_shared_total_lbs", 0.0)))
            except Exception:
                total = 0.0
        try:
            formats.FuelFormat._shared_total_lbs = max(0.0, float(total))
        except Exception:
            pass

    def get_status_fuel_snapshot() -> Dict[str, object]:
        # Grouped bars: F1, F2(L/R), F3(L/R), F4(L/R), F5(L/R), LW/RW.
        defaults_qty = {
            "F1": 0.0, "F1I": 0.0, "F2L": 0.0, "F2R": 0.0, "F3L": 0.0, "F3R": 0.0,
            "F4L": 0.0, "F4R": 0.0, "F5L": 0.0, "F5R": 0.0, "LW": 0.0, "RW": 0.0,
        }
        defaults_max = {
            "F1": 5100.0, "F1I": 1300.0, "F2L": 1150.0, "F2R": 1150.0, "F3L": 2150.0, "F3R": 2150.0,
            "F4L": 1100.0, "F4R": 1100.0, "F5L": 1000.0, "F5R": 1000.0, "LW": 1150.0, "RW": 1150.0,
        }
        qty = defaults_qty
        mx = defaults_max
        joker = 0.0
        bingo = 0.0
        found_fuel_fmt = False
        for pf in portal_formats:
            candidates = [pf.primary, pf.subs[0], pf.subs[1]]
            for fmt in candidates:
                if fmt is None or getattr(fmt, "name", "").upper() != "FUEL":
                    continue
                fq = getattr(fmt, "fuel_qty", None)
                fm = getattr(fmt, "fuel_max", None)
                if isinstance(fq, dict):
                    qty = {**defaults_qty, **{k: float(v) for k, v in fq.items() if k in defaults_qty}}
                if isinstance(fm, dict):
                    mx = {**defaults_max, **{k: float(v) for k, v in fm.items() if k in defaults_max}}
                try:
                    data_vals = getattr(fmt, "_data_values", None)
                    if isinstance(data_vals, dict):
                        joker = float(data_vals.get("R2", joker))
                        bingo = float(data_vals.get("R3", bingo))
                except Exception:
                    pass
                found_fuel_fmt = True
                break
            if found_fuel_fmt:
                break

        if not found_fuel_fmt:
            # Fallback to shared FUEL class state when no FUEL page is mounted.
            try:
                shared_qty = getattr(formats.FuelFormat, "_shared_fuel_qty", None)
                if isinstance(shared_qty, dict):
                    qty = {**defaults_qty, **{k: float(v) for k, v in shared_qty.items() if k in defaults_qty}}
            except Exception:
                pass
            try:
                shared_max = getattr(formats.FuelFormat, "_shared_fuel_max", None)
                if isinstance(shared_max, dict):
                    mx = {**defaults_max, **{k: float(v) for k, v in shared_max.items() if k in defaults_max}}
            except Exception:
                pass
            try:
                shared_vals = getattr(formats.FuelFormat, "_shared_data_values", None)
                if isinstance(shared_vals, dict):
                    joker = float(shared_vals.get("R2", joker))
                    bingo = float(shared_vals.get("R3", bingo))
            except Exception:
                pass

        groups = [
            {"id": "F1", "qty": qty["F1"] + qty["F1I"], "max": mx["F1"] + mx["F1I"]},
            {"id": "F2", "qty": qty["F2L"] + qty["F2R"], "max": mx["F2L"] + mx["F2R"]},
            {"id": "F3", "qty": qty["F3L"] + qty["F3R"], "max": mx["F3L"] + mx["F3R"]},
            {"id": "F4", "qty": qty["F4L"] + qty["F4R"], "max": mx["F4L"] + mx["F4R"]},
            {"id": "F5", "qty": qty["F5L"] + qty["F5R"], "max": mx["F5L"] + mx["F5R"]},
            {"id": "W", "qty": qty["LW"] + qty["RW"], "max": mx["LW"] + mx["RW"]},
        ]
        total = sum(g["qty"] for g in groups)
        max_total = max(1.0, sum(g["max"] for g in groups))
        return {
            "groups": groups,
            "total": total / 1000.0,
            "internal": total / 1000.0,
            "external": 0.0,
            "max_total": max_total / 1000.0,
            "joker": joker,
            "bingo": bingo,
        }

    def get_status_engine_thrust() -> float:
        # Prefer shared ENG runtime values so status stays correct even when
        # ENG is not currently mounted in any portal/subportal slot.
        try:
            shared = getattr(formats.EngineFormat, "_shared_gauge_values", {})
            if isinstance(shared, dict) and "THRUST" in shared:
                return float(shared.get("THRUST", 0.0))
        except Exception:
            pass
        for pf in portal_formats:
            candidates = [pf.primary, pf.subs[0], pf.subs[1]]
            for fmt in candidates:
                if fmt is None or getattr(fmt, "name", "").upper() != "ENG":
                    continue
                gv = getattr(fmt, "gauge_values", None)
                if isinstance(gv, dict) and "THRUST" in gv:
                    try:
                        return float(gv["THRUST"])
                    except Exception:
                        return 0.0
        return 0.0

    def get_status_fps() -> float:
        try:
            return float(clock.get_fps())
        except Exception:
            return 0.0

    def adjust_engine_thrust(delta: float, source: str = "unknown") -> None:
        try:
            if _active_icaw_has("ENG CTRL FAIL") or _active_icaw_has("THROTTLE JAMMED"):
                return
            panel = _ensure_panel_button_states()
            throttle_state = panel.get("THROTTLE", {})
            if isinstance(throttle_state, dict):
                if bool(throttle_state.get("VS_BIT_RUNNING", False)):
                    current = float(throttle_state.get("THROTTLE_POS", 0.0))
                    src = str(source).strip().lower()
                    if src == "hotas_axis":
                        # Compare HOTAS commanded throttle value against previous HOTAS
                        # command, not against current throttle position (which VS BIT
                        # auto-sweeps), so a stable axis does not false-abort.
                        hotas_cmd = max(0.0, min(150.0, current + float(delta)))
                        last_cmd_raw = throttle_state.get("VS_BIT_HOTAS_LAST_CMD", None)
                        try:
                            last_cmd = float(last_cmd_raw)
                            if not math.isfinite(last_cmd):
                                raise ValueError
                            have_last = True
                        except Exception:
                            last_cmd = hotas_cmd
                            have_last = False
                        throttle_state["VS_BIT_HOTAS_LAST_CMD"] = float(hotas_cmd)
                        cmd_delta = abs(float(hotas_cmd) - float(last_cmd)) if have_last else 0.0
                        if cmd_delta <= float(VS_BIT_THROTTLE_ABORT_DELTA):
                            return
                        detail = (
                            f"source=hotas_axis, cmd={hotas_cmd:.3f}, last_cmd={last_cmd:.3f}, "
                            f"cmd_delta={cmd_delta:.3f}, threshold={float(VS_BIT_THROTTLE_ABORT_DELTA):.3f}, "
                            f"throttle_pos={current:.3f}"
                        )
                        throttle_state["VS_BIT_THROTTLE_MOVED"] = True
                        throttle_state["VS_BIT_ABORT_INPUT_SOURCE"] = "THROTTLE"
                        throttle_state["VS_BIT_ABORT_INPUT_DETAIL"] = detail
                        _vs_bit_reset_runtime(throttle_state)
                        # Preserve captured abort detail after runtime reset for error logging.
                        throttle_state["VS_BIT_THROTTLE_MOVED"] = True
                        throttle_state["VS_BIT_ABORT_INPUT_SOURCE"] = "THROTTLE"
                        throttle_state["VS_BIT_ABORT_INPUT_DETAIL"] = detail
                        _vs_bit_set_result(throttle_state, "FN", ["VS BIT: ABORT-HOTAS"])
                        throttle_state["THROTTLE_POS"] = float(hotas_cmd)
                        return
                    # Non-HOTAS throttle input (e.g., keyboard/manual) aborts immediately.
                    delta_abs = abs(float(delta))
                    if delta_abs <= 1e-9:
                        return
                    detail = (
                        f"source={source}, delta={float(delta):.3f}, abs_delta={delta_abs:.3f}, "
                        f"throttle_pos={current:.3f}"
                    )
                    throttle_state["VS_BIT_THROTTLE_MOVED"] = True
                    throttle_state["VS_BIT_ABORT_INPUT_SOURCE"] = "THROTTLE"
                    throttle_state["VS_BIT_ABORT_INPUT_DETAIL"] = detail
                    _vs_bit_reset_runtime(throttle_state)
                    # Preserve captured abort detail after runtime reset for error logging.
                    throttle_state["VS_BIT_THROTTLE_MOVED"] = True
                    throttle_state["VS_BIT_ABORT_INPUT_SOURCE"] = "THROTTLE"
                    throttle_state["VS_BIT_ABORT_INPUT_DETAIL"] = detail
                    _vs_bit_set_result(throttle_state, "FN", ["VS BIT: ABORT-HOTAS"])
                    throttle_state["THROTTLE_POS"] = max(0.0, min(150.0, current + float(delta)))
                    return
                current = float(throttle_state.get("THROTTLE_POS", 0.0))
                throttle_state["THROTTLE_POS"] = max(0.0, min(150.0, current + float(delta)))
        except Exception:
            pass

    def _engine_off_color_map() -> Dict[str, Tuple[int, int, int]]:
        yellow = (255, 255, 0)
        green = (0, 255, 0)
        red = (255, 0, 0)
        return {
            "THRUST": red,
            "EGT": green,
            "NOZZLE": green,
            "N1 RPM": green,
            "N2 RPM": yellow,
            "OIL": red,
            "FF": green,
            "HYDA": yellow,
            "HYDB": yellow,
        }

    def update_engine_runtime(dt_sec: float) -> None:
        panel = _ensure_panel_button_states()
        power = panel.get("POWER PANEL", {})
        throttle = panel.get("THROTTLE", {})
        aircraft = panel.get("AIRCRAFT", {})
        if not isinstance(power, dict) or not isinstance(throttle, dict):
            return
        if not isinstance(aircraft, dict):
            aircraft = {}
            panel["AIRCRAFT"] = aircraft
        try:
            gv = getattr(formats.EngineFormat, "_shared_gauge_values", {})
            mv = getattr(formats.EngineFormat, "_shared_mid_values", {})
            colors = getattr(formats.EngineFormat, "_shared_colors", {})
            if not isinstance(gv, dict) or not isinstance(mv, dict) or not isinstance(colors, dict):
                return
        except Exception:
            return

        dt = max(0.0, float(dt_sec))
        dt_ms = dt * 1000.0
        engine_start_spool_ms = float(get_sound_length_or_default_ms("ENGINE START", ENGINE_RUN_SPOOL_MS))
        engine_off_spool_ms = float(get_sound_length_or_default_ms("ENGINE OFF", ENGINE_OFF_FROM_RUN_SPOOL_MS))
        throttle_pos = max(0.0, min(150.0, float(throttle.get("THROTTLE_POS", 0.0))))
        throttle["THROTTLE_POS"] = float(throttle_pos)
        # Autopilot speed channels drive throttle position directly.
        ap_state = _autopilot_state()
        if isinstance(ap_state, dict):
            ap_speed_hold = bool(ap_state.get("speed_hold", False))
            ap_speed_sel = bool(ap_state.get("speed_sel", False))
            if ap_speed_hold and ap_speed_sel:
                ap_speed_sel = False
                ap_state["speed_sel"] = False
            try:
                ap_curr_speed_kts = float(aircraft.get("TOTAL_SPEED_KTS", aircraft.get("AIRSPEED_KTS", 0.0)))
            except Exception:
                ap_curr_speed_kts = 0.0
            ap_curr_speed_kts = max(0.0, ap_curr_speed_kts)
            ap_speed_target_kts: Optional[float] = None
            if ap_speed_hold:
                hold_raw = ap_state.get("speed_hold_target_kts", None)
                try:
                    hold_target = float(hold_raw)
                    if not math.isfinite(hold_target):
                        raise ValueError
                except Exception:
                    hold_target = float(ap_curr_speed_kts)
                    ap_state["speed_hold_target_kts"] = float(hold_target)
                ap_speed_target_kts = max(0.0, hold_target)
                hold_trim_raw = ap_state.get("speed_hold_trim_throttle_pct", None)
                try:
                    hold_trim = float(hold_trim_raw)
                    if (not math.isfinite(hold_trim)) or hold_trim < 0.0 or hold_trim > 150.0:
                        raise ValueError
                except Exception:
                    hold_trim = float(throttle_pos)
                ap_state["speed_hold_trim_throttle_pct"] = float(hold_trim)
            elif ap_speed_sel:
                ap_state.pop("speed_hold_trim_throttle_pct", None)
                spd_digits = "".join(ch for ch in str(ap_state.get("speed_value", "")) if ch.isdigit())
                if spd_digits != "":
                    try:
                        ap_speed_target_kts = float(int(spd_digits[-3:].rjust(3, "0")))
                    except Exception:
                        ap_speed_target_kts = None
            else:
                ap_state.pop("speed_up_hold", None)
            if ap_speed_target_kts is not None and dt > 0.0:
                ap_min_throttle_pct = 49.0
                # Feedforward from target-speed curve + damped feedback.
                # Keep SPEED SEL/HOLD smooth to avoid throttle over-adjustment.
                throttle_ff = float(_thrust_pct_from_airspeed_kts(ap_speed_target_kts))
                now_ms_raw = ap_state.get("now_ms", None)
                prev_speed_kts_raw = ap_state.get("speed_prev_kts", None)
                prev_speed_ms_raw = ap_state.get("speed_prev_ms", None)
                speed_rate_ktsps = 0.0
                try:
                    now_ms = float(now_ms_raw)
                except Exception:
                    now_ms = 0.0
                try:
                    prev_speed_kts = float(prev_speed_kts_raw)
                    if not math.isfinite(prev_speed_kts):
                        raise ValueError
                except Exception:
                    prev_speed_kts = float(ap_curr_speed_kts)
                ap_tau = 0.55 if ap_speed_sel else 0.75
                ap_alpha = max(0.0, min(1.0, dt / max(1e-6, float(ap_tau) + dt)))
                speed_meas_kts = float(prev_speed_kts) + ((float(ap_curr_speed_kts) - float(prev_speed_kts)) * float(ap_alpha))
                speed_error_kts = float(ap_speed_target_kts) - float(speed_meas_kts)
                try:
                    prev_speed_ms = float(prev_speed_ms_raw)
                    dt_rate = (now_ms - prev_speed_ms) / 1000.0
                    if dt_rate > 1e-3:
                        speed_rate_ktsps = (float(speed_meas_kts) - float(prev_speed_kts)) / dt_rate
                except Exception:
                    speed_rate_ktsps = 0.0
                ap_state["speed_prev_kts"] = float(speed_meas_kts)
                ap_state["speed_prev_ms"] = float(now_ms)

                if ap_speed_hold:
                    hold_trim = float(ap_state.get("speed_hold_trim_throttle_pct", throttle_pos))
                    throttle_base = (0.85 * hold_trim) + (0.15 * float(throttle_ff))
                    speed_kp = 0.03
                    speed_kd = 0.50
                    smooth_alpha = 0.15
                    near_speed_deadband_kts = 3.0
                    near_speed_rate_deadband_ktsps = 0.35
                    deadband_kts = 3.0
                    min_drive_scale = 0.006
                    min_drive_floor = 0.02
                    min_drive_cap = 0.35
                    throttle_rate_pct_per_sec = 4.0 + min(8.0, abs(float(speed_error_kts)) * 0.08)
                else:
                    sel_trim_raw = ap_state.get("speed_sel_trim_throttle_pct", None)
                    try:
                        sel_trim = float(sel_trim_raw)
                        if (not math.isfinite(sel_trim)) or sel_trim < 0.0 or sel_trim > 150.0:
                            raise ValueError
                    except Exception:
                        sel_trim = float(throttle_pos)
                    # Integrate slowly toward the set speed to avoid hunting.
                    sel_trim += float(speed_error_kts) * 0.08 * dt
                    sel_trim = max(float(ap_min_throttle_pct), min(150.0, float(sel_trim)))
                    ap_state["speed_sel_trim_throttle_pct"] = float(sel_trim)

                    throttle_base = float(sel_trim)
                    speed_kp = 0.02
                    speed_kd = 0.45
                    smooth_alpha = 0.18
                    near_speed_deadband_kts = 3.0
                    near_speed_rate_deadband_ktsps = 0.30
                    deadband_kts = 3.0
                    min_drive_scale = 0.003
                    min_drive_floor = 0.0
                    min_drive_cap = 0.25
                    throttle_rate_pct_per_sec = 6.0 + min(10.0, abs(float(speed_error_kts)) * 0.10)

                # Anti-hunt zone near target: hold throttle unless error/rate is meaningful.
                if abs(float(speed_error_kts)) <= near_speed_deadband_kts and abs(float(speed_rate_ktsps)) <= near_speed_rate_deadband_ktsps:
                    throttle_cmd = float(throttle_pos)
                else:
                    # Conservative PD around feedforward with strong smoothing.
                    raw_cmd = float(throttle_base) + (float(speed_error_kts) * float(speed_kp)) - (float(speed_rate_ktsps) * float(speed_kd))
                    smooth_alpha = max(0.0, min(1.0, float(smooth_alpha)))
                    throttle_cmd = ((1.0 - smooth_alpha) * float(throttle_pos)) + (smooth_alpha * float(raw_cmd))
                throttle_cmd = max(float(ap_min_throttle_pct), min(150.0, float(throttle_cmd)))
                # If speed is already increasing toward target, pause further
                # throttle-up until that acceleration tapers off.
                speed_up_hold = bool(ap_state.get("speed_up_hold", False))
                if float(speed_error_kts) > float(deadband_kts):
                    engage_rate = 0.12
                    release_rate = 0.03
                    if speed_up_hold:
                        if float(speed_rate_ktsps) <= release_rate:
                            speed_up_hold = False
                    else:
                        if float(speed_rate_ktsps) >= engage_rate:
                            speed_up_hold = True
                else:
                    speed_up_hold = False
                ap_state["speed_up_hold"] = bool(speed_up_hold)
                # Directional guard + minimum drive:
                # above target => force some throttle decrease,
                # below target => force some throttle increase.
                if speed_error_kts < -deadband_kts:
                    min_drop = max(float(min_drive_floor), min(float(min_drive_cap), abs(float(speed_error_kts)) * float(min_drive_scale)))
                    throttle_cmd = min(float(throttle_cmd), float(throttle_pos) - float(min_drop))
                elif speed_error_kts > deadband_kts:
                    if speed_up_hold:
                        throttle_cmd = min(float(throttle_cmd), float(throttle_pos))
                    else:
                        min_rise = max(float(min_drive_floor), min(float(min_drive_cap), abs(float(speed_error_kts)) * float(min_drive_scale)))
                        throttle_cmd = max(float(throttle_cmd), float(throttle_pos) + float(min_rise))
                throttle_cmd = max(float(ap_min_throttle_pct), min(150.0, float(throttle_cmd)))
                # Limit how fast throttle can move; scale with error so large
                # setpoint changes are still responsive.
                throttle_step = float(throttle_rate_pct_per_sec) * dt
                throttle_pos = float(_step_toward(float(throttle_pos), float(throttle_cmd), float(throttle_step)))
                throttle_pos = max(float(ap_min_throttle_pct), min(150.0, float(throttle_pos)))
                throttle["THROTTLE_POS"] = float(throttle_pos)
        # During V/S BIT, keep engine thrust input frozen so the sweep animation
        # does not alter engine response.
        if bool(throttle.get("VS_BIT_RUNNING", False)):
            throttle_input = max(0.0, min(150.0, float(throttle.get("VS_BIT_HOLD_THROTTLE_POS", throttle_pos))))
        else:
            throttle_input = throttle_pos
        mf_sov_on = _is_mf_sov_on()
        cmd_mode = str(throttle.get("ENGINE", "OFF")).upper()
        if cmd_mode not in {"OFF", "MOTOR", "RUN"}:
            cmd_mode = "OFF"
            throttle["ENGINE"] = "OFF"
        if mf_sov_on and cmd_mode != "OFF":
            # MF SOV ON cuts fuel to engine: force engine command OFF.
            cmd_mode = "OFF"
            throttle["ENGINE"] = "OFF"
        fuel_available = bool(_fuel_feed_available())
        if (not fuel_available) and cmd_mode != "OFF":
            # No fuel feed available: force engine command OFF and spool down.
            cmd_mode = "OFF"
            throttle["ENGINE"] = "OFF"
        prev_cmd = str(throttle.get("ENGINE_PREV_CMD", "OFF")).upper()
        if prev_cmd not in {"OFF", "MOTOR", "RUN"}:
            prev_cmd = "OFF"
        run_transition_active = bool(throttle.get("ENGINE_RUN_TRANSITION_ACTIVE", False))
        try:
            run_transition_ms = float(throttle.get("ENGINE_RUN_TRANSITION_MS", 0.0))
        except Exception:
            run_transition_ms = 0.0
        run_transition_from = throttle.get("ENGINE_RUN_TRANSITION_FROM", {})
        if not isinstance(run_transition_from, dict):
            run_transition_from = {}

        spool = max(0.0, min(1.0, float(throttle.get("ENGINE_SPOOL", 0.0))))
        spool_mode = str(throttle.get("ENGINE_SPOOL_MODE", "OFF")).upper()
        if spool_mode not in {"OFF", "MOTOR", "RUN"}:
            spool_mode = "OFF"
        prev_spool_mode = spool_mode
        last_non_off = str(throttle.get("ENGINE_LAST_NON_OFF", "OFF")).upper()
        if last_non_off not in {"MOTOR", "RUN"}:
            last_non_off = "OFF"
        try:
            off_egt_base = float(throttle.get("ENGINE_OFF_EGT_BASE", random.uniform(20.0, 60.0)))
        except Exception:
            off_egt_base = float(random.uniform(20.0, 60.0))
        off_egt_base = max(20.0, min(60.0, off_egt_base))

        try:
            batt_28v = float(power.get("BATT_28V", 0.0))
        except Exception:
            batt_28v = 0.0
        batt_active = bool(power.get("BAT_ACTIVE", False)) and batt_28v > 0.0
        icc1_on = str(power.get("ICC1", "OFF")).upper() == "ON"
        icc2_on = str(power.get("ICC2", "OFF")).upper() == "ON"
        icc3_on = str(power.get("ICC3", "OFF")).upper() == "ON"
        ipp_on = bool(power.get("IPP_ON", False))
        engine_start_prereqs_met = bool(batt_active and icc1_on and icc2_on and icc3_on and ipp_on and fuel_available)

        # HOTAS and other external throttle axes can hold THROTTLE_POS above idle
        # during cold start, which blocks motoring/spool-up. When a valid start
        # command is present from OFF, auto-capture to idle for startup.
        if (
            cmd_mode in {"MOTOR", "RUN"}
            and spool <= 0.0
            and engine_start_prereqs_met
            and throttle_input > 1.0
        ):
            throttle_input = 0.0
            throttle["THROTTLE_POS"] = 0.0

        throttle_idle_ok = bool(throttle_input <= 0.001 or spool > 0.0)
        start_allowed = bool(throttle_idle_ok and (engine_start_prereqs_met or spool > 0.0))
        if cmd_mode in {"MOTOR", "RUN"} and (not start_allowed) and spool <= 0.0:
            spool = 0.0
            spool_mode = "OFF"
        if cmd_mode in {"MOTOR", "RUN"} and start_allowed:
            if spool_mode != cmd_mode:
                # Preserve current spool when transitioning MOTOR -> RUN so
                # gauges continue rising from current MOTOR state.
                if not (spool_mode == "MOTOR" and cmd_mode == "RUN"):
                    spool = 0.0
                spool_mode = cmd_mode
            dur_ms = float(engine_start_spool_ms if cmd_mode == "RUN" else ENGINE_MOTOR_SPOOL_MS)
            spool = min(1.0, spool + (dt_ms / max(1.0, dur_ms)))
            last_non_off = cmd_mode
        elif cmd_mode == "OFF":
            if spool > 0.0:
                dur_ms = float(engine_off_spool_ms)
                spool = max(0.0, spool - (dt_ms / max(1.0, dur_ms)))
            if spool <= 0.0:
                spool = 0.0
                spool_mode = "OFF"
                # Re-roll OFF EGT once when transitioning into fully OFF.
                if prev_spool_mode != "OFF":
                    off_egt_base = float(random.uniform(20.0, 60.0))

        off_targets = {
            "THRUST": 0.0,
            "EGT": float(off_egt_base),
            "NOZZLE": 106.0,
            "N1 RPM": 0.0,
            "N2 RPM": 0.0,
            "OIL": 0.0,
            "FF": 0.0,
        }
        motor_targets = {
            "THRUST": 10.0,
            # MOTOR mode does not drive EGT/FF changes.
            "EGT": float(off_egt_base),
            "NOZZLE": 106.0,
            "N1 RPM": 8.0,
            "N2 RPM": 15.0,
            "OIL": 22.0,
            "FF": 0.0,
        }
        if throttle_input <= 100.0:
            f = throttle_input / 100.0
            run_targets = {
                "THRUST": 12.5 + (100.0 - 12.5) * f,
                "EGT": 475.0 + (775.0 - 475.0) * f,
                "NOZZLE": 65.0 + (40.0 - 65.0) * f,
                "N1 RPM": 60.0 + (95.0 - 60.0) * f,
                "N2 RPM": 72.0 + (98.5 - 72.0) * f,
                "OIL": 42.0 + (87.0 - 42.0) * f,
                "FF": 2000.0 + (18000.0 - 2000.0) * f,
            }
        else:
            f = (throttle_input - 100.0) / 50.0
            run_targets = {
                "THRUST": 100.0 + (150.0 - 100.0) * f,
                "EGT": 775.0 + (1935.0 - 775.0) * f,
                "NOZZLE": 40.0 + (35.0 - 40.0) * f,
                "N1 RPM": 95.0 + (102.5 - 95.0) * f,
                "N2 RPM": 98.5 + (102.5 - 98.5) * f,
                "OIL": 87.0,
                "FF": 18000.0 + (60000.0 - 18000.0) * f,
            }

        # MOTOR -> RUN transition should take 60s from current MOTOR values.
        # Also cover MOTOR -> OFF -> RUN while still spooling down in MOTOR state.
        from_motor_path = (
            (prev_cmd == "MOTOR")
            or (prev_cmd == "OFF" and prev_spool_mode == "MOTOR" and spool > 0.0)
        )
        if from_motor_path and cmd_mode == "RUN" and not run_transition_active:
            run_transition_active = True
            run_transition_ms = 0.0
            run_transition_from = {
                "THRUST": float(gv.get("THRUST", 0.0)),
                "EGT": float(gv.get("EGT", 0.0)),
                "NOZZLE": float(gv.get("NOZZLE", 106.0)),
                "N1 RPM": float(gv.get("N1 RPM", 0.0)),
                "N2 RPM": float(gv.get("N2 RPM", 0.0)),
                "OIL": float(gv.get("OIL", 0.0)),
                "FF": float(mv.get("FF", 0.0)),
            }
        if cmd_mode != "RUN":
            run_transition_active = False
            run_transition_ms = 0.0
            run_transition_from = {}

        if cmd_mode == "OFF" and spool_mode == "OFF":
            targets = off_targets
            eff_mode = "OFF"
        elif spool_mode == "MOTOR":
            targets = {k: off_targets[k] + (motor_targets[k] - off_targets[k]) * spool for k in off_targets.keys()}
            eff_mode = "MOTOR"
        elif spool_mode == "RUN":
            targets = {k: off_targets[k] + (run_targets[k] - off_targets[k]) * spool for k in off_targets.keys()}
            eff_mode = "RUN"
        else:
            targets = off_targets
            eff_mode = "OFF"

        # Engine OFF must display zero thrust regardless throttle lever position.
        if eff_mode == "OFF":
            targets["THRUST"] = 0.0
        # On commanded shutdown, fuel flow is cut immediately.
        if cmd_mode == "OFF":
            targets["FF"] = 0.0
        if mf_sov_on:
            # No fuel flow while MF SOV is ON.
            targets["FF"] = 0.0

        if run_transition_active and eff_mode == "RUN":
            run_transition_ms = max(0.0, run_transition_ms + dt_ms)
            alpha = max(0.0, min(1.0, run_transition_ms / float(max(1, engine_start_spool_ms))))
            for k in ("THRUST", "EGT", "NOZZLE", "N1 RPM", "N2 RPM", "OIL"):
                start_v = float(run_transition_from.get(k, targets.get(k, 0.0)))
                targets[k] = start_v + (float(targets[k]) - start_v) * alpha
            ff_start = float(run_transition_from.get("FF", targets.get("FF", 0.0)))
            targets["FF"] = ff_start + (float(targets["FF"]) - ff_start) * alpha
            if alpha >= 1.0:
                run_transition_active = False
                run_transition_ms = 0.0
                run_transition_from = {}

        # Fuel tank degrade reduces available feed flow proportionally.
        try:
            tank_degrd_map = getattr(formats.FuelFormat, "_shared_tank_degrd", {})
            fuel_qty_map = getattr(formats.FuelFormat, "_shared_fuel_qty", {})
            if (
                eff_mode == "RUN"
                and isinstance(tank_degrd_map, dict)
                and isinstance(fuel_qty_map, dict)
                and float(targets.get("FF", 0.0)) > 0.0
                and len(fuel_qty_map) > 0
            ):
                total_lbs = 0.0
                usable_lbs = 0.0
                for tank_key, qty_raw in fuel_qty_map.items():
                    try:
                        qty = max(0.0, float(qty_raw))
                    except Exception:
                        qty = 0.0
                    total_lbs += qty
                    if not bool(tank_degrd_map.get(str(tank_key), False)):
                        usable_lbs += qty
                if total_lbs > 1e-6:
                    usable_ratio = max(0.0, min(1.0, usable_lbs / total_lbs))
                    targets["FF"] = float(targets["FF"]) * float(usable_ratio)
        except Exception:
            pass

        gv["THRUST"] = max(0.0, min(150.0, float(targets["THRUST"])))
        gv["EGT"] = max(0.0, min(2000.0, float(targets["EGT"])))
        gv["NOZZLE"] = max(0.0, min(106.0, float(targets["NOZZLE"])))
        gv["N1 RPM"] = max(0.0, min(105.0, float(targets["N1 RPM"])))
        gv["N2 RPM"] = max(0.0, min(105.0, float(targets["N2 RPM"])))
        gv["OIL"] = max(0.0, min(105.0, float(targets["OIL"])))
        mv["FF"] = int(round(max(0.0, float(targets["FF"]))))

        eng_comm_fail = _active_icaw_has("ENG COMM FAIL")
        try:
            setattr(formats.EngineFormat, "_shared_comm_fail_active", bool(eng_comm_fail))
        except Exception:
            pass

        color_map = _engine_off_color_map()
        if eng_comm_fail:
            yellow = (255, 255, 0)
            color_map = {k: yellow for k in color_map.keys()}
        elif eff_mode == "RUN":
            color_map = {k: (0, 255, 0) for k in color_map.keys()}
        elif eff_mode == "MOTOR":
            color_map = _engine_off_color_map()
            if gv["OIL"] > 15.0:
                color_map["OIL"] = (0, 255, 0)
                color_map["THRUST"] = (255, 255, 0)

        colors.update(color_map)
        try:
            formats.EngineFormat._shared_status_engine_hazard = bool(cmd_mode == "RUN" and throttle_input > 100.0)
        except Exception:
            pass

        throttle["ENGINE_SPOOL"] = float(spool)
        throttle["ENGINE_SPOOL_MODE"] = str(spool_mode)
        throttle["ENGINE_LAST_NON_OFF"] = str(last_non_off)
        throttle["ENGINE_PREV_CMD"] = str(cmd_mode)
        throttle["ENGINE_RUN_TRANSITION_ACTIVE"] = bool(run_transition_active)
        throttle["ENGINE_RUN_TRANSITION_MS"] = float(run_transition_ms)
        throttle["ENGINE_RUN_TRANSITION_FROM"] = dict(run_transition_from)
        throttle["ENGINE_OFF_EGT_BASE"] = float(off_egt_base)
        try:
            current_airspeed = float(max(0.0, min(AIRSPEED_MAX_KTS, float(aircraft.get("AIRSPEED_KTS", 0.0)))))
            aircraft["AIRSPEED_KTS"] = float(current_airspeed)
            current_altitude = float(max(0.0, float(aircraft.get("ALTITUDE_FT", 0.0))))
            dt_for_alt = max(0.0, float(dt_sec))
            max_defl = max(1e-6, float(FLIGHT_CONTROL_MAX_DEG))

            # Persistent raw attitude state (continuous, can exceed +/-180).
            pitch_raw_deg = float(aircraft.get("ATT_PITCH_RAW_DEG", aircraft.get("ATT_PITCH_DEG", 0.0)))
            roll_raw_deg = float(aircraft.get("ATT_ROLL_RAW_DEG", aircraft.get("ATT_ROLL_DEG", 0.0)))
            try:
                heading_base_deg: Optional[float] = float(aircraft.get("ATT_HEADING_BASE_DEG", None))
            except Exception:
                heading_base_deg = None
            heading_deg_fallback: Optional[float] = None
            for key in ("HEADING_DEG", "HDG_DEG", "HEADING", "HDG"):
                if key in aircraft:
                    try:
                        heading_deg_fallback = float(aircraft.get(key, 0.0))
                        break
                    except Exception:
                        continue
            if heading_base_deg is None:
                heading_base_deg = heading_deg_fallback
            if heading_base_deg is None:
                try:
                    twd_state = getattr(formats, "TWD_STATE", {})
                    heading_base_deg = float(twd_state.get("heading_deg", 35.0)) if isinstance(twd_state, dict) else 35.0
                except Exception:
                    heading_base_deg = 35.0

            # Autopilot applies virtual flight-control inputs so FCS page reflects
            # AP commands through elevator/aileron/rudder movement.
            ap_state = _autopilot_state()
            ap_att_hold_on = bool(ap_state.get("att_hold", False))
            ap_alt_hold_on = bool(ap_state.get("alt_hold", False))
            ap_alt_sel_on = bool(ap_state.get("alt_sel", False))
            if ap_att_hold_on:
                ap_alt_hold_on = False
                ap_alt_sel_on = False
                ap_state["alt_hold"] = False
                ap_state["alt_sel"] = False
            elif ap_alt_hold_on and ap_alt_sel_on:
                ap_alt_sel_on = False
                ap_state["alt_sel"] = False
            ap_hdg_sel_on = bool(ap_state.get("hdg_sel", False))
            ap_upright_on = bool(ap_att_hold_on or ap_hdg_sel_on or ap_alt_hold_on or ap_alt_sel_on)

            if bool(ap_att_hold_on or ap_alt_hold_on or ap_alt_sel_on or ap_hdg_sel_on):
                # Use current-state values as control feedback.
                try:
                    ap_curr_pitch = float(aircraft.get("ATTITUDE", 0.0))
                except Exception:
                    ap_curr_pitch = 0.0
                try:
                    ap_curr_bank = float(aircraft.get("BANK", 0.0))
                except Exception:
                    ap_curr_bank = 0.0
                try:
                    ap_curr_vs_fps = float(aircraft.get("VERTICAL_SPEED_FPM", 0.0)) / 60.0
                except Exception:
                    ap_curr_vs_fps = 0.0

                ap_pitch_norm_cmd = 0.0
                if ap_att_hold_on:
                    att_target_raw = ap_state.get("att_target_pitch_deg", None)
                    try:
                        att_target_pitch = float(att_target_raw)
                        if not math.isfinite(att_target_pitch):
                            raise ValueError
                    except Exception:
                        att_target_pitch = float(ap_curr_pitch)
                        ap_state["att_target_pitch_deg"] = float(att_target_pitch)
                    ap_pitch_err = float(att_target_pitch) - float(ap_curr_pitch)
                    ap_pitch_norm_cmd = max(-1.0, min(1.0, ap_pitch_err / 20.0))
                elif ap_alt_hold_on or ap_alt_sel_on:
                    if ap_alt_hold_on:
                        alt_target_raw = ap_state.get("alt_hold_target_ft", None)
                        try:
                            ap_target_alt_ft = float(alt_target_raw)
                            if (not math.isfinite(ap_target_alt_ft)) or ap_target_alt_ft < 0.0:
                                raise ValueError
                        except Exception:
                            ap_target_alt_ft = float(max(0.0, current_altitude))
                            ap_state["alt_hold_target_ft"] = float(ap_target_alt_ft)
                    else:
                        alt_digits = "".join(ch for ch in str(ap_state.get("alt_value", "00000")) if ch.isdigit())
                        try:
                            ap_target_alt_ft = float(int(alt_digits[-5:].rjust(5, "0")))
                        except Exception:
                            ap_target_alt_ft = float(max(0.0, current_altitude))
                    ap_alt_error_ft = float(ap_target_alt_ft) - float(current_altitude)
                    ap_target_vs_fps = max(-100.0, min(100.0, ap_alt_error_ft * 0.03))
                    ap_vs_error_fps = float(ap_target_vs_fps) - float(ap_curr_vs_fps)
                    # Hold a target pitch from altitude+VS demand so ALT HOLD/SEL
                    # does not briefly pitch up and then relax nose-down.
                    ap_pitch_target_deg = max(
                        -20.0,
                        min(20.0, (ap_target_vs_fps * 0.20) + (ap_alt_error_ft * 0.003)),
                    )
                    ap_pitch_err = float(ap_pitch_target_deg) - float(ap_curr_pitch)
                    ap_pitch_norm_cmd = max(
                        -1.0,
                        min(1.0, (ap_pitch_err / 10.0) + (ap_vs_error_fps * 0.02)),
                    )

                # Elevator convention: negative deflection commands nose-up.
                ap_elev_target = -float(ap_pitch_norm_cmd) * float(max_defl)

                # Keep aircraft upright while AP vertical/lateral modes are active.
                if ap_upright_on:
                    ap_ail_norm_cmd = max(-1.0, min(1.0, -float(ap_curr_bank) / 45.0))
                else:
                    ap_ail_norm_cmd = 0.0
                ap_ail_l_target = -float(ap_ail_norm_cmd) * float(max_defl)
                ap_ail_r_target = float(ap_ail_norm_cmd) * float(max_defl)

                if ap_hdg_sel_on:
                    hdg_digits = "".join(ch for ch in str(ap_state.get("hdg_value", "")) if ch.isdigit())
                    try:
                        ap_hdg_target = float(int(hdg_digits[-3:].rjust(3, "0")) % 360) if hdg_digits != "" else float(heading_base_deg)
                    except Exception:
                        ap_hdg_target = float(heading_base_deg)
                    hdg_err = ((float(ap_hdg_target) - float(heading_base_deg) + 180.0) % 360.0) - 180.0
                    ap_rud_norm_cmd = max(-1.0, min(1.0, hdg_err / 45.0))
                else:
                    ap_rud_norm_cmd = 0.0
                ap_rud_target = float(ap_rud_norm_cmd) * float(max_defl)

                ap_rate_step = max(0.0, float(FLIGHT_CONTROL_MOVE_RATE_DPS) * dt_for_alt)

                def _ap_apply_axis(key: str, target: float) -> None:
                    cur = _clamp_fcs(float(aircraft.get(key, 0.0)), -max_defl, max_defl)
                    if ap_rate_step <= 0.0:
                        nxt = float(target)
                    else:
                        nxt = _step_toward(cur, float(target), ap_rate_step)
                    aircraft[key] = _clamp_fcs(float(nxt), -max_defl, max_defl)

                _ap_apply_axis("l_elevator", ap_elev_target)
                _ap_apply_axis("r_elevator", ap_elev_target)
                _ap_apply_axis("l_aileron", ap_ail_l_target)
                _ap_apply_axis("r_aileron", ap_ail_r_target)
                _ap_apply_axis("l_rudder", ap_rud_target)
                _ap_apply_axis("r_rudder", ap_rud_target)

            elev_l = _clamp_fcs(float(aircraft.get("l_elevator", 0.0)), -max_defl, max_defl)
            elev_r = _clamp_fcs(float(aircraft.get("r_elevator", 0.0)), -max_defl, max_defl)
            ail_l = _clamp_fcs(float(aircraft.get("l_aileron", 0.0)), -max_defl, max_defl)
            ail_r = _clamp_fcs(float(aircraft.get("r_aileron", 0.0)), -max_defl, max_defl)
            rud_l = _clamp_fcs(float(aircraft.get("l_rudder", 0.0)), -max_defl, max_defl)
            rud_r = _clamp_fcs(float(aircraft.get("r_rudder", 0.0)), -max_defl, max_defl)

            # S (stick back) climbs, W (stick forward) descends.
            elev_norm = _clamp_fcs((elev_l + elev_r) * 0.5 / max_defl, -1.0, 1.0)
            pitch_input = _clamp_fcs(-elev_norm, -1.0, 1.0)
            aileron_norm = _clamp_fcs((ail_r - ail_l) * 0.5 / max_defl, -1.0, 1.0)
            rudder_norm = _clamp_fcs((rud_l + rud_r) * 0.5 / max_defl, -1.0, 1.0)
            aircraft["PITCH_CMD"] = float(pitch_input)
            _sync_fcs_control_overlay_state(throttle, aircraft)

            stall_speed = float(ALTITUDE_STALL_SPEED_KTS)
            speed_factor = max(0.0, min(1.0, current_airspeed / max(1e-6, float(AIRSPEED_MAX_KTS))))

            pitch_rate_auth = float(ATTITUDE_PITCH_RATE_MIN_DPS) + (
                float(ATTITUDE_PITCH_RATE_MAX_DPS) - float(ATTITUDE_PITCH_RATE_MIN_DPS)
            ) * speed_factor
            roll_rate_auth = float(ATTITUDE_ROLL_RATE_MIN_DPS) + (
                float(ATTITUDE_ROLL_RATE_MAX_DPS) - float(ATTITUDE_ROLL_RATE_MIN_DPS)
            ) * speed_factor
            rudder_yaw_rate_auth = float(ATTITUDE_RUDDER_YAW_RATE_MAX_DPS) * speed_factor
            cmd_pitch_dps = float(pitch_input) * float(pitch_rate_auth)
            cmd_roll_dps = -float(aileron_norm) * float(roll_rate_auth)
            cmd_yaw_dps = float(rudder_norm) * float(rudder_yaw_rate_auth)
            on_ground = current_altitude <= 0.0
            if on_ground:
                # Ground constraint: do not allow roll input while on the ground.
                cmd_roll_dps = 0.0

            q_state = (
                float(aircraft.get("ATT_Q_W", 1.0)),
                float(aircraft.get("ATT_Q_X", 0.0)),
                float(aircraft.get("ATT_Q_Y", 0.0)),
                float(aircraft.get("ATT_Q_Z", 0.0)),
            )
            q_state = _quat_normalize(q_state)
            if abs(q_state[0]) >= 0.999999 and abs(q_state[1]) <= 1e-9 and abs(q_state[2]) <= 1e-9 and abs(q_state[3]) <= 1e-9:
                # Initialize orientation from current heading so startup/reset
                # heading and quaternion stay aligned.
                q_state = _quat_from_axis_angle((0.0, 0.0, 1.0), math.radians(-float(heading_base_deg)))
            q_prev_for_rates = q_state

            # Basic aero moments: stall nose drop + banked-flight nose dip + mild pitch stability.
            forward_pre = _vec_norm3(_quat_rotate_vec(q_state, (0.0, 1.0, 0.0)))
            up_pre = _vec_norm3(_quat_rotate_vec(q_state, (0.0, 0.0, 1.0)))
            fz_pre = float(forward_pre[2])
            upright_sign = 1.0 if float(up_pre[2]) >= 0.0 else -1.0
            stall_ratio = max(0.0, min(1.0, (stall_speed - current_airspeed) / max(1e-6, stall_speed)))
            bank_prev_deg = float(aircraft.get("BANK", 0.0))
            bank_effect = abs(math.sin(math.radians(bank_prev_deg)))
            ap_vertical_mode_on = bool(ap_att_hold_on or ap_alt_hold_on or ap_alt_sel_on)
            auto_pitch_dps = 0.0
            auto_pitch_dps += -float(STALL_NOSE_DROP_DPS_MAX) * stall_ratio * upright_sign
            auto_pitch_dps += -float(BANK_NOSE_DIP_DPS_MAX) * bank_effect * upright_sign
            if not ap_vertical_mode_on:
                auto_pitch_dps += -float(PITCH_STABILITY_DPS) * fz_pre
            cmd_pitch_dps += auto_pitch_dps
            if on_ground:
                # Ground constraint: only block nose-down once we are at the 0 deg floor.
                pitch_pre_deg = math.degrees(math.asin(max(-1.0, min(1.0, float(fz_pre)))))
                if pitch_pre_deg <= 0.0:
                    cmd_pitch_dps = max(0.0, float(cmd_pitch_dps))

            heading_prev = float(heading_base_deg)
            if dt_for_alt > 0.0:
                # Body axes:
                #   right  = +X, forward = +Y, up = +Z
                # Controls:
                #   W/S -> pitch (nose down/up), A/D -> roll, Q/E -> yaw.
                d_roll = math.radians(float(cmd_roll_dps) * dt_for_alt)
                d_pitch = math.radians(float(cmd_pitch_dps) * dt_for_alt)
                d_yaw = math.radians(float(cmd_yaw_dps) * dt_for_alt)

                # Integrate in body frame: q_new = q_current * dq_body
                if abs(d_roll) > 1e-12:
                    q_state = _quat_mul(q_state, _quat_from_axis_angle((0.0, 1.0, 0.0), d_roll))
                if abs(d_pitch) > 1e-12:
                    q_state = _quat_mul(q_state, _quat_from_axis_angle((1.0, 0.0, 0.0), d_pitch))
                if abs(d_yaw) > 1e-12:
                    q_state = _quat_mul(q_state, _quat_from_axis_angle((0.0, 0.0, 1.0), d_yaw))
                q_state = _quat_normalize(q_state)
            if on_ground:
                # Ground constraint: aircraft pitch cannot go below 0 deg at altitude 0.
                forward_ground = _vec_norm3(_quat_rotate_vec(q_state, (0.0, 1.0, 0.0)))
                pitch_ground_deg = math.degrees(math.asin(max(-1.0, min(1.0, float(forward_ground[2])))))
                if pitch_ground_deg < 0.0:
                    q_state = _quat_mul(
                        q_state,
                        _quat_from_axis_angle((1.0, 0.0, 0.0), math.radians(-pitch_ground_deg)),
                    )
                    q_state = _quat_normalize(q_state)
                # Ground constraint: aircraft roll/bank must stay at 0 deg.
                right_ground = _vec_cross3(forward_ground, (0.0, 0.0, 1.0))
                if (right_ground[0] * right_ground[0] + right_ground[1] * right_ground[1] + right_ground[2] * right_ground[2]) > 1e-10:
                    right_ground = _vec_norm3(right_ground)
                    up_ground = _vec_norm3(_vec_cross3(right_ground, forward_ground))
                    q_state = _quat_from_basis(right_ground, forward_ground, up_ground)
            local_pitch_dps, local_yaw_dps, local_roll_dps = _quat_body_rates_dps(
                q_prev_for_rates,
                q_state,
                dt_for_alt,
            )
            def _wrap_local_angle(v: float) -> float:
                return ((float(v) + 180.0) % 360.0) - 180.0
            local_pitch_deg = float(aircraft.get("PITCH", 0.0))
            local_yaw_deg = float(aircraft.get("YAW", 0.0))
            local_roll_deg = float(aircraft.get("ROLL", 0.0))
            if dt_for_alt > 0.0:
                local_pitch_deg = _wrap_local_angle(local_pitch_deg + (local_pitch_dps * dt_for_alt))
                local_yaw_deg = _wrap_local_angle(local_yaw_deg + (local_yaw_dps * dt_for_alt))
                local_roll_deg = _wrap_local_angle(local_roll_deg + (local_roll_dps * dt_for_alt))
            if on_ground:
                local_roll_deg = 0.0

            forward = _vec_norm3(_quat_rotate_vec(q_state, (0.0, 1.0, 0.0)))
            right = _vec_norm3(_quat_rotate_vec(q_state, (1.0, 0.0, 0.0)))
            up_vec = _vec_norm3(_quat_rotate_vec(q_state, (0.0, 0.0, 1.0)))

            # Heading from forward vector projection on horizontal plane.
            fx, fy, fz = float(forward[0]), float(forward[1]), float(forward[2])
            horiz_norm = math.hypot(fx, fy)
            # Near-vertical nose, heading from horizontal projection is unstable and
            # can jump 180 deg frame-to-frame. Hold previous heading until there is
            # enough horizontal component again.
            heading_update_min_horiz = 0.10
            heading_proj_deg = float(heading_prev)
            if horiz_norm > heading_update_min_horiz:
                heading_proj_deg = (math.degrees(math.atan2(fy, fx)) + 360.0) % 360.0

            # Stabilize heading response through steep bank angles:
            # keep projection-driven heading, but enforce coordinated-turn
            # min/max rates from bank+pull input to avoid sudden spikes near >90 bank.
            delta_hdg_proj = ((float(heading_proj_deg) - float(heading_prev) + 180.0) % 360.0) - 180.0
            # Use quaternion-integrated local roll for turn coupling.
            # ATT_ROLL_DEG is display-derived and can change sign behavior around
            # steep banks, which can invert pitch-coupled turn direction.
            try:
                bank_turn_ref_deg = float(aircraft.get("ROLL", bank_prev_deg))
            except Exception:
                bank_turn_ref_deg = float(bank_prev_deg)
            bank_sin = math.sin(math.radians(float(bank_turn_ref_deg)))
            if abs(float(bank_sin)) < 0.05:
                bank_sin = 0.0
            pull_input = max(0.0, float(pitch_input))
            coordinated_turn_dps = (
                -float(ATTITUDE_BANK_TURN_RATE_SCALE)
                * float(ATTITUDE_BANK_TURN_RATE_MAX_DPS)
                * speed_factor
                * pull_input
                * bank_sin
            )
            desired_delta_hdg = float(coordinated_turn_dps) * dt_for_alt
            max_heading_rate_dps = abs(float(cmd_yaw_dps)) + abs(float(coordinated_turn_dps)) + 2.0
            max_delta_hdg = max(0.0, float(max_heading_rate_dps) * dt_for_alt)

            delta_hdg = float(delta_hdg_proj)
            yaw_input_active = abs(float(cmd_yaw_dps)) > 0.25
            # When pilot yaw input is active, do not force bank-coupled turn bias
            # that can invert/override commanded yaw direction.
            if not yaw_input_active:
                if abs(delta_hdg) < abs(desired_delta_hdg):
                    delta_hdg = float(desired_delta_hdg)
            if max_delta_hdg > 0.0:
                delta_hdg = max(-max_delta_hdg, min(max_delta_hdg, float(delta_hdg)))
            heading_base_deg = (float(heading_prev) + float(delta_hdg)) % 360.0

            # Signed pitch in [-180, 180] with >90 represented on opposite side.
            pitch_core = math.degrees(math.asin(max(-1.0, min(1.0, fz))))
            if float(up_vec[2]) >= 0.0:
                pitch_raw_deg = float(pitch_core)
            else:
                pitch_raw_deg = (180.0 - pitch_core) if pitch_core >= 0.0 else (-180.0 - pitch_core)

            # Bank angle around forward axis.
            world_up = (0.0, 0.0, 1.0)
            # Reversed again per request.
            right_ref = _vec_cross3(forward, world_up)
            if (right_ref[0] * right_ref[0] + right_ref[1] * right_ref[1] + right_ref[2] * right_ref[2]) > 1e-10:
                right_ref = _vec_norm3(right_ref)
                up_ref = _vec_norm3(_vec_cross3(forward, right_ref))
                roll_raw_deg = -math.degrees(
                    math.atan2(
                        _vec_dot3(right, up_ref),
                        _vec_dot3(right, right_ref),
                    )
                )
            else:
                roll_raw_deg = float(aircraft.get("ATT_ROLL_RAW_DEG", 0.0))

            curr_wrapped_pitch = ((float(pitch_raw_deg) + 180.0) % 360.0) - 180.0

            if dt_for_alt > 1e-6:
                delta_hdg = ((float(heading_base_deg) - float(heading_prev) + 180.0) % 360.0) - 180.0
                heading_rate_dps = float(delta_hdg) / dt_for_alt
            else:
                heading_rate_dps = 0.0
            pitch_inverted = abs(curr_wrapped_pitch) > 90.0
            pitch_flip_blend = 1.0 if pitch_inverted else 0.0
            flip_latched = bool(pitch_inverted)
            pitch_deg = float(pitch_core)

            roll_deg = float(roll_raw_deg)
            heading_deg = float(heading_base_deg) % 360.0

            thrust_pct = float(gv.get("THRUST", 0.0))
            thrust_lbf = float(_engine_thrust_lbf_from_percent(thrust_pct))
            gross_weight_lbf = float(_gross_weight_lbf_from_fuel())
            mass_slugs = max(1.0, gross_weight_lbf / float(G_ACCEL_FTPS2))

            speed_fps = max(0.0, float(current_airspeed) / float(KTS_PER_FPS))
            drag_lbf = float(_aero_drag_lbf(speed_fps))
            # Keep forward gravity contribution lift-weighted so high-lift,
            # near-level flight still bleeds speed from drag at low/no thrust.
            lift_coeff_pre = float(_lift_coeff_from_airspeed_kts(current_airspeed, current_altitude, roll_deg))
            gravity_mix_pre = abs(float(fz)) + ((1.0 - abs(float(fz))) * (1.0 - lift_coeff_pre))
            gravity_mix_pre = max(0.0, min(1.0, gravity_mix_pre))
            # Gravity projected on flight path slows climbs and accelerates dives.
            forward_gravity_lbf = gross_weight_lbf * float(fz) * gravity_mix_pre
            forward_force_lbf = thrust_lbf - drag_lbf - forward_gravity_lbf
            forward_accel_fps2 = forward_force_lbf / mass_slugs
            if dt_for_alt > 0.0:
                speed_fps = max(0.0, speed_fps + (forward_accel_fps2 * dt_for_alt))
            current_airspeed = max(0.0, min(AIRSPEED_MAX_KTS, speed_fps * float(KTS_PER_FPS)))
            aircraft["AIRSPEED_KTS"] = float(current_airspeed)

            lift_coeff = float(_lift_coeff_from_airspeed_kts(current_airspeed, current_altitude, roll_deg))
            # Horizontal flight (|fz|~0) gets near-zero gravity when lift is sufficient.
            # Vertical flight (|fz|~1) gets full gravity.
            gravity_mix = abs(float(fz)) + ((1.0 - abs(float(fz))) * (1.0 - lift_coeff))
            gravity_mix = max(0.0, min(1.0, gravity_mix))
            thrust_vertical_accel_fps2 = (thrust_lbf * float(fz)) / mass_slugs
            gravity_accel_fps2 = float(G_ACCEL_FTPS2) * gravity_mix
            vertical_rate_fps = float(aircraft.get("VERTICAL_SPEED_FPM", 0.0)) / 60.0
            if dt_for_alt > 0.0:
                # Lift tends to align vertical speed with the aircraft flight-path angle.
                vertical_rate_target_fps = speed_fps * float(fz)
                # Landing behavior: if already descending at low speed, slight pull-up
                # should reduce sink rate but not force an immediate climb.
                low_speed_no_climb_kts = float(stall_speed) * float(LOW_SPEED_DESCENT_NO_CLIMB_STALL_FACTOR)
                if vertical_rate_fps < 0.0 and float(current_airspeed) < low_speed_no_climb_kts:
                    vertical_rate_target_fps = min(0.0, float(vertical_rate_target_fps))
                align_rate = float(VERTICAL_LIFT_ALIGN_RATE_MIN) + (
                    float(VERTICAL_LIFT_ALIGN_RATE_MAX) - float(VERTICAL_LIFT_ALIGN_RATE_MIN)
                ) * lift_coeff
                align_alpha = max(0.0, min(1.0, align_rate * dt_for_alt))
                vertical_rate_fps += (vertical_rate_target_fps - vertical_rate_fps) * align_alpha
                vertical_rate_fps += (thrust_vertical_accel_fps2 - gravity_accel_fps2) * dt_for_alt
            vertical_rate_fpm = vertical_rate_fps * 60.0
            altitude_step = vertical_rate_fpm * (dt_for_alt / 60.0)
            new_altitude = max(0.0, current_altitude + altitude_step)
            # Exchange kinetic/potential energy so climbs bleed speed and dives gain speed.
            if dt_for_alt > 0.0:
                altitude_delta_ft = float(new_altitude) - float(current_altitude)
                if abs(altitude_delta_ft) > 1e-6:
                    speed_sq = float(speed_fps) * float(speed_fps)
                    energy_term = (
                        2.0
                        * float(G_ACCEL_FTPS2)
                        * abs(float(altitude_delta_ft))
                        * float(CLIMB_ENERGY_EXCHANGE_FACTOR)
                    )
                    if altitude_delta_ft > 0.0:
                        speed_sq = max(0.0, speed_sq - energy_term)
                    else:
                        speed_sq = max(0.0, speed_sq + energy_term)
                    speed_fps = math.sqrt(max(0.0, speed_sq))
                    current_airspeed = max(0.0, min(AIRSPEED_MAX_KTS, speed_fps * float(KTS_PER_FPS)))
                    aircraft["AIRSPEED_KTS"] = float(current_airspeed)
            if new_altitude <= 0.0:
                # Ground contact: kill sink rate and rapidly bleed speed unless thrust is high.
                new_altitude = 0.0
                vertical_rate_fps = 0.0
                vertical_rate_fpm = 0.0
                if float(thrust_pct) > float(GROUND_DECEL_DISABLE_THRUST_PCT):
                    ground_decel_kts_per_sec = 0.0
                else:
                    thrust_norm_ground = max(
                        0.0,
                        min(1.0, thrust_lbf / max(1e-6, float(ENGINE_THRUST_LBF_MIL))),
                    )
                    ground_decel_kts_per_sec = float(GROUND_ROLLING_RESIST_KTS_PER_SEC) + (
                        (1.0 - thrust_norm_ground) * float(GROUND_IDLE_BRAKING_KTS_PER_SEC)
                    )
                if dt_for_alt > 0.0:
                    current_airspeed = max(0.0, current_airspeed - (ground_decel_kts_per_sec * dt_for_alt))
                    speed_fps = max(0.0, current_airspeed / float(KTS_PER_FPS))
                aircraft["AIRSPEED_KTS"] = float(current_airspeed)
            if dt_for_alt > 1e-6:
                actual_vertical_rate_fpm = ((new_altitude - current_altitude) / dt_for_alt) * 60.0
            else:
                actual_vertical_rate_fpm = 0.0

            # Compute normal load factor from translational acceleration.
            vertical_fps_curr = float(actual_vertical_rate_fpm) / 60.0
            total_fps_curr = max(0.0, float(current_airspeed) / float(KTS_PER_FPS))
            horiz_fps_curr = math.sqrt(max(0.0, (total_fps_curr * total_fps_curr) - (vertical_fps_curr * vertical_fps_curr)))
            hdg_rad = math.radians(float(heading_deg))
            vel_x_fps = horiz_fps_curr * math.sin(hdg_rad)
            vel_y_fps = horiz_fps_curr * math.cos(hdg_rad)
            vel_z_fps = vertical_fps_curr
            prev_vx = float(aircraft.get("VEL_X_FPS", vel_x_fps))
            prev_vy = float(aircraft.get("VEL_Y_FPS", vel_y_fps))
            prev_vz = float(aircraft.get("VEL_Z_FPS", vel_z_fps))
            if dt_for_alt > 1e-6:
                ax_fps2 = (vel_x_fps - prev_vx) / dt_for_alt
                ay_fps2 = (vel_y_fps - prev_vy) / dt_for_alt
                az_fps2 = (vel_z_fps - prev_vz) / dt_for_alt
            else:
                ax_fps2 = 0.0
                ay_fps2 = 0.0
                az_fps2 = 0.0
            specific_x = ax_fps2
            specific_y = ay_fps2
            specific_z = az_fps2 + float(G_ACCEL_FTPS2)
            g_load = math.sqrt((specific_x * specific_x) + (specific_y * specific_y) + (specific_z * specific_z)) / float(G_ACCEL_FTPS2)
            if float(new_altitude) <= 0.0 and float(current_airspeed) < 1.0:
                g_load = 1.0
            g_load = max(0.0, min(12.0, float(g_load)))
            aircraft["G_LOAD"] = float(g_load)
            aircraft["VEL_X_FPS"] = float(vel_x_fps)
            aircraft["VEL_Y_FPS"] = float(vel_y_fps)
            aircraft["VEL_Z_FPS"] = float(vel_z_fps)

            aircraft["ATT_PITCH_RAW_DEG"] = float(pitch_raw_deg)
            aircraft["ATT_ROLL_RAW_DEG"] = float(roll_raw_deg)
            aircraft["ATT_HEADING_BASE_DEG"] = float(heading_base_deg)
            aircraft["ATT_Q_W"] = float(q_state[0])
            aircraft["ATT_Q_X"] = float(q_state[1])
            aircraft["ATT_Q_Y"] = float(q_state[2])
            aircraft["ATT_Q_Z"] = float(q_state[3])
            aircraft["ATT_PITCH_FLIP_BLEND"] = float(pitch_flip_blend)
            aircraft["ATT_PITCH_FLIP_LATCH"] = bool(flip_latched)
            aircraft["ATT_PITCH_INVERTED"] = bool(pitch_flip_blend >= 0.5)
            aircraft["ATT_INPUT_INVERTED"] = False
            aircraft["ATT_PITCH_DEG"] = float(pitch_deg)
            aircraft["ATT_ROLL_DEG"] = float(roll_deg)
            aircraft["ATT_YAW_RATE_DPS"] = float(heading_rate_dps)
            aircraft["PITCH"] = float(local_pitch_deg)
            aircraft["YAW"] = float(local_yaw_deg)
            aircraft["ROLL"] = float(local_roll_deg)
            aircraft["ATTITUDE"] = float(pitch_deg)
            aircraft["BANK"] = float(roll_deg)
            for key in ("HEADING_DEG", "HDG_DEG", "HEADING", "HDG"):
                aircraft[key] = float(heading_deg)
            try:
                twd_state = getattr(formats, "TWD_STATE", {})
                if isinstance(twd_state, dict):
                    twd_state["heading_deg"] = float(heading_deg)
            except Exception:
                pass
            aircraft["ALTITUDE_TARGET_FT"] = float(new_altitude)
            aircraft["ALTITUDE_FT"] = float(new_altitude)
            aircraft["VERTICAL_SPEED_FPM"] = float(actual_vertical_rate_fpm)
            # `current_airspeed` is already the speed-vector magnitude from the
            # forward-force integration, so don't add vertical speed again.
            total_speed_kts = float(current_airspeed)
            aircraft["TOTAL_SPEED_KTS"] = float(max(0.0, min(9999.0, total_speed_kts)))
        except Exception:
            aircraft["AIRSPEED_KTS"] = 0.0
            aircraft["TOTAL_SPEED_KTS"] = 0.0
            aircraft["ALTITUDE_TARGET_FT"] = 0.0
            aircraft["ALTITUDE_FT"] = 0.0
            aircraft["VERTICAL_SPEED_FPM"] = 0.0
            aircraft["G_LOAD"] = 1.0
            aircraft["VEL_X_FPS"] = 0.0
            aircraft["VEL_Y_FPS"] = 0.0
            aircraft["VEL_Z_FPS"] = 0.0
            aircraft["PITCH_CMD"] = 0.0
            aircraft["ATT_PITCH_RAW_DEG"] = 0.0
            aircraft["ATT_ROLL_RAW_DEG"] = 0.0
            aircraft["ATT_HEADING_BASE_DEG"] = 35.0
            q_reset = _quat_from_axis_angle((0.0, 0.0, 1.0), math.radians(-35.0))
            aircraft["ATT_Q_W"] = float(q_reset[0])
            aircraft["ATT_Q_X"] = float(q_reset[1])
            aircraft["ATT_Q_Y"] = float(q_reset[2])
            aircraft["ATT_Q_Z"] = float(q_reset[3])
            aircraft["ATT_PITCH_INVERTED"] = False
            aircraft["ATT_PITCH_FLIP_BLEND"] = 0.0
            aircraft["ATT_PITCH_FLIP_LATCH"] = False
            aircraft["ATT_INPUT_INVERTED"] = False
            aircraft["ATT_PITCH_DEG"] = 0.0
            aircraft["ATT_ROLL_DEG"] = 0.0
            aircraft["ATT_YAW_RATE_DPS"] = 0.0
            aircraft["PITCH"] = 0.0
            aircraft["YAW"] = 0.0
            aircraft["ROLL"] = 0.0
            aircraft["ATTITUDE"] = 0.0
            aircraft["BANK"] = 0.0
    def _all_fuel_formats() -> List[object]:
        out: List[object] = []
        seen: set = set()
        for pf in portal_formats:
            for fmt in [pf.primary, pf.subs[0], pf.subs[1]]:
                if fmt is None or getattr(fmt, "name", "").upper() != "FUEL":
                    continue
                obj_id = id(fmt)
                if obj_id in seen:
                    continue
                seen.add(obj_id)
                out.append(fmt)
        return out

    def _deplete_fuel_lbs(requested_lbs: float, min_total_lbs: float = 0.0) -> Tuple[float, float]:
        requested = max(0.0, float(requested_lbs))
        floor_total = max(0.0, float(min_total_lbs))
        if requested <= 0.0:
            return (0.0, 0.0)

        fuel_formats = _all_fuel_formats()
        qty: Optional[Dict[str, float]] = None
        if fuel_formats:
            base_fmt = fuel_formats[0]
            maybe_qty = getattr(base_fmt, "fuel_qty", None)
            if isinstance(maybe_qty, dict):
                qty = maybe_qty
        if not isinstance(qty, dict):
            shared_qty = getattr(formats.FuelFormat, "_shared_fuel_qty", None)
            if isinstance(shared_qty, dict):
                qty = shared_qty
        if not isinstance(qty, dict):
            return (0.0, 0.0)

        keys = [k for k in ("F1", "F1I", "F2L", "F2R", "F3L", "F3R", "F4L", "F4R", "F5L", "F5R", "LW", "RW") if k in qty]
        if not keys:
            return (0.0, 0.0)
        current = {k: max(0.0, float(qty.get(k, 0.0))) for k in keys}
        total = sum(current.values())
        if total <= 0.0:
            return (0.0, 0.0)

        usable_keys = list(keys)
        try:
            tank_degrd_map = getattr(formats.FuelFormat, "_shared_tank_degrd", {})
            if isinstance(tank_degrd_map, dict):
                filtered = [k for k in usable_keys if not bool(tank_degrd_map.get(k, False))]
                if len(filtered) > 0:
                    usable_keys = filtered
                else:
                    return (0.0, total)
        except Exception:
            pass

        removable = max(0.0, total - floor_total)
        to_remove = min(requested, removable)
        if to_remove <= 0.0:
            return (0.0, total)

        # Flat per-tank randomized depletion chunks (same behavior as fuel dump).
        residual = to_remove
        while residual > 0.0001:
            active_keys = [k for k in usable_keys if current[k] > 0.0]
            if not active_keys:
                break
            factors = {k: random.uniform(0.6, 1.4) for k in active_keys}
            factor_sum = sum(factors.values())
            if factor_sum <= 0.0:
                break
            removed_this_pass = 0.0
            for k in active_keys:
                if residual <= 0.0:
                    break
                planned = residual * (factors[k] / factor_sum)
                q = current[k]
                delta = min(q, planned, residual)
                if delta <= 0.0:
                    continue
                current[k] = q - delta
                residual -= delta
                removed_this_pass += delta
            if removed_this_pass <= 0.0001:
                break

        for fmt in fuel_formats:
            fq = getattr(fmt, "fuel_qty", None)
            if not isinstance(fq, dict):
                continue
            for k in keys:
                fq[k] = max(0.0, current[k])
        try:
            shared_qty = getattr(formats.FuelFormat, "_shared_fuel_qty", None)
            if isinstance(shared_qty, dict):
                for k in keys:
                    shared_qty[k] = max(0.0, current[k])
        except Exception:
            pass

        removed = max(0.0, to_remove - residual)
        return (removed, sum(current.values()))

    def update_fuel_burn_from_ff(dt_sec: float) -> None:
        if dt_sec <= 0.0:
            return
        mf_sov_on = _is_mf_sov_on()
        try:
            ff_lbs_hr = float(getattr(formats.EngineFormat, "_shared_mid_values", {}).get("FF", 0.0))
        except Exception:
            ff_lbs_hr = 0.0
        ff_burn_lbs = 0.0 if mf_sov_on else (max(0.0, ff_lbs_hr / 3600.0) * dt_sec)
        ipp_burn_lbs = 0.0
        try:
            panel = _ensure_panel_button_states()
            power = panel.get("POWER PANEL", {})
            throttle = panel.get("THROTTLE", {})
            engine_mode = str(throttle.get("ENGINE", "OFF")).upper() if isinstance(throttle, dict) else "OFF"
            engine_on = engine_mode in {"MOTOR", "RUN"}
            if isinstance(power, dict) and bool(power.get("IPP_ON", False)) and (not engine_on):
                ipp_burn_lbs = (880.0 / 3600.0) * dt_sec
        except Exception:
            ipp_burn_lbs = 0.0
        total_burn_lbs = ff_burn_lbs + ipp_burn_lbs
        if total_burn_lbs <= 0.0:
            return
        _deplete_fuel_lbs(total_burn_lbs, 0.0)

    def update_fuel_dump(dt_sec: float) -> None:
        if dt_sec <= 0.0:
            return
        try:
            dump_on = bool(getattr(formats.FuelFormat, "_shared_hazard_on", {}).get("L2", False))
        except Exception:
            dump_on = False
        if not dump_on:
            return

        fuel_formats = _all_fuel_formats()
        base_fmt = fuel_formats[0] if fuel_formats else None
        qty = getattr(base_fmt, "fuel_qty", None) if base_fmt is not None else None
        if not isinstance(qty, dict):
            qty = getattr(formats.FuelFormat, "_shared_fuel_qty", None)
        if not isinstance(qty, dict):
            return
        total = sum(max(0.0, float(v)) for v in qty.values())
        if total <= 0.0:
            return

        data_vals = getattr(base_fmt, "_data_values", None) if base_fmt is not None else None
        if not isinstance(data_vals, dict):
            data_vals = getattr(formats.FuelFormat, "_shared_data_values", {})
        try:
            stop_lbs = max(0.0, float(data_vals.get("L3", 0.0)) * 1000.0)
        except Exception:
            stop_lbs = 0.0

        if total <= stop_lbs:
            try:
                formats.FuelFormat._shared_hazard_on["L2"] = False
                formats.FuelFormat._shared_hazard_cover_closed["L2"] = True
            except Exception:
                pass
            return

        dump_rate_lbs_per_s = 50.0
        requested = dump_rate_lbs_per_s * dt_sec
        removed, remaining_total = _deplete_fuel_lbs(requested, stop_lbs)
        if removed <= 0.0:
            try:
                formats.FuelFormat._shared_hazard_on["L2"] = False
                formats.FuelFormat._shared_hazard_cover_closed["L2"] = True
            except Exception:
                pass
            return

        # Auto-stop and re-arm hazard cover once threshold is reached.
        try:
            if remaining_total <= stop_lbs:
                formats.FuelFormat._shared_hazard_on["L2"] = False
                formats.FuelFormat._shared_hazard_cover_closed["L2"] = True
        except Exception:
            pass

    def get_fuel_tank_values() -> Dict[str, int]:
        values = {k: 0 for k in PMD_DR_TANK_LIMITS.keys()}
        for pf in portal_formats:
            for fmt in [pf.primary, pf.subs[0], pf.subs[1]]:
                if fmt is None or getattr(fmt, "name", "").upper() != "FUEL":
                    continue
                qty = getattr(fmt, "fuel_qty", None)
                if not isinstance(qty, dict):
                    continue
                for tank_id in values.keys():
                    try:
                        values[tank_id] = int(float(qty.get(tank_id, values[tank_id])))
                    except Exception:
                        pass
        return values

    def set_fuel_tank_value(tank_id: str, value: int) -> None:
        if tank_id not in PMD_DR_TANK_LIMITS:
            return
        clamped = max(0, min(PMD_DR_TANK_LIMITS[tank_id], int(value)))
        for pf in portal_formats:
            for fmt in [pf.primary, pf.subs[0], pf.subs[1]]:
                if fmt is None or getattr(fmt, "name", "").upper() != "FUEL":
                    continue
                qty = getattr(fmt, "fuel_qty", None)
                if isinstance(qty, dict) and tank_id in qty:
                    qty[tank_id] = float(clamped)

    def refresh_pmd_dr_from_fuel() -> None:
        pmd_dr_state["tank_values"] = get_fuel_tank_values()
        pmd_dr_state["inputs"] = {k: "" for k in PMD_DR_TANK_LIMITS.keys()}
        pmd_dr_state["selected_field"] = None

    def sync_svc_debug_outputs() -> None:
        svc_vals = pmd_dr_state.get("svc_values", {})
        if not isinstance(svc_vals, dict):
            return
        try:
            bos_qty_ref = max(0.0, min(400.0, float(svc_vals.get("BOS_QTY", 330.0))))
            bos_live = float(pmd_dr_state.get("bos_live_qty", bos_qty_ref))
            bos_qty = max(0.0, min(400.0, bos_live))
            eng_oil = max(0.0, min(12.0, float(svc_vals.get("ENG_OIL", 12.0))))
            hyd_a_cuin = max(0.0, min(500.0, float(svc_vals.get("HYD_A", 436.0))))
            hyd_b_cuin = max(450.0, min(600.0, float(svc_vals.get("HYD_B", 540.0))))
            pao_cuin = max(0.0, min(11.0, float(svc_vals.get("PAO", 5.3))))
            batt_28v = max(0.0, min(100.0, float(svc_vals.get("28V_BAT", 95.0))))
        except Exception:
            return

        # Update ECS BOS readout.
        ecs_state["c1_bos"] = int(round(bos_qty))

        bos_psi = (bos_qty / 400.0) * 2545.0
        hyd_a_qts = hyd_a_cuin * 0.017316
        hyd_b_qts = hyd_b_cuin * 0.017316
        try:
            formats.SVC_DEBUG_STATE["bos_qty"] = bos_qty
            formats.SVC_DEBUG_STATE["bos_psi"] = bos_psi
            formats.SVC_DEBUG_STATE["eng_oil_qts"] = eng_oil
            formats.SVC_DEBUG_STATE["hyd_a_cuin"] = hyd_a_cuin
            formats.SVC_DEBUG_STATE["hyd_b_cuin"] = hyd_b_cuin
            formats.SVC_DEBUG_STATE["hyd_a_qts"] = hyd_a_qts
            formats.SVC_DEBUG_STATE["hyd_b_qts"] = hyd_b_qts
            formats.SVC_DEBUG_STATE["pao_cuin"] = pao_cuin
            formats.SVC_DEBUG_STATE["batt_28v"] = batt_28v
        except Exception:
            pass

