    def _seclvl_field_prefix() -> Optional[str]:
        if bool(seclvl_state["user_selected"]):
            return "user"
        if bool(seclvl_state["pass_selected"]):
            return "pass"
        return None

    def _seclvl_user_has_input() -> bool:
        committed = str(seclvl_state.get("user_committed", "")).strip()
        if committed != "":
            return True
        chars_raw = seclvl_state.get("user_chars", [])
        if isinstance(chars_raw, list):
            live = "".join(str(ch) for ch in chars_raw if str(ch) != "").strip()
            return live != ""
        return str(chars_raw).strip() != ""

    def _seclvl_sync_login() -> None:
        logged_in = bool(seclvl_state["user_committed"]) and bool(seclvl_state["pass_committed"])
        seclvl_state["logged_in"] = logged_in
        seclvl_state["level_idx"] = 1 if logged_in else 0

    def clear_seclvl_selected_field() -> None:
        prefix = _seclvl_field_prefix()
        if prefix is None:
            return
        seclvl_state[f"{prefix}_chars"] = []
        seclvl_state[f"{prefix}_cursor"] = 0
        seclvl_state[f"{prefix}_comp_key"] = None
        seclvl_state[f"{prefix}_comp_idx"] = -1
        seclvl_state[f"{prefix}_comp_cycle"] = 0
        seclvl_state[f"{prefix}_committed"] = ""
        _seclvl_sync_login()

    def finalize_seclvl_field(prefix: str) -> None:
        chars = seclvl_state[f"{prefix}_chars"]
        committed = "".join(ch for ch in chars if ch != "")
        seclvl_state[f"{prefix}_committed"] = committed
        seclvl_state[f"{prefix}_selected"] = False
        seclvl_state[f"{prefix}_comp_key"] = None
        seclvl_state[f"{prefix}_comp_idx"] = -1
        seclvl_state[f"{prefix}_comp_cycle"] = 0
        _seclvl_sync_login()

    def finalize_all_seclvl_fields() -> None:
        finalize_seclvl_field("user")
        finalize_seclvl_field("pass")

    def select_seclvl_field(prefix: str) -> None:
        if prefix == "pass" and not _seclvl_user_has_input():
            return
        other = "pass" if prefix == "user" else "user"
        if bool(seclvl_state[f"{prefix}_selected"]):
            finalize_seclvl_field(prefix)
            return
        finalize_seclvl_field(other)
        committed = str(seclvl_state[f"{prefix}_committed"])
        chars = list(committed)
        seclvl_state[f"{prefix}_chars"] = chars
        cursor = len(committed)
        seclvl_state[f"{prefix}_cursor"] = cursor
        seclvl_state[f"{prefix}_selected"] = True
        seclvl_state[f"{prefix}_comp_key"] = None
        seclvl_state[f"{prefix}_comp_idx"] = -1
        seclvl_state[f"{prefix}_comp_cycle"] = 0

    def seclvl_keypad_press(key: str) -> None:
        prefix = _seclvl_field_prefix()
        if prefix is None:
            return
        chars_raw = seclvl_state.get(f"{prefix}_chars", [])
        if isinstance(chars_raw, list):
            chars = [str(ch) for ch in chars_raw if str(ch) != ""]
        else:
            chars = list(str(chars_raw or ""))
        cursor = int(seclvl_state[f"{prefix}_cursor"])
        comp_key = seclvl_state[f"{prefix}_comp_key"]
        comp_idx = int(seclvl_state[f"{prefix}_comp_idx"])
        comp_cycle = int(seclvl_state[f"{prefix}_comp_cycle"])

        alpha_map = {
            "KP_2": "ABC2",
            "KP_3": "DEF3",
            "KP_4": "GHI4",
            "KP_5": "JKL5",
            "KP_6": "MNO6",
            "KP_7": "PQRS7",
            "KP_8": "TUV8",
            "KP_9": "WXYZ9",
        }

        if key in alpha_map:
            options = alpha_map[key]
            if comp_key == key and comp_idx >= 0 and comp_idx < len(chars):
                comp_cycle = (comp_cycle + 1) % len(options)
                chars[comp_idx] = options[comp_cycle]
            else:
                if comp_key is not None and comp_idx >= 0:
                    idx = max(0, comp_idx + 1)
                else:
                    idx = max(0, min(len(chars), cursor))
                if idx >= len(chars):
                    chars.append(options[0])
                else:
                    chars.insert(idx, options[0])
                comp_idx = idx
                comp_cycle = 0
                comp_key = key
                cursor = idx
            seclvl_state[f"{prefix}_chars"] = chars
            seclvl_state[f"{prefix}_cursor"] = cursor
            seclvl_state[f"{prefix}_comp_key"] = comp_key
            seclvl_state[f"{prefix}_comp_idx"] = comp_idx
            seclvl_state[f"{prefix}_comp_cycle"] = comp_cycle
            return

        if key in {"KP_0", "KP_1"}:
            digit = "0" if key == "KP_0" else "1"
            if comp_key is not None and comp_idx >= 0:
                idx = max(0, comp_idx + 1)
            else:
                idx = max(0, min(len(chars), cursor))
            if idx >= len(chars):
                chars.append(digit)
            else:
                chars.insert(idx, digit)
            seclvl_state[f"{prefix}_chars"] = chars
            seclvl_state[f"{prefix}_cursor"] = idx + 1
            seclvl_state[f"{prefix}_comp_key"] = None
            seclvl_state[f"{prefix}_comp_idx"] = -1
            seclvl_state[f"{prefix}_comp_cycle"] = 0
            return

        if key == "KP_RIGHT":
            # Manual next-character step for repeated same-key entry.
            base = comp_idx if comp_idx >= 0 else cursor
            seclvl_state[f"{prefix}_cursor"] = max(0, base + 1)
            seclvl_state[f"{prefix}_comp_key"] = None
            seclvl_state[f"{prefix}_comp_idx"] = -1
            seclvl_state[f"{prefix}_comp_cycle"] = 0
            return

        if key == "KP_BACK":
            if comp_idx >= 0 and comp_idx < len(chars):
                idx = comp_idx
            elif cursor > 0:
                idx = cursor - 1
            else:
                idx = 0
            if 0 <= idx < len(chars):
                chars.pop(idx)
                seclvl_state[f"{prefix}_cursor"] = idx
            seclvl_state[f"{prefix}_chars"] = chars
            seclvl_state[f"{prefix}_comp_key"] = None
            seclvl_state[f"{prefix}_comp_idx"] = -1
            seclvl_state[f"{prefix}_comp_cycle"] = 0
            return

    def _comm_selected_field() -> Optional[str]:
        value = comm_state.get("selected_field")
        return str(value) if value else None

    def _comm_profile_for(radio_key: str) -> Dict[str, bool]:
        radio_key = str(radio_key).strip().lower()
        profiles = comm_state.get("radio_profiles", {})
        if not isinstance(profiles, dict):
            profiles = {}
            comm_state["radio_profiles"] = profiles
        prof = profiles.get(radio_key)
        if not isinstance(prof, dict):
            prof = {"tone_on": False, "mute_on": False, "sqlch_on": False, "aj_on": False, "secure_on": False}
            profiles[radio_key] = prof
        for key in ("tone_on", "mute_on", "sqlch_on", "aj_on", "secure_on"):
            prof[key] = bool(prof.get(key, False))
        return {
            "tone_on": bool(prof.get("tone_on", False)),
            "mute_on": bool(prof.get("mute_on", False)),
            "sqlch_on": bool(prof.get("sqlch_on", False)),
            "aj_on": bool(prof.get("aj_on", False)),
            "secure_on": bool(prof.get("secure_on", False)),
        }

    def _comm_set_profile_value(radio_key: str, key: str, value: bool) -> None:
        radio_key = str(radio_key).strip().lower()
        profiles = comm_state.get("radio_profiles", {})
        if not isinstance(profiles, dict):
            profiles = {}
            comm_state["radio_profiles"] = profiles
        prof = profiles.get(radio_key)
        if not isinstance(prof, dict):
            prof = {"tone_on": False, "mute_on": False, "sqlch_on": False, "aj_on": False, "secure_on": False}
            profiles[radio_key] = prof
        prof[key] = bool(value)

    def _comm_sync_a123_from_asgn() -> None:
        radio = str(comm_state.get("asgn_radio", "comb"))
        if radio not in {"coma", "comb", "comc", "comd"}:
            radio = "comb"
        prof = _comm_profile_for(radio)
        comm_state["tone_on"] = bool(prof.get("tone_on", False))
        comm_state["mute_on"] = bool(prof.get("mute_on", False))
        comm_state["sqlch_on"] = bool(prof.get("sqlch_on", False))
        comm_state["aj_on"] = bool(prof.get("aj_on", False))
        comm_state["secure_on"] = bool(prof.get("secure_on", False))

    def _comm_enforce_cni_linkage(now_ms: int) -> None:
        try:
            rows = getattr(formats.CniFormat, "_table_rows", [])
            break_after = int(getattr(formats.CniFormat, "_table_break_after", -1))
            restart_until = getattr(formats.CniFormat, "_shared_restart_until_by_key", {})
        except Exception:
            return
        if not isinstance(rows, list):
            return
        if not isinstance(restart_until, dict):
            restart_until = {}
        forced_off_raw = comm_state.get("cni_forced_off_radios", set())
        if isinstance(forced_off_raw, set):
            forced_off_radios: Set[str] = set(str(x).strip().lower() for x in forced_off_raw)
        elif isinstance(forced_off_raw, list):
            forced_off_radios = set(str(x).strip().lower() for x in forced_off_raw)
        else:
            forced_off_radios = set()
        radio_by_letter = {"A": "coma", "B": "comb", "C": "comc", "D": "comd"}
        class_by_radio: Dict[str, str] = {}
        unavailable_radios: Set[str] = set()
        for idx, row in enumerate(rows):
            if not isinstance(row, (list, tuple)) or len(row) < 5:
                continue
            com_letter = str(row[4]).upper().strip()
            radio = radio_by_letter.get(com_letter, "")
            if radio == "":
                continue
            class_value = str(row[1]).upper().strip()
            if class_value != "" and radio not in class_by_radio:
                class_by_radio[radio] = class_value
            is_active = idx <= break_after
            row_key = (str(row[0]), str(row[2]), str(row[4]))
            restarting = int(restart_until.get(row_key, 0) or 0) > int(now_ms)
            if (not is_active) or restarting:
                unavailable_radios.add(radio)

        # Class-driven comm security policy from CNI:
        # S => SECURE on, AJ off. SS/TS => SECURE on + AJ on.
        for radio in ("coma", "comb", "comc"):
            class_value = str(class_by_radio.get(radio, "")).upper().strip()
            secure_on = class_value in {"S", "SS", "TS"}
            aj_on = class_value in {"SS", "TS"}
            _comm_set_profile_value(radio, "secure_on", secure_on)
            _comm_set_profile_value(radio, "aj_on", aj_on)

        # Linked comms are forced off while their CNI activity is stopped/restarting.
        for radio in ("coma", "comb", "comc"):
            key = f"{radio}_on"
            if key not in comm_state:
                continue
            if radio in unavailable_radios:
                if bool(comm_state.get(key, False)):
                    forced_off_radios.add(radio)
                comm_state[key] = False
            else:
                # Auto-restore only radios that CNI forced off earlier.
                if radio in forced_off_radios:
                    comm_state[key] = True
                    forced_off_radios.discard(radio)
        comm_state["cni_forced_off_radios"] = sorted(forced_off_radios)

    def _comm_format_freq_from_digits(raw: str) -> str:
        digits = "".join(ch for ch in str(raw) if ch.isdigit())[-6:]
        if digits == "":
            return "000.000"
        # Fill from the left of the 6-digit field so "119" becomes "119000" -> "119.000".
        padded = digits.ljust(6, "0")
        return f"{padded[:3]}.{padded[3:]}"

    def _comm_apply_preset(field: str, preset_value: int) -> None:
        field_map = {
            "coma": ("preset_a", "coma_presets", "coma_freq"),
            "comb": ("preset_b", "comb_presets", "comb_freq"),
            "comc": ("preset_c", "comc_presets", "comc_freq"),
            "comd": ("preset_d", "comd_presets", "comd_freq"),
        }
        if field not in field_map:
            return
        preset_key, presets_key, freq_key = field_map[field]
        presets = comm_state.get(presets_key, [])
        if not isinstance(presets, list) or len(presets) == 0:
            return
        idx = max(1, min(len(presets), int(preset_value)))
        comm_state[preset_key] = idx
        comm_state[freq_key] = str(presets[idx - 1])

    def _comm_sync_panel_dial_from_volume_field(field: str) -> None:
        key = str(field).strip().lower()
        dial_key = {"vola": "DIAL_A", "volb": "DIAL_B", "volc": "DIAL_C"}.get(key, "")
        if dial_key == "":
            return
        try:
            raw_vol = comm_state.get(key, 5)
            vol = int(raw_vol)
        except Exception:
            vol = 5
        vol = max(0, min(10, vol))
        try:
            panel_state = _ensure_panel_button_states()
            master_arm_state = panel_state.get("MASTER ARM", {})
            if isinstance(master_arm_state, dict):
                master_arm_state[dial_key] = int(vol)
        except Exception:
            pass

