    def _comm_persist_audio_settings() -> None:
        try:
            settings_changed = False
            persist_values: Dict[str, object] = {
                "comm_vola": int(max(0, min(10, int(comm_state.get("vola", 5) or 5)))),
                "comm_volb": int(max(0, min(10, int(comm_state.get("volb", 5) or 5)))),
                "comm_volc": int(max(0, min(10, int(comm_state.get("volc", 5) or 5)))),
                "comm_vold": int(max(0, min(10, int(comm_state.get("vold", 5) or 5)))),
                "audio_thrt_on": bool(comm_state.get("audio_thrt_on", True)),
                "audio_wpn_on": bool(comm_state.get("audio_wpn_on", True)),
                "audio_navaid_on": bool(comm_state.get("audio_navaid_on", True)),
                "audio_icaws_on": bool(comm_state.get("audio_icaws_on", True)),
                "audio_ics_on": bool(comm_state.get("audio_ics_on", True)),
                "audio_vox_on": bool(comm_state.get("audio_vox_on", True)),
                "audio_ckpt_on": bool(comm_state.get("audio_ckpt_on", True)),
                "audio_thrt_vol": int(max(0, min(10, int(comm_state.get("audio_thrt_vol", 5) or 5)))),
                "audio_wpn_vol": int(max(0, min(10, int(comm_state.get("audio_wpn_vol", 5) or 5)))),
                "audio_navaid_vol": int(max(0, min(10, int(comm_state.get("audio_navaid_vol", 5) or 5)))),
                "audio_icaws_vol": int(max(0, min(10, int(comm_state.get("audio_icaws_vol", 5) or 5)))),
                "audio_ics_vol": int(max(0, min(10, int(comm_state.get("audio_ics_vol", 5) or 5)))),
                "audio_vox_vol": int(max(0, min(10, int(comm_state.get("audio_vox_vol", 5) or 5)))),
                "audio_ckpt_vol": int(max(0, min(10, int(comm_state.get("audio_ckpt_vol", 3) or 3)))),
            }
            for key_name, key_value in persist_values.items():
                if settings.get(key_name) != key_value:
                    settings[key_name] = key_value
                    settings_changed = True
            # Backward-compatible key for old builds.
            legacy_icaws = int(persist_values["audio_icaws_vol"])
            if settings.get("audio_icaws_volume") != legacy_icaws:
                settings["audio_icaws_volume"] = legacy_icaws
                settings_changed = True
            ckpt_gain = (
                float(persist_values["audio_ckpt_vol"]) / 10.0
                if bool(persist_values["audio_ckpt_on"])
                else 0.0
            )
            try:
                current_gain = float(settings.get("engine_ipp_volume", ckpt_gain))
            except Exception:
                current_gain = ckpt_gain
            if abs(current_gain - ckpt_gain) > 1e-6:
                settings["engine_ipp_volume"] = float(ckpt_gain)
                settings_changed = True
            if settings_changed:
                save_settings(settings)
        except Exception:
            pass

    def _comm_apply_ckpt_volume(*, persist: bool = False) -> None:
        try:
            ckpt_on = bool(comm_state.get("audio_ckpt_on", True))
            raw_vol = int(comm_state.get("audio_ckpt_vol", 0) or 0)
        except Exception:
            ckpt_on = True
            raw_vol = 0
        raw_vol = max(0, min(10, raw_vol))
        gain = (float(raw_vol) / 10.0) if ckpt_on else 0.0
        try:
            set_engine_ipp_volume(float(gain))
        except Exception:
            pass
        if persist:
            _comm_persist_audio_settings()

    def _comm_apply_icaws_volume(*, persist: bool = False) -> None:
        try:
            icaws_on = bool(comm_state.get("audio_icaws_on", True))
            raw_vol = int(comm_state.get("audio_icaws_vol", 0) or 0)
        except Exception:
            icaws_on = True
            raw_vol = 0
        raw_vol = max(0, min(10, raw_vol))
        gain = (float(raw_vol) / 10.0) if icaws_on else 0.0
        try:
            set_icaws_alert_audio(bool(icaws_on), float(gain))
        except Exception:
            pass
        if persist:
            _comm_persist_audio_settings()

    def _comm_rx_volume_field_for_radio(radio: str) -> str:
        return {
            "coma": "vola",
            "comb": "volb",
            "comc": "volc",
            "comd": "vold",
        }.get(str(radio).strip().lower(), "")

    def _comm_rx_gain_for_radio(radio: str) -> float:
        rr = str(radio).strip().lower()
        vol_field = _comm_rx_volume_field_for_radio(rr)
        if vol_field == "":
            return 1.0
        try:
            raw_vol = comm_state.get(vol_field, 10)
            vol = int(raw_vol)
        except Exception:
            vol = 10
        vol = max(0, min(10, vol))
        # Per-radio mute from COMM A2 profile should hard-mute that radio.
        try:
            prof = _comm_profile_for(rr)
            if bool(prof.get("mute_on", False)):
                return 0.0
        except Exception:
            pass
        return float(vol) / 10.0

    def _comm_apply_rx_gain(raw: bytes, gain: float) -> bytes:
        g = max(0.0, min(1.0, float(gain)))
        if g >= 0.999:
            return raw
        if g <= 0.0001:
            return b"\x00" * len(raw)
        return _apply_pcm16_gain_fade(raw, audio_sample_rate, 1, g, 0, 0)

    def finalize_comm_data_entry(field: str) -> None:
        if field in _comm_basic_volume_fields:
            input_key = f"{field}_input"
            raw = str(comm_state.get(input_key, ""))
            if raw != "":
                try:
                    comm_state[field] = max(0, min(10, int(raw)))
                except ValueError:
                    pass
            _comm_sync_panel_dial_from_volume_field(field)
            comm_state[input_key] = ""
            _comm_persist_audio_settings()
        elif field in _comm_audio_volume_fields:
            input_key = f"{field}_input"
            raw = str(comm_state.get(input_key, ""))
            if raw != "":
                try:
                    comm_state[field] = max(0, min(_comm_audio_volume_max(field), int(raw)))
                except ValueError:
                    pass
            comm_state[input_key] = ""
            if field == "audio_ckpt_vol":
                _comm_apply_ckpt_volume(persist=True)
            elif field == "audio_icaws_vol":
                _comm_apply_icaws_volume(persist=True)
            else:
                _comm_persist_audio_settings()
        elif field in {"coma", "comb", "comc", "comd"}:
            input_key = f"{field}_input"
            raw = str(comm_state.get(input_key, ""))
            if raw != "":
                committed = _comm_format_freq_from_digits(raw)
                comm_state[f"{field}_freq"] = committed
                preset_key = {"coma": "preset_a", "comb": "preset_b", "comc": "preset_c", "comd": "preset_d"}[field]
                presets_key = {"coma": "coma_presets", "comb": "comb_presets", "comc": "comc_presets", "comd": "comd_presets"}[field]
                presets = comm_state.get(presets_key, [])
                if isinstance(presets, list) and committed in presets:
                    comm_state[preset_key] = presets.index(committed) + 1
                else:
                    comm_state[preset_key] = None
            comm_state[input_key] = ""
        if _comm_selected_field() == field:
            comm_state["selected_field"] = None

    def select_comm_data_entry(field: str) -> None:
        current = _comm_selected_field()
        if current == field:
            finalize_comm_data_entry(field)
            return
        if current is not None:
            finalize_comm_data_entry(current)
        comm_state["selected_field"] = field
        if field in _comm_basic_volume_fields or field in {"coma", "comb", "comc", "comd"} or field in _comm_audio_volume_fields:
            comm_state[f"{field}_input"] = ""

    def comm_keypad_press(key: str) -> None:
        field = _comm_selected_field()
        if field is None:
            return
        if field in _comm_basic_volume_fields:
            input_key = f"{field}_input"
            current = str(comm_state.get(input_key, ""))
            if key == "KP_UP":
                base_value = comm_state.get(field, 0)
                try:
                    base = int(current) if current != "" else int(base_value)
                except Exception:
                    base = 0
                new_value = max(0, min(10, base + 1))
                comm_state[input_key] = str(int(new_value)).rjust(2, "0")
                return
            if key == "KP_DOWN":
                base_value = comm_state.get(field, 0)
                try:
                    base = int(current) if current != "" else int(base_value)
                except Exception:
                    base = 0
                new_value = max(0, min(10, base - 1))
                comm_state[input_key] = str(int(new_value)).rjust(2, "0")
                return
            if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
                digit = key.split("_", 1)[1]
                scratch = (current + digit)[-2:]
                try:
                    scratch_val = int(scratch)
                    if scratch_val > 10:
                        scratch = "10"
                except Exception:
                    scratch = "00"
                comm_state[input_key] = scratch
                return
            if key == "KP_BACK":
                comm_state[input_key] = current[:-1]
                return
        if field in _comm_audio_volume_fields:
            toggle_key = _comm_audio_toggle_key_for_volume(field)
            if toggle_key != "" and (not bool(comm_state.get(toggle_key, True))):
                return
        input_key = f"{field}_input"
        current = str(comm_state.get(input_key, ""))
        if key == "KP_UP" and field in _comm_audio_volume_fields:
            base_value = comm_state.get(field, 0)
            try:
                if current != "":
                    base = int(current)
                else:
                    base = int(base_value)
            except Exception:
                base = 0
            max_val = _comm_audio_volume_max(field)
            new_value = max(0, min(max_val, base + 1))
            comm_state[input_key] = str(int(new_value)).rjust(2, "0")
            return
        if key == "KP_DOWN" and field in _comm_audio_volume_fields:
            base_value = comm_state.get(field, 0)
            try:
                if current != "":
                    base = int(current)
                else:
                    base = int(base_value)
            except Exception:
                base = 0
            max_val = _comm_audio_volume_max(field)
            new_value = max(0, min(max_val, base - 1))
            comm_state[input_key] = str(int(new_value)).rjust(2, "0")
            return
        if key == "KP_UP" and field in {"coma", "comb", "comc", "comd"}:
            preset_key = {"coma": "preset_a", "comb": "preset_b", "comc": "preset_c", "comd": "preset_d"}[field]
            current = comm_state.get(preset_key, 1)
            try:
                base = int(current) if current is not None else 1
            except Exception:
                base = 1
            new_preset = base + 1
            _comm_apply_preset(field, new_preset)
            comm_state[input_key] = ""
            return
        if key == "KP_DOWN" and field in {"coma", "comb", "comc", "comd"}:
            preset_key = {"coma": "preset_a", "comb": "preset_b", "comc": "preset_c", "comd": "preset_d"}[field]
            current = comm_state.get(preset_key, 1)
            try:
                base = int(current) if current is not None else 1
            except Exception:
                base = 1
            new_preset = base - 1
            _comm_apply_preset(field, new_preset)
            comm_state[input_key] = ""
            return
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            width = 2 if (field in _comm_basic_volume_fields or field in _comm_audio_volume_fields) else 6
            scratch = (current + digit)[-width:]
            if field in _comm_audio_volume_fields:
                max_val = _comm_audio_volume_max(field)
                try:
                    scratch_val = int(scratch)
                    if scratch_val > max_val:
                        scratch = str(int(max_val)).rjust(width, "0")
                except Exception:
                    pass
            comm_state[input_key] = scratch
            return
        if key == "KP_BACK":
            comm_state[input_key] = current[:-1]
            return

    _comm_apply_ckpt_volume(persist=False)
    _comm_apply_icaws_volume(persist=False)

    def comm_trigger_flash(key: str, until_ms: int) -> None:
        flash = comm_state.get("flash_until")
        if not isinstance(flash, dict):
            flash = {}
            comm_state["flash_until"] = flash
        flash[str(key)] = int(until_ms)

    def _iff_field_width(field: str) -> int:
        return {
            "mode1": 2,
            "mode2": 4,
            "mode3a": 4,
            "mode4": 4,
            "mode_s_addr": 8,
            "mode_s_acid": 7,
        }.get(field, 4)

    def _iff_selected_field() -> Optional[str]:
        value = iff_state.get("selected_field")
        return str(value) if value else None

    def _iff_clear_comp_state() -> None:
        iff_state["input_comp_key"] = None
        iff_state["input_comp_idx"] = -1
        iff_state["input_comp_cycle"] = 0

    def _iff_get_addr_format() -> str:
        options = iff_state.get("mode_s_addr_format_options", ["OCTAL", "HEX"])
        if not isinstance(options, list) or len(options) == 0:
            options = ["OCTAL", "HEX"]
        options = [str(x).upper() for x in options]
        try:
            idx = int(iff_state.get("mode_s_addr_format_idx", 0))
        except Exception:
            idx = 0
        idx = max(0, min(len(options) - 1, idx))
        return str(options[idx]).upper()

    def _iff_master_mode_off() -> bool:
        if bool(iff_state.get("emergency_on", False)) and bool(iff_state.get("iff_on", False)):
            return False
        options = iff_state.get("mode_options", ["OFF", "STBY", "MAN", "AUTO"])
        if not isinstance(options, list) or len(options) == 0:
            options = ["OFF", "STBY", "MAN", "AUTO"]
        try:
            idx = int(iff_state.get("mode_idx", 0))
        except Exception:
            idx = 0
        idx = max(0, min(len(options) - 1, idx))
        return str(options[idx]).upper() == "OFF"

    def _iff_field_is_editable(field: str) -> bool:
        f = str(field)
        if f == "mode1":
            return (not _iff_master_mode_off()) and bool(iff_state.get("mode1_enabled", True))
        if f == "mode2":
            return (not _iff_master_mode_off()) and bool(iff_state.get("mode2_enabled", True))
        if f == "mode3a":
            return (not _iff_master_mode_off()) and bool(iff_state.get("mode3ac_on", True))
        return True

    def _iff_allowed_char(field: str, ch: str) -> bool:
        c = str(ch).upper()[:1]
        if c == "":
            return False
        if field in {"mode1", "mode2", "mode3a", "mode4"}:
            return c in "01234567"
        if field == "mode_s_addr":
            if _iff_get_addr_format() == "HEX":
                return c.isdigit() or ("A" <= c <= "F")
            return c in "01234567"
        if field == "mode_s_acid":
            return c.isdigit() or ("A" <= c <= "Z")
        return False

    def _iff_type_char_press(ch: str) -> bool:
        field = _iff_selected_field()
        if field is None:
            return False
        if not _iff_field_is_editable(field):
            return False
        c = str(ch).upper()[:1]
        if not _iff_allowed_char(field, c):
            return False
        input_key = f"{field}_input"
        width = _iff_field_width(field)
        current = str(iff_state.get(input_key, ""))
        chars = list(current)
        cursor = max(0, min(len(chars), int(iff_state.get("input_cursor", len(chars)))))
        comp_idx = int(iff_state.get("input_comp_idx", -1))
        idx = max(0, comp_idx + 1) if comp_idx >= 0 else cursor
        if idx >= width:
            _iff_clear_comp_state()
            return True
        if idx >= len(chars):
            chars.append(c)
        else:
            chars.insert(idx, c)
        if len(chars) > width:
            chars = chars[:width]
        iff_state[input_key] = "".join(chars)
        iff_state["input_cursor"] = min(width, idx + 1)
        _iff_clear_comp_state()
        return True

    def finalize_iff_data_entry(field: str, now_ms: Optional[int] = None) -> None:
        input_key = f"{field}_input"
        raw_input = str(iff_state.get(input_key, ""))
        raw = "".join(ch for ch in raw_input if ch.isdigit())
        width = _iff_field_width(field)
        if field in {"mode_s_addr", "mode_s_acid"}:
            if field == "mode_s_addr":
                if _iff_get_addr_format() == "HEX":
                    filtered = "".join(ch for ch in raw_input.upper() if ch.isdigit() or ("A" <= ch <= "F"))
                else:
                    filtered = "".join(ch for ch in raw_input if ch in "01234567")
                if filtered != "":
                    iff_state[field] = filtered[-width:].rjust(width, "0")
            else:
                filtered = "".join(ch for ch in raw_input.upper() if ch.isdigit() or ("A" <= ch <= "Z"))
                if filtered != "":
                    iff_state[field] = filtered[-width:]
            iff_state["invalid_until_ms"] = 0
        else:
            if raw != "":
                raw = raw[-width:].rjust(width, "0")
                valid = True
                try:
                    value = int(raw, 8)
                except Exception:
                    value = 0
                    valid = False
                if valid and field == "mode1" and value > int("73", 8):
                    valid = False
                if valid and field in {"mode2", "mode3a", "mode4"} and value > int("7777", 8):
                    valid = False
                if valid:
                    iff_state[field] = raw
                    iff_state["invalid_until_ms"] = 0
                else:
                    if now_ms is None:
                        now_ms = int(iff_state.get("now_ms", 0))
                    iff_state["invalid_until_ms"] = int(now_ms) + 1500
        iff_state[input_key] = ""
        iff_state["input_cursor"] = 0
        _iff_clear_comp_state()
        if _iff_selected_field() == field:
            iff_state["selected_field"] = None

    def select_iff_data_entry(field: str, now_ms: Optional[int] = None) -> None:
        current = _iff_selected_field()
        if current == field:
            finalize_iff_data_entry(field, now_ms)
            return
        if current is not None:
            finalize_iff_data_entry(current, now_ms)
        iff_state["selected_field"] = field
        iff_state[f"{field}_input"] = ""
        iff_state["input_cursor"] = 0
        _iff_clear_comp_state()

    def iff_keypad_press(key: str) -> None:
        field = _iff_selected_field()
        if field is None:
            return
        if not _iff_field_is_editable(field):
            return
        input_key = f"{field}_input"
        current = str(iff_state.get(input_key, ""))
        width = _iff_field_width(field)

        if field in {"mode_s_addr", "mode_s_acid"}:
            chars = list(current)
            cursor = max(0, min(len(chars), int(iff_state.get("input_cursor", len(chars)))))
            comp_key = iff_state.get("input_comp_key")
            comp_idx = int(iff_state.get("input_comp_idx", -1))
            comp_cycle = int(iff_state.get("input_comp_cycle", 0))
            alpha_map = {
                "KP_2": "ABC2",
                "KP_3": "DEF3",
                "KP_4": "GHI4",
                "KP_5": "JKL5",
                "KP_6": "MNO6",
                "KP_7": "PQRS7",
                "KP_8": "TUV",
                "KP_9": "WXYZ",
            }
            if key in alpha_map:
                opts = [ch for ch in alpha_map[key] if _iff_allowed_char(field, ch)]
                if len(opts) == 0:
                    return
                if comp_key == key and 0 <= comp_idx < len(chars):
                    comp_cycle = (comp_cycle + 1) % len(opts)
                    chars[comp_idx] = opts[comp_cycle]
                    iff_state[input_key] = "".join(chars[:width])
                    iff_state["input_comp_cycle"] = comp_cycle
                    return
                idx = max(0, comp_idx + 1) if comp_idx >= 0 else cursor
                if idx >= width:
                    return
                ch0 = opts[0]
                if idx >= len(chars):
                    chars.append(ch0)
                else:
                    chars.insert(idx, ch0)
                if len(chars) > width:
                    chars = chars[:width]
                iff_state[input_key] = "".join(chars)
                iff_state["input_cursor"] = idx
                iff_state["input_comp_key"] = key
                iff_state["input_comp_idx"] = idx
                iff_state["input_comp_cycle"] = 0
                return
            if key in {"KP_0", "KP_1"}:
                _iff_type_char_press("0" if key == "KP_0" else "1")
                return
            if key == "KP_RIGHT":
                base = comp_idx if comp_idx >= 0 else cursor
                iff_state["input_cursor"] = max(0, min(width, base + 1))
                _iff_clear_comp_state()
                return
            if key == "KP_BACK":
                if comp_idx >= 0 and comp_idx < len(chars):
                    idx = comp_idx
                elif cursor > 0:
                    idx = cursor - 1
                else:
                    idx = 0
                if 0 <= idx < len(chars):
                    chars.pop(idx)
                    iff_state["input_cursor"] = idx
                iff_state[input_key] = "".join(chars)
                _iff_clear_comp_state()
                return
            return

        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7"}:
            digit = key.split("_", 1)[1]
            iff_state[input_key] = (current + digit)[-width:]
            _iff_clear_comp_state()
            return
        if key == "KP_BACK":
            iff_state[input_key] = current[:-1]
            _iff_clear_comp_state()
            return
        if key in {"KP_UP", "KP_DOWN"}:
            width = _iff_field_width(field)
            base = "".join(ch for ch in (current if current else str(iff_state.get(field, ""))) if ch.isdigit())
            if base == "":
                base = "0" * width
            base = base[-width:].rjust(width, "0")
            try:
                value = int(base, 8)
            except Exception:
                value = 0
            max_val = int("73", 8) if field == "mode1" else int("7777", 8)
            if key == "KP_UP":
                value = min(max_val, value + 1)
            else:
                value = max(0, value - 1)
            iff_state[input_key] = format(value, "o").rjust(width, "0")
            _iff_clear_comp_state()

    def iff_trigger_flash(key: str, until_ms: int) -> None:
        flash = iff_state.get("flash_until")
        if not isinstance(flash, dict):
            flash = {}
            iff_state["flash_until"] = flash
        flash[str(key)] = int(until_ms)

    def _alt_selected_field() -> Optional[str]:
        value = altitude_state.get("selected_field")
        return str(value) if value else None

    def _alt_field_width(field: str) -> int:
        return {"e1": 4, "e2": 4, "e4": 4}.get(field, 4)

    def _alt_format_inhg_from_digits(digits: str) -> str:
        raw = "".join(ch for ch in str(digits) if ch.isdigit())[-4:].rjust(4, "0")
        return f"{raw[0]}{raw[1]}.{raw[2]}{raw[3]}"

    def finalize_altitude_data_entry(field: str) -> None:
        input_key = f"{field}_input"
        raw = "".join(ch for ch in str(altitude_state.get(input_key, "")) if ch.isdigit())
        if field == "e1":
            if raw != "":
                altitude_state["baro_inhg"] = _alt_format_inhg_from_digits(raw)
                altitude_state["line1_value"] = str(altitude_state["baro_inhg"])
                altitude_state["line1_source"] = "E1"
        elif field == "e2":
            if raw != "":
                altitude_state["hpa"] = raw[-4:].rjust(4, "0")
                altitude_state["line1_value"] = str(altitude_state["hpa"])
                altitude_state["line1_source"] = "E2"
        elif field == "e4":
            if raw != "":
                altitude_state["alow"] = raw[-4:].rjust(4, "0")
        altitude_state[input_key] = ""
        if _alt_selected_field() == field:
            altitude_state["selected_field"] = None

    def select_altitude_data_entry(field: str) -> None:
        current = _alt_selected_field()
        if current == field:
            finalize_altitude_data_entry(field)
            return
        if current is not None:
            finalize_altitude_data_entry(current)
        altitude_state["selected_field"] = field
        altitude_state[f"{field}_input"] = ""

    def altitude_keypad_press(key: str) -> None:
        field = _alt_selected_field()
        if field is None:
            return
        input_key = f"{field}_input"
        current = "".join(ch for ch in str(altitude_state.get(input_key, "")) if ch.isdigit())
        width = _alt_field_width(field)
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            altitude_state[input_key] = (current + digit)[-width:]
            return
        if key == "KP_BACK":
            altitude_state[input_key] = current[:-1]
            return
        if key in {"KP_UP", "KP_DOWN"}:
            step = 1 if key == "KP_UP" else -1
            base_str = current
            if base_str == "":
                if field == "e1":
                    base_str = "".join(ch for ch in str(altitude_state.get("baro_inhg", "29.87")) if ch.isdigit())
                elif field == "e2":
                    base_str = "".join(ch for ch in str(altitude_state.get("hpa", "1013")) if ch.isdigit())
                else:
                    base_str = "".join(ch for ch in str(altitude_state.get("alow", "0000")) if ch.isdigit())
            try:
                val = int(base_str)
            except Exception:
                val = 0
            max_val = (10 ** width) - 1
            val = max(0, min(max_val, val + step))
            altitude_state[input_key] = str(val).rjust(width, "0")

    def altitude_trigger_flash(key: str, until_ms: int) -> None:
        flash = altitude_state.get("flash_until")
        if not isinstance(flash, dict):
            flash = {}
            altitude_state["flash_until"] = flash
        flash[str(key)] = int(until_ms)

    def _autopilot_state() -> Dict[str, object]:
        state = getattr(formats, "AUTOPILOT_STATE", {})
        if not isinstance(state, dict):
            state = {}
            formats.AUTOPILOT_STATE = state
        state.setdefault("att_hold", False)
        state.setdefault("hdg_sel", False)
        state.setdefault("hdg_value", "000")
        state.setdefault("hdg_input", "")
        state.setdefault("alt_hold", False)
        state.setdefault("alt_sel", False)
        state.setdefault("alt_value", "00000")
        state.setdefault("alt_input", "")
        state.setdefault("speed_hold", False)
        state.setdefault("speed_mode_options", ["IAS", "FLCH", "SPEED"])
        state.setdefault("speed_mode_idx", 0)
        state.setdefault("speed_menu_open", False)
        state.setdefault("speed_sel", False)
        state.setdefault("speed_value", "000")
        state.setdefault("speed_input", "")
        state.setdefault("rte_hold", False)
        state.setdefault("att_target_pitch_deg", None)
        state.setdefault("alt_hold_target_ft", None)
        state.setdefault("speed_hold_target_kts", None)
        state.setdefault("selected_field", None)
        state.setdefault("flash_until", {})
        state.setdefault("now_ms", 0)
        state["hdg_value"] = "".join(ch for ch in str(state.get("hdg_value", "000")) if ch.isdigit())[-3:].rjust(3, "0")
        state["alt_value"] = "".join(ch for ch in str(state.get("alt_value", "00000")) if ch.isdigit())[-5:].rjust(5, "0")
        state["speed_value"] = "".join(ch for ch in str(state.get("speed_value", "000")) if ch.isdigit())[-3:].rjust(3, "0")
        return state

    def _autopilot_selected_field() -> Optional[str]:
        state = _autopilot_state()
        value = state.get("selected_field")
        sval = str(value) if value else None
        return sval if sval in {"hdg", "alt", "speed"} else None

    def finalize_autopilot_data_entry(field: str) -> None:
        state = _autopilot_state()
        if field == "hdg":
            raw = "".join(ch for ch in str(state.get("hdg_input", "")) if ch.isdigit())
            if raw != "":
                state["hdg_value"] = raw[-3:].rjust(3, "0")
            state["hdg_input"] = ""
        elif field == "alt":
            raw = "".join(ch for ch in str(state.get("alt_input", "")) if ch.isdigit())
            if raw != "":
                state["alt_value"] = raw[-5:].rjust(5, "0")
            state["alt_input"] = ""
        elif field == "speed":
            raw = "".join(ch for ch in str(state.get("speed_input", "")) if ch.isdigit())
            if raw != "":
                state["speed_value"] = raw[-3:].rjust(3, "0")
            state["speed_input"] = ""
        if _autopilot_selected_field() == field:
            state["selected_field"] = None

    def select_autopilot_data_entry(field: str) -> None:
        state = _autopilot_state()
        current = _autopilot_selected_field()
        if current == field:
            finalize_autopilot_data_entry(field)
            return
        if current is not None:
            finalize_autopilot_data_entry(current)
        state["selected_field"] = field
        if field == "hdg":
            state["hdg_input"] = ""
        elif field == "alt":
            state["alt_input"] = ""
        elif field == "speed":
            state["speed_input"] = ""

    def autopilot_keypad_press(key: str) -> None:
        state = _autopilot_state()
        field = _autopilot_selected_field()
        if field is None:
            return
        if field == "hdg":
            input_key, width = "hdg_input", 3
        elif field == "alt":
            input_key, width = "alt_input", 5
        else:
            input_key, width = "speed_input", 3
        current = "".join(ch for ch in str(state.get(input_key, "")) if ch.isdigit())
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            state[input_key] = (current + digit)[-width:]
            return
        if key == "KP_BACK":
            state[input_key] = current[:-1]

    def autopilot_trigger_flash(key: str, until_ms: int) -> None:
        state = _autopilot_state()
        flash = state.get("flash_until")
        if not isinstance(flash, dict):
            flash = {}
            state["flash_until"] = flash
        flash[str(key)] = int(until_ms)

    def _crus_rolex_display(selected: bool) -> str:
        if not selected:
            return str(crus_state.get("rolex_value", "00:00:00"))
        mode = str(crus_state.get("rolex_mode", "roll"))
        slots = list("______")
        if mode == "segment":
            base = "".join(ch for ch in str(crus_state.get("rolex_value", "00:00:00")) if ch.isdigit())[-6:].rjust(6, "0")
            slots = list(base)
            seg_idx = max(0, min(2, int(crus_state.get("rolex_seg", 2))))
            seg_input = "".join(ch for ch in str(crus_state.get("rolex_seg_input", "")) if ch.isdigit())[-2:]
            if seg_input == "":
                seg_slots = ["0", "0"]
            elif len(seg_input) == 1:
                seg_slots = ["0", seg_input[0]]
            else:
                seg_slots = [seg_input[0], seg_input[1]]
            start = seg_idx * 2
            slots[start] = seg_slots[0]
            slots[start + 1] = seg_slots[1]
        else:
            raw = "".join(ch for ch in str(crus_state.get("rolex_raw", "")) if ch.isdigit())[-6:]
            start = 6 - len(raw)
            for i, ch in enumerate(raw):
                slots[start + i] = ch
        return f"{slots[0]}{slots[1]}:{slots[2]}{slots[3]}:{slots[4]}{slots[5]}"

    def _crus_finalize_rolex() -> None:
        if not bool(crus_state.get("rolex_selected", False)):
            return
        mode = str(crus_state.get("rolex_mode", "roll"))
        if mode == "segment":
            base = "".join(ch for ch in str(crus_state.get("rolex_value", "00:00:00")) if ch.isdigit())[-6:].rjust(6, "0")
            seg_idx = max(0, min(2, int(crus_state.get("rolex_seg", 2))))
            seg_input = "".join(ch for ch in str(crus_state.get("rolex_seg_input", "")) if ch.isdigit())[-2:]
            seg = list(seg_input.rjust(2, "0") if seg_input != "" else "00")
            slots = list(base)
            start = seg_idx * 2
            slots[start] = seg[0]
            slots[start + 1] = seg[1]
            raw = "".join(slots)
        else:
            raw = "".join(ch for ch in str(crus_state.get("rolex_raw", "")) if ch.isdigit())[-6:].rjust(6, "0")
        hh = raw[0:2]
        mm = raw[2:4]
        ss = raw[4:6]
        crus_state["rolex_value"] = f"{hh}:{mm}:{ss}"
        crus_state["rolex_raw"] = raw
        crus_state["rolex_mode"] = "roll"
        crus_state["rolex_roll_started"] = False
        crus_state["rolex_seg_input"] = ""
        crus_state["rolex_hh_input"] = ""
        crus_state["rolex_mm_input"] = ""
        crus_state["rolex_ss_input"] = ""
        crus_state["rolex_selected"] = False

    def _crus_select_rolex() -> None:
        if bool(crus_state.get("rolex_selected", False)):
            _crus_finalize_rolex()
        else:
            crus_state["rolex_selected"] = True
            committed = str(crus_state.get("rolex_value", "00:00:00"))
            crus_state["rolex_raw"] = "".join(ch for ch in committed if ch.isdigit())[-6:].rjust(6, "0")
            crus_state["rolex_mode"] = "roll"
            crus_state["rolex_roll_started"] = False
            crus_state["rolex_seg_input"] = ""
            crus_state["rolex_hh_input"] = ""
            crus_state["rolex_mm_input"] = ""
            crus_state["rolex_ss_input"] = ""
            crus_state["rolex_seg"] = 2

    def _crus_rolex_keypad_press(key: str) -> None:
        if not bool(crus_state.get("rolex_selected", False)):
            return
        seg_idx = max(0, min(2, int(crus_state.get("rolex_seg", 2))))
        mode = str(crus_state.get("rolex_mode", "roll"))
        raw = "".join(ch for ch in str(crus_state.get("rolex_raw", "")) if ch.isdigit())
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            if mode == "segment":
                seg_input = "".join(ch for ch in str(crus_state.get("rolex_seg_input", "")) if ch.isdigit())
                # Per-slot entry is right-to-left (ones first, then tens).
                crus_state["rolex_seg_input"] = (digit + seg_input)[:2]
            else:
                # First digit after selecting DE7 clears previous committed time.
                if not bool(crus_state.get("rolex_roll_started", False)):
                    raw = ""
                    crus_state["rolex_roll_started"] = True
                # Rolling overflow left across HH:MM:SS.
                crus_state["rolex_raw"] = (raw + digit)[-6:]
            return
        if key == "KP_BACK":
            if mode == "segment":
                seg_input = "".join(ch for ch in str(crus_state.get("rolex_seg_input", "")) if ch.isdigit())
                crus_state["rolex_seg_input"] = seg_input[1:] if len(seg_input) > 0 else ""
            else:
                crus_state["rolex_raw"] = raw[:-1]
            return
        if key == "KP_UP":
            crus_state["rolex_mode"] = "segment"
            crus_state["rolex_seg_input"] = ""
            crus_state["rolex_seg"] = (seg_idx - 1) % 3
            return
        if key == "KP_DOWN":
            crus_state["rolex_mode"] = "segment"
            crus_state["rolex_seg_input"] = ""
            crus_state["rolex_seg"] = (seg_idx + 1) % 3
            return

    def _crus_finalize_de1() -> None:
        if not bool(crus_state.get("de1_selected", False)):
            return
        raw = "".join(ch for ch in str(crus_state.get("de1_input", "")) if ch.isdigit())
        if raw != "":
            nav_state["de1_value"] = raw[-3:].rjust(3, "0")
        crus_state["de1_input"] = ""
        crus_state["de1_selected"] = False

    def _crus_select_de1() -> None:
        if bool(crus_state.get("de1_selected", False)):
            _crus_finalize_de1()
            return
        _crus_finalize_rolex()
        crus_state["de1_selected"] = True
        crus_state["de1_input"] = ""

    def _crus_de1_keypad_press(key: str) -> None:
        if not bool(crus_state.get("de1_selected", False)):
            return
        raw = "".join(ch for ch in str(crus_state.get("de1_input", "")) if ch.isdigit())
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            crus_state["de1_input"] = (raw + digit)[-3:]
            return
        if key == "KP_BACK":
            crus_state["de1_input"] = raw[:-1]
            return
        if key == "KP_UP":
            try:
                r_idx = int(nav_state.get("de1_r_idx", 1))
            except Exception:
                r_idx = 1
            nav_state["de1_r_idx"] = max(1, min(99, r_idx + 1))
            return
        if key == "KP_DOWN":
            try:
                r_idx = int(nav_state.get("de1_r_idx", 1))
            except Exception:
                r_idx = 1
            nav_state["de1_r_idx"] = max(1, min(99, r_idx - 1))
            return

    def _nav_selected_field() -> Optional[str]:
        value = nav_state.get("selected_field")
        return str(value) if value else None

    def _nav_format_freq(digits: str) -> str:
        raw = "".join(ch for ch in str(digits) if ch.isdigit())[-6:].rjust(6, "0")
        return f"{raw[:3]}.{raw[3:]}"

    def _nav_format_geo(digits: str) -> str:
        raw = "".join(ch for ch in str(digits) if ch.isdigit())[-7:].rjust(7, "0")
        return f"{raw[0]}.{raw[1:]}"

    def _nav_parse_tacan_channel_band(raw_channel: object) -> Optional[Tuple[int, str]]:
        text = str(raw_channel or "").strip().upper()
        if text == "":
            return None
        m = re.match(r"^0*([0-9]{1,3})([XY])$", text)
        if m is None:
            return None
        try:
            ch = int(m.group(1))
        except Exception:
            return None
        if ch < 1 or ch > 126:
            return None
        band = str(m.group(2)).upper().strip()
        if band not in {"X", "Y"}:
            return None
        return int(ch), str(band)

    def _nav_mode_allows_ground_tacan(mode: object) -> bool:
        return str(mode or "").upper().strip() in {"RECV", "T/R"}

    def _nav_tacan_max_range_nm(mode: object) -> float:
        return 260.0 if str(mode or "").upper().strip() == "T/R" else 220.0

    def _nav_selector_tacan() -> Tuple[int, str, str]:
        raw_channel = "".join(ch for ch in str(nav_state.get("c1_value", "001")) if ch.isdigit())
        try:
            channel = int(raw_channel) if raw_channel != "" else 1
        except Exception:
            channel = 1
        channel = max(0, min(126, int(channel)))
        band = "Y" if int(nav_state.get("c2_mode", 0)) == 1 else "X"
        options = nav_state.get("c3_options", ["RECV", "T/R", "A-A RCV", "A-A T/R"])
        if not isinstance(options, list) or len(options) <= 0:
            options = ["RECV", "T/R", "A-A RCV", "A-A T/R"]
        try:
            idx = max(0, min(len(options) - 1, int(nav_state.get("c3_idx", 0))))
        except Exception:
            idx = 0
        mode = str(options[idx]).upper().strip()
        return int(channel), str(band), str(mode)

    def _nav_own_lat_lon() -> Optional[Tuple[float, float]]:
        snap = getattr(formats, "TSD_ADSB_STATE", {})
        if not isinstance(snap, dict):
            return None
        lat = _safe_float_or_none(snap.get("lat"))
        lon = _safe_float_or_none(snap.get("lon"))
        if lat is None or lon is None:
            geo = snap.get("geo")
            if isinstance(geo, dict):
                lat = _safe_float_or_none(geo.get("lat"))
                lon = _safe_float_or_none(geo.get("lon"))
        if lat is None or lon is None:
            return None
        return float(lat), float(lon)

    def _nav_clear_tacan_ils_context() -> None:
        nav_state["de1_ils_active"] = False
        nav_state["de1_ils_runway"] = ""
        nav_state["ils_tacan_airport"] = ""
        nav_state["ils_tacan_entries"] = []
        nav_state["ils_tacan_index"] = 1
        nav_state["ils_tacan_signature"] = ""

    def _nav_ils_entries() -> List[Dict[str, str]]:
        entries_raw = nav_state.get("ils_tacan_entries", [])
        if not isinstance(entries_raw, list):
            return []
        out: List[Dict[str, str]] = []
        for item in entries_raw:
            if isinstance(item, dict):
                out.append(
                    {
                        "runway": str(item.get("runway", "")).strip().upper(),
                        "freq_text": str(item.get("freq_text", "")).strip(),
                    }
                )
        return out

    def _nav_has_tacan_ils_context() -> bool:
        if str(nav_state.get("submenu", "")) not in {"", "NONE", "None"} and nav_state.get("submenu") is not None:
            return False
        if not bool(nav_state.get("de1_ils_active", False)):
            return False
        return len(_nav_ils_entries()) > 0

    def _nav_apply_tacan_ils_index(idx_1_based: int) -> bool:
        entries = _nav_ils_entries()
        if len(entries) <= 0:
            return False
        idx = max(1, min(len(entries), int(idx_1_based)))
        chosen = entries[idx - 1]
        nav_state["ils_tacan_index"] = int(idx)
        nav_state["de1_ils_runway"] = str(chosen.get("runway", "")).strip().upper()
        nav_state["b1_value"] = str(chosen.get("freq_text", "")).strip()
        nav_state["b1_input"] = ""
        return True

    def _nav_sync_tacan_ils_binding(*, reset_index: bool = False) -> None:
        channel, band, mode = _nav_selector_tacan()
        if int(channel) < 1 or not _nav_mode_allows_ground_tacan(mode):
            _nav_clear_tacan_ils_context()
            return
        own = _nav_own_lat_lon()
        if own is None:
            _nav_clear_tacan_ils_context()
            return
        own_lat, own_lon = own
        navaids = formats.Tsd1Format._load_tacan_vor_navaids()
        best_nav: Optional[Dict[str, object]] = None
        best_lat = 0.0
        best_lon = 0.0
        best_dist = float("inf")
        max_range_nm = _nav_tacan_max_range_nm(mode)
        for nav in navaids:
            if not isinstance(nav, dict):
                continue
            nav_type = str(nav.get("type") or "").upper().strip()
            if ("TACAN" not in nav_type) and (nav_type != "VORTAC"):
                continue
            nav_chan = formats.Tsd1Format._format_tacan_channel(nav.get("dme_channel"))
            parsed = _nav_parse_tacan_channel_band(nav_chan)
            if parsed is None:
                continue
            nav_channel, nav_band = parsed
            if int(nav_channel) != int(channel) or str(nav_band) != str(band):
                continue
            lat = _safe_float_or_none(nav.get("lat"))
            lon = _safe_float_or_none(nav.get("lon"))
            if lat is None or lon is None:
                continue
            _bearing, dist_nm = formats.Tsd1Format._bearing_and_distance_nm(
                float(own_lat),
                float(own_lon),
                float(lat),
                float(lon),
            )
            if float(dist_nm) > float(max_range_nm):
                continue
            if float(dist_nm) < best_dist:
                best_dist = float(dist_nm)
                best_nav = nav
                best_lat = float(lat)
                best_lon = float(lon)
        if not isinstance(best_nav, dict):
            _nav_clear_tacan_ils_context()
            return
        airport_ident = ""
        try:
            helper = formats.EfiFormat()
            airport_ident = str(helper._resolve_tacan_airport_ident(best_nav, float(best_lat), float(best_lon)))
        except Exception:
            airport_ident = str(best_nav.get("associated_airport") or "")
        airport_ident = airport_ident.strip().upper()
        if airport_ident == "":
            _nav_clear_tacan_ils_context()
            return
        ils_by_airport = formats.Tsd1Format._load_faa_ils_by_airport()
        airport_entries_raw = ils_by_airport.get(airport_ident, []) if isinstance(ils_by_airport, dict) else []
        airport_entries = airport_entries_raw if isinstance(airport_entries_raw, list) else []
        entries: List[Dict[str, str]] = []
        for item in airport_entries:
            if not isinstance(item, dict):
                continue
            runway = str(item.get("runway_end_id") or item.get("runway_id") or "").strip().upper()
            try:
                freq = float(item.get("loc_freq_mhz", 0.0))
            except Exception:
                freq = 0.0
            freq_text = str(item.get("loc_freq_text") or "").strip()
            if freq <= 0.0 and freq_text == "":
                continue
            if freq_text == "":
                freq_text = f"{float(freq):.2f}"
            entries.append({"runway": runway, "freq_text": freq_text})
        if len(entries) <= 0:
            _nav_clear_tacan_ils_context()
            return
        signature = f"{int(channel):03d}{str(band)}:{str(mode)}:{airport_ident}"
        nav_state["de1_ils_active"] = True
        nav_state["ils_tacan_airport"] = airport_ident
        nav_state["ils_tacan_entries"] = entries
        prev_sig = str(nav_state.get("ils_tacan_signature", "")).strip()
        nav_state["ils_tacan_signature"] = signature
        if reset_index or prev_sig != signature:
            idx = 1
        else:
            try:
                idx = int(nav_state.get("ils_tacan_index", 1))
            except Exception:
                idx = 1
        _nav_apply_tacan_ils_index(idx)

    def finalize_nav_data_entry(field: str) -> None:
        if field == "a1":
            raw = "".join(ch for ch in str(nav_state.get("a1_input", "")) if ch.isdigit())
            if raw != "":
                nav_state["a1_value"] = _nav_format_freq(raw)
            nav_state["a1_input"] = ""
        elif field == "b1":
            raw = "".join(ch for ch in str(nav_state.get("b1_input", "")) if ch.isdigit())
            if raw != "":
                nav_state["b1_value"] = _nav_format_freq(raw)
            nav_state["b1_input"] = ""
        elif field == "c1":
            raw = "".join(ch for ch in str(nav_state.get("c1_input", "")) if ch.isdigit())
            if raw != "":
                nav_state["c1_value"] = raw[-3:].rjust(3, "0")
            nav_state["c1_input"] = ""
            _nav_sync_tacan_ils_binding(reset_index=True)
        elif field == "de1":
            raw = "".join(ch for ch in str(nav_state.get("de1_input", "")) if ch.isdigit())
            if _nav_has_tacan_ils_context():
                if raw != "":
                    try:
                        idx = int(raw)
                    except Exception:
                        idx = int(nav_state.get("ils_tacan_index", 1))
                    _nav_apply_tacan_ils_index(idx)
                nav_state["de1_input"] = ""
            else:
                if raw != "":
                    nav_state["de1_value"] = raw[-3:].rjust(3, "0")
                nav_state["de1_input"] = ""
        elif field == "de2":
            line = str(nav_state.get("de2_edit_line", "N")).upper()
            key = "de2_n_input" if line == "N" else "de2_e_input"
            raw = "".join(ch for ch in str(nav_state.get(key, "")) if ch.isdigit())
            if raw != "":
                if line == "N":
                    nav_state["de2_n"] = _nav_format_geo(raw)
                else:
                    nav_state["de2_e"] = _nav_format_geo(raw)
            nav_state["de2_n_input"] = ""
            nav_state["de2_e_input"] = ""
        elif field == "ref_e1":
            raw = "".join(ch for ch in str(nav_state.get("ref_e1_input", "")) if ch.isdigit())
            if raw != "":
                nav_state["ref_e1_value"] = raw[-3:].rjust(3, "0")
            nav_state["ref_e1_input"] = ""
        elif field == "ref_de5":
            raw = "".join(ch for ch in str(nav_state.get("ref_de5_input", "")) if ch.isdigit())
            if raw != "":
                nav_state["ref_de5_value"] = raw[-1:]
            nav_state["ref_de5_input"] = ""
        elif field == "ref_de6":
            raw = "".join(ch for ch in str(nav_state.get("ref_de6_input", "")) if ch.isdigit())
            if raw != "":
                nav_state["ref_de6_value"] = raw[-1:]
            nav_state["ref_de6_input"] = ""
        elif field == "ref_de7":
            raw = "".join(ch for ch in str(nav_state.get("ref_de7_input", "")) if ch.isdigit())
            if raw != "":
                nav_state["ref_de7_value"] = raw[-1:]
            nav_state["ref_de7_input"] = ""
        if _nav_selected_field() == field:
            nav_state["selected_field"] = None

    def select_nav_data_entry(field: str) -> None:
        current = _nav_selected_field()
        if current == field:
            finalize_nav_data_entry(field)
            return
        if current is not None:
            finalize_nav_data_entry(current)
        nav_state["selected_field"] = field
        if field == "a1":
            nav_state["a1_input"] = ""
        elif field == "b1":
            nav_state["b1_input"] = ""
        elif field == "c1":
            nav_state["c1_input"] = ""
        elif field == "de1":
            nav_state["de1_input"] = ""
        elif field == "de2":
            nav_state["de2_n_input"] = ""
            nav_state["de2_e_input"] = ""
            nav_state["de2_edit_line"] = str(nav_state.get("de2_edit_line", "N")).upper()
        elif field == "ref_e1":
            nav_state["ref_e1_input"] = ""
        elif field == "ref_de5":
            nav_state["ref_de5_input"] = ""
        elif field == "ref_de6":
            nav_state["ref_de6_input"] = ""
        elif field == "ref_de7":
            nav_state["ref_de7_input"] = ""

    def finalize_all_nav_data_entries() -> None:
        current = _nav_selected_field()
        if current is not None:
            finalize_nav_data_entry(current)

    def nav_keypad_press(key: str) -> None:
        field = _nav_selected_field()
        if field is None:
            return
        if field == "a1":
            input_key, width = "a1_input", 6
        elif field == "b1":
            input_key, width = "b1_input", 6
        elif field == "c1":
            input_key, width = "c1_input", 3
        elif field == "de1":
            input_key, width = "de1_input", 3
        elif field == "ref_e1":
            input_key, width = "ref_e1_input", 3
        elif field == "ref_de5":
            input_key, width = "ref_de5_input", 1
        elif field == "ref_de6":
            input_key, width = "ref_de6_input", 1
        elif field == "ref_de7":
            input_key, width = "ref_de7_input", 1
        else:
            line = str(nav_state.get("de2_edit_line", "N")).upper()
            input_key, width = ("de2_n_input", 7) if line == "N" else ("de2_e_input", 7)

        current = "".join(ch for ch in str(nav_state.get(input_key, "")) if ch.isdigit())
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            nav_state[input_key] = (current + digit)[-width:]
            return
        if key == "KP_BACK":
            nav_state[input_key] = current[:-1]
            return
        if field == "de1" and key in {"KP_UP", "KP_DOWN"}:
            if _nav_has_tacan_ils_context():
                try:
                    idx = int(nav_state.get("ils_tacan_index", 1))
                except Exception:
                    idx = 1
                idx += 1 if key == "KP_UP" else -1
                _nav_apply_tacan_ils_index(idx)
            else:
                try:
                    r_idx = int(nav_state.get("de1_r_idx", 1))
                except Exception:
                    r_idx = 1
                r_idx += 1 if key == "KP_UP" else -1
                nav_state["de1_r_idx"] = max(1, min(99, r_idx))
            return
        if field == "ref_e1" and key in {"KP_UP", "KP_DOWN"}:
            try:
                v = int(nav_state.get("ref_e1_value", "000"))
            except Exception:
                v = 0
            v += 1 if key == "KP_UP" else -1
            nav_state["ref_e1_value"] = str(max(0, min(999, v))).rjust(3, "0")
            return
        if field == "de2" and key in {"KP_UP", "KP_DOWN"}:
            nav_state["de2_edit_line"] = "N" if key == "KP_UP" else "E"

    def _ins_coord_format_digits(raw_digits: str, is_lat: bool) -> str:
        digits = "".join(ch for ch in str(raw_digits) if ch.isdigit())
        if is_lat:
            digits = digits[-8:].rjust(8, "0")
            return f"{digits[:2]} {digits[2:4]}.{digits[4:]}"
        digits = digits[-9:].rjust(9, "0")
        return f"{digits[:3]} {digits[3:5]}.{digits[5:]}"

    def _ins_coord_scratch(raw_digits: str, is_lat: bool) -> str:
        digits = "".join(ch for ch in str(raw_digits) if ch.isdigit())
        width = 8 if is_lat else 9
        digits = digits[-width:]
        slots = list("_" * width)
        for idx, ch in enumerate(digits):
            slots[idx] = ch
        if is_lat:
            return f"{slots[0]}{slots[1]} {slots[2]}{slots[3]}.{''.join(slots[4:])}"
        return f"{slots[0]}{slots[1]}{slots[2]} {slots[3]}{slots[4]}.{''.join(slots[5:])}"

    def _ins_coord_decimal_from_digits(raw_digits: str, is_lat: bool, hemi: str) -> float:
        digits = "".join(ch for ch in str(raw_digits) if ch.isdigit())
        deg_w = 2 if is_lat else 3
        width = 8 if is_lat else 9
        max_deg = 90 if is_lat else 180
        digits = digits[-width:].rjust(width, "0")
        deg = max(0, min(max_deg, int(digits[:deg_w])))
        mins_int = int(digits[deg_w:deg_w + 2])
        mins_frac = int(digits[deg_w + 2:deg_w + 6])
        mins = float(mins_int) + (float(mins_frac) / 10000.0)
        if mins >= 60.0:
            mins = 59.9999
        if deg >= max_deg:
            deg = max_deg
            mins = 0.0
        out = float(deg) + (mins / 60.0)
        hemi_u = str(hemi).upper()
        if hemi_u in {"S", "W"}:
            out = -out
        return out

    def _ins_coord_digits_from_decimal(value: float, is_lat: bool) -> Tuple[str, str]:
        lat_mode = bool(is_lat)
        hemi_pos, hemi_neg = ("N", "S") if lat_mode else ("E", "W")
        max_deg = 90 if lat_mode else 180
        deg_w = 2 if lat_mode else 3
        v = abs(float(value))
        deg = int(v)
        mins = (v - float(deg)) * 60.0
        mins = round(mins, 4)
        if mins >= 60.0:
            mins = 0.0
            deg += 1
        if deg > max_deg:
            deg = max_deg
            mins = 0.0
        mins_txt = f"{mins:07.4f}"
        mins_digits = mins_txt.replace(".", "")
        out_digits = f"{deg:0{deg_w}d}{mins_digits}"
        hemi = hemi_pos if float(value) >= 0.0 else hemi_neg
        width = 8 if lat_mode else 9
        return hemi, out_digits[-width:].rjust(width, "0")

    def _ins_coord_digits_from_line(line_value: object, is_lat: bool) -> str:
        digits = "".join(ch for ch in str(line_value) if ch.isdigit())
        width = 8 if is_lat else 9
        return digits[-width:].rjust(width, "0")

    def _ins_coord_decimal_from_text(raw_value: object, is_lat: bool, default_hemi: str) -> Optional[float]:
        text = str(raw_value or "").strip().upper()
        if text == "":
            return None
        max_deg = 90.0 if bool(is_lat) else 180.0
        hemi = str(default_hemi or "").strip().upper()
        explicit_hemi = ""
        for ch in text:
            if bool(is_lat) and ch in {"N", "S"}:
                explicit_hemi = ch
                break
            if (not bool(is_lat)) and ch in {"E", "W"}:
                explicit_hemi = ch
                break
        sign = -1.0 if ("-" in text) else 1.0
        if explicit_hemi in {"S", "W"}:
            sign = -1.0
        elif explicit_hemi in {"N", "E"}:
            sign = 1.0
        elif hemi in {"S", "W"}:
            sign = -1.0
        cleaned = "".join(ch for ch in text if ch.isdigit() or ch in {".", "-", "+"})
        if cleaned in {"", "-", "+", ".", "-.", "+."}:
            return None
        try:
            value_abs = abs(float(cleaned))
        except Exception:
            return None
        value_abs = max(0.0, min(max_deg, float(value_abs)))
        return float(value_abs * sign)

    def _ins_gps_option_text(options: List[str], idx_value: object, fallback_idx: int = 0) -> str:
        opts = [str(v).strip().upper() for v in options if str(v).strip() != ""]
        if len(opts) <= 0:
            return ""
        try:
            idx = int(idx_value)
        except Exception:
            idx = int(fallback_idx)
        idx = max(0, min(len(opts) - 1, idx))
        return str(opts[idx])

    def _ins_gps_master_mode() -> str:
        return _ins_gps_option_text(INS_GPS_MODE_OPTIONS, ins_gps_state.get("a1_mode_idx", 1), 1) or "NAV"

    def _ins_gps_nav_output_allowed(master_mode: str, nav_output: str) -> bool:
        master = str(master_mode).upper().strip()
        output = str(nav_output).upper().strip()
        if output not in {"STBY", "ATT", "NAV"}:
            return False
        if master == "STBY":
            return output == "STBY"
        if master == "ALIGN":
            return output in {"STBY", "ATT"}
        if master in {"NAV", "COMP", "SEC"}:
            return output in {"STBY", "ATT", "NAV"}
        return output == "STBY"

    def _ins_gps_set_nav_output_mode(target_mode: str) -> bool:
        mode = str(target_mode).upper().strip()
        if mode not in {"STBY", "ATT", "NAV"}:
            return False
        master_mode = _ins_gps_master_mode()
        if not _ins_gps_nav_output_allowed(master_mode, mode):
            return False
        ins_gps_state["nav_output_mode"] = mode
        return True

    def _ins_gps_normalize_mode_state() -> None:
        try:
            mode_idx = int(ins_gps_state.get("a1_mode_idx", 1))
        except Exception:
            mode_idx = 1
        mode_idx = max(0, min(len(INS_GPS_MODE_OPTIONS) - 1, mode_idx))
        ins_gps_state["a1_mode_idx"] = int(mode_idx)

        nav_mode = str(ins_gps_state.get("nav_output_mode", "NAV")).upper().strip()
        if nav_mode not in {"STBY", "ATT", "NAV"}:
            nav_mode = "NAV"
        master_mode = _ins_gps_master_mode()
        if not _ins_gps_nav_output_allowed(master_mode, nav_mode):
            nav_mode = "STBY" if master_mode == "STBY" else ("ATT" if master_mode == "ALIGN" else "NAV")
        ins_gps_state["nav_output_mode"] = nav_mode

        for key, options in (
            ("align_profile_idx", INS_GPS_ALIGN_PROFILE_OPTIONS),
            ("gps_aiding_idx", INS_GPS_GPS_AIDING_OPTIONS),
            ("fix_source_idx", INS_GPS_FIX_SOURCE_OPTIONS),
            ("nav_filter_idx", INS_GPS_NAV_FILTER_OPTIONS),
            ("magvar_mode_idx", INS_GPS_MAGVAR_MODE_OPTIONS),
            ("wypt_source_idx", INS_GPS_WYPT_SOURCE_OPTIONS),
        ):
            try:
                idx = int(ins_gps_state.get(key, 0))
            except Exception:
                idx = 0
            idx = max(0, min(len(options) - 1, idx))
            ins_gps_state[key] = int(idx)

        try:
            qual = float(ins_gps_state.get("align_quality", 0.98))
        except Exception:
            qual = 0.98
        ins_gps_state["align_quality"] = max(0.0, min(1.0, qual))
        try:
            tsec = float(ins_gps_state.get("align_time_sec", 0.0))
        except Exception:
            tsec = 0.0
        ins_gps_state["align_time_sec"] = max(0.0, tsec)

    def _update_ins_gps_runtime(dt_seconds: object) -> None:
        _ins_gps_normalize_mode_state()
        try:
            dt_s = float(dt_seconds)
        except Exception:
            dt_s = 0.0
        if dt_s <= 0.0:
            return

        master_mode = _ins_gps_master_mode()
        profile = _ins_gps_option_text(INS_GPS_ALIGN_PROFILE_OPTIONS, ins_gps_state.get("align_profile_idx", 0), 0)
        gps_aiding = _ins_gps_option_text(INS_GPS_GPS_AIDING_OPTIONS, ins_gps_state.get("gps_aiding_idx", 0), 0)
        nav_filter = _ins_gps_option_text(INS_GPS_NAV_FILTER_OPTIONS, ins_gps_state.get("nav_filter_idx", 0), 0)
        ima_on = bool(ins_gps_state.get("c5_on", False))

        try:
            qual = float(ins_gps_state.get("align_quality", 0.98))
        except Exception:
            qual = 0.98
        try:
            tsec = float(ins_gps_state.get("align_time_sec", 0.0))
        except Exception:
            tsec = 0.0

        align_rate_by_profile = {
            "NORM": 0.010,
            "FINE": 0.006,
            "FAST": 0.020,
            "STOR": 0.014,
        }
        if master_mode == "ALIGN":
            tsec += dt_s
            qual += float(align_rate_by_profile.get(profile, 0.010)) * dt_s
        else:
            # Minor drift without aiding / integration; mild recovery with aiding.
            if gps_aiding == "OFF" or (not ima_on):
                qual -= 0.0018 * dt_s
            elif gps_aiding == "ON":
                qual += 0.0009 * dt_s
            else:  # AUTO
                qual += 0.0004 * dt_s

        if nav_filter == "TIGHT":
            qual -= 0.0003 * dt_s
        elif nav_filter == "SMTH":
            qual += 0.0002 * dt_s

        if bool(ins_gps_state.get("ins_fail_active", False)):
            qual = 0.0
        elif bool(ins_gps_state.get("ins_degd_active", False) or ins_gps_state.get("nav_degd_active", False)):
            qual = min(qual, 0.72)
        if bool(ins_gps_state.get("gps_degd_active", False)):
            qual = min(qual, 0.88)

        ins_gps_state["align_quality"] = max(0.0, min(1.0, qual))
        ins_gps_state["align_time_sec"] = max(0.0, tsec)
        _ins_gps_normalize_mode_state()

    def _set_ins_gps_position(lat: object, lon: object, set_manual_override: Optional[bool], publish_runtime: bool) -> None:
        lat_f = _safe_float_or_none(lat)
        lon_f = _safe_float_or_none(lon)
        if lat_f is None or lon_f is None:
            return
        lat_hemi, lat_digits = _ins_coord_digits_from_decimal(lat_f, True)
        lon_hemi, lon_digits = _ins_coord_digits_from_decimal(lon_f, False)
        ins_gps_state["lat_hem"] = lat_hemi
        ins_gps_state["lon_hem"] = lon_hemi
        ins_gps_state["lon"] = f"{lat_hemi} {_ins_coord_format_digits(lat_digits, True)}"
        ins_gps_state["lat"] = f"{lon_hemi} {_ins_coord_format_digits(lon_digits, False)}"
        ins_gps_state["position_lat"] = float(lat_f)
        ins_gps_state["position_lon"] = float(lon_f)
        if set_manual_override is not None:
            ins_gps_state["manual_position"] = bool(set_manual_override)
        if publish_runtime:
            with adsb_runtime_lock:
                adsb_runtime["lat"] = float(lat_f)
                adsb_runtime["lon"] = float(lon_f)
                if set_manual_override is not None:
                    adsb_runtime["manual_position"] = bool(set_manual_override)
                geo_raw = adsb_runtime.get("geo")
                if isinstance(geo_raw, dict):
                    geo = dict(geo_raw)
                    geo["lat"] = float(lat_f)
                    geo["lon"] = float(lon_f)
                    adsb_runtime["geo"] = geo
            _publish_adsb_runtime()

    def _place_aircraft_on_startup_runway(hot_start: bool) -> None:
        if bool(pmd_dr_state.get("startup_runway_spawn_applied", False)):
            return
        lat = _safe_float_or_none(ins_gps_state.get("position_lat"))
        lon = _safe_float_or_none(ins_gps_state.get("position_lon"))
        if lat is None or lon is None:
            with adsb_runtime_lock:
                lat = _safe_float_or_none(adsb_runtime.get("lat"))
                lon = _safe_float_or_none(adsb_runtime.get("lon"))
        if lat is None or lon is None:
            return

        runway = None
        try:
            runway = formats.Tsd1Format.nearest_military_runway(float(lat), float(lon))
        except Exception:
            runway = None
        if not isinstance(runway, dict):
            return
        spawn = None
        try:
            spawn = formats.Tsd1Format.spawn_point_for_runway(runway)
        except Exception:
            spawn = None
        if not isinstance(spawn, dict):
            return
        spawn_lat = _safe_float_or_none(spawn.get("lat"))
        spawn_lon = _safe_float_or_none(spawn.get("lon"))
        heading = _safe_float_or_none(spawn.get("heading_deg"))
        if spawn_lat is None or spawn_lon is None or heading is None:
            return

        _set_ins_gps_position(float(spawn_lat), float(spawn_lon), set_manual_override=True, publish_runtime=True)
        heading = float(heading) % 360.0
        panel = _ensure_panel_button_states()
        aircraft = panel.get("AIRCRAFT", {}) if isinstance(panel, dict) else {}
        if not isinstance(aircraft, dict):
            aircraft = {}
            panel["AIRCRAFT"] = aircraft
        for key in ("HEADING_DEG", "HDG_DEG", "HEADING", "HDG"):
            aircraft[key] = float(heading)
        aircraft["ATT_HEADING_BASE_DEG"] = float(heading)
        q_reset = _quat_from_axis_angle((0.0, 0.0, 1.0), math.radians(-float(heading)))
        aircraft["ATT_Q_W"] = float(q_reset[0])
        aircraft["ATT_Q_X"] = float(q_reset[1])
        aircraft["ATT_Q_Y"] = float(q_reset[2])
        aircraft["ATT_Q_Z"] = float(q_reset[3])
        aircraft["ATT_PITCH_RAW_DEG"] = 0.0
        aircraft["ATT_ROLL_RAW_DEG"] = 0.0
        aircraft["ATT_PITCH_DEG"] = 0.0
        aircraft["ATT_ROLL_DEG"] = 0.0
        aircraft["ATT_YAW_RATE_DPS"] = 0.0
        aircraft["PITCH"] = 0.0
        aircraft["YAW"] = 0.0
        aircraft["ROLL"] = 0.0
        aircraft["ATTITUDE"] = 0.0
        aircraft["BANK"] = 0.0
        if not bool(hot_start):
            aircraft["ALTITUDE_FT"] = 0.0
            aircraft["ALTITUDE_TARGET_FT"] = 0.0
            aircraft["VERTICAL_SPEED_FPM"] = 0.0
        try:
            speed_kts = max(0.0, float(aircraft.get("AIRSPEED_KTS", 0.0) or 0.0))
        except Exception:
            speed_kts = 0.0
        speed_fps = speed_kts / float(KTS_PER_FPS)
        hdg_rad = math.radians(float(heading))
        aircraft["VEL_X_FPS"] = float(speed_fps * math.sin(hdg_rad))
        aircraft["VEL_Y_FPS"] = float(speed_fps * math.cos(hdg_rad))
        aircraft["VEL_Z_FPS"] = 0.0
        try:
            twd_state = getattr(formats, "TWD_STATE", {})
            if isinstance(twd_state, dict):
                twd_state["heading_deg"] = float(heading)
        except Exception:
            pass
        pmd_dr_state["startup_runway_spawn_applied"] = True
        airport_ident = str(runway.get("airport_ident") or "").strip().upper()
        airport_name = str(runway.get("airport_name") or "").strip()
        runway_label = f"{str(runway.get('le_ident') or '').strip()}/{str(runway.get('he_ident') or '').strip()}".strip("/")
        pmd_dr_state["startup_runway_spawn"] = {
            "airport_ident": airport_ident,
            "airport_name": airport_name,
            "runway": runway_label,
            "lat": float(spawn_lat),
            "lon": float(spawn_lon),
            "heading_deg": float(heading),
        }
        print(
            f"[STARTUP RUNWAY] {airport_name if airport_name else 'Unknown airport'} | "
            f"ICAO {airport_ident if airport_ident else '----'} | "
            f"RWY {runway_label if runway_label else '----'} | HDG {heading:03.0f}"
        )

    def _project_lat_lon_nm(lat_deg: float, lon_deg: float, heading_deg: float, distance_nm: float) -> Tuple[float, float]:
        if distance_nm <= 0.0:
            return float(lat_deg), float(lon_deg)
        radius_km = 6371.0088
        dist_km = float(distance_nm) * 1.852
        angular = dist_km / radius_km
        lat1 = math.radians(float(lat_deg))
        lon1 = math.radians(float(lon_deg))
        brg = math.radians(float(heading_deg) % 360.0)
        sin_lat2 = math.sin(lat1) * math.cos(angular) + math.cos(lat1) * math.sin(angular) * math.cos(brg)
        lat2 = math.asin(max(-1.0, min(1.0, sin_lat2)))
        lon2 = lon1 + math.atan2(
            math.sin(brg) * math.sin(angular) * math.cos(lat1),
            math.cos(angular) - math.sin(lat1) * math.sin(lat2),
        )
        lon2 = (lon2 + math.pi) % (2.0 * math.pi) - math.pi
        return float(math.degrees(lat2)), float(math.degrees(lon2))

    def _update_ownship_geo_from_motion(dt_seconds: object) -> None:
        dbg_emit = False

        dbg_speed_kts = 0.0
        dbg_heading_deg = 35.0
        dbg_old_lat: Optional[float] = None
        dbg_old_lon: Optional[float] = None
        dbg_new_lat: Optional[float] = None
        dbg_new_lon: Optional[float] = None
        dbg_reason = "ok"

        def _fmt_coord(v: Optional[float]) -> str:
            if v is None:
                return "None"
            try:
                return f"{float(v):.6f}"
            except Exception:
                return "None"

        try:
            dt_s = float(dt_seconds)
        except Exception:
            dt_s = 0.0
        if dt_s <= 0.0:
            dbg_reason = "dt<=0"
            if dbg_emit:
                print(
                    f"OWNSHIP GEO DBG: spd={dbg_speed_kts:.2f} hdg={dbg_heading_deg:.2f} "
                    f"old=({_fmt_coord(dbg_old_lat)},{_fmt_coord(dbg_old_lon)}) "
                    f"new=({_fmt_coord(dbg_new_lat)},{_fmt_coord(dbg_new_lon)}) reason={dbg_reason}"
                )
            return
        # Do not move the reference position while user is actively editing coordinates.
        if (
            bool(ins_gps_state.get("de1_selected", False))
            and bool(status_menu_popup_active)
            and str(status_menu_active_submenu) in {"INS_GPS", "PMD_DR_GPS_DEBUG"}
        ):
            dbg_reason = "ins_edit_active"
            if dbg_emit:
                try:
                    dbg_old_lat = _safe_float_or_none(ins_gps_state.get("position_lat"))
                    dbg_old_lon = _safe_float_or_none(ins_gps_state.get("position_lon"))
                except Exception:
                    pass
                dbg_new_lat = dbg_old_lat
                dbg_new_lon = dbg_old_lon
                print(
                    f"OWNSHIP GEO DBG: spd={dbg_speed_kts:.2f} hdg={dbg_heading_deg:.2f} "
                    f"old=({_fmt_coord(dbg_old_lat)},{_fmt_coord(dbg_old_lon)}) "
                    f"new=({_fmt_coord(dbg_new_lat)},{_fmt_coord(dbg_new_lon)}) reason={dbg_reason}"
                )
            return

        lat = _safe_float_or_none(ins_gps_state.get("position_lat"))
        lon = _safe_float_or_none(ins_gps_state.get("position_lon"))
        if lat is None or lon is None:
            with adsb_runtime_lock:
                lat = _safe_float_or_none(adsb_runtime.get("lat"))
                lon = _safe_float_or_none(adsb_runtime.get("lon"))
        if lat is None or lon is None:
            dbg_reason = "no_position"
            if dbg_emit:
                print(
                    f"OWNSHIP GEO DBG: spd={dbg_speed_kts:.2f} hdg={dbg_heading_deg:.2f} "
                    f"old=({_fmt_coord(dbg_old_lat)},{_fmt_coord(dbg_old_lon)}) "
                    f"new=({_fmt_coord(dbg_new_lat)},{_fmt_coord(dbg_new_lon)}) reason={dbg_reason}"
                )
            return
        dbg_old_lat = float(lat)
        dbg_old_lon = float(lon)

        # Match FCS L2 data source: read live aircraft state from PANEL_BUTTON_STATES.
        speed_kts = 0.0
        aircraft_motion: Dict[str, object] = {}
        try:
            panel = _ensure_panel_button_states()
            candidate = panel.get("AIRCRAFT", {}) if isinstance(panel, dict) else {}
            if isinstance(candidate, dict):
                aircraft_motion = candidate
            else:
                aircraft_motion = {}
            # INS/GPS motion must use only AIRSPEED_KTS (no TOTAL_SPEED / vertical component).
            speed_kts = float(_safe_float_or_none(aircraft_motion.get("AIRSPEED_KTS", 0.0)) or 0.0)
        except Exception:
            speed_kts = 0.0
        speed_kts = max(0.0, min(5000.0, speed_kts))
        dbg_speed_kts = float(speed_kts)
        distance_nm = speed_kts * (dt_s / 3600.0)

        heading_deg: Optional[float] = None
        for key in ("HEADING_DEG", "HDG_DEG", "HEADING", "HDG"):
            try:
                if key in aircraft_motion:
                    heading_deg = float(aircraft_motion.get(key, 0.0))
                    break
            except Exception:
                continue
        if heading_deg is None:
            try:
                twd_state = getattr(formats, "TWD_STATE", {})
                if isinstance(twd_state, dict):
                    heading_deg = float(twd_state.get("heading_deg", 35.0))
            except Exception:
                heading_deg = None
        if heading_deg is None:
            heading_deg = 35.0
        heading_deg = float(heading_deg) % 360.0
        dbg_heading_deg = float(heading_deg)

        if distance_nm <= 1e-7:
            dbg_reason = "speed~0"
            dbg_new_lat = dbg_old_lat
            dbg_new_lon = dbg_old_lon
            if dbg_emit:
                print(
                    f"OWNSHIP GEO DBG: spd={dbg_speed_kts:.2f} hdg={dbg_heading_deg:.2f} "
                    f"old=({_fmt_coord(dbg_old_lat)},{_fmt_coord(dbg_old_lon)}) "
                    f"new=({_fmt_coord(dbg_new_lat)},{_fmt_coord(dbg_new_lon)}) reason={dbg_reason}"
                )
            return

        new_lat, new_lon = _project_lat_lon_nm(float(lat), float(lon), heading_deg, distance_nm)
        _set_ins_gps_position(new_lat, new_lon, set_manual_override=None, publish_runtime=True)
        dbg_new_lat = float(new_lat)
        dbg_new_lon = float(new_lon)
        dbg_reason = "moved"
        if dbg_emit:
            print(
                f"OWNSHIP GEO DBG: spd={dbg_speed_kts:.2f} hdg={dbg_heading_deg:.2f} "
                f"old=({_fmt_coord(dbg_old_lat)},{_fmt_coord(dbg_old_lon)}) "
                f"new=({_fmt_coord(dbg_new_lat)},{_fmt_coord(dbg_new_lon)}) reason={dbg_reason}"
            )

    def _sync_ins_gps_from_adsb_runtime() -> None:
        if bool(ins_gps_state.get("manual_position", False)):
            return
        if bool(ins_gps_state.get("de1_selected", False)):
            return
        with adsb_runtime_lock:
            lat = _safe_float_or_none(adsb_runtime.get("lat"))
            lon = _safe_float_or_none(adsb_runtime.get("lon"))
            runtime_manual = bool(adsb_runtime.get("manual_position", False))
        if runtime_manual:
            ins_gps_state["manual_position"] = True
            return
        if lat is None or lon is None:
            return
        curr_lat = _safe_float_or_none(ins_gps_state.get("position_lat"))
        curr_lon = _safe_float_or_none(ins_gps_state.get("position_lon"))
        if curr_lat is None or curr_lon is None or abs(curr_lat - lat) > 1e-7 or abs(curr_lon - lon) > 1e-7:
            _set_ins_gps_position(lat, lon, set_manual_override=False, publish_runtime=False)

    def _ins_selected_field() -> Optional[str]:
        if bool(ins_gps_state.get("de1_selected", False)):
            return "de1"
        if bool(ins_gps_state.get("alt_selected", False)):
            return "alt"
        return None

    def finalize_ins_gps_data_entry() -> None:
        selected = _ins_selected_field()
        if selected == "de1":
            lat_digits = _ins_coord_digits_from_line(ins_gps_state.get("lon", "N 00 00.0000"), True)
            lon_digits = _ins_coord_digits_from_line(ins_gps_state.get("lat", "W 000 00.0000"), False)
            lat_raw = str(ins_gps_state.get("de1_n_input", ""))
            lon_raw = str(ins_gps_state.get("de1_w_input", ""))
            lat_in = "".join(ch for ch in lat_raw if ch.isdigit())
            lon_in = "".join(ch for ch in lon_raw if ch.isdigit())
            if lat_in != "":
                lat_digits = lat_in[-8:].rjust(8, "0")
            if lon_in != "":
                lon_digits = lon_in[-9:].rjust(9, "0")
            lat_hemi = str(ins_gps_state.get("lat_hem", "N")).upper()
            if lat_hemi not in {"N", "S"}:
                lat_hemi = "N"
            lon_hemi = str(ins_gps_state.get("lon_hem", "W")).upper()
            if lon_hemi not in {"E", "W"}:
                lon_hemi = "W"
            lat_val = _ins_coord_decimal_from_digits(lat_digits, True, lat_hemi)
            lon_val = _ins_coord_decimal_from_digits(lon_digits, False, lon_hemi)
            lat_text_val = _ins_coord_decimal_from_text(lat_raw, True, lat_hemi)
            lon_text_val = _ins_coord_decimal_from_text(lon_raw, False, lon_hemi)
            if lat_text_val is not None:
                lat_val = float(lat_text_val)
            if lon_text_val is not None:
                lon_val = float(lon_text_val)
            _set_ins_gps_position(lat_val, lon_val, set_manual_override=True, publish_runtime=True)
            ins_gps_state["de1_n_input"] = ""
            ins_gps_state["de1_w_input"] = ""
            ins_gps_state["de1_selected"] = False
            return
        if selected == "alt":
            max_alt_ft = 65000
            raw = "".join(ch for ch in str(ins_gps_state.get("alt_input", "")) if ch.isdigit())
            if raw != "":
                try:
                    alt_ft = float(int(raw))
                except Exception:
                    alt_ft = 0.0
                alt_ft = max(0.0, min(float(max_alt_ft), alt_ft))
                panel = _ensure_panel_button_states()
                aircraft = panel.get("AIRCRAFT", {}) if isinstance(panel, dict) else {}
                if isinstance(aircraft, dict):
                    aircraft["ALTITUDE_FT"] = float(alt_ft)
                    aircraft["ALTITUDE_TARGET_FT"] = float(alt_ft)
                    aircraft["VERTICAL_SPEED_FPM"] = 0.0
            ins_gps_state["alt_input"] = ""
            ins_gps_state["alt_selected"] = False

    def select_ins_gps_data_entry(field: str = "de1") -> None:
        target = str(field).strip().lower()
        if target not in {"de1", "alt"}:
            return
        current = _ins_selected_field()
        if current == target:
            finalize_ins_gps_data_entry()
            return
        if current is not None:
            finalize_ins_gps_data_entry()
        if target == "de1":
            ins_gps_state["de1_selected"] = True
            ins_gps_state["alt_selected"] = False
            line = str(ins_gps_state.get("de1_edit_line", "N")).upper()
            ins_gps_state["de1_edit_line"] = line if line in {"N", "W"} else "N"
            ins_gps_state["de1_n_input"] = ""
            ins_gps_state["de1_w_input"] = ""
        else:
            ins_gps_state["de1_selected"] = False
            ins_gps_state["de1_n_input"] = ""
            ins_gps_state["de1_w_input"] = ""
            ins_gps_state["alt_selected"] = True
            ins_gps_state["alt_input"] = ""

    def ins_gps_keypad_press(key: str) -> None:
        selected = _ins_selected_field()
        if selected is None:
            return
        if selected == "de1":
            if key == "KP_UP":
                ins_gps_state["de1_edit_line"] = "N"
                return
            if key == "KP_DOWN":
                ins_gps_state["de1_edit_line"] = "W"
                return
            line = str(ins_gps_state.get("de1_edit_line", "N")).upper()
            is_lat_line = line == "N"
            input_key = "de1_n_input" if is_lat_line else "de1_w_input"
            width = 12
            current = str(ins_gps_state.get(input_key, ""))
            if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
                digit = key.split("_", 1)[1]
                ins_gps_state[input_key] = (current + digit)[:width]
                return
            if key == "KP_BACK":
                ins_gps_state[input_key] = str(current)[:-1]
                return
            return
        # ALT field.
        max_alt_ft = 65000
        current = "".join(ch for ch in str(ins_gps_state.get("alt_input", "")) if ch.isdigit())
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            try:
                cand = int((current + digit)[-6:])
            except Exception:
                cand = 0
            ins_gps_state["alt_input"] = str(max(0, min(max_alt_ft, cand)))
            return
        if key == "KP_BACK":
            ins_gps_state["alt_input"] = current[:-1]
            return
        if key in {"KP_UP", "KP_DOWN"}:
            panel = _ensure_panel_button_states()
            aircraft = panel.get("AIRCRAFT", {}) if isinstance(panel, dict) else {}
            base_alt = 0
            if current != "":
                try:
                    base_alt = int(current)
                except Exception:
                    base_alt = 0
            elif isinstance(aircraft, dict):
                try:
                    base_alt = int(round(max(0.0, float(aircraft.get("ALTITUDE_FT", 0.0)))))
                except Exception:
                    base_alt = 0
            delta = 100 if key == "KP_UP" else -100
            ins_gps_state["alt_input"] = str(max(0, min(max_alt_ft, base_alt + delta)))

    def ins_gps_text_press(char: str) -> bool:
        selected = _ins_selected_field()
        if selected != "de1":
            return False
        ch = str(char or "")
        if ch == "":
            return False
        if ch == ",":
            line_now = str(ins_gps_state.get("de1_edit_line", "N")).upper()
            ins_gps_state["de1_edit_line"] = "W" if line_now == "N" else "N"
            return True
        line = str(ins_gps_state.get("de1_edit_line", "N")).upper()
        is_lat_line = line == "N"
        input_key = "de1_n_input" if is_lat_line else "de1_w_input"
        current = str(ins_gps_state.get(input_key, ""))
        if ch in {"-", "+"}:
            if is_lat_line:
                ins_gps_state["lat_hem"] = "S" if ch == "-" else "N"
            else:
                ins_gps_state["lon_hem"] = "W" if ch == "-" else "E"
            if current.startswith("-"):
                current = current[1:]
            if ch == "-":
                current = "-" + current
            ins_gps_state[input_key] = current
            return True
        if ch == ".":
            if "." not in current:
                ins_gps_state[input_key] = current + "."
            return True
        if len(ch) == 1 and ch.isdigit():
            max_len = 12
            ins_gps_state[input_key] = (current + ch)[:max_len]
            return True
        if ch.upper() in {"N", "S", "E", "W"}:
            hemi = ch.upper()
            if hemi in {"N", "S"} and is_lat_line:
                ins_gps_state["lat_hem"] = hemi
                return True
            if hemi in {"E", "W"} and (not is_lat_line):
                ins_gps_state["lon_hem"] = hemi
                return True
        return False

    def nav_trigger_flash(key: str, until_ms: int) -> None:
        flash = nav_state.get("flash_until")
        if not isinstance(flash, dict):
            flash = {}
            nav_state["flash_until"] = flash
        flash[str(key)] = int(until_ms)

    def nav_schedule_submenu_change(target_submenu: Optional[str], due_ms: int) -> None:
        nav_state["pending_action"] = ("submenu", target_submenu, int(due_ms))

    def _ensure_degrd_system_state() -> Tuple[List[str], int]:
        opts = pmd_dr_state.get("degrd_system_options", [])
        if not isinstance(opts, list) or len(opts) <= 0:
            names: List[str] = []
            try:
                rows = list(formats.PhmFormat._vehicle_systems()) + list(formats.PhmFormat._mission_systems())
                for row in rows:
                    if not isinstance(row, tuple) or len(row) < 1:
                        continue
                    name = str(row[0]).strip()
                    if name == "":
                        continue
                    names.append(name)
            except Exception:
                names = []
            if len(names) <= 0:
                names = [k for k in PHM_SYSTEM_LCN_PREFIX.keys()]
            opts = list(dict.fromkeys(names))
            pmd_dr_state["degrd_system_options"] = list(opts)
        idx = int(pmd_dr_state.get("degrd_system_idx", 0))
        idx = max(0, min(len(opts) - 1, idx))
        pmd_dr_state["degrd_system_idx"] = idx
        return opts, idx

    def _ensure_degrd_subsystem_state() -> Tuple[List[str], int]:
        sys_opts, sys_idx = _ensure_degrd_system_state()
        selected_system = str(sys_opts[sys_idx]) if len(sys_opts) > 0 else "VSP"
        selected_system_key = _phm_system_key_for_name(selected_system)

        opts = pmd_dr_state.get("degrd_subsystem_options", [])
        cached_system = _phm_system_key_for_name(str(pmd_dr_state.get("degrd_subsystem_system", "")))
        required = _phm_subsystems_for_system(selected_system_key)
        if not isinstance(opts, list):
            opts = []
        opts_norm = [str(x).upper().strip() for x in opts if str(x).strip() != ""]
        if cached_system != selected_system_key or len(opts_norm) <= 0 or opts_norm != required:
            opts_norm = list(required)
            pmd_dr_state["degrd_subsystem_options"] = list(opts_norm)
            pmd_dr_state["degrd_subsystem_system"] = selected_system_key
            pmd_dr_state["degrd_subsystem_idx"] = 0

        idx = int(pmd_dr_state.get("degrd_subsystem_idx", 0))
        idx = max(0, min(len(opts_norm) - 1, idx)) if len(opts_norm) > 0 else 0
        pmd_dr_state["degrd_subsystem_idx"] = idx
        return opts_norm, idx

    def _degrd_selected_system_name() -> str:
        opts, idx = _ensure_degrd_system_state()
        if len(opts) <= 0:
            return "VSP"
        return str(opts[idx])

    def _degrd_selected_subsystem_name() -> str:
        opts, idx = _ensure_degrd_subsystem_state()
        if len(opts) <= 0:
            return _degrd_selected_system_name().upper()
        return str(opts[idx]).upper()

    def _degrd_lcn_prefix() -> str:
        return str(PHM_SYSTEM_LCN_PREFIX.get(_degrd_selected_system_name().upper(), "00")).rjust(2, "0")[-2:]

    def _degrd_lcn_digits_full() -> str:
        digits = "".join(ch for ch in str(pmd_dr_state.get("degrd_lcn_input", "")) if ch.isdigit())[:13]
        auto = bool(pmd_dr_state.get("degrd_lcn_autofill", True))
        if auto:
            prefix = _degrd_lcn_prefix()
            suffix = digits[2:] if len(digits) > 2 else ""
            digits = (prefix + suffix)[:13]
        pmd_dr_state["degrd_lcn_input"] = digits
        return digits

    def _degrd_lcn_formatted() -> str:
        full = _degrd_lcn_digits_full().ljust(13, "_")
        return f"{full[:7]} {full[7:9]} {full[9:13]}"

    def _ensure_phm_status_debug_state() -> Dict[str, object]:
        panel = _ensure_panel_button_states()
        state = panel.get("PHM STATUS", {})
        if not isinstance(state, dict):
            state = {}
            panel["PHM STATUS"] = state
        if not isinstance(state.get("status_overrides", {}), dict):
            state["status_overrides"] = {}
        if not isinstance(state.get("hrc_events", {}), dict):
            state["hrc_events"] = {}
        if not isinstance(state.get("fna_events", {}), dict):
            state["fna_events"] = {}
        if not isinstance(state.get("bit_runs", {}), dict):
            state["bit_runs"] = {}
        return state

    def _update_on_off_and_phm_runtime(now_ms: int) -> None:
        states_raw = pmd_dr_state.get("on_off_states", {})
        if not isinstance(states_raw, dict):
            states_raw = _default_on_off_states()
            pmd_dr_state["on_off_states"] = states_raw
        else:
            for key, default_val in _default_on_off_states().items():
                states_raw.setdefault(key, bool(default_val))

        runtime_raw = pmd_dr_state.get("on_off_runtime", {})
        if not isinstance(runtime_raw, dict):
            runtime_raw = {}
            pmd_dr_state["on_off_runtime"] = runtime_raw

        panel = _ensure_panel_button_states()
        power = panel.get("POWER PANEL", {})
        throttle = panel.get("THROTTLE", {})
        master_arm_panel = panel.get("MASTER ARM", {})
        if not isinstance(power, dict):
            power = {}
        if not isinstance(throttle, dict):
            throttle = {}
        if not isinstance(master_arm_panel, dict):
            master_arm_panel = {}

        batt_on = bool(power.get("BAT_ACTIVE", str(power.get("BAT", "OFF")).upper() == "ON"))
        try:
            batt_28v = float(power.get("BATT_28V", 0.0))
        except Exception:
            batt_28v = 0.0
        power_28v = bool(batt_on and batt_28v > 0.0)
        ipp_on = bool(power.get("IPP_ON", False))
        engine_cmd = str(throttle.get("ENGINE", "OFF")).upper()
        engine_spool_mode = str(throttle.get("ENGINE_SPOOL_MODE", "OFF")).upper()
        try:
            engine_spool = float(throttle.get("ENGINE_SPOOL", 0.0))
        except Exception:
            engine_spool = 0.0
        engine_fully_on = bool(engine_cmd == "RUN" and engine_spool_mode == "RUN" and engine_spool >= 0.99)
        power_270v = bool(power_28v and (ipp_on or engine_fully_on))
        if int(pmd_dr_state.get("on_off_aircraft_pwr_idx", 0)) == 1:
            # External power mode.
            power_28v = True
            power_270v = True

        logged_in = bool(seclvl_state.get("logged_in", False))
        master_arm_on = str(master_arm_panel.get("MASTER_ARM", "OFF")).upper() == "ON"

        label_power_class: Dict[str, str] = {
            "CNI-A": "270V",
            "CNI-B": "270V",
            "CM-L": "270V",
            "CM-R": "270V",
            "DAS-BA": "270V",
            "DAS-BF": "270V",
            "DAS-L": "270V",
            "DAS-R": "270V",
            "DAS-TA": "270V",
            "DAS-TF": "270V",
            "EW-SYS": "270V",
            "EW-B": "270V",
            "EW-AFT": "270V",
            "GPS": "270V",
            "INS": "270V",
            "RADAR": "270V",
            "EOTS": "270V",
            "ACE": "28V",
            "DMC-L": "28V",
            "DMC-R": "28V",
            "DMC-H": "28V",
            "PMD": "28V",
            "ICP-A": "28V",
            "ICP-B": "28V",
            "ICP-C": "28V",
            "BUR": "28V",
            "LADC": "28V",
        }

        def _button_on(label: str) -> bool:
            key = ON_OFF_LABEL_TO_BUTTON_KEY.get(str(label).upper(), "")
            if key == "":
                return False
            return bool(states_raw.get(key, False))

        def _button_status(label: str) -> str:
            label_key = str(label).upper().strip()
            if label_key == "":
                return "OFF"
            key = ON_OFF_LABEL_TO_BUTTON_KEY.get(label_key, "")
            if key == "":
                return "OFF"
            on = bool(states_raw.get(key, False))
            meta = runtime_raw.get(label_key, {})
            if not isinstance(meta, dict):
                meta = {}
            bit_complete = bool(meta.get("bit_complete", False))
            bit_end_ms = int(meta.get("bit_end_ms", 0))
            if not on:
                bit_complete = False
                bit_end_ms = 0
                meta["bit_complete"] = False
                meta["bit_end_ms"] = 0
                runtime_raw[label_key] = meta
                return "OFF"

            p_class = str(label_power_class.get(label_key, "28V")).upper()
            power_ready = True
            if p_class == "270V":
                power_ready = bool(power_270v)
            elif p_class == "28V":
                power_ready = bool(power_28v)
            if not power_ready:
                return "OFF"

            if bit_complete:
                return "OK"
            if bit_end_ms <= 0:
                bit_end_ms = int(now_ms) + int(random.randint(ON_OFF_BIT_MIN_MS, ON_OFF_BIT_MAX_MS))
                meta["bit_end_ms"] = int(bit_end_ms)
                meta["bit_complete"] = False
                runtime_raw[label_key] = meta
                return "INIT"
            if int(now_ms) < bit_end_ms:
                return "INIT"
            meta["bit_complete"] = True
            meta["bit_end_ms"] = 0
            runtime_raw[label_key] = meta
            return "OK"

        button_status_raw: Dict[str, str] = {}
        for label in ON_OFF_LABELS:
            button_status_raw[label] = _button_status(label)

        def _all_off(values: List[str]) -> bool:
            return len(values) > 0 and all(str(v).upper() == "OFF" for v in values)

        def _any_off(values: List[str]) -> bool:
            return any(str(v).upper() == "OFF" for v in values)

        def _any_init(values: List[str]) -> bool:
            return any(str(v).upper() == "INIT" for v in values)

        off_since_raw = runtime_raw.get("__off_since_ms", {})
        off_since: Dict[str, int]
        if isinstance(off_since_raw, dict):
            off_since = {}
            for k, v in off_since_raw.items():
                try:
                    off_since[str(k)] = int(v)
                except Exception:
                    continue
        else:
            off_since = {}
        runtime_raw["__off_since_ms"] = off_since

        def _display_status(track_key: str, status: str) -> str:
            st = str(status).upper().strip()
            key = str(track_key)
            if st == "OFF":
                since_ms = int(off_since.get(key, 0))
                if since_ms <= 0:
                    since_ms = int(now_ms)
                    off_since[key] = since_ms
                if int(now_ms) - int(since_ms) >= int(ON_OFF_OFF_TO_GRAY_MS):
                    return "OF"
                return "OFF"
            off_since.pop(key, None)
            return st

        cm_l = button_status_raw.get("CM-L", "OFF")
        cm_r = button_status_raw.get("CM-R", "OFF")
        cm_vals = [cm_l, cm_r]
        if _all_off(cm_vals):
            cm_status = "OFF"
        elif _any_off(cm_vals):
            cm_status = "DEGD"
        elif _any_init(cm_vals):
            cm_status = "INIT"
        else:
            cm_status = "OK"

        das_parts = [
            button_status_raw.get("DAS-BA", "OFF"),
            button_status_raw.get("DAS-BF", "OFF"),
            button_status_raw.get("DAS-L", "OFF"),
            button_status_raw.get("DAS-R", "OFF"),
            button_status_raw.get("DAS-TA", "OFF"),
            button_status_raw.get("DAS-TF", "OFF"),
        ]
        if _all_off(das_parts):
            das_status = "FAIL"
        elif _any_off(das_parts):
            das_status = "DEGD"
        elif _any_init(das_parts):
            das_status = "INIT"
        else:
            das_status = "OK"

        ew_sys = button_status_raw.get("EW-SYS", "OFF")
        ew_b = button_status_raw.get("EW-B", "OFF")
        ew_aft = button_status_raw.get("EW-AFT", "OFF")
        if ew_sys == "OFF":
            esm_status = "OFF"
        elif ew_sys == "INIT":
            esm_status = "INIT"
        elif ew_b == "INIT" or ew_aft == "INIT":
            esm_status = "INIT"
        elif ew_b == "OFF" or ew_aft == "OFF":
            esm_status = "DEGD"
        else:
            esm_status = "OK"

        cni_a = button_status_raw.get("CNI-A", "OFF")
        cni_b = button_status_raw.get("CNI-B", "OFF")
        cni_vals = [cni_a, cni_b]
        cni_all_off = _all_off(cni_vals)
        cni_any_off = _any_off(cni_vals)
        cni_any_init = _any_init(cni_vals)
        if cni_all_off:
            cni_status = "INOP"
            cni_page_phase = "INOP"
        elif cni_any_init:
            cni_status = "INIT"
            cni_page_phase = "STARTUP"
        elif cni_any_off:
            cni_status = "DEGD"
            cni_page_phase = "SHUTDOWN"
        else:
            cni_status = "OK"
            cni_page_phase = "STD"

        gps_status = button_status_raw.get("GPS", "OFF")
        ins_status = button_status_raw.get("INS", "OFF")
        radar_status = button_status_raw.get("RADAR", "OFF")
        eots_status = button_status_raw.get("EOTS", "OFF")
        pmd_status = button_status_raw.get("PMD", "OFF")
        icp_a_status = button_status_raw.get("ICP-A", "OFF")
        icp_b_status = button_status_raw.get("ICP-B", "OFF")
        icp_c_status = button_status_raw.get("ICP-C", "OFF")
        icp_vals = [icp_a_status, icp_b_status, icp_c_status]
        icp_off_count = sum(1 for v in icp_vals if str(v).upper() == "OFF")
        if icp_off_count >= 3:
            icp_status = "OFF"
        elif icp_off_count >= 1:
            icp_status = "DEGD"
        elif _any_init(icp_vals):
            icp_status = "INIT"
        else:
            icp_status = "OK"

        com_nav_vals = [cni_status, gps_status, ins_status]
        if cni_status == "BIT":
            com_nav_status = "BIT"
        elif _all_off(com_nav_vals):
            com_nav_status = "OFF"
        elif _any_init(com_nav_vals):
            com_nav_status = "INIT"
        elif any(str(v).upper() in {"OFF", "DEGD", "FAIL", "INOP", "SHUTDOWN"} for v in com_nav_vals):
            com_nav_status = "DEGD"
        else:
            com_nav_status = "OK"

        if esm_status == "OFF" and cm_status == "OFF":
            ew_status = "OFF"
        elif esm_status == "INIT" or cm_status == "INIT":
            ew_status = "INIT"
        elif esm_status in {"DEGD", "OFF"} or cm_status in {"DEGD", "OFF"}:
            ew_status = "DEGD"
        else:
            ew_status = "OK"

        if pmd_status == "OFF" and icp_status == "OFF":
            msp_status = "OFF"
        elif pmd_status == "INIT" or icp_status == "INIT":
            msp_status = "INIT"
        elif pmd_status in {"DEGD", "OFF"} or icp_status in {"DEGD", "OFF"}:
            msp_status = "DEGD"
        else:
            msp_status = "OK"

        # Master-arm behavior for CM/RADAR/EOTS with user logged in.
        if logged_in:
            if master_arm_on:
                if cm_status == "STBY":
                    cm_status = "OK"
                if radar_status == "STBY":
                    radar_status = "OK"
                if eots_status == "STBY":
                    eots_status = "OK"
            else:
                if cm_status == "OK":
                    cm_status = "STBY"
                if radar_status == "OK":
                    radar_status = "STBY"
                if eots_status == "OK":
                    eots_status = "STBY"

        mission_system_status: Dict[str, str] = {
            "COM_NAV": com_nav_status,
            "DAS": das_status,
            "DISPL": "OK",
            "EW": ew_status,
            "GUN": "OK",
            "EOTS": eots_status,
            "MSP": msp_status,
            "RADAR": radar_status,
            "RIUS": "OK",
            "SRES": "OK",
            "LIGHTG": "OK",
        }

        # No SECLVL user: mission systems report PIN unless already degraded/off/init/fail.
        if not logged_in:
            for special_name in ("DAS", "EW", "RADAR", "EOTS"):
                if str(mission_system_status.get(special_name, "")).upper() == "OK":
                    mission_system_status[special_name] = "PIN"
            if str(cm_status).upper() == "OK":
                cm_status = "PIN"

        runtime_subsystem_status: Dict[str, str] = {
            "CNI": cni_status,
            "GPS": gps_status,
            "INS": ins_status,
            "PSCTS": cni_status,
            "DAS": das_status,
            "ESM": esm_status,
            "CM": cm_status,
            "EOTS": eots_status,
            "PMD": pmd_status,
            "ICP": icp_status,
            "RADAR": radar_status,
        }

        phm_state = _ensure_phm_status_debug_state()
        def _resolve_completed_phm_status_bits() -> None:
            bit_runs_raw = phm_state.get("bit_runs", {})
            if not isinstance(bit_runs_raw, dict):
                phm_state["bit_runs"] = {}
                return
            hrc_events = phm_state.get("hrc_events", {})
            if not isinstance(hrc_events, dict):
                hrc_events = {}
                phm_state["hrc_events"] = hrc_events
            catalog = getattr(formats, "ICAWS_ALERT_CATALOG", {})
            chooser = getattr(formats, "_choose_random_icaw_hrc", None)
            if not isinstance(catalog, dict):
                catalog = {}
            remaining_runs: Dict[str, object] = {}
            for run_key, run in list(bit_runs_raw.items()):
                if not isinstance(run, dict):
                    continue
                try:
                    end_ms = int(run.get("end_ms", 0))
                except Exception:
                    end_ms = 0
                if end_ms > int(now_ms):
                    remaining_runs[str(run_key)] = dict(run)
                    continue

                target = str(run.get("target", run_key)).upper().strip()
                system = str(run.get("system", "")).upper().strip()
                subsystem = str(run.get("subsystem", target)).upper().strip()
                match_keys = {target, subsystem}
                match_keys = {k for k in match_keys if k != ""}
                candidates: List[Tuple[str, str]] = []
                for entry in catalog.values():
                    if not isinstance(entry, dict):
                        continue
                    rules = entry.get("hrc_rules", [])
                    if not isinstance(rules, list) or len(rules) <= 0:
                        continue
                    target_keys_raw = entry.get("target_keys", [])
                    target_keys = {
                        str(x).upper().strip()
                        for x in target_keys_raw
                        if str(x).strip() != ""
                    } if isinstance(target_keys_raw, list) else set()
                    entry_system = str(entry.get("target_system", entry.get("system", ""))).upper().strip()
                    if not (match_keys & target_keys) and not (target in {entry_system, system} and len(target_keys) > 0):
                        continue
                    hrc_value = ""
                    try:
                        if callable(chooser):
                            hrc_value = str(chooser(rules)).strip()
                    except Exception:
                        hrc_value = ""
                    if hrc_value == "":
                        for rule in rules:
                            if not isinstance(rule, dict):
                                continue
                            hrcs = rule.get("hrcs", [])
                            if isinstance(hrcs, list) and len(hrcs) > 0:
                                hrc_value = str(random.choice(hrcs)).strip()
                                break
                    if hrc_value != "":
                        candidates.append((target, hrc_value))

                random.shuffle(candidates)
                triggered: List[Tuple[str, str]] = []
                for target_key, hrc_value in candidates:
                    # BITs usually pass; HRCs should be occasional.
                    if random.random() > 0.06:
                        continue
                    triggered.append((target_key, hrc_value))
                    if len(triggered) >= 2:
                        break
                for target_key, hrc_value in triggered:
                    vals = hrc_events.get(target_key, [])
                    if not isinstance(vals, list):
                        vals = []
                    if hrc_value not in vals:
                        vals.append(hrc_value)
                    hrc_events[target_key] = [str(x) for x in vals if str(x).strip() != ""]
                if len(triggered) > 0:
                    print(f"[PHM][BIT] {target} complete: HRC triggered {[h for _, h in triggered]}")
                else:
                    print(f"[PHM][BIT] {target} complete: OK")
            phm_state["bit_runs"] = remaining_runs

        _resolve_completed_phm_status_bits()
        bit_map_raw = phm_state.get("bit_until_ms", {})
        bit_map: Dict[str, int] = {}
        if isinstance(bit_map_raw, dict):
            for k, v in bit_map_raw.items():
                try:
                    vv = int(v)
                except Exception:
                    continue
                if vv > int(now_ms):
                    bit_map[str(k).upper().strip()] = vv
        phm_state["bit_until_ms"] = dict(bit_map)

        def _force_bit_system(name: str) -> None:
            key = str(name).upper().strip()
            if key in mission_system_status:
                mission_system_status[key] = "TS"

        def _force_bit_subsystem(name: str) -> None:
            key = str(name).upper().strip()
            if key != "":
                runtime_subsystem_status[key] = "TS"

        for bit_key in list(bit_map.keys()):
            _force_bit_system(bit_key)
            _force_bit_subsystem(bit_key)
        if str(runtime_subsystem_status.get("CNI", "")).upper() == "TS":
            cni_page_phase = "BIT"
            mission_system_status["COM_NAV"] = "TS"
            runtime_subsystem_status["PSCTS"] = "TS"

        cni_status = str(runtime_subsystem_status.get("CNI", cni_status)).upper().strip() or cni_status

        hrc_events = phm_state.get("hrc_events", {})
        if not isinstance(hrc_events, dict):
            hrc_events = {}
            phm_state["hrc_events"] = hrc_events
        cni_hrc_code = "CNI CH DEGRADED"
        cni_event_vals = hrc_events.get("CNI", [])
        if not isinstance(cni_event_vals, list):
            cni_event_vals = []
        clean_cni_events = [str(x).strip() for x in cni_event_vals if str(x).strip() != ""]
        if cni_any_off and (not cni_all_off):
            if cni_hrc_code not in clean_cni_events:
                clean_cni_events.append(cni_hrc_code)
        else:
            clean_cni_events = [x for x in clean_cni_events if str(x).upper() != cni_hrc_code]
        if len(clean_cni_events) > 0:
            hrc_events["CNI"] = clean_cni_events
        else:
            hrc_events.pop("CNI", None)

        def _icp_rows(side_status: str, rows: List[str]) -> List[Tuple[str, str]]:
            state = str(side_status).upper()
            out: List[Tuple[str, str]] = []
            if state == "OFF":
                return [(name, "OFF") for name in rows]
            if state == "INIT":
                return [(name, "INIT") for name in rows]
            for name in rows:
                base = "OK"
                if (not logged_in) and name in {"DSA1A", "DSA1B", "DSB1A", "DSB1B"}:
                    base = "PIN"
                out.append((name, base))
            return out

        mission_system_status_raw = dict(mission_system_status)
        runtime_subsystem_status_raw = dict(runtime_subsystem_status)
        button_status = {
            label: _display_status(f"btn:{label}", status)
            for label, status in button_status_raw.items()
        }
        mission_system_status = {
            name: _display_status(f"sys:{name}", status)
            for name, status in mission_system_status_raw.items()
        }
        runtime_subsystem_status = {
            name: _display_status(f"sub:{name}", status)
            for name, status in runtime_subsystem_status_raw.items()
        }

        msstat_blocks_raw: Dict[str, List[Tuple[str, str]]] = {
            "28V": [
                ("ACE", button_status_raw.get("ACE", "OFF")),
                ("AMD", "INIT" if icp_a_status == "INIT" else ("OFF" if icp_a_status == "OFF" else "OK")),
                ("DMCH-DP", button_status_raw.get("DMC-H", "OFF")),
                ("DMCH-SP", button_status_raw.get("DMC-H", "OFF")),
                ("DMCL", button_status_raw.get("DMC-L", "OFF")),
                ("DMCR", button_status_raw.get("DMC-R", "OFF")),
                ("PMD", pmd_status),
            ],
            "270V": [
                ("CNI-A", cni_a),
                ("CNI-B", cni_b),
                ("CM", cm_status),
                ("DAS", mission_system_status_raw.get("DAS", das_status)),
                ("EOTS", mission_system_status_raw.get("EOTS", eots_status)),
                ("EW", mission_system_status_raw.get("EW", ew_status)),
                ("P5-CTS", cni_status),
                ("RADAR", mission_system_status_raw.get("RADAR", radar_status)),
            ],
            "ICP-A": _icp_rows(
                icp_a_status,
                ["DSA1A", "DSA1B", "GPA1A1", "GPA1A2", "GPA1B1", "GPA1B2", "GPA2A1", "GPA2A2", "GPA2B1", "GPA 2B2", "GPIOA1", "GPIOA2"],
            ),
            "ICP-B": _icp_rows(
                icp_b_status,
                ["DSB1A", "DSB1B", "GPA1A1", "GPA1A2", "GPA1B1", "GPA1B2", "GPIOB1", "GPIOB2"],
            ),
        }
        msstat_blocks: Dict[str, List[Tuple[str, str]]] = {}
        for block_name, rows in msstat_blocks_raw.items():
            out_rows: List[Tuple[str, str]] = []
            for row_name, row_status in rows:
                disp_status = _display_status(f"ms:{block_name}:{row_name}", row_status)
                out_rows.append((str(row_name), str(disp_status)))
            msstat_blocks[str(block_name)] = out_rows

        phm_state["runtime_system_status"] = dict(mission_system_status)
        phm_state["runtime_subsystem_status"] = dict(runtime_subsystem_status)
        phm_state["msstat_blocks"] = {k: list(v) for k, v in msstat_blocks.items()}
        phm_state["on_off_button_status"] = dict(button_status)
        phm_state["cni_page_phase"] = str(cni_page_phase).upper().strip() or "STD"

    def _phm_debug_recompute_system_override(system_name: str) -> None:
        s = _ensure_phm_status_debug_state()
        sys_key = _phm_system_key_for_name(system_name)
        if sys_key == "":
            return
        overrides = s.get("status_overrides", {})
        hrc_events = s.get("hrc_events", {})
        fna_events = s.get("fna_events", {})
        if not isinstance(overrides, dict) or not isinstance(hrc_events, dict) or not isinstance(fna_events, dict):
            return
        event_keys = _phm_related_event_keys_for_system(sys_key)
        if len(event_keys) <= 0:
            event_keys = [sys_key]

        def _has_events(event_map: Dict[str, object]) -> bool:
            for event_key in event_keys:
                vals = event_map.get(event_key, [])
                if not isinstance(vals, list):
                    continue
                if any(str(x).strip() != "" for x in vals):
                    return True
            return False

        has_hrc = _has_events(hrc_events)
        has_fna = _has_events(fna_events)
        if has_fna:
            overrides[sys_key] = "OT"
        elif has_hrc:
            overrides[sys_key] = "HR"
        else:
            overrides.pop(sys_key, None)

    def _phm_debug_toggle_event(system_name: str, text: str, event_key: str) -> None:
        label = str(text).strip()
        if label == "":
            return
        label_norm = label.upper()
        s = _ensure_phm_status_debug_state()
        sys_key = str(system_name).upper()
        if sys_key == "":
            return
        event_map = s.get(event_key, {})
        if not isinstance(event_map, dict):
            event_map = {}
            s[event_key] = event_map
        related_keys = _phm_related_event_keys_for_system(sys_key)
        if len(related_keys) <= 0:
            related_keys = [sys_key]
        label_exists = False
        for key in related_keys:
            vals = event_map.get(key, [])
            if not isinstance(vals, list):
                continue
            existing_norm = [str(x).strip().upper() for x in vals]
            if label_norm in existing_norm:
                label_exists = True
                break
        if label_exists:
            for key in related_keys:
                vals = event_map.get(key, [])
                if not isinstance(vals, list):
                    continue
                new_vals = [str(x) for x in vals if str(x).strip() != "" and str(x).strip().upper() != label_norm]
                if len(new_vals) > 0:
                    event_map[key] = new_vals
                else:
                    event_map.pop(key, None)
        else:
            vals = event_map.get(sys_key, [])
            if not isinstance(vals, list):
                vals = []
            vals.append(label)
            vals = [str(x) for x in vals if str(x).strip() != ""]
            if len(vals) > 0:
                event_map[sys_key] = vals
            else:
                event_map.pop(sys_key, None)
        _phm_debug_recompute_system_override(sys_key)

    def trigger_degrd_hrc() -> None:
        subsystem_name = _degrd_selected_subsystem_name()
        # Save compact HRC text (no display-format spacing) into PHM/ICAW lists.
        _phm_debug_toggle_event(subsystem_name, _degrd_lcn_digits_full(), "hrc_events")

    def trigger_degrd_fna() -> None:
        subsystem_name = _degrd_selected_subsystem_name()
        fna_name = str(pmd_dr_state.get("degrd_fna_input", "")).strip()
        if fna_name == "":
            return
        _phm_debug_toggle_event(subsystem_name, fna_name, "fna_events")

    def _pmd_degrd_selected_field() -> Optional[str]:
        raw = str(pmd_dr_state.get("degrd_selected_field", "")).upper()
        if raw in {"LCN", "FNA"}:
            return raw
        return None

    def finalize_pmd_degrd_data_entry() -> None:
        pmd_dr_state["degrd_selected_field"] = None
        pmd_dr_state["degrd_fna_comp_key"] = None
        pmd_dr_state["degrd_fna_comp_idx"] = -1

    def select_pmd_degrd_data_entry(field: str) -> None:
        target = str(field).upper()
        if target not in {"LCN", "FNA"}:
            return
        current = _pmd_degrd_selected_field()
        if current == target:
            finalize_pmd_degrd_data_entry()
            return
        pmd_dr_state["degrd_selected_field"] = target
        pmd_dr_state["degrd_fna_comp_key"] = None
        pmd_dr_state["degrd_fna_comp_idx"] = -1

    def _pmd_degrd_type_char(ch: str) -> bool:
        field = _pmd_degrd_selected_field()
        if field != "FNA":
            return False
        txt = str(ch)
        if txt == "":
            return False
        c = txt[0]
        if not (c.isalnum() or c == " "):
            return False
        current = str(pmd_dr_state.get("degrd_fna_input", ""))
        pmd_dr_state["degrd_fna_input"] = (current + c.upper())[:64]
        pmd_dr_state["degrd_fna_comp_key"] = None
        pmd_dr_state["degrd_fna_comp_idx"] = -1
        return True

    def pmd_degrd_keypad_press(key: str) -> None:
        field = _pmd_degrd_selected_field()
        if field is None:
            return
        if field == "LCN":
            current = _degrd_lcn_digits_full()
            if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
                digit = key.split("_", 1)[1]
                pmd_dr_state["degrd_lcn_input"] = (current + digit)[:13]
                return
            if key == "KP_BACK":
                if bool(pmd_dr_state.get("degrd_lcn_autofill", True)) and len(current) <= 2:
                    pmd_dr_state["degrd_lcn_autofill"] = False
                pmd_dr_state["degrd_lcn_input"] = current[:-1]
            return

        if key == "KP_BACK":
            current = str(pmd_dr_state.get("degrd_fna_input", ""))
            pmd_dr_state["degrd_fna_input"] = current[:-1]
            pmd_dr_state["degrd_fna_comp_key"] = None
            pmd_dr_state["degrd_fna_comp_idx"] = -1
            return
        if key == "KP_SPACE":
            _pmd_degrd_type_char(" ")
            return
        alpha_map = {
            "KP_0": "0",
            "KP_1": "1",
            "KP_2": "ABC2",
            "KP_3": "DEF3",
            "KP_4": "GHI4",
            "KP_5": "JKL5",
            "KP_6": "MNO6",
            "KP_7": "PQRS7",
            "KP_8": "TUV8",
            "KP_9": "WXYZ9",
        }
        choices = alpha_map.get(str(key))
        if choices is None or choices == "":
            return
        current = str(pmd_dr_state.get("degrd_fna_input", ""))
        comp_key = pmd_dr_state.get("degrd_fna_comp_key")
        comp_idx = int(pmd_dr_state.get("degrd_fna_comp_idx", -1))
        if str(comp_key) == str(key) and len(current) > 0:
            comp_idx = (comp_idx + 1) % len(choices)
            pmd_dr_state["degrd_fna_input"] = (current[:-1] + choices[comp_idx])[:64]
        else:
            comp_idx = 0
            pmd_dr_state["degrd_fna_input"] = (current + choices[0])[:64]
        pmd_dr_state["degrd_fna_comp_key"] = str(key)
        pmd_dr_state["degrd_fna_comp_idx"] = comp_idx

    def _stores_cfg() -> Dict[str, object]:
        raw = pmd_dr_state.get("stores_cfg")
        if isinstance(raw, dict):
            return raw
        cfg = load_stores_config()
        pmd_dr_state["stores_cfg"] = cfg
        return cfg

    def _ensure_pmd_stores_state() -> None:
        cfg = _stores_cfg()
        weapons_raw = cfg.get("weapons", {})
        weapons = weapons_raw if isinstance(weapons_raw, dict) else {}
        stations: Dict[str, List[str]] = {}
        for sta in PMD_STORES_STATION_ORDER:
            required_mode = ""
            if sta in PMD_STORES_EXTERNAL_STATIONS:
                required_mode = "EXT"
            elif sta in PMD_STORES_INTERNAL_STATIONS:
                required_mode = "INT"
            opts: List[str] = ["NONE"]
            inv_opts = _stores_inventory_station_options(cfg, sta)
            if len(inv_opts) > 0:
                opts.extend([wid for wid in inv_opts if wid not in opts])
            else:
                for weapon_id, weapon_meta in weapons.items():
                    wid = str(weapon_id).strip()
                    if wid == "" or not isinstance(weapon_meta, dict):
                        continue
                    car_raw = weapon_meta.get("carriage", [])
                    carriage: List[str] = []
                    if isinstance(car_raw, list):
                        for mode in car_raw:
                            tag = str(mode).upper().strip()
                            if tag in {"INT", "EXT"} and tag not in carriage:
                                carriage.append(tag)
                    if len(carriage) <= 0:
                        carriage = ["INT", "EXT"]
                    wtype = str(weapon_meta.get("type", "AS")).upper().strip()
                    if wtype not in {"AS", "SRM", "MRM"}:
                        wtype = "AS"
                    if sta in PMD_STORES_AA_ONLY_STATIONS and wtype == "AS":
                        continue
                    if (required_mode == "" or required_mode in carriage) and wid not in opts:
                        opts.append(wid)
            stations[sta] = opts

        idx_map_raw = pmd_dr_state.get("stores_sta_idx")
        if isinstance(idx_map_raw, dict):
            idx_map = idx_map_raw
        else:
            idx_map = {}
            pmd_dr_state["stores_sta_idx"] = idx_map
        _apply_default_stores_loadout_once(pmd_dr_state, stations, idx_map)
        for sta in PMD_STORES_STATION_ORDER:
            opts_raw = stations.get(sta, ["NONE"])
            opts = [str(v) for v in opts_raw] if isinstance(opts_raw, list) else ["NONE"]
            try:
                idx = int(idx_map.get(sta, 0))
            except Exception:
                idx = 0
            idx_map[sta] = max(0, min(len(opts) - 1, idx))
        cfg["stations"] = stations
        pmd_dr_state["stores_cfg"] = cfg
        try:
            pmd_dr_state["stores_gun_value"] = max(0, min(182, int(pmd_dr_state.get("stores_gun_value", 182))))
        except Exception:
            pmd_dr_state["stores_gun_value"] = 182
        try:
            pmd_dr_state["stores_chaff_value"] = max(0, min(30, int(pmd_dr_state.get("stores_chaff_value", 10))))
        except Exception:
            pmd_dr_state["stores_chaff_value"] = 10
        try:
            pmd_dr_state["stores_flare_value"] = max(0, min(30, int(pmd_dr_state.get("stores_flare_value", 10))))
        except Exception:
            pmd_dr_state["stores_flare_value"] = 10

    def _pmd_stores_selected_field() -> Optional[str]:
        value = str(pmd_dr_state.get("stores_selected", "")).upper().strip()
        if value in {"GUN", "CHAFF", "FLARE"}:
            return value
        return None

    def finalize_pmd_stores_data_entry() -> None:
        field = _pmd_stores_selected_field()
        if field not in {"GUN", "CHAFF", "FLARE"}:
            return
        input_key = f"stores_{field.lower()}_input"
        value_key = f"stores_{field.lower()}_value"
        raw = "".join(ch for ch in str(pmd_dr_state.get(input_key, "")) if ch.isdigit())
        if raw != "":
            try:
                max_val = 30 if field in {"CHAFF", "FLARE"} else 182
                pmd_dr_state[value_key] = max(0, min(max_val, int(raw)))
            except Exception:
                pass
        pmd_dr_state[input_key] = ""
        pmd_dr_state["stores_selected"] = None

    def select_pmd_stores_data_entry(field: str) -> None:
        target = str(field).upper().strip()
        if target not in {"GUN", "CHAFF", "FLARE"}:
            return
        if _pmd_stores_selected_field() == target:
            finalize_pmd_stores_data_entry()
            return
        pmd_dr_state["stores_selected"] = target
        pmd_dr_state[f"stores_{target.lower()}_input"] = ""

    def pmd_stores_keypad_press(key: str) -> None:
        field = _pmd_stores_selected_field()
        if field not in {"GUN", "CHAFF", "FLARE"}:
            return
        input_key = f"stores_{field.lower()}_input"
        value_key = f"stores_{field.lower()}_value"
        max_val = 182 if field == "GUN" else 30
        current = str(pmd_dr_state.get(input_key, ""))
        if key == "KP_BACK":
            pmd_dr_state[input_key] = current[:-1]
            return
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            pmd_dr_state[input_key] = (current + digit)[-3:]
            return
        if key in {"KP_UP", "KP_DOWN"}:
            raw = "".join(ch for ch in str(current) if ch.isdigit())
            if raw != "":
                try:
                    base_val = int(raw)
                except Exception:
                    base_val = int(pmd_dr_state.get(value_key, 0))
            else:
                try:
                    base_val = int(pmd_dr_state.get(value_key, 0))
                except Exception:
                    base_val = 0
            base_val = max(0, min(max_val, base_val))
            step = 1 if key == "KP_UP" else -1
            pmd_dr_state[input_key] = str(max(0, min(max_val, base_val + step)))

    _PMD_STORES_INV_STATE_MAP_MAIN: Dict[str, str] = {
        "cntl_inv_selected_stations": "stores_inv_selected_stations",
        "cntl_inv_load_open": "stores_inv_load_open",
        "cntl_inv_load_type_menu_open": "stores_inv_load_type_menu_open",
        "cntl_inv_load_type_page": "stores_inv_load_type_page",
        "cntl_inv_load_selected_field": "stores_inv_load_selected_field",
        "cntl_inv_load_type_value": "stores_inv_load_type_value",
        "cntl_inv_load_rack_value": "stores_inv_load_rack_value",
        "cntl_inv_load_wpn_value": "stores_inv_load_wpn_value",
        "cntl_inv_load_fuze_value": "stores_inv_load_fuze_value",
        "cntl_inv_load_fuze_mode_value": "stores_inv_load_fuze_mode_value",
        "cntl_inv_load_fuze_mode_open": "stores_inv_load_fuze_mode_open",
        "cntl_inv_load_qty_value": "stores_inv_load_qty_value",
        "cntl_inv_load_qty_max": "stores_inv_load_qty_max",
        "cntl_inv_load_qty_input": "stores_inv_load_qty_input",
    }

    def _pmd_stores_inv_default_value(sms_key: str) -> object:
        if sms_key == "cntl_inv_selected_stations":
            return []
        if sms_key.endswith("_open") or sms_key.endswith("_page") or sms_key.endswith("_value") or sms_key.endswith("_max"):
            if sms_key in {"cntl_inv_load_type_value", "cntl_inv_load_rack_value", "cntl_inv_load_wpn_value", "cntl_inv_load_fuze_value", "cntl_inv_load_fuze_mode_value"}:
                return ""
            return 0
        return ""

    def _pmd_stores_inv_actual_store_loads() -> Dict[str, Dict[str, object]]:
        _ensure_pmd_stores_state()
        cfg = _stores_cfg()
        weapons_raw = cfg.get("weapons", {})
        stations_raw = cfg.get("stations", {})
        idx_map_raw = pmd_dr_state.get("stores_sta_idx", {})
        qty_map_raw = pmd_dr_state.get("stores_sta_qty", {})
        weapons = weapons_raw if isinstance(weapons_raw, dict) else {}
        stations = stations_raw if isinstance(stations_raw, dict) else {}
        idx_map = idx_map_raw if isinstance(idx_map_raw, dict) else {}
        qty_map = qty_map_raw if isinstance(qty_map_raw, dict) else {}
        out: Dict[str, Dict[str, object]] = {}
        for sta in PMD_STORES_STATION_ORDER:
            opts_raw = stations.get(sta, ["NONE"])
            opts = [str(v) for v in opts_raw] if isinstance(opts_raw, list) and len(opts_raw) > 0 else ["NONE"]
            try:
                idx = int(idx_map.get(sta, 0))
            except Exception:
                idx = 0
            idx = max(0, min(len(opts) - 1, idx))
            wid = str(opts[idx]).strip()
            if wid == "" or wid.upper() == "NONE":
                continue
            meta = weapons.get(wid, {})
            if not isinstance(meta, dict):
                continue
            try:
                qty = max(1, int(qty_map.get(sta, 1)))
            except Exception:
                qty = 1
            icon_name = str(meta.get("icon", "")).strip()
            if icon_name != "" and not _stores_icon_exists(icon_name):
                icon_name = ""
            wtype = str(meta.get("type", "AS")).upper().strip()
            if wtype not in {"AS", "SRM", "MRM"}:
                wtype = "AS"
            out[sta] = {"weapon": wid, "icon": icon_name, "type": wtype, "qty": int(qty)}
        return out

    def _pmd_stores_inv_apply_clear(stations_to_clear: List[str]) -> None:
        if len(stations_to_clear) <= 0:
            return
        _ensure_pmd_stores_state()
        cfg = _stores_cfg()
        stations_raw = cfg.get("stations", {})
        stations = stations_raw if isinstance(stations_raw, dict) else {}
        idx_map_raw = pmd_dr_state.get("stores_sta_idx", {})
        idx_map = idx_map_raw if isinstance(idx_map_raw, dict) else {}
        qty_map_raw = pmd_dr_state.get("stores_sta_qty", {})
        qty_map = qty_map_raw if isinstance(qty_map_raw, dict) else {}
        for sta in stations_to_clear:
            token = str(sta).upper().strip()
            if token not in PMD_STORES_STATION_ORDER:
                continue
            opts_raw = stations.get(token, ["NONE"])
            opts = [str(v) for v in opts_raw] if isinstance(opts_raw, list) and len(opts_raw) > 0 else ["NONE"]
            none_idx = 0
            for i, opt in enumerate(opts):
                if str(opt).upper().strip() == "NONE":
                    none_idx = int(i)
                    break
            idx_map[token] = int(none_idx)
            qty_map[token] = 0
        pmd_dr_state["stores_sta_idx"] = dict(idx_map)
        pmd_dr_state["stores_sta_qty"] = dict(qty_map)

    def _pmd_stores_inv_apply_load_request(load_req: Dict[str, object]) -> None:
        if len(load_req) <= 0:
            return
        _ensure_pmd_stores_state()
        cfg = _stores_cfg()
        weapons_raw = cfg.get("weapons", {})
        stations_raw = cfg.get("stations", {})
        weapons = weapons_raw if isinstance(weapons_raw, dict) else {}
        stations = stations_raw if isinstance(stations_raw, dict) else {}
        idx_map_raw = pmd_dr_state.get("stores_sta_idx", {})
        idx_map = idx_map_raw if isinstance(idx_map_raw, dict) else {}
        qty_map_raw = pmd_dr_state.get("stores_sta_qty", {})
        qty_map = qty_map_raw if isinstance(qty_map_raw, dict) else {}
        req_weapon = str(load_req.get("weapon", "")).upper().strip()
        req_type = str(load_req.get("type", "")).upper().strip()
        if req_weapon == "":
            return
        aliases = _stores_inventory_alias_map(cfg)
        alias_weapon = str(aliases.get(req_weapon, req_weapon)).strip()
        req_stations: List[str] = []
        raw_stations = load_req.get("stations", [])
        if isinstance(raw_stations, (list, tuple)):
            for sta in raw_stations:
                token = str(sta).upper().strip()
                if token in PMD_STORES_STATION_ORDER and token not in req_stations:
                    req_stations.append(token)
        try:
            req_qty = max(1, int(load_req.get("qty", 1)))
        except Exception:
            req_qty = 1
        if alias_weapon not in weapons and req_weapon not in weapons:
            weapons[alias_weapon] = _stores_inventory_weapon_meta(alias_weapon, req_weapon, req_type, req_stations, weapons, cfg)
            cfg["weapons"] = weapons
        norm_req = _stores_normalize_weapon_id(req_weapon)
        norm_alias = _stores_normalize_weapon_id(alias_weapon)
        for sta in req_stations:
            opts_raw = stations.get(sta, ["NONE"])
            opts = [str(v) for v in opts_raw] if isinstance(opts_raw, list) and len(opts_raw) > 0 else ["NONE"]
            hit_idx: Optional[int] = None
            if alias_weapon in opts:
                hit_idx = int(opts.index(alias_weapon))
            elif req_weapon in opts:
                hit_idx = int(opts.index(req_weapon))
            else:
                for i, wid in enumerate(opts):
                    wid_norm = _stores_normalize_weapon_id(wid)
                    if wid_norm != "" and (wid_norm == norm_req or wid_norm == norm_alias):
                        hit_idx = int(i)
                        break
            if hit_idx is None:
                opts.append(alias_weapon)
                stations[sta] = opts
                hit_idx = len(opts) - 1
            idx_map[sta] = int(hit_idx)
            qty_map[sta] = int(req_qty)
        cfg["stations"] = stations
        pmd_dr_state["stores_cfg"] = cfg
        pmd_dr_state["stores_sta_idx"] = dict(idx_map)
        pmd_dr_state["stores_sta_qty"] = dict(qty_map)

    def _pmd_stores_inv_with_sms_state(callback: Callable[[formats.SmsFormat, pygame.Rect], object]) -> object:
        sms_state = formats.SMS_STATE
        keys = set(_PMD_STORES_INV_STATE_MAP_MAIN.keys()) | {
            "store_loads",
            "gun_count",
            "cntl_submenu_open",
            "cntl_inv_prog_open",
            "cntl_inv_actual_request_mode",
            "cntl_inv_load_request",
            "cntl_inv_clear_request",
        }
        saved = {key: sms_state.get(key) for key in keys}
        rect = get_portal_rect(status_menu_popup_portal_index).copy()
        try:
            sms_state["store_loads"] = _pmd_stores_inv_actual_store_loads()
            sms_state["gun_count"] = int(pmd_dr_state.get("stores_gun_value", 182))
            sms_state["cntl_submenu_open"] = 1
            sms_state["cntl_inv_prog_open"] = 1
            sms_state["cntl_inv_actual_request_mode"] = 1
            sms_state["cntl_inv_load_request"] = {}
            sms_state["cntl_inv_clear_request"] = []
            for sms_key, pmd_key in _PMD_STORES_INV_STATE_MAP_MAIN.items():
                sms_state[sms_key] = pmd_dr_state.get(pmd_key, _pmd_stores_inv_default_value(sms_key))
            result = callback(formats.SmsFormat(), rect)
            clear_req_raw = sms_state.get("cntl_inv_clear_request", [])
            clear_req = [str(v).upper().strip() for v in clear_req_raw] if isinstance(clear_req_raw, (list, tuple)) else []
            _pmd_stores_inv_apply_clear(clear_req)
            load_req_raw = sms_state.get("cntl_inv_load_request", {})
            if isinstance(load_req_raw, dict):
                _pmd_stores_inv_apply_load_request(load_req_raw)
            for sms_key, pmd_key in _PMD_STORES_INV_STATE_MAP_MAIN.items():
                pmd_dr_state[pmd_key] = sms_state.get(sms_key, _pmd_stores_inv_default_value(sms_key))
            return result
        finally:
            for key, value in saved.items():
                if value is None:
                    sms_state.pop(key, None)
                else:
                    sms_state[key] = value

    def _pmd_stores_inv_cell_rect(cell_name: str, rect: pygame.Rect) -> Optional[pygame.Rect]:
        token = str(cell_name).upper().strip()
        if len(token) < 2 or token == "E8":
            return None
        col = ord(token[0]) - ord("A")
        try:
            row = int(token[1:]) - 1
        except Exception:
            return None
        if col < 0 or col >= 5 or row < 0 or row >= 8:
            return None
        cell_w = rect.width // 5
        cell_h = rect.height // 8
        return pygame.Rect(rect.x + col * cell_w, rect.y + row * cell_h, cell_w, cell_h)

    def _pmd_stores_inv_click_cell(cell_name: str) -> None:
        def _click(fmt: formats.SmsFormat, fmt_rect: pygame.Rect) -> object:
            cell = _pmd_stores_inv_cell_rect(cell_name, fmt_rect)
            if cell is None:
                return None
            ctx = FormatContext(0, lambda *_args: None, lambda *_args: None, lambda *_args: None)
            return fmt.on_click(cell.center, fmt_rect, ctx)

        _pmd_stores_inv_with_sms_state(_click)

    def _sync_pmd_actual_stores_to_sms_live() -> None:
        actual_loads = _pmd_stores_inv_actual_store_loads()
        sms = getattr(formats, "SMS_STATE", {})
        if not isinstance(sms, dict):
            return
        sms["store_loads"] = dict(actual_loads)
        sms["stores_thought_initialized"] = 1
        counts: Dict[str, int] = {"AS": 0, "SRM": 0, "MRM": 0}
        for entry in actual_loads.values():
            if not isinstance(entry, dict):
                continue
            weapon = str(entry.get("weapon", "")).strip().upper()
            if weapon == "" or weapon == "NONE":
                continue
            store_type = str(entry.get("type", "AS")).upper().strip()
            if store_type not in counts:
                store_type = "AS"
            counts[store_type] = int(counts.get(store_type, 0)) + 1
        try:
            gun = max(0, min(182, int(pmd_dr_state.get("stores_gun_value", 182))))
        except Exception:
            gun = 182
        sms["gun_count"] = int(gun)
        sms["mrm_count"] = int(counts.get("MRM", 0))
        sms["srm_count"] = int(counts.get("SRM", 0))
        sms["as_count"] = int(counts.get("AS", 0))

    def _pmd_load_msn_action_press(action_key: str, now_ms_local: int) -> bool:
        action_keys = {
            "PMD_LOAD_MSN_D1_POS",
            "PMD_LOAD_MSN_D2_NAV",
            "PMD_LOAD_MSN_D3_COM",
            "PMD_LOAD_MSN_D4_SENSOR",
            "PMD_LOAD_MSN_D5_WPNS",
            "PMD_LOAD_MSN_D6_PLAN_DATA",
            "PMD_LOAD_MSN_E2_ELINT",
            "PMD_LOAD_MSN_E6_LOAD_ALL",
        }
        key_token = str(action_key).strip()
        if key_token not in action_keys:
            return False
        try:
            active_until = int(pmd_dr_state.get("load_msn_active_until_ms", 0))
        except Exception:
            active_until = 0
        active_key = str(pmd_dr_state.get("load_msn_active_key", "")).strip()
        if active_until > now_ms_local and active_key != "" and key_token != active_key:
            return True
        pmd_dr_state["load_msn_active_key"] = key_token
        pmd_dr_state["load_msn_active_until_ms"] = int(now_ms_local + 5000)
        if key_token in {"PMD_LOAD_MSN_D5_WPNS", "PMD_LOAD_MSN_E6_LOAD_ALL"}:
            _sync_pmd_actual_stores_to_sms_live()
        return True

    def _sync_stores_to_sms_state() -> None:
        _ensure_pmd_stores_state()
        cfg = _stores_cfg()
        weapons_raw = cfg.get("weapons", {})
        stations_raw = cfg.get("stations", {})
        idx_map_raw = pmd_dr_state.get("stores_sta_idx", {})
        weapons = weapons_raw if isinstance(weapons_raw, dict) else {}
        stations = stations_raw if isinstance(stations_raw, dict) else {}
        idx_map = idx_map_raw if isinstance(idx_map_raw, dict) else {}
        qty_map_raw = pmd_dr_state.get("stores_sta_qty", {})
        qty_map = qty_map_raw if isinstance(qty_map_raw, dict) else {}
        if not isinstance(qty_map_raw, dict):
            pmd_dr_state["stores_sta_qty"] = qty_map

        # SMS INV CLR requests must update PMD station indices; otherwise
        # SMS store_loads gets repopulated by PMD sync on the next frame.
        try:
            sms_state = getattr(formats, "SMS_STATE", {})
        except Exception:
            sms_state = {}
        if isinstance(sms_state, dict):
            # SMS INV now represents believed inventory only. Do not let its
            # load/clear requests mutate PMD actual stores during background
            # PMD->SMS sync.
            sms_state["cntl_inv_clear_request"] = []
            sms_state["cntl_inv_load_request"] = {}
        clear_request: List[str] = []
        if isinstance(sms_state, dict):
            raw_req = sms_state.get("cntl_inv_clear_request", [])
            if isinstance(raw_req, (list, tuple)):
                for sta in raw_req:
                    token = str(sta).upper().strip()
                    if token.startswith("STA") and token not in clear_request:
                        clear_request.append(token)
        if len(clear_request) > 0:
            for sta in clear_request:
                opts_raw = stations.get(sta, ["NONE"])
                opts = [str(v) for v in opts_raw] if isinstance(opts_raw, list) and len(opts_raw) > 0 else ["NONE"]
                none_idx = 0
                for i, opt in enumerate(opts):
                    if str(opt).strip().upper() == "NONE":
                        none_idx = int(i)
                        break
                idx_map[sta] = int(none_idx)
                qty_map[sta] = 0
            pmd_dr_state["stores_sta_idx"] = dict(idx_map)
            pmd_dr_state["stores_sta_qty"] = dict(qty_map)
            if isinstance(sms_state, dict):
                sms_state["cntl_inv_clear_request"] = []

        # SMS INV LOAD requests update PMD station indices so selected
        # TYPE/RACK/WPN choices persist through PMD->SMS sync.
        load_req: Dict[str, object] = {}
        if isinstance(sms_state, dict):
            raw_req = sms_state.get("cntl_inv_load_request", {})
            if isinstance(raw_req, dict):
                load_req = raw_req
        if len(load_req) > 0:
            req_weapon = str(load_req.get("weapon", "")).upper().strip()
            req_type = str(load_req.get("type", "")).upper().strip()
            req_stations_raw = load_req.get("stations", [])
            req_stations: List[str] = []
            if isinstance(req_stations_raw, (list, tuple)):
                for sta in req_stations_raw:
                    token = str(sta).upper().strip()
                    if token.startswith("STA") and token in PMD_STORES_STATION_ORDER and token not in req_stations:
                        req_stations.append(token)
            try:
                req_qty = max(1, int(load_req.get("qty", 1)))
            except Exception:
                req_qty = 1

            # Map SMS INV weapon tokens onto stores.json weapon IDs.
            req_alias_map = _stores_inventory_alias_map(cfg)

            alias_weapon = str(req_alias_map.get(req_weapon, req_weapon)).strip()
            norm_req = _stores_normalize_weapon_id(req_weapon)
            norm_alias = _stores_normalize_weapon_id(alias_weapon)
            if req_weapon != "" and len(req_stations) > 0:
                if alias_weapon not in weapons and req_weapon not in weapons:
                    weapons[alias_weapon] = _stores_inventory_weapon_meta(alias_weapon, req_weapon, req_type, req_stations, weapons, cfg)
                    cfg["weapons"] = weapons
                for sta in req_stations:
                    opts_raw = stations.get(sta, ["NONE"])
                    opts = [str(v) for v in opts_raw] if isinstance(opts_raw, list) and len(opts_raw) > 0 else ["NONE"]
                    hit_idx: Optional[int] = None
                    if alias_weapon in opts:
                        hit_idx = int(opts.index(alias_weapon))
                    elif req_weapon in opts:
                        hit_idx = int(opts.index(req_weapon))
                    else:
                        for i, wid in enumerate(opts):
                            wid_norm = _stores_normalize_weapon_id(wid)
                            if wid_norm != "" and (wid_norm == norm_req or wid_norm == norm_alias):
                                hit_idx = int(i)
                                break
                    if hit_idx is None:
                        opts.append(alias_weapon)
                        stations[sta] = opts
                        hit_idx = len(opts) - 1
                    if hit_idx is not None:
                        idx_map[sta] = int(hit_idx)
                        qty_map[sta] = int(req_qty)
                pmd_dr_state["stores_sta_idx"] = dict(idx_map)
                pmd_dr_state["stores_sta_qty"] = dict(qty_map)
                cfg["stations"] = stations
                pmd_dr_state["stores_cfg"] = cfg
            if isinstance(sms_state, dict):
                sms_state["cntl_inv_load_request"] = {}

        counts: Dict[str, int] = {"AS": 0, "SRM": 0, "MRM": 0}
        store_loads: Dict[str, Dict[str, object]] = {}
        for sta in PMD_STORES_STATION_ORDER:
            opts_raw = stations.get(sta, ["NONE"])
            opts = [str(v) for v in opts_raw] if isinstance(opts_raw, list) and len(opts_raw) > 0 else ["NONE"]
            try:
                idx = int(idx_map.get(sta, 0))
            except Exception:
                idx = 0
            idx = max(0, min(len(opts) - 1, idx))
            wid = str(opts[idx]).strip()
            if wid == "" or wid.upper() == "NONE":
                continue
            meta = weapons.get(wid, {})
            if not isinstance(meta, dict):
                continue
            wtype = str(meta.get("type", "AS")).upper().strip()
            if wtype not in {"AS", "SRM", "MRM"}:
                wtype = "AS"
            counts[wtype] = int(counts.get(wtype, 0)) + 1
            try:
                qty = max(1, int(qty_map.get(sta, 1)))
            except Exception:
                qty = 1
            icon_name = str(meta.get("icon", "")).strip()
            if icon_name != "" and not _stores_icon_exists(icon_name):
                icon_name = ""
            store_loads[sta] = {
                "weapon": wid,
                "icon": icon_name,
                "type": wtype,
                "qty": int(qty),
            }

        try:
            gun = max(0, min(182, int(pmd_dr_state.get("stores_gun_value", 182))))
        except Exception:
            gun = 182
        try:
            chaff = max(0, min(30, int(pmd_dr_state.get("stores_chaff_value", 10))))
        except Exception:
            chaff = 10
        try:
            flare = max(0, min(30, int(pmd_dr_state.get("stores_flare_value", 10))))
        except Exception:
            flare = 10
        pmd_dr_state["stores_gun_value"] = int(gun)
        pmd_dr_state["stores_chaff_value"] = int(chaff)
        pmd_dr_state["stores_flare_value"] = int(flare)

        sms = getattr(formats, "SMS_STATE", {})
        if isinstance(sms, dict):
            if not bool(sms.get("stores_thought_initialized", 0)):
                sms["store_loads"] = dict(store_loads)
                sms["stores_thought_initialized"] = 1
            thought_raw = sms.get("store_loads", {})
            thought_loads = thought_raw if isinstance(thought_raw, dict) else {}
            if not isinstance(thought_raw, dict):
                sms["store_loads"] = thought_loads
            training_raw = sms.get("training_store_loads", {})
            training_loads = training_raw if isinstance(training_raw, dict) else {}
            if not isinstance(training_raw, dict):
                sms["training_store_loads"] = training_loads
            try:
                live_train_idx = int(sms.get("live_train_idx", 0))
            except Exception:
                live_train_idx = 0
            if live_train_idx not in (0, 1):
                live_train_idx = 0
            sms["live_train_idx"] = int(live_train_idx)
            sms["cntl_live_train_idx"] = int(live_train_idx)
            master_arm_on_for_sms = False
            try:
                panel_sms = getattr(formats, "PANEL_BUTTON_STATES", {})
                master_arm_panel = panel_sms.get("MASTER ARM", {}) if isinstance(panel_sms, dict) else {}
                if isinstance(master_arm_panel, dict):
                    master_arm_on_for_sms = str(master_arm_panel.get("MASTER_ARM", "OFF")).upper() == "ON"
            except Exception:
                master_arm_on_for_sms = False
            active_thought_loads = training_loads if (master_arm_on_for_sms and live_train_idx == 1) else thought_loads
            thought_counts: Dict[str, int] = {"AS": 0, "SRM": 0, "MRM": 0}
            for entry in active_thought_loads.values():
                if not isinstance(entry, dict):
                    continue
                weapon = str(entry.get("weapon", "")).strip().upper()
                if weapon == "" or weapon == "NONE":
                    continue
                wtype = str(entry.get("type", "AS")).upper().strip()
                if wtype not in {"AS", "SRM", "MRM"}:
                    wtype = "AS"
                thought_counts[wtype] = int(thought_counts.get(wtype, 0)) + 1
            sms["gun_count"] = int(gun)
            sms["mrm_count"] = int(thought_counts.get("MRM", 0))
            sms["srm_count"] = int(thought_counts.get("SRM", 0))
            sms["as_count"] = int(thought_counts.get("AS", 0))
            sms["chaff"] = int(chaff)
            sms["flare"] = int(flare)
            sms["actual_store_loads"] = dict(store_loads)

    def _apply_gun_trigger_fire(dt_local: float) -> None:
        _ensure_pmd_stores_state()
        try:
            gun_count = int(pmd_dr_state.get("stores_gun_value", 182))
        except Exception:
            gun_count = 182
        gun_count = max(0, min(182, gun_count))
        try:
            accum = float(pmd_dr_state.get("gun_fire_accum_rounds", 0.0))
        except Exception:
            accum = 0.0
        accum = max(0.0, accum)
        if _pmd_is_action_down("gun_trigger") and gun_count > 0:
            accum += max(0.0, float(dt_local)) * float(GUN_FIRE_RATE_RPS)
            rounds_to_fire = int(accum)
            if rounds_to_fire > 0:
                fired = min(gun_count, rounds_to_fire)
                gun_count -= fired
                accum -= float(fired)
        pmd_dr_state["stores_gun_value"] = int(gun_count)
        pmd_dr_state["gun_fire_accum_rounds"] = max(0.0, accum)

    def _pmd_dr_selected_field() -> Optional[str]:
        value = pmd_dr_state.get("selected_field")
        if not value:
            return None
        sval = str(value)
        return sval if sval in PMD_DR_TANK_LIMITS else None

    def finalize_pmd_dr_data_entry(field: str) -> None:
        if field not in PMD_DR_TANK_LIMITS:
            return
        inputs = pmd_dr_state.get("inputs", {})
        values = pmd_dr_state.get("tank_values", {})
        if not isinstance(inputs, dict) or not isinstance(values, dict):
            return
        raw = "".join(ch for ch in str(inputs.get(field, "")) if ch.isdigit())
        if raw != "":
            committed = max(0, min(PMD_DR_TANK_LIMITS[field], int(raw)))
            values[field] = committed
            set_fuel_tank_value(field, committed)
        inputs[field] = ""
        if _pmd_dr_selected_field() == field:
            pmd_dr_state["selected_field"] = None

    def select_pmd_dr_data_entry(field: str) -> None:
        current = _pmd_dr_selected_field()
        if current == field:
            finalize_pmd_dr_data_entry(field)
            return
        if current is not None:
            finalize_pmd_dr_data_entry(current)
        pmd_dr_state["selected_field"] = field
        inputs = pmd_dr_state.get("inputs", {})
        if isinstance(inputs, dict):
            inputs[field] = ""

    def pmd_dr_keypad_press(key: str) -> None:
        field = _pmd_dr_selected_field()
        if field is None:
            return
        inputs = pmd_dr_state.get("inputs", {})
        values = pmd_dr_state.get("tank_values", {})
        if not isinstance(inputs, dict) or not isinstance(values, dict):
            return
        current = str(inputs.get(field, ""))
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            digit = key.split("_", 1)[1]
            inputs[field] = (current + digit)[-4:]
            return
        if key == "KP_BACK":
            inputs[field] = current[:-1]
            return
        if key in {"KP_UP", "KP_DOWN"}:
            baseline = current if current != "" else str(values.get(field, 0))
            try:
                value = int("".join(ch for ch in baseline if ch.isdigit()) or "0")
            except Exception:
                value = 0
            if key == "KP_UP":
                value = min(PMD_DR_TANK_LIMITS[field], value + 1)
            else:
                value = max(0, value - 1)
            inputs[field] = str(value)

    def _sanitize_cesium_ion_token(value: object, max_len: int = 4096) -> str:
        text = str(value or "").replace("\r", "").replace("\n", "").strip()
        if text == "":
            return ""
        out = "".join(ch for ch in text if 32 <= ord(ch) <= 126)
        if len(out) > int(max_len):
            out = out[: int(max_len)]
        return out

    def _pmd_cesium_token_selected() -> bool:
        return bool(pmd_dr_state.get("cesium_token_selected", False))

    def _pmd_cesium_finalize_token_entry() -> None:
        if not _pmd_cesium_token_selected() and str(pmd_dr_state.get("cesium_token_input", "")) == "":
            return
        token = _sanitize_cesium_ion_token(
            pmd_dr_state.get("cesium_token_input", pmd_dr_state.get("cesium_token_value", ""))
        )
        settings["cesium_ion_token"] = token
        pmd_dr_state["cesium_token_value"] = token
        try:
            save_settings(settings)
            pmd_dr_state["cesium_token_status"] = "Token saved."
        except Exception:
            pmd_dr_state["cesium_token_status"] = "Failed to save token."
        pmd_dr_state["cesium_token_selected"] = False
        pmd_dr_state["cesium_token_input"] = ""

    def _pmd_cesium_select_token_entry() -> None:
        if _pmd_cesium_token_selected():
            _pmd_cesium_finalize_token_entry()
            return
        pmd_dr_state["cesium_token_selected"] = True
        pmd_dr_state["cesium_token_input"] = ""
        pmd_dr_state["cesium_token_status"] = "Editing token..."

    def _pmd_cesium_backspace() -> None:
        if not _pmd_cesium_token_selected():
            return
        current = str(pmd_dr_state.get("cesium_token_input", ""))
        pmd_dr_state["cesium_token_input"] = current[:-1]

    def _pmd_cesium_type_char(ch: str) -> bool:
        if not _pmd_cesium_token_selected():
            return False
        txt = str(ch or "")
        if len(txt) != 1:
            return False
        if ord(txt) < 32 or ord(txt) > 126:
            return False
        current = str(pmd_dr_state.get("cesium_token_input", ""))
        pmd_dr_state["cesium_token_input"] = _sanitize_cesium_ion_token(current + txt)
        return True

    def _pmd_cesium_paste_clipboard() -> bool:
        if not _pmd_cesium_token_selected():
            return False
        payload = _sanitize_cesium_ion_token(_term_read_clipboard_text())
        if payload == "":
            return False
        current = str(pmd_dr_state.get("cesium_token_input", ""))
        pmd_dr_state["cesium_token_input"] = _sanitize_cesium_ion_token(current + payload)
        return True

    def _ensure_fuel_degrd_state() -> Dict[str, object]:
        raw = pmd_dr_state.get("fuel_degrd", {})
        state = raw if isinstance(raw, dict) else {}
        defaults = _default_fuel_degrd_state()
        for key, default_val in defaults.items():
            if key not in state:
                state[key] = default_val
        for map_key in ("tank_degrd", "sensor_degrd"):
            raw_map = state.get(map_key, {})
            out_map = raw_map if isinstance(raw_map, dict) else {}
            for tank in PMD_FUEL_DEGRD_TANK_ORDER:
                out_map[tank] = bool(out_map.get(tank, False))
            state[map_key] = out_map
        for map_key in ("valve_state", "valve_degrd"):
            raw_outer = state.get(map_key, {})
            outer = raw_outer if isinstance(raw_outer, dict) else {}
            normalized_outer: Dict[str, Dict[str, bool]] = {}
            for tank, valves in PMD_FUEL_DEGRD_VALVE_LAYOUT.items():
                tank_raw = outer.get(tank, {})
                tank_map = tank_raw if isinstance(tank_raw, dict) else {}
                defaults_map = PMD_FUEL_DEGRD_VALVE_DEFAULTS.get(tank, {})
                normalized_outer[tank] = {}
                for valve in valves:
                    if map_key == "valve_state":
                        normalized_outer[tank][valve] = bool(tank_map.get(valve, defaults_map.get(valve, False)))
                    else:
                        normalized_outer[tank][valve] = bool(tank_map.get(valve, False))
            state[map_key] = normalized_outer
        page = str(state.get("page", "HOME")).upper().strip()
        if page not in {"HOME"} | set(PMD_FUEL_DEGRD_TANK_ORDER):
            page = "HOME"
        state["page"] = page
        state["stale_data"] = bool(state.get("stale_data", False))
        pmd_dr_state["fuel_degrd"] = state
        return state

    def _fuel_degrd_page() -> str:
        state = _ensure_fuel_degrd_state()
        page = str(state.get("page", "HOME")).upper().strip()
        if page not in {"HOME"} | set(PMD_FUEL_DEGRD_TANK_ORDER):
            page = "HOME"
            state["page"] = page
        return page

    def _fuel_degrd_hrc_code(group: str, label: str) -> str:
        group_key = str(group).upper().strip()
        base_map = {
            "FEED": "2801000000",
            "MEASUR": "2802000000",
            "TRNSFR": "2803000000",
        }
        base = base_map.get(group_key, "2809000000")
        key = f"{group_key}:{str(label).upper().strip()}"
        checksum = sum(ord(ch) for ch in key) % 1000
        return f"{base}{checksum:03d}"

    def _ensure_runtime_icaw_entry(name: str, severity: str, system_key: str, target_key: str) -> None:
        try:
            sev = str(severity).strip().lower()
            if sev not in {"warning", "caution", "advisory"}:
                sev = "advisory"
            name_clean = str(name).strip()
            if name_clean == "":
                return
            key_fn = getattr(formats, "_icaw_alert_key", None)
            if callable(key_fn):
                catalog_key = str(key_fn(name_clean, sev))
            else:
                catalog_key = f"{name_clean.upper()}|{sev}"
            catalog = getattr(formats, "ICAWS_ALERT_CATALOG", None)
            if not isinstance(catalog, dict):
                return
            if catalog_key not in catalog:
                catalog[catalog_key] = {
                    "name": name_clean,
                    "severity": sev,
                    "system": str(system_key).upper().strip(),
                    "target_mode": "single",
                    "target_keys": [str(target_key).upper().strip()],
                    "hrc_rules": [],
                }
            canon = getattr(formats, "ICAWS_ALERT_CANONICAL_NAME", None)
            if isinstance(canon, dict):
                canon[name_clean.upper()] = name_clean
            defaults = getattr(formats, "ICAWS_ALERT_DEFAULT_SEVERITY", None)
            if isinstance(defaults, dict):
                defaults[name_clean.upper()] = sev
            if sev == "warning":
                seq_name = "ICAWS_WARNING_ALERTS"
            elif sev == "caution":
                seq_name = "ICAWS_CAUTION_ALERTS"
            else:
                seq_name = "ICAWS_ADVISORY_ALERTS"
            seq = getattr(formats, seq_name, None)
            if isinstance(seq, list) and name_clean not in seq:
                seq.append(name_clean)
        except Exception:
            pass

    def _sync_fuel_degrd_runtime() -> None:
        state = _ensure_fuel_degrd_state()
        tank_degrd = state.get("tank_degrd", {})
        sensor_degrd = state.get("sensor_degrd", {})
        stale_data = bool(state.get("stale_data", False))
        valve_state = state.get("valve_state", {})
        valve_degrd = state.get("valve_degrd", {})
        if not isinstance(tank_degrd, dict):
            tank_degrd = {}
        if not isinstance(sensor_degrd, dict):
            sensor_degrd = {}
        if not isinstance(valve_state, dict):
            valve_state = {}
        if not isinstance(valve_degrd, dict):
            valve_degrd = {}

        tank_effective = {tank: False for tank in PMD_DR_TANK_LIMITS.keys()}
        sensor_effective = {tank: False for tank in PMD_DR_TANK_LIMITS.keys()}
        for tank in PMD_FUEL_DEGRD_TANK_ORDER:
            t_on = bool(tank_degrd.get(tank, False))
            s_on = bool(sensor_degrd.get(tank, False))
            tank_effective[tank] = t_on
            sensor_effective[tank] = s_on
            if tank == "F1":
                tank_effective["F1I"] = t_on
                sensor_effective["F1I"] = s_on

        try:
            formats.FuelFormat._shared_tank_degrd = dict(tank_effective)
            formats.FuelFormat._shared_sensor_degrd = dict(sensor_effective)
            formats.FuelFormat._shared_stale_data = bool(stale_data)
            # Keep only supported valve tanks/valves.
            normalized_valve_state: Dict[str, Dict[str, bool]] = {}
            normalized_valve_degrd: Dict[str, Dict[str, bool]] = {}
            for tank, valves in PMD_FUEL_DEGRD_VALVE_LAYOUT.items():
                local_state_raw = valve_state.get(tank, {}) if isinstance(valve_state, dict) else {}
                local_degrd_raw = valve_degrd.get(tank, {}) if isinstance(valve_degrd, dict) else {}
                local_state = local_state_raw if isinstance(local_state_raw, dict) else {}
                local_degrd = local_degrd_raw if isinstance(local_degrd_raw, dict) else {}
                defaults_map = PMD_FUEL_DEGRD_VALVE_DEFAULTS.get(tank, {})
                normalized_valve_state[tank] = {}
                normalized_valve_degrd[tank] = {}
                for valve in valves:
                    normalized_valve_state[tank][valve] = bool(local_state.get(valve, defaults_map.get(valve, False)))
                    normalized_valve_degrd[tank][valve] = bool(local_degrd.get(valve, False))
            formats.FuelFormat._shared_valve_state = normalized_valve_state
            formats.FuelFormat._shared_valve_degrd = normalized_valve_degrd
        except Exception:
            pass

        phm = _ensure_phm_status_debug_state()
        hrc_map_raw = phm.get("hrc_events", {})
        fna_map_raw = phm.get("fna_events", {})
        hrc_map = hrc_map_raw if isinstance(hrc_map_raw, dict) else {}
        fna_map = fna_map_raw if isinstance(fna_map_raw, dict) else {}
        phm["hrc_events"] = hrc_map
        phm["fna_events"] = fna_map

        prev_raw = pmd_dr_state.get("fuel_degrd_prev_events", {})
        prev = prev_raw if isinstance(prev_raw, dict) else {}
        prev_hrc = prev.get("hrc", {}) if isinstance(prev.get("hrc", {}), dict) else {}
        prev_fna = prev.get("fna", {}) if isinstance(prev.get("fna", {}), dict) else {}
        for comp_key, entries_raw in prev_hrc.items():
            vals = hrc_map.get(comp_key, [])
            if not isinstance(vals, list):
                continue
            entries = [str(x).strip() for x in entries_raw] if isinstance(entries_raw, list) else []
            norms = {x.upper() for x in entries if x != ""}
            new_vals = [str(v) for v in vals if str(v).strip() != "" and str(v).strip().upper() not in norms]
            if len(new_vals) > 0:
                hrc_map[comp_key] = new_vals
            else:
                hrc_map.pop(comp_key, None)
        for comp_key, entries_raw in prev_fna.items():
            vals = fna_map.get(comp_key, [])
            if not isinstance(vals, list):
                continue
            entries = [str(x).strip() for x in entries_raw] if isinstance(entries_raw, list) else []
            norms = {x.upper() for x in entries if x != ""}
            new_vals = [str(v) for v in vals if str(v).strip() != "" and str(v).strip().upper() not in norms]
            if len(new_vals) > 0:
                fna_map[comp_key] = new_vals
            else:
                fna_map.pop(comp_key, None)

        new_hrc: Dict[str, List[str]] = {}
        new_fna: Dict[str, List[str]] = {}

        def _append_event(target: Dict[str, List[str]], comp_key: str, text: str) -> None:
            label = str(text).strip()
            if label == "":
                return
            vals = target.get(comp_key, [])
            if not isinstance(vals, list):
                vals = []
            if label.upper() not in {str(v).strip().upper() for v in vals}:
                vals.append(label)
            target[comp_key] = vals

        for tank in PMD_FUEL_DEGRD_TANK_ORDER:
            if bool(tank_degrd.get(tank, False)):
                _append_event(new_hrc, "FEED", _fuel_degrd_hrc_code("FEED", f"{tank}:TANK"))
                _append_event(new_fna, "FEED", f"{tank} TANK DEGRADE")
            if bool(sensor_degrd.get(tank, False)):
                _append_event(new_hrc, "MEASUR", _fuel_degrd_hrc_code("MEASUR", f"{tank}:SENSOR"))
                _append_event(new_fna, "MEASUR", f"{tank} SENSOR DEGRADE")

        for tank, valves in PMD_FUEL_DEGRD_VALVE_LAYOUT.items():
            local_degrd_raw = valve_degrd.get(tank, {}) if isinstance(valve_degrd, dict) else {}
            local_degrd = local_degrd_raw if isinstance(local_degrd_raw, dict) else {}
            for valve in valves:
                if bool(local_degrd.get(valve, False)):
                    _append_event(new_hrc, "TRNSFR", _fuel_degrd_hrc_code("TRNSFR", f"{tank}:{valve}"))
                    _append_event(new_fna, "TRNSFR", f"{tank} {valve} DEGRADE")

        if stale_data:
            _append_event(new_fna, "MEASUR", "STALE FUEL DATA")

        for comp_key, vals in new_hrc.items():
            existing = hrc_map.get(comp_key, [])
            existing_list = existing if isinstance(existing, list) else []
            existing_norm = {str(v).strip().upper() for v in existing_list}
            for item in vals:
                if str(item).strip().upper() not in existing_norm:
                    existing_list.append(str(item))
            if len(existing_list) > 0:
                hrc_map[comp_key] = existing_list
        for comp_key, vals in new_fna.items():
            existing = fna_map.get(comp_key, [])
            existing_list = existing if isinstance(existing, list) else []
            existing_norm = {str(v).strip().upper() for v in existing_list}
            for item in vals:
                if str(item).strip().upper() not in existing_norm:
                    existing_list.append(str(item))
            if len(existing_list) > 0:
                fna_map[comp_key] = existing_list

        pmd_dr_state["fuel_degrd_prev_events"] = {
            "hrc": {k: list(v) for k, v in new_hrc.items()},
            "fna": {k: list(v) for k, v in new_fna.items()},
        }
        _phm_debug_recompute_system_override("FUEL")

        _ensure_runtime_icaw_entry("TANK DEGRD", "caution", "FUEL", "FEED")
        _ensure_runtime_icaw_entry("SENSOR DEGRD", "caution", "FUEL", "MEASUR")
        try:
            active_raw = getattr(formats, "ICAWS_STATE", {}).get("active", [])
            active = active_raw if isinstance(active_raw, list) else []
            cleaned: List[Dict[str, str]] = []
            for item in active:
                if isinstance(item, dict):
                    txt = str(item.get("text", "")).strip().upper()
                    if txt in {"TANK DEGRD", "SENSOR DEGRD"}:
                        continue
                    sev = str(item.get("severity", "advisory")).strip().lower()
                    cleaned.append({"text": str(item.get("text", "")), "severity": sev})
                else:
                    txt = str(item).strip()
                    if txt.upper() in {"TANK DEGRD", "SENSOR DEGRD"}:
                        continue
                    cleaned.append({"text": txt, "severity": "advisory"})
            if any(bool(tank_degrd.get(t, False)) for t in PMD_FUEL_DEGRD_TANK_ORDER):
                cleaned.append({"text": "TANK DEGRD", "severity": "caution"})
            if any(bool(sensor_degrd.get(t, False)) for t in PMD_FUEL_DEGRD_TANK_ORDER):
                cleaned.append({"text": "SENSOR DEGRD", "severity": "caution"})
            formats.ICAWS_STATE["active"] = cleaned
        except Exception:
            pass

    def _pmd_keybind_selected_field() -> Optional[str]:
        raw = str(pmd_dr_state.get("keybind_selected", "")).strip().lower()
        return raw if raw in PMD_KEYBIND_ACTION_ORDER else None

    def _pmd_normalize_key_name(raw_key: object) -> str:
        raw = str(raw_key).strip()
        if raw == "":
            return ""
        try:
            code = int(pygame.key.key_code(raw.lower()))
        except Exception:
            try:
                code = int(pygame.key.key_code(raw))
            except Exception:
                return ""
        try:
            normalized = str(pygame.key.name(code)).strip()
        except Exception:
            normalized = raw
        return normalized

    def _pmd_keybind_key_name(action: str) -> str:
        action_key = str(action).strip().lower()
        if action_key not in PMD_KEYBIND_ACTION_ORDER:
            return ""
        values_raw = pmd_dr_state.get("keybind_values", {})
        values = values_raw if isinstance(values_raw, dict) else {}
        if action_key in _FLIGHT_CTRL_MANUAL_KEYS:
            keys_tuple = _FLIGHT_CTRL_MANUAL_KEYS.get(action_key, ())
            if isinstance(keys_tuple, tuple) and len(keys_tuple) > 0:
                try:
                    name = str(pygame.key.name(int(keys_tuple[0]))).strip()
                    if name != "":
                        return name
                except Exception:
                    pass
        if action_key in values:
            explicit = str(values.get(action_key, "")).strip()
            if explicit == "":
                return ""
            return _pmd_normalize_key_name(explicit) or explicit
        fallback = str(PMD_KEYBIND_DEFAULT_NAMES.get(action_key, "")).strip()
        return _pmd_normalize_key_name(fallback) or fallback

    def _pmd_keybind_owner_for_key(raw_key: object, exclude_action: str = "") -> Optional[str]:
        normalized = _pmd_normalize_key_name(raw_key)
        if normalized == "":
            return None
        exclude = str(exclude_action).strip().lower()
        for action in PMD_KEYBIND_ACTION_ORDER:
            if action == exclude:
                continue
            other_name = _pmd_keybind_key_name(action)
            if _pmd_normalize_key_name(other_name) == normalized:
                return action
        return None

    def _pmd_set_keybind_value(action: str, raw_key: object) -> bool:
        action_key = str(action).strip().lower()
        if action_key not in PMD_KEYBIND_ACTION_ORDER:
            return False
        normalized = _pmd_normalize_key_name(raw_key)
        if normalized == "":
            return False
        if _pmd_keybind_owner_for_key(normalized, action_key) is not None:
            return False
        if action_key in _FLIGHT_CTRL_MANUAL_KEYS:
            if not _pmd_set_flight_keybind(action_key, normalized):
                return False
        values_raw = pmd_dr_state.get("keybind_values", {})
        values = values_raw if isinstance(values_raw, dict) else {}
        values[action_key] = normalized
        pmd_dr_state["keybind_values"] = values
        return True

    def _pmd_clear_keybind_value(action: str) -> bool:
        action_key = str(action).strip().lower()
        if action_key not in PMD_KEYBIND_ACTION_ORDER:
            return False
        if action_key in _FLIGHT_CTRL_MANUAL_KEYS:
            _FLIGHT_CTRL_MANUAL_KEYS[action_key] = tuple()
        values_raw = pmd_dr_state.get("keybind_values", {})
        values = values_raw if isinstance(values_raw, dict) else {}
        values[action_key] = ""
        pmd_dr_state["keybind_values"] = values
        return True

    def _pmd_keybind_current_char(action: str) -> str:
        key_name = _pmd_keybind_key_name(action)
        display = _format_keybind_display_text(key_name)
        return display if display != "" else "?"

    def _pmd_action_key_codes(action: str) -> Tuple[int, ...]:
        action_key = str(action).strip().lower()
        if action_key in _FLIGHT_CTRL_MANUAL_KEYS:
            keys_tuple = _FLIGHT_CTRL_MANUAL_KEYS.get(action_key, ())
            return tuple(int(v) for v in keys_tuple if isinstance(v, int))
        key_name = _pmd_keybind_key_name(action_key)
        if key_name == "":
            values_raw = pmd_dr_state.get("keybind_values", {})
            values = values_raw if isinstance(values_raw, dict) else {}
            if action_key in values:
                return ()
            key_name = str(PMD_KEYBIND_DEFAULT_NAMES.get(action_key, "")).strip()
        if key_name == "":
            return ()
        try:
            code = int(pygame.key.key_code(key_name.lower()))
        except Exception:
            try:
                code = int(pygame.key.key_code(key_name))
            except Exception:
                return ()
        return (code,)

    def _pmd_is_action_down(action: str, key_state: Optional[object] = None) -> bool:
        action_key = str(action).strip().lower()
        hotas_down_raw = pmd_dr_state.get("hotas_down", {})
        hotas_down = hotas_down_raw if isinstance(hotas_down_raw, dict) else {}
        if bool(hotas_down.get(action_key, False)):
            return True
        # Raw HOTAS digital actions are stored by HOTAS action IDs.
        # Accept direct matches and keybind aliases.
        hotas_raw_down_raw = pmd_dr_state.get("hotas_action_down_raw", {})
        hotas_raw_down = hotas_raw_down_raw if isinstance(hotas_raw_down_raw, dict) else {}
        hotas_aliases = {
            "czoom_plus": ("zoom_plus",),
            "czoom_minus": ("zoom_minus",),
            "poi_lt": ("poi_left",),
            "poi_rt": ("poi_right",),
            "poi_up": ("poi_up",),
            "poi_dn": ("poi_down",),
            "com_a": ("comm_ctl_left",),
            "com_b": ("comm_ctl_right",),
            "com_c": ("comm_ctl_aft",),
        }
        if bool(hotas_raw_down.get(action_key, False)):
            return True
        for alias in hotas_aliases.get(action_key, tuple()):
            if bool(hotas_raw_down.get(str(alias).strip().lower(), False)):
                return True
        for key_code in _pmd_action_key_codes(action):
            if key_code in held_keys:
                return True
            if key_state is not None:
                try:
                    if bool(key_state[key_code]):
                        return True
                except Exception:
                    pass
        return False

    def _pmd_event_matches_action(event_key: object, action: str) -> bool:
        try:
            key_code = int(event_key)
        except Exception:
            return False
        return key_code in set(_pmd_action_key_codes(action))

    def _pmd_event_matches_landing_gear(event_key: object) -> bool:
        try:
            key_code = int(event_key)
        except Exception:
            return False
        # Keep the hard default as a fallback so gear remains usable if a
        # saved keybind is missing or stale after settings migrations.
        return bool(key_code == pygame.K_g or _pmd_event_matches_action(key_code, "ldg_gear"))

    def _pmd_is_hold_action_key(event_key: object) -> bool:
        hold_actions = (
            "elev_up",
            "elev_down",
            "ail_left",
            "ail_right",
            "rud_left",
            "rud_right",
            "throt_plus",
            "throt_minus",
            "ipp_run",
            "engine_run",
            "gun_trigger",
            "pickle",
            "com_mute",
            "tx",
            "brake",
            "ldg_gear",
            "wpn_sel",
            "disconnect",
            "nws",
            "tms_up",
            "tms_down",
            "tms_left",
            "tms_right",
            "dms_up",
            "dms_down",
            "dms_left",
            "dms_right",
            "fov_up",
            "fov_down",
            "fov_left",
            "fov_right",
            "cms_up",
            "cms_down",
            "cms_left",
            "cms_right",
            "mngmt_z",
            "mngmt_up",
            "mngmt_down",
            "wms_z",
            "wms_fwd",
            "wms_aft",
            "wms_left",
            "wms_right",
            "slew_z",
            "slew_fwd",
            "slew_aft",
            "slew_left",
            "slew_right",
            "comm_ctl_z",
            "comm_ctl_fwd",
            "comm_ctl_aft",
            "comm_ctl_left",
            "comm_ctl_right",
            "cage_uncage",
            "mpo",
            "pol_ctrl",
            "aprch_pwr_comp",
            "cffl_z",
            "cffl_fwd",
            "cffl_aft",
            "spd_brk_fwd",
            "spd_brk_aft",
            "spd_hold_z",
            "spd_hold_up",
            "spd_hold_down",
        )
        return any(_pmd_event_matches_action(event_key, action) for action in hold_actions)

    def _save_flight_keybinds_to_settings() -> None:
        out: Dict[str, str] = {}
        for action in PMD_KEYBIND_ACTION_ORDER:
            key_name = _pmd_keybind_key_name(action)
            out[action] = key_name
        settings[FLIGHT_KEYBINDS_SETTINGS_KEY] = dict(out)
        save_settings(settings)

    def _hotas_bindings_dict() -> Dict[str, Dict[str, object]]:
        raw = pmd_dr_state.get("hotas_bindings", {})
        out: Dict[str, Dict[str, object]] = {}
        if isinstance(raw, dict):
            for action, binding in raw.items():
                action_key = str(action).strip().lower()
                if action_key not in HOTAS_ACTION_ORDER:
                    continue
                if isinstance(binding, dict):
                    out[action_key] = dict(binding)
        pmd_dr_state["hotas_bindings"] = out
        return out

    def _hotas_current_slew_mode() -> str:
        mode = str(pmd_dr_state.get("hotas_slew_mode", "AXIS")).upper()
        if mode not in {"AXIS", "HAT"}:
            mode = "AXIS"
        pmd_dr_state["hotas_slew_mode"] = mode
        return mode

    def _hotas_current_pan_mode() -> str:
        mode = str(pmd_dr_state.get("hotas_pan_mode", "HAT")).upper()
        if mode not in {"AXIS", "HAT"}:
            mode = "HAT"
        pmd_dr_state["hotas_pan_mode"] = mode
        return mode

    def _hotas_save_to_settings() -> None:
        engine_mode = str(pmd_dr_state.get("hotas_engine_run_mode", "MOMENTARY")).upper()
        if engine_mode not in {"MOMENTARY", "TOGGLE"}:
            engine_mode = "MOMENTARY"
        ldg_mode = str(pmd_dr_state.get("hotas_ldg_gear_mode", "TOGGLE")).upper()
        if ldg_mode not in {"MOMENTARY", "TOGGLE"}:
            ldg_mode = "TOGGLE"
        brake_mode = str(pmd_dr_state.get("hotas_brake_mode", "TOGGLE")).upper()
        if brake_mode not in {"MOMENTARY", "TOGGLE"}:
            brake_mode = "TOGGLE"
        try:
            slew_speed = float(pmd_dr_state.get("hotas_slew_speed", 1.0))
        except Exception:
            slew_speed = 1.0
        slew_speed = max(0.0, min(1.0, slew_speed))
        pmd_dr_state["hotas_slew_speed"] = float(slew_speed)
        try:
            pan_speed = float(pmd_dr_state.get("hotas_pan_speed", 1.0))
        except Exception:
            pan_speed = 1.0
        pan_speed = max(0.0, min(1.0, pan_speed))
        pmd_dr_state["hotas_pan_speed"] = float(pan_speed)
        payload = {
            "slew_mode": _hotas_current_slew_mode(),
            "pan_mode": _hotas_current_pan_mode(),
            "slew_speed": float(slew_speed),
            "pan_speed": float(pan_speed),
            "engine_run_mode": engine_mode,
            "engine_run_invert": bool(pmd_dr_state.get("hotas_engine_run_invert", False)),
            "ldg_gear_mode": ldg_mode,
            "brake_mode": brake_mode,
            "bindings": _hotas_bindings_dict(),
        }
        settings[HOTAS_BINDINGS_SETTINGS_KEY] = payload
        save_settings(settings)

    def _hotas_binding_label(binding: Optional[Dict[str, object]]) -> str:
        if not isinstance(binding, dict):
            return ""
        b_type = str(binding.get("type", "")).strip().lower()
        try:
            joy_idx = int(binding.get("joy", -1))
        except Exception:
            joy_idx = -1
        if joy_idx < 0:
            return ""
        token = ""
        if b_type == "axis":
            try:
                axis_idx = int(binding.get("id", -1))
            except Exception:
                axis_idx = -1
            if axis_idx < 0:
                return ""
            token = f"AXIS{axis_idx + 1}"
            if bool(binding.get("invert", False)):
                token += " INV"
        elif b_type == "button":
            try:
                btn_idx = int(binding.get("id", -1))
            except Exception:
                btn_idx = -1
            if btn_idx < 0:
                return ""
            token = f"BTN{btn_idx + 1}"
        elif b_type == "hat":
            try:
                hat_idx = int(binding.get("id", -1))
            except Exception:
                hat_idx = -1
            hat_dir = str(binding.get("dir", "")).upper()
            dir_tag = {"UP": "U", "DOWN": "D", "LEFT": "L", "RIGHT": "R"}.get(hat_dir, "")
            if hat_idx < 0 or dir_tag == "":
                return ""
            token = f"HAT{hat_idx + 1}_{dir_tag}"
        else:
            return ""
        return f"{joy_idx + 1}; {token}"

    def _hotas_excluded_inputs_set() -> Set[str]:
        raw = pmd_dr_state.get("hotas_edit_excluded_inputs", [])
        out: Set[str] = set()
        if isinstance(raw, list):
            for item in raw:
                token = str(item).strip().lower()
                if token != "":
                    out.add(token)
        pmd_dr_state["hotas_edit_excluded_inputs"] = sorted(out)
        return out

    def _hotas_set_excluded_inputs(values: Set[str]) -> None:
        out = sorted({str(v).strip().lower() for v in values if str(v).strip() != ""})
        pmd_dr_state["hotas_edit_excluded_inputs"] = out

    def _hotas_binding_exclude_signature(binding: Optional[Dict[str, object]]) -> str:
        if not isinstance(binding, dict):
            return ""
        b_type = str(binding.get("type", "")).strip().lower()
        try:
            joy_idx = int(binding.get("joy", -1))
        except Exception:
            joy_idx = -1
        if joy_idx < 0:
            return ""
        if b_type == "button":
            try:
                btn_idx = int(binding.get("id", -1))
            except Exception:
                btn_idx = -1
            if btn_idx < 0:
                return ""
            return f"button:{joy_idx}:{btn_idx}"
        if b_type == "hat":
            try:
                hat_idx = int(binding.get("id", -1))
            except Exception:
                hat_idx = -1
            hat_dir = str(binding.get("dir", "")).upper().strip()
            if hat_idx < 0 or hat_dir not in {"UP", "DOWN", "LEFT", "RIGHT"}:
                return ""
            return f"hat:{joy_idx}:{hat_idx}:{hat_dir.lower()}"
        return ""

    def _hotas_allowed_types(action: str) -> Tuple[str, ...]:
        action_key = str(action).strip().lower()
        allowed = HOTAS_ALLOWED_INPUTS.get(action_key, tuple())
        return tuple(v for v in allowed if v in {"axis", "button", "hat"})

    def _hotas_get_binding(action: str) -> Optional[Dict[str, object]]:
        action_key = str(action).strip().lower()
        bindings = _hotas_bindings_dict()
        binding = bindings.get(action_key)
        if not isinstance(binding, dict):
            return None
        return dict(binding)

    def _hotas_resolve_binding_joy_index(binding: Optional[Dict[str, object]]) -> Optional[int]:
        if not isinstance(binding, dict):
            return None
        try:
            saved_idx = int(binding.get("joy", -1))
        except Exception:
            saved_idx = -1
        saved_guid = str(binding.get("joy_guid", "") or "").strip().lower()
        saved_name = str(binding.get("joy_name", "") or "").strip().lower()
        devices_raw = pmd_dr_state.get("hotas_devices", [])
        devices = devices_raw if isinstance(devices_raw, list) else []

        if saved_guid != "" or saved_name != "":
            if saved_idx in hotas_joysticks:
                for dev_raw in devices:
                    dev = dev_raw if isinstance(dev_raw, dict) else {}
                    try:
                        dev_idx = int(dev.get("index", -1))
                    except Exception:
                        dev_idx = -1
                    if dev_idx != saved_idx:
                        continue
                    dev_guid = str(dev.get("guid", "") or "").strip().lower()
                    dev_name = str(dev.get("name", "") or "").strip().lower()
                    guid_ok = bool(saved_guid != "" and dev_guid != "" and dev_guid == saved_guid)
                    name_ok = bool(saved_name != "" and dev_name != "" and dev_name == saved_name)
                    if guid_ok or name_ok:
                        return int(saved_idx)
            for dev_raw in devices:
                dev = dev_raw if isinstance(dev_raw, dict) else {}
                try:
                    dev_idx = int(dev.get("index", -1))
                except Exception:
                    dev_idx = -1
                if dev_idx < 0 or dev_idx not in hotas_joysticks:
                    continue
                dev_guid = str(dev.get("guid", "") or "").strip().lower()
                dev_name = str(dev.get("name", "") or "").strip().lower()
                if saved_guid != "" and dev_guid != "" and dev_guid == saved_guid:
                    return int(dev_idx)
                if saved_name != "" and dev_name != "" and dev_name == saved_name:
                    return int(dev_idx)
            return None

        if saved_idx in hotas_joysticks:
            return int(saved_idx)
        return None

    def _hotas_binding_is_connected(binding: Optional[Dict[str, object]]) -> bool:
        return _hotas_resolve_binding_joy_index(binding) is not None

    def _hotas_get_connected_binding(action: str) -> Optional[Dict[str, object]]:
        binding = _hotas_get_binding(action)
        if not _hotas_binding_is_connected(binding):
            return None
        return binding

    def _hotas_set_binding(action: str, binding: Dict[str, object]) -> bool:
        action_key = str(action).strip().lower()
        if action_key not in HOTAS_ACTION_ORDER:
            return False
        if not isinstance(binding, dict):
            return False
        b_type = str(binding.get("type", "")).strip().lower()
        if b_type not in _hotas_allowed_types(action_key):
            return False
        try:
            joy_idx = int(binding.get("joy", -1))
        except Exception:
            joy_idx = -1
        if joy_idx < 0:
            return False
        out: Dict[str, object] = {"type": b_type, "joy": joy_idx}
        devices_raw = pmd_dr_state.get("hotas_devices", [])
        devices = devices_raw if isinstance(devices_raw, list) else []
        for dev_raw in devices:
            dev = dev_raw if isinstance(dev_raw, dict) else {}
            try:
                dev_idx = int(dev.get("index", -1))
            except Exception:
                dev_idx = -1
            if dev_idx != joy_idx:
                continue
            dev_guid = str(dev.get("guid", "") or "").strip()
            dev_name = str(dev.get("name", "") or "").strip()
            if dev_guid != "":
                out["joy_guid"] = dev_guid
            if dev_name != "":
                out["joy_name"] = dev_name
            break
        if b_type == "axis":
            try:
                axis_idx = int(binding.get("id", -1))
            except Exception:
                axis_idx = -1
            if axis_idx < 0:
                return False
            out["id"] = axis_idx
            out["invert"] = bool(binding.get("invert", False))
        elif b_type == "button":
            try:
                btn_idx = int(binding.get("id", -1))
            except Exception:
                btn_idx = -1
            if btn_idx < 0:
                return False
            out["id"] = btn_idx
        else:
            try:
                hat_idx = int(binding.get("id", -1))
            except Exception:
                hat_idx = -1
            hat_dir = str(binding.get("dir", "")).upper()
            if hat_idx < 0 or hat_dir not in {"UP", "DOWN", "LEFT", "RIGHT"}:
                return False
            out["id"] = hat_idx
            out["dir"] = hat_dir
        bindings = _hotas_bindings_dict()
        bindings[action_key] = out
        pmd_dr_state["hotas_bindings"] = bindings
        pmd_dr_state["hotas_edit_input_text"] = _hotas_binding_label(out)
        _hotas_save_to_settings()
        return True

    def _hotas_clear_binding(action: str) -> bool:
        action_key = str(action).strip().lower()
        if action_key not in HOTAS_ACTION_ORDER:
            return False
        bindings = _hotas_bindings_dict()
        if action_key in bindings:
            bindings.pop(action_key, None)
        pmd_dr_state["hotas_bindings"] = bindings
        pmd_dr_state["hotas_edit_input_text"] = ""
        _hotas_save_to_settings()
        return True

    def _hotas_refresh_devices() -> None:
        try:
            pygame.joystick.init()
        except Exception:
            pass
        hotas_joysticks.clear()
        devices: List[Dict[str, object]] = []
        try:
            count = int(pygame.joystick.get_count())
        except Exception:
            count = 0
        for idx in range(max(0, count)):
            try:
                js = pygame.joystick.Joystick(idx)
                if not bool(js.get_init()):
                    js.init()
                hotas_joysticks[idx] = js
                name = str(js.get_name())
                try:
                    guid = str(js.get_guid() or "").strip()
                except Exception:
                    guid = ""
                try:
                    instance_id = int(js.get_instance_id())
                except Exception:
                    instance_id = idx
                devices.append({"index": idx, "name": name, "guid": guid, "instance_id": instance_id})
            except Exception:
                continue
        pmd_dr_state["hotas_devices"] = devices
        try:
            edit_idx = int(pmd_dr_state.get("hotas_edit_device", -1))
        except Exception:
            edit_idx = -1
        valid_indices = {int(d.get("index", -1)) for d in devices if isinstance(d, dict)}
        if edit_idx not in valid_indices:
            if len(valid_indices) > 0:
                pmd_dr_state["hotas_edit_device"] = min(valid_indices)
            else:
                pmd_dr_state["hotas_edit_device"] = -1

    def _hotas_event_joy_index(event: pygame.event.Event) -> int:
        def _map_value_to_index(value: object, strict_instance: bool = False) -> int:
            try:
                raw_val = int(value)
            except Exception:
                return -1
            devices_raw = pmd_dr_state.get("hotas_devices", [])
            devices = devices_raw if isinstance(devices_raw, list) else []
            instance_to_index: Dict[int, int] = {}
            index_set: Set[int] = set()
            for dev in devices:
                if not isinstance(dev, dict):
                    continue
                try:
                    idx = int(dev.get("index", -1))
                    inst = int(dev.get("instance_id", -1))
                except Exception:
                    continue
                if idx >= 0:
                    index_set.add(idx)
                if idx >= 0 and inst >= 0:
                    instance_to_index[inst] = idx
            if strict_instance:
                return int(instance_to_index.get(raw_val, -1))
            has_instance = raw_val in instance_to_index
            has_index = raw_val in index_set
            if has_instance and (not has_index):
                return int(instance_to_index.get(raw_val, -1))
            if has_index and (not has_instance):
                return raw_val
            if has_instance and has_index:
                # Ambiguous value; prefer instance-id mapping to avoid assigning
                # to a different device that happens to share the same index.
                return int(instance_to_index.get(raw_val, -1))
            return raw_val if raw_val in hotas_joysticks else -1

        try:
            if hasattr(event, "instance_id"):
                mapped = _map_value_to_index(getattr(event, "instance_id"), strict_instance=True)
                if mapped >= 0:
                    return mapped
        except Exception:
            pass
        for attr in ("joy", "which"):
            try:
                if hasattr(event, attr):
                    mapped = _map_value_to_index(getattr(event, attr))
                    if mapped >= 0:
                        return mapped
            except Exception:
                continue
        return -1

    def _hotas_axis_value(binding: Dict[str, object]) -> Optional[float]:
        if not isinstance(binding, dict):
            return None
        if str(binding.get("type", "")).strip().lower() != "axis":
            return None
        try:
            axis_idx = int(binding.get("id", -1))
        except Exception:
            return None
        joy_idx_raw = _hotas_resolve_binding_joy_index(binding)
        if joy_idx_raw is None:
            return None
        joy_idx = int(joy_idx_raw)
        js = hotas_joysticks.get(joy_idx)
        if js is None:
            return None
        try:
            value = float(js.get_axis(axis_idx))
        except Exception:
            return None
        value = max(-1.0, min(1.0, value))
        if bool(binding.get("invert", False)):
            value = -value
        return float(value)

    def _hotas_button_down(binding: Dict[str, object]) -> bool:
        if not isinstance(binding, dict):
            return False
        if str(binding.get("type", "")).strip().lower() != "button":
            return False
        try:
            btn_idx = int(binding.get("id", -1))
        except Exception:
            return False
        joy_idx_raw = _hotas_resolve_binding_joy_index(binding)
        if joy_idx_raw is None:
            return False
        joy_idx = int(joy_idx_raw)
        js = hotas_joysticks.get(joy_idx)
        if js is None:
            return False
        try:
            return bool(js.get_button(btn_idx))
        except Exception:
            return False

    def _hotas_hat_down(binding: Dict[str, object]) -> bool:
        if not isinstance(binding, dict):
            return False
        if str(binding.get("type", "")).strip().lower() != "hat":
            return False
        try:
            hat_idx = int(binding.get("id", -1))
        except Exception:
            return False
        hat_dir = str(binding.get("dir", "")).upper()
        joy_idx_raw = _hotas_resolve_binding_joy_index(binding)
        if joy_idx_raw is None:
            return False
        joy_idx = int(joy_idx_raw)
        js = hotas_joysticks.get(joy_idx)
        if js is None:
            return False
        try:
            hat = js.get_hat(hat_idx)
            x_val = int(hat[0]) if isinstance(hat, (tuple, list)) and len(hat) > 0 else 0
            y_val = int(hat[1]) if isinstance(hat, (tuple, list)) and len(hat) > 1 else 0
        except Exception:
            return False
        if hat_dir == "UP":
            return y_val > 0
        if hat_dir == "DOWN":
            return y_val < 0
        if hat_dir == "LEFT":
            return x_val < 0
        if hat_dir == "RIGHT":
            return x_val > 0
        return False

    def _hotas_is_binding_down(binding: Optional[Dict[str, object]]) -> bool:
        if not isinstance(binding, dict):
            return False
        b_type = str(binding.get("type", "")).strip().lower()
        if b_type == "button":
            return _hotas_button_down(binding)
        if b_type == "hat":
            return _hotas_hat_down(binding)
        return False

    def _hotas_update_runtime_inputs() -> None:
        try:
            now_ms = int(pygame.time.get_ticks())
        except Exception:
            now_ms = 0
        try:
            next_refresh_ms = int(pmd_dr_state.get("hotas_refresh_next_ms", 0))
        except Exception:
            next_refresh_ms = 0
        if now_ms >= next_refresh_ms:
            _hotas_refresh_devices()
            # Device enumeration can stall SDL/DirectInput briefly. Do not
            # poll it every frame when no HOTAS is present; device add/remove
            # events still force an immediate refresh.
            retry_ms = 5000 if len(hotas_joysticks) <= 0 else 10000
            pmd_dr_state["hotas_refresh_next_ms"] = int(now_ms + retry_ms)
        bindings = _hotas_bindings_dict()
        try:
            key_focus = bool(pygame.key.get_focused())
        except Exception:
            key_focus = True
        try:
            display_focus = bool(pygame.display.get_active())
        except Exception:
            display_focus = key_focus
        window_has_focus = bool(key_focus and display_focus)
        try:
            prev_focus = bool(pmd_dr_state.get("hotas_window_has_focus", window_has_focus))
        except Exception:
            prev_focus = window_has_focus
        try:
            stabilize_until_ms = int(pmd_dr_state.get("hotas_focus_stabilize_until_ms", 0))
        except Exception:
            stabilize_until_ms = 0
        if window_has_focus != prev_focus:
            # On refocus, keep previous button/hat state briefly to avoid false
            # edge transitions from transient joystick state reads.
            if window_has_focus:
                stabilize_until_ms = max(stabilize_until_ms, now_ms + 600)
            pmd_dr_state["hotas_window_has_focus"] = bool(window_has_focus)
            pmd_dr_state["hotas_focus_stabilize_until_ms"] = int(stabilize_until_ms)
        read_live_buttons = bool(window_has_focus and now_ms >= stabilize_until_ms)
        prev_down_raw = pmd_dr_state.get("hotas_action_down_raw", {})
        prev_down_map = prev_down_raw if isinstance(prev_down_raw, dict) else {}
        down_raw: Dict[str, bool] = {}
        axis_raw: Dict[str, float] = {}
        for action in HOTAS_ACTION_ORDER:
            binding = bindings.get(action)
            if not isinstance(binding, dict):
                continue
            if not _hotas_binding_is_connected(binding):
                continue
            b_type = str(binding.get("type", "")).strip().lower()
            if b_type == "axis":
                value = _hotas_axis_value(binding)
                if value is not None:
                    axis_raw[action] = float(value)
            elif b_type in {"button", "hat"}:
                if read_live_buttons:
                    down_raw[action] = bool(_hotas_is_binding_down(binding))
                else:
                    down_raw[action] = bool(prev_down_map.get(action, False))
        event_override_raw = pmd_dr_state.get("hotas_event_down_override", {})
        event_override = event_override_raw if isinstance(event_override_raw, dict) else {}
        for action_name, down_value in event_override.items():
            action_key = str(action_name).strip().lower()
            if action_key in HOTAS_ACTION_ORDER:
                down_raw[action_key] = bool(down_value)
        action_down: Dict[str, bool] = {}
        # Map HOTAS cursor/zoom into existing keybind action names.
        action_down["czoom_plus"] = bool(down_raw.get("zoom_plus", False))
        action_down["czoom_minus"] = bool(down_raw.get("zoom_minus", False))
        if _hotas_current_pan_mode() == "AXIS":
            try:
                pan_lr = float(axis_raw.get("pan_lr", 0.0))
            except Exception:
                pan_lr = 0.0
            try:
                pan_ud = float(axis_raw.get("pan_ud", 0.0))
            except Exception:
                pan_ud = 0.0
            pan_dead = 0.2
            action_down["pan_left"] = bool(pan_lr <= -pan_dead)
            action_down["pan_right"] = bool(pan_lr >= pan_dead)
            action_down["pan_up"] = bool(pan_ud <= -pan_dead)
            action_down["pan_down"] = bool(pan_ud >= pan_dead)
        else:
            action_down["pan_up"] = bool(down_raw.get("pan_up", False))
            action_down["pan_down"] = bool(down_raw.get("pan_down", False))
            action_down["pan_left"] = bool(down_raw.get("pan_left", False))
            action_down["pan_right"] = bool(down_raw.get("pan_right", False))
        pmd_dr_state["hotas_down"] = action_down
        pmd_dr_state["hotas_axis"] = axis_raw
        pmd_dr_state["hotas_action_down_raw"] = down_raw
        # While binding input (and not manually pinned to a device), auto-select
        # the active gamepad so capture targets the detected source.
        if (
            status_menu_active_submenu == "PMD_DR_HOTAS_BIND"
            and bool(pmd_dr_state.get("hotas_edit_capture_selected", False))
            and (not bool(pmd_dr_state.get("hotas_edit_device_manual", False)))
        ):
            try:
                auto_lock_until_ms = int(pmd_dr_state.get("hotas_edit_device_auto_lock_until_ms", 0))
            except Exception:
                auto_lock_until_ms = 0
            try:
                auto_lock_idx = int(pmd_dr_state.get("hotas_edit_device_auto_lock", -1))
            except Exception:
                auto_lock_idx = -1
            if now_ms < auto_lock_until_ms and auto_lock_idx in hotas_joysticks:
                pmd_dr_state["hotas_edit_device"] = int(auto_lock_idx)
                return
            best_idx = -1
            best_score = 0.0
            for joy_idx, js in hotas_joysticks.items():
                score = 0.0
                try:
                    btn_count = int(js.get_numbuttons())
                except Exception:
                    btn_count = 0
                for b in range(max(0, btn_count)):
                    try:
                        if bool(js.get_button(b)):
                            score = max(score, 2.0)
                            break
                    except Exception:
                        continue
                try:
                    hat_count = int(js.get_numhats())
                except Exception:
                    hat_count = 0
                for h in range(max(0, hat_count)):
                    try:
                        hat_val = js.get_hat(h)
                        hx = int(hat_val[0]) if isinstance(hat_val, (tuple, list)) and len(hat_val) > 0 else 0
                        hy = int(hat_val[1]) if isinstance(hat_val, (tuple, list)) and len(hat_val) > 1 else 0
                        if hx != 0 or hy != 0:
                            score = max(score, 2.0)
                            break
                    except Exception:
                        continue
                try:
                    axis_count = int(js.get_numaxes())
                except Exception:
                    axis_count = 0
                axis_peak = 0.0
                for a in range(max(0, axis_count)):
                    try:
                        axis_peak = max(axis_peak, abs(float(js.get_axis(a))))
                    except Exception:
                        continue
                if axis_peak >= 0.2:
                    score = max(score, axis_peak)
                if score > best_score:
                    best_score = score
                    best_idx = int(joy_idx)
            if best_idx >= 0:
                pmd_dr_state["hotas_edit_device"] = int(best_idx)
                pmd_dr_state["hotas_edit_device_auto_lock"] = int(best_idx)
                pmd_dr_state["hotas_edit_device_auto_lock_until_ms"] = int(now_ms + 1200)

    def _command_landing_gear_input(source: str) -> None:
        print(f"[GEAR][INPUT] source={source}")
        _set_console_left_panel_control("GEAR", 1, True)

    def _hotas_apply_edge_actions(dbg_overlay_active: bool, dt_local: float) -> None:
        nonlocal cockpit_panels_page_index, poi_portal_index, poi_sub_index, poi_on_screen, system_mode, efi_hotas_popup_active
        raw_now = pmd_dr_state.get("hotas_action_down_raw", {})
        hotas_now_map = dict(raw_now) if isinstance(raw_now, dict) else {}

        def _keyboard_action_down(action: str) -> bool:
            for key_code in _pmd_action_key_codes(action):
                if key_code in held_keys:
                    return True
            return False

        key_now_map: Dict[str, bool] = {}
        now_map: Dict[str, bool] = {}
        runtime_action_order = list(dict.fromkeys(list(HOTAS_ACTION_ORDER) + list(PMD_KEYBIND_ACTION_ORDER)))
        for action_name in runtime_action_order:
            down_hotas = bool(hotas_now_map.get(action_name, False))
            down_key = bool(_keyboard_action_down(action_name))
            key_now_map[action_name] = bool(down_key)
            now_map[action_name] = bool(down_hotas or down_key)

        raw_prev = pmd_dr_state.get("hotas_prev_down_raw", {})
        prev_raw_map = raw_prev if isinstance(raw_prev, dict) else {}
        key_prev_raw = pmd_dr_state.get("hotas_prev_key_down", {})
        key_prev_map = key_prev_raw if isinstance(key_prev_raw, dict) else {}

        def _rising(action: str) -> bool:
            action_key = str(action).strip().lower()
            hotas_rising = bool(hotas_now_map.get(action_key, False)) and (not bool(prev_raw_map.get(action_key, False)))
            key_rising = bool(key_now_map.get(action_key, False)) and (not bool(key_prev_map.get(action_key, False)))
            return bool(hotas_rising or key_rising)

        def _single_press(action: str, state_key: str) -> bool:
            action_key = str(action).strip().lower()
            down = bool(now_map.get(action_key, False))
            prev_down = bool(pmd_dr_state.get(state_key, False))
            pmd_dr_state[state_key] = bool(down)
            return bool(down and not prev_down)

        def _command_landing_gear(source: str) -> None:
            _command_landing_gear_input(source)

        def _mngmt_rotary_pos() -> int:
            try:
                return max(0, min(15, int(pmd_dr_state.get("hotas_mngmt_rotary_pos", 0))))
            except Exception:
                return 0

        mngmt_scroll_delta = 0
        axis_raw_for_mngmt = pmd_dr_state.get("hotas_axis", {})
        axis_map_for_mngmt = axis_raw_for_mngmt if isinstance(axis_raw_for_mngmt, dict) else {}
        prev_mngmt_pos = _mngmt_rotary_pos()
        if "mngmt" in axis_map_for_mngmt:
            try:
                mngmt_axis = float(axis_map_for_mngmt.get("mngmt", 0.0))
            except Exception:
                mngmt_axis = 0.0
            mngmt_axis = max(-1.0, min(1.0, mngmt_axis))
            rotary_pos = int(((mngmt_axis + 1.0) * 0.5) * 16.0)
            next_mngmt_pos = max(0, min(15, rotary_pos))
            pmd_dr_state["hotas_mngmt_rotary_pos"] = next_mngmt_pos
            if next_mngmt_pos != prev_mngmt_pos:
                mngmt_scroll_delta = 1 if next_mngmt_pos > prev_mngmt_pos else -1
        elif _rising("mngmt_up"):
            pmd_dr_state["hotas_mngmt_rotary_pos"] = (_mngmt_rotary_pos() + 1) % 16
            mngmt_scroll_delta = -1
        elif _rising("mngmt_down"):
            pmd_dr_state["hotas_mngmt_rotary_pos"] = (_mngmt_rotary_pos() - 1) % 16
            mngmt_scroll_delta = 1

        def _read_slew_cursor_pos() -> Tuple[int, int]:
            raw_pos = pmd_dr_state.get("hotas_slew_cursor_logical", (WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2))
            if isinstance(raw_pos, (tuple, list)) and len(raw_pos) >= 2:
                try:
                    cx = int(raw_pos[0])
                    cy = int(raw_pos[1])
                except Exception:
                    cx = WINDOW_WIDTH // 2
                    cy = WINDOW_HEIGHT // 2
            else:
                cx = WINDOW_WIDTH // 2
                cy = WINDOW_HEIGHT // 2
            cx = max(0, min(WINDOW_WIDTH - 1, cx))
            cy = max(0, min(WINDOW_HEIGHT - 1, cy))
            return cx, cy

        def _poi_format_consumes_slew_input() -> bool:
            target = _poi_target_format()
            if target is None:
                return False
            try:
                fmt_name = str(getattr(target[2], "name", "")).upper().strip()
            except Exception:
                fmt_name = ""
            return bool(_normalize_tsd_name(fmt_name) is not None or fmt_name in {"ASR1", "TFLIR"})

        def _read_slew_input_vector() -> Tuple[float, float]:
            slew_x_local = 0.0
            slew_y_local = 0.0
            if _hotas_current_slew_mode() == "AXIS":
                axis_raw = pmd_dr_state.get("hotas_axis", {})
                axis_map = axis_raw if isinstance(axis_raw, dict) else {}
                try:
                    lr = float(axis_map.get("slew_lr", 0.0))
                except Exception:
                    lr = 0.0
                try:
                    ud = float(axis_map.get("slew_ud", 0.0))
                except Exception:
                    ud = 0.0
                dead = 0.2
                slew_x_local = lr if abs(lr) >= dead else 0.0
                slew_y_local = ud if abs(ud) >= dead else 0.0
            else:
                slew_x_local = float(int(bool(now_map.get("slew_right", False))) - int(bool(now_map.get("slew_left", False))))
                slew_y_local = float(int(bool(now_map.get("slew_down", False))) - int(bool(now_map.get("slew_up", False))))
            return float(slew_x_local), float(slew_y_local)

        # SLEW drives the active POI sensor/display when applicable; otherwise it moves
        # the global screen cursor for HOTAS virtual clicks.
        dt_s = max(0.0, float(dt_local))
        if dt_s > 0.0:
            slew_x, slew_y = _read_slew_input_vector()
            poi_consumes_slew = _poi_format_consumes_slew_input()
            curr_x, curr_y = _read_slew_cursor_pos()
            if (not poi_consumes_slew) and (abs(slew_x) > 1e-6 or abs(slew_y) > 1e-6):
                try:
                    slew_speed_scalar = float(pmd_dr_state.get("hotas_slew_speed", 1.0))
                except Exception:
                    slew_speed_scalar = 1.0
                slew_speed_scalar = max(0.0, min(1.0, slew_speed_scalar))
                slew_speed_px_s = 900.0 * slew_speed_scalar
                next_x = int(round(float(curr_x) + (slew_x * slew_speed_px_s * dt_s)))
                next_y = int(round(float(curr_y) + (slew_y * slew_speed_px_s * dt_s)))
                next_x = max(0, min(WINDOW_WIDTH - 1, next_x))
                next_y = max(0, min(WINDOW_HEIGHT - 1, next_y))
                pmd_dr_state["hotas_slew_cursor_logical"] = (next_x, next_y)
            else:
                pmd_dr_state["hotas_slew_cursor_logical"] = (curr_x, curr_y)
            if poi_consumes_slew and (abs(slew_x) > 1e-6 or abs(slew_y) > 1e-6):
                pmd_dr_state["hotas_slew_cursor_visible"] = False
            elif abs(slew_x) > 1e-6 or abs(slew_y) > 1e-6:
                try:
                    pmd_dr_state["hotas_slew_cursor_last_move_ms"] = int(pygame.time.get_ticks())
                except Exception:
                    pmd_dr_state["hotas_slew_cursor_last_move_ms"] = 0
                pmd_dr_state["hotas_slew_cursor_visible"] = True

        def _portal_index_under_pos(pos: Tuple[int, int]) -> Optional[int]:
            x = int(pos[0])
            y = int(pos[1])
            for portal_idx in range(4):
                pair_idx = portal_idx // 2
                owner_idx = pair_owner[pair_idx]
                if owner_idx is not None and portal_idx != owner_idx:
                    continue
                portal_rect = get_portal_rect(portal_idx)
                if owner_idx is not None and portal_idx == owner_idx:
                    pair_start = pair_idx * 2
                    use_full_height = bool(portal_states[owner_idx].expanded_vertical)
                    portal_rect = pygame.Rect(
                        pair_start * PORTAL_WIDTH,
                        ICAWS_HEIGHT,
                        PORTAL_WIDTH * 2,
                        PORTAL_HEIGHT if use_full_height else MAIN_PORTAL_HEIGHT,
                    )
                elif not bool(portal_states[portal_idx].expanded_vertical):
                    portal_rect = pygame.Rect(
                        portal_rect.x,
                        portal_rect.y,
                        portal_rect.width,
                        MAIN_PORTAL_HEIGHT,
                    )
                if portal_rect.collidepoint(x, y):
                    return int(portal_idx)
            return None

        def _poi_sequence() -> List[Tuple[int, int]]:
            seq: List[Tuple[int, int]] = []
            for idx in range(4):
                seq.append((idx, -1))
                if _poi_subportal_selectable(idx, 0):
                    seq.append((idx, 0))
                if _poi_subportal_selectable(idx, 1):
                    seq.append((idx, 1))
            return seq if len(seq) > 0 else [(0, -1)]

        def _poi_target_under_pos(pos: Tuple[int, int]) -> Optional[Tuple[int, int]]:
            x = int(pos[0])
            y = int(pos[1])
            seq = _poi_sequence()
            for portal_idx, sub_idx in [item for item in seq if int(item[1]) >= 0]:
                if _poi_target_rect(int(portal_idx), int(sub_idx)).collidepoint(x, y):
                    return int(portal_idx), int(sub_idx)
            for portal_idx, sub_idx in [item for item in seq if int(item[1]) < 0]:
                if _poi_target_rect(int(portal_idx), int(sub_idx)).collidepoint(x, y):
                    return int(portal_idx), int(sub_idx)
            return None

        def _set_poi_target(portal_idx: int, sub_idx: int) -> None:
            nonlocal poi_portal_index, poi_sub_index, poi_on_screen
            poi_portal_index = max(0, min(3, int(portal_idx)))
            poi_sub_index = _clamp_poi_sub_index(sub_idx)
            poi_on_screen = True
            _center_hotas_cursor_on_poi(make_visible=True)

        def _step_poi_target(delta: int) -> None:
            seq = _poi_sequence()
            curr = (int(poi_portal_index), _clamp_poi_sub_index(poi_sub_index))
            if curr not in seq:
                curr = (normalize_poi_index(int(poi_portal_index)), -1)
            try:
                pos = seq.index(curr)
            except Exception:
                pos = 0
            nxt = seq[(pos + int(delta)) % len(seq)]
            _set_poi_target(nxt[0], nxt[1])

        def _poi_to_subportal_or_main(target_sub: int) -> None:
            curr_sub = _clamp_poi_sub_index(poi_sub_index)
            if target_sub < 0:
                if curr_sub >= 0:
                    _set_poi_target(poi_portal_index, -1)
            elif curr_sub < 0:
                if _poi_subportal_selectable(poi_portal_index, 0):
                    _set_poi_target(poi_portal_index, 0)

        dms_dir = ""
        if bool(now_map.get("poi_left", False)) or bool(now_map.get("dms_left", False)):
            dms_dir = "left"
        elif bool(now_map.get("poi_right", False)) or bool(now_map.get("dms_right", False)):
            dms_dir = "right"
        elif bool(now_map.get("poi_up", False)) or bool(now_map.get("dms_up", False)):
            dms_dir = "up"
        elif bool(now_map.get("poi_down", False)) or bool(now_map.get("dms_down", False)):
            dms_dir = "down"
        try:
            prev_dms_dir = str(pmd_dr_state.get("hotas_dms_poi_prev_dir", "") or "")
        except Exception:
            prev_dms_dir = ""
        dms_edge_dir = dms_dir if dms_dir != "" and dms_dir != prev_dms_dir else ""
        pmd_dr_state["hotas_dms_poi_prev_dir"] = str(dms_dir)

        if dms_edge_dir == "left":
            if dbg_overlay_active:
                total = max(1, len(_discover_panel_pages()))
                cockpit_panels_page_index = (cockpit_panels_page_index - 1) % total
            elif phase >= 1 and poi_on_screen:
                _step_poi_target(-1)
        if dms_edge_dir == "right":
            if dbg_overlay_active:
                total = max(1, len(_discover_panel_pages()))
                cockpit_panels_page_index = (cockpit_panels_page_index + 1) % total
            elif phase >= 1 and poi_on_screen:
                _step_poi_target(1)
        if dms_edge_dir == "up" and phase >= 1:
            _poi_to_subportal_or_main(-1)
        if dms_edge_dir == "down" and phase >= 1:
            _poi_to_subportal_or_main(0)

        def _poi_control_portal_index() -> Optional[int]:
            target = _poi_target_format()
            if target is None:
                return None
            return int(target[0])

        def _poi_format_obj() -> Optional[Tuple[int, int, object]]:
            target = _poi_target_format()
            if target is None:
                return None
            return int(target[0]), int(target[1]), target[2]

        def _poi_tsd_state() -> Optional[Dict[str, object]]:
            target = _poi_format_obj()
            if target is None:
                return None
            _control_idx, _sub_idx, fmt_obj = target
            fmt_name = str(getattr(fmt_obj, "name", ""))
            tsd_key = _normalize_tsd_name(fmt_name)
            if tsd_key is None:
                return None
            tsd_states = getattr(formats, "TSD_STATES_BY_NAME", {})
            if not isinstance(tsd_states, dict):
                return None
            tsd_state = tsd_states.get(tsd_key)
            if not isinstance(tsd_state, dict):
                return None
            try:
                view_idx = int(tsd_state.get("view_idx", 0))
            except Exception:
                view_idx = 0
            # L1/L2/R1 behavior is HSD-only.
            if view_idx == 1:
                return None
            return tsd_state

        def _hotas_apply_poi_osb(label: str, valid_formats: Set[str]) -> bool:
            osb_label = str(label).upper().strip()
            target = _poi_format_obj()
            if target is None:
                return False
            control_idx, _sub_idx, portal_fmt = target
            fmt_name = str(getattr(portal_fmt, "name", "")).upper().strip()
            if fmt_name not in valid_formats:
                return False
            context = FormatContext(control_idx, request_vded, set_format, close_vded)
            try:
                handled = bool(portal_fmt.on_osb(osb_label, context))
            except Exception:
                handled = False
            if handled:
                try:
                    osb_flash_until[(control_idx, osb_label)] = int(pygame.time.get_ticks()) + OSB_FLASH_MS
                except Exception:
                    pass
            return handled

        def _hotas_management_scroll(delta: int) -> bool:
            target = _poi_format_obj()
            if target is None or int(delta) == 0:
                return False
            control_idx, _sub_idx, portal_fmt = target
            fmt_name = str(getattr(portal_fmt, "name", "")).upper().strip()
            label = ""
            if fmt_name == "CNI":
                label = "L4" if int(delta) < 0 else "L5"
            elif fmt_name in {"DIM", "ICAWS", "PHM"}:
                label = "L1" if int(delta) < 0 else "L2"
            if label == "":
                return False
            context = FormatContext(control_idx, request_vded, set_format, close_vded)
            try:
                handled = bool(portal_fmt.on_osb(label, context))
            except Exception:
                handled = False
            if handled:
                try:
                    osb_flash_until[(int(control_idx), label)] = int(pygame.time.get_ticks()) + OSB_FLASH_MS
                except Exception:
                    pass
                print(f"[HOTAS][MNGMT] {fmt_name} {label}")
            return handled

        def _set_system_mode_from_hotas(mode: str, source: str) -> None:
            nonlocal system_mode
            next_mode = str(mode).upper().strip()
            if next_mode not in set(SYSTEM_MODES):
                return
            if system_mode != next_mode:
                system_mode = next_mode
                print(f"[HOTAS][WMS] {source} -> {next_mode}")

        if int(mngmt_scroll_delta) != 0:
            _hotas_management_scroll(int(mngmt_scroll_delta))

        def _toggle_thermal_polarity_for_poi() -> None:
            target = _poi_format_obj()
            fmt_name = ""
            if target is not None:
                try:
                    fmt_name = str(getattr(target[2], "name", "")).upper().strip()
                except Exception:
                    fmt_name = ""
            targets: List[Tuple[str, str]] = []
            if fmt_name == "TFLIR":
                targets.append(("TFLIR", "TFLIR3D_STATE"))
            elif fmt_name == "DAS":
                targets.append(("DAS", "DAS3D_STATE"))
            else:
                # Fallback keeps the button useful if POI is not yet on a
                # thermal format; the active renderer will pick up its state.
                targets.extend((("TFLIR", "TFLIR3D_STATE"), ("DAS", "DAS3D_STATE")))
            for label, state_attr in targets:
                raw_state = getattr(formats, state_attr, {})
                state_dict = raw_state if isinstance(raw_state, dict) else {}
                current_whot = bool(state_dict.get("whot", not bool(state_dict.get("bhot", False))))
                next_whot = not current_whot
                state_dict["whot"] = bool(next_whot)
                state_dict["bhot"] = bool(not next_whot)
                setattr(formats, state_attr, state_dict)
                print(f"[HOTAS][POL] {label} -> {'WHOT' if next_whot else 'BHOT'}")

        def _toggle_sms_weapon_bay_doors() -> None:
            try:
                sms_cls = getattr(formats, "SmsFormat", None)
                if sms_cls is not None:
                    sms_fmt = sms_cls()
                    # Use the same implementation behind SMS L3 DOORS without
                    # depending on whatever SMS submenu is currently visible.
                    before_open = bool(int(getattr(formats, "SMS_STATE", {}).get("doors_open", 0) or 0))
                    sms_fmt._toggle_doors()
                    doors_open = bool(int(getattr(formats, "SMS_STATE", {}).get("doors_open", 0) or 0))
                    suffix = "" if doors_open != before_open else " no_change"
                    print(f"[HOTAS][APC] SMS L3 DOORS -> {'OPEN' if doors_open else 'CLOSED'}{suffix}")
                    return
            except Exception as exc:
                print(f"[HOTAS][APC] SMS L3 DOORS failed: {exc}")

            # Fallback only if the SMS format class is unavailable.
            sms_state = getattr(formats, "SMS_STATE", {})
            if not isinstance(sms_state, dict):
                return
            lt_state = str(sms_state.get("lt_state", "CLOSE")).upper()
            rt_state = str(sms_state.get("rt_state", "CLOSE")).upper()
            doors_open_legacy = bool(int(sms_state.get("doors_open", 0) or 0))
            target_open = not (doors_open_legacy or lt_state in {"OPEN", "PARTIAL"} or rt_state in {"OPEN", "PARTIAL"})
            target = "OPEN" if target_open else "CLOSE"
            sms_state["doors_open"] = 1 if target_open else 0
            for prefix in ("lt", "rt"):
                state_key = f"{prefix}_state"
                target_key = f"{prefix}_target"
                due_key = f"{prefix}_transition_due_ms"
                sms_state[target_key] = target
                if str(sms_state.get(state_key, "CLOSE")).upper() != target:
                    sms_state[state_key] = "PARTIAL"
                    sms_state[due_key] = int(now_ms + 3000)
            print(f"[HOTAS][APC] fallback weapon_bay_doors -> {target}")

        def _trigger_sms_l3_doors_from_hotas() -> None:
            _toggle_sms_weapon_bay_doors()

        def _autopilot_any_mode_on() -> bool:
            ap_state = _autopilot_state()
            return bool(
                ap_state.get("att_hold", False)
                or ap_state.get("hdg_sel", False)
                or ap_state.get("alt_hold", False)
                or ap_state.get("alt_sel", False)
                or ap_state.get("speed_hold", False)
                or ap_state.get("speed_sel", False)
                or ap_state.get("rte_hold", False)
            )

        def _autopilot_disconnect() -> None:
            ap_state = _autopilot_state()
            try:
                fcs_state = getattr(formats, "FCS_STATE", None)
                if isinstance(fcs_state, dict):
                    fcs_state["ap"] = False
            except Exception:
                pass
            for key in (
                "att_hold",
                "hdg_sel",
                "alt_hold",
                "alt_sel",
                "speed_hold",
                "speed_sel",
                "rte_hold",
                "speed_menu_open",
            ):
                ap_state[key] = False
            ap_state["selected_field"] = None
            ap_state.pop("speed_hold_trim_throttle_pct", None)
            ap_state.pop("speed_sel_trim_throttle_pct", None)
            print("[HOTAS][DISCONNECT] FCS A/P OSB -> OFF")

        def _refuel_doors_open() -> bool:
            try:
                fuel_cls = getattr(formats, "FuelFormat", None)
                if fuel_cls is None:
                    return False
                t2_open = bool(getattr(fuel_cls, "_shared_refuel_t2_on", False))
                hazard_on = getattr(fuel_cls, "_shared_hazard_on", None)
                r6_open = bool(hazard_on.get("R6", False)) if isinstance(hazard_on, dict) else False
                return bool(t2_open or r6_open)
            except Exception:
                return False

        def _set_fuel_refuel_osb_from_disconnect(target_open: bool) -> None:
            try:
                fuel_cls = getattr(formats, "FuelFormat", None)
                if fuel_cls is None:
                    return
                # FUEL T2 REFUEL is the normal refuel door command path. Clear
                # the emergency R6 path so DISCONNECT does not bypass the OSB.
                setattr(fuel_cls, "_shared_refuel_t2_on", bool(target_open))
                hazard_on = getattr(fuel_cls, "_shared_hazard_on", None)
                if isinstance(hazard_on, dict):
                    hazard_on["R6"] = False
                cover_closed = getattr(fuel_cls, "_shared_hazard_cover_closed", None)
                if isinstance(cover_closed, dict):
                    cover_closed["R6"] = True
            except Exception:
                return
            print(f"[HOTAS][DISCONNECT] FUEL REFUEL OSB -> {'OPEN' if target_open else 'CLOSE'}")

        def _toggle_speed_hold() -> None:
            ap_state = _autopilot_state()
            new_on = not bool(ap_state.get("speed_hold", False))
            ap_state["speed_hold"] = bool(new_on)
            if new_on:
                ap_state["speed_sel"] = False
                try:
                    curr_speed = float(aircraft.get("TOTAL_SPEED_KTS", aircraft.get("AIRSPEED_KTS", 0.0)))
                except Exception:
                    curr_speed = 0.0
                ap_state["speed_hold_target_kts"] = float(max(0.0, curr_speed))
            print(f"[HOTAS][SPD HOLD] {'ON' if new_on else 'OFF'} target={float(ap_state.get('speed_hold_target_kts') or 0.0):.0f}")

        def _step_speed_hold(delta_kts: float) -> None:
            ap_state = _autopilot_state()
            if not bool(ap_state.get("speed_hold", False)):
                try:
                    curr_speed = float(aircraft.get("TOTAL_SPEED_KTS", aircraft.get("AIRSPEED_KTS", 0.0)))
                except Exception:
                    curr_speed = 0.0
                ap_state["speed_hold"] = True
                ap_state["speed_sel"] = False
                ap_state["speed_hold_target_kts"] = float(max(0.0, curr_speed))
            try:
                base = float(ap_state.get("speed_hold_target_kts", aircraft.get("TOTAL_SPEED_KTS", aircraft.get("AIRSPEED_KTS", 0.0))))
            except Exception:
                base = 0.0
            ap_state["speed_hold_target_kts"] = float(max(0.0, base + float(delta_kts)))
            print(f"[HOTAS][SPD HOLD] target={float(ap_state.get('speed_hold_target_kts') or 0.0):.0f}")

        if _rising("wms_fwd"):
            _set_system_mode_from_hotas("AA1", "FWD")
        if _rising("wms_right"):
            _set_system_mode_from_hotas("AA2", "RIGHT")
        if _rising("wms_left"):
            _set_system_mode_from_hotas("AS", "LEFT")
        if _rising("wms_aft"):
            _set_system_mode_from_hotas("DGFT", "AFT")
        if _rising("wms_z"):
            _set_system_mode_from_hotas("NAV", "Z")

        if _rising("cage_uncage"):
            marker = str(pmd_dr_state.get("hotas_nav_marker", "FPM")).upper().strip()
            marker = "CDM" if marker == "FPM" else "FPM"
            pmd_dr_state["hotas_nav_marker"] = marker
            print(f"[HOTAS][CAGE] nav_marker={marker}")

        if _single_press("pol_ctrl", "hotas_pol_ctrl_prev_down"):
            _toggle_thermal_polarity_for_poi()

        if _single_press("spd_hold_z", "hotas_spd_hold_z_prev_down"):
            _toggle_speed_hold()
        if _rising("spd_hold_up"):
            _step_speed_hold(1.0)
        if _rising("spd_hold_down"):
            _step_speed_hold(-1.0)

        apc_binding = _hotas_get_connected_binding("aprch_pwr_comp")
        apc_live_down = bool(_hotas_is_binding_down(apc_binding)) if isinstance(apc_binding, dict) else False
        apc_override_raw = pmd_dr_state.get("hotas_event_down_override", {})
        apc_override = apc_override_raw if isinstance(apc_override_raw, dict) else {}
        apc_event_down = bool(apc_override.get("aprch_pwr_comp", False))
        apc_raw_down = bool(hotas_now_map.get("aprch_pwr_comp", False))
        apc_key_down = bool(key_now_map.get("aprch_pwr_comp", False))
        apc_instant_down = bool(apc_key_down or apc_event_down or apc_raw_down or apc_live_down)
        if apc_instant_down:
            pmd_dr_state["apc_last_down_ms"] = int(now_ms)
        try:
            apc_last_down_ms = int(pmd_dr_state.get("apc_last_down_ms", 0))
        except Exception:
            apc_last_down_ms = 0
        # Warthog buttons can emit brief release bounces. Treat releases under
        # 300ms as still held so a real hold reaches the 500ms threshold.
        apc_held = bool(apc_instant_down or (apc_last_down_ms > 0 and int(now_ms) - apc_last_down_ms <= 300))
        apc_debug_state = (
            bool(apc_key_down),
            bool(apc_event_down),
            bool(apc_raw_down),
            bool(apc_live_down),
            bool(apc_held),
        )
        if tuple(pmd_dr_state.get("apc_debug_state", (None, None, None, None, None))) != apc_debug_state:
            pmd_dr_state["apc_debug_state"] = apc_debug_state
            print(
                "[HOTAS][APC] "
                f"key={int(apc_key_down)} event={int(apc_event_down)} "
                f"raw={int(apc_raw_down)} live={int(apc_live_down)} held={int(apc_held)}"
            )
        apc_prev_held = bool(pmd_dr_state.get("apc_prev_held", False))
        if apc_held and not apc_prev_held:
            pmd_dr_state["apc_hold_start_ms"] = int(now_ms)
            pmd_dr_state["apc_hold_fired"] = False
            print("[HOTAS][APC] hold_start")
        if apc_held:
            try:
                apc_start_ms = int(pmd_dr_state.get("apc_hold_start_ms", now_ms))
            except Exception:
                apc_start_ms = int(now_ms)
            if (not bool(pmd_dr_state.get("apc_hold_fired", False))) and int(now_ms) - int(apc_start_ms) >= 500:
                _trigger_sms_l3_doors_from_hotas()
                pmd_dr_state["apc_hold_fired"] = True
        elif apc_prev_held:
            try:
                held_ms = int(now_ms) - int(pmd_dr_state.get("apc_hold_start_ms", now_ms))
            except Exception:
                held_ms = 0
            if not bool(pmd_dr_state.get("apc_hold_fired", False)):
                print(f"[HOTAS][APC] released_before_500ms held_ms={held_ms}")
            pmd_dr_state["apc_hold_start_ms"] = 0
            pmd_dr_state["apc_hold_fired"] = False
        pmd_dr_state["apc_prev_held"] = bool(apc_held)

        if _single_press("comm_ctl_z", "hotas_comm_ctl_z_prev_down"):
            try:
                if bool(efi_hotas_popup_active):
                    efi_hotas_popup_active = False
                    print("[HOTAS][COMM CTL] EFI popup OFF")
                else:
                    _close_status_menu_if_portal_conflicts(0)
                    _close_status_popups_for_portal(0)
                    close_vded_for_portal(0)
                    efi_hotas_popup_active = True
                    print("[HOTAS][COMM CTL] EFI popup -> P1")
            except Exception as exc:
                print(f"[HOTAS][COMM CTL] EFI failed: {exc}")

        if _single_press("disconnect", "hotas_disconnect_prev_down"):
            refuel_open = _refuel_doors_open()
            if _autopilot_any_mode_on():
                _autopilot_disconnect()
                if refuel_open:
                    _set_fuel_refuel_osb_from_disconnect(False)
            elif refuel_open:
                _set_fuel_refuel_osb_from_disconnect(False)
            else:
                _set_fuel_refuel_osb_from_disconnect(True)

        tsd_state = _poi_tsd_state()
        if tsd_state is not None and _rising("zoom_zero"):
            tsd_state["kbd_zoom_scale"] = 1.0
            tsd_state["kbd_pan_x_px"] = 0.0
            tsd_state["kbd_pan_y_px"] = 0.0
        if _rising("zoom_zero"):
            _hotas_apply_poi_osb("T2", {"PHM"})
        if tsd_state is not None and (_rising("poi_plus") or _rising("poi_minus") or _rising("fov_up") or _rising("fov_down")):
            current_range = _quantize_tsd_range_nm(tsd_state.get("range_nm", 20.0))
            if _rising("poi_plus") or _rising("fov_down"):
                next_range = _quantize_tsd_range_nm(float(current_range) + 10.0)
            else:
                next_range = _quantize_tsd_range_nm(float(current_range) - 10.0)
            tsd_state["range_nm"] = float(next_range)
            try:
                zoom_scale = float(tsd_state.get("kbd_zoom_scale", 1.0))
            except Exception:
                zoom_scale = 1.0
            max_zoom_scale = max(1.0, float(next_range) / 0.01)
            tsd_state["kbd_zoom_scale"] = max(1.0, min(max_zoom_scale, float(zoom_scale)))

        if _rising("poi_plus"):
            _hotas_apply_poi_osb("L1", {"PHM", "DIM", "ICAWS"})
        if _rising("poi_minus"):
            _hotas_apply_poi_osb("L2", {"PHM", "DIM", "ICAWS"})

        def _post_hotas_cursor_click() -> bool:
            try:
                if not bool(pmd_dr_state.get("hotas_slew_cursor_visible", True)):
                    return False
                slew_pos_local = _read_slew_cursor_pos()
                win_pos = _window_from_logical_pos((int(slew_pos_local[0]), int(slew_pos_local[1])))
                pygame.event.post(pygame.event.Event(pygame.MOUSEBUTTONDOWN, {"pos": win_pos, "button": 1, "hotas_virtual": True}))
                pygame.event.post(pygame.event.Event(pygame.MOUSEBUTTONUP, {"pos": win_pos, "button": 1, "hotas_virtual": True}))
                return True
            except Exception:
                return False

        if _single_press("slew_z", "hotas_slew_z_prev_down"):
            if _post_hotas_cursor_click():
                print("[HOTAS][SLEW Z] click")

        if _rising("slew_select"):
            if not _poi_format_consumes_slew_input():
                slew_pos = _read_slew_cursor_pos()
                hovered_target = _poi_target_under_pos(slew_pos)
                poi_idx_now = normalize_poi_index(poi_portal_index)
                selected_new_poi = False
                if hovered_target is not None:
                    hovered_portal, hovered_sub = hovered_target
                    if ((not bool(poi_on_screen)) or (int(hovered_portal) != int(poi_idx_now)) or (_clamp_poi_sub_index(poi_sub_index) != int(hovered_sub))):
                        _set_poi_target(int(hovered_portal), int(hovered_sub))
                        selected_new_poi = True
                if not selected_new_poi:
                    _post_hotas_cursor_click()

        if _rising("toi"):
            _toggle_toi_at_cursor()

        if _rising("com_mute"):
            radio = str(comm_state.get("asgn_radio", "comb")).strip().lower()
            if radio not in {"coma", "comb", "comc", "comd"}:
                radio = "comb"
            prof = _comm_profile_for(radio)
            new_val = not bool(prof.get("mute_on", False))
            _comm_set_profile_value(radio, "mute_on", new_val)
            if radio == str(comm_state.get("asgn_radio", "comb")).strip().lower():
                comm_state["mute_on"] = bool(new_val)

        gun_binding_active = isinstance(_hotas_get_connected_binding("gun_trigger"), dict) or (len(_pmd_action_key_codes("gun_trigger")) > 0)
        pickle_binding_active = isinstance(_hotas_get_connected_binding("pickle"), dict) or (len(_pmd_action_key_codes("pickle")) > 0)
        pmd_dr_state["hotas_gun_trigger_down"] = bool(now_map.get("gun_trigger", False)) if gun_binding_active else False
        pmd_dr_state["hotas_pickle_down"] = bool(now_map.get("pickle", False)) if pickle_binding_active else False

        engine_hotas_bound = isinstance(_hotas_get_connected_binding("engine_run"), dict)
        engine_pressed = bool(now_map.get("engine_run", False))
        # Ignore unbound ENGINE RUN input sources when idle so they cannot
        # force the switch to OFF.
        engine_binding_active = bool(engine_hotas_bound or engine_pressed)
        if engine_binding_active:
            engine_mode = str(pmd_dr_state.get("hotas_engine_run_mode", "MOMENTARY")).upper()
            if engine_mode not in {"MOMENTARY", "TOGGLE"}:
                engine_mode = "MOMENTARY"
            engine_invert = bool(pmd_dr_state.get("hotas_engine_run_invert", False))
            if engine_mode == "MOMENTARY" and _rising("engine_run"):
                pmd_dr_state["hotas_engine_run_latch"] = not bool(pmd_dr_state.get("hotas_engine_run_latch", False))
            engine_on = bool(pmd_dr_state.get("hotas_engine_run_latch", False)) if engine_mode == "MOMENTARY" else engine_pressed
            if engine_invert:
                target_engine = "OFF" if engine_on else "RUN"
            else:
                target_engine = "RUN" if (engine_mode == "MOMENTARY" and engine_on) else ("MOTOR" if engine_on else "OFF")
            panel_state = _ensure_panel_button_states()
            throttle_state = panel_state.get("THROTTLE", {})
            if isinstance(throttle_state, dict):
                throttle_state["ENGINE"] = str(target_engine)

        gear_binding = _hotas_get_connected_binding("ldg_gear")
        gear_hotas_bound = isinstance(gear_binding, dict)
        keyboard_gear_rising = bool(key_now_map.get("ldg_gear", False)) and (not bool(key_prev_map.get("ldg_gear", False)))
        gear_live_down = bool(_hotas_is_binding_down(gear_binding)) if isinstance(gear_binding, dict) else False
        gear_raw_now = bool(hotas_now_map.get("ldg_gear", False) or gear_live_down)
        gear_raw_prev_global = bool(prev_raw_map.get("ldg_gear", False))
        if "hotas_gear_handler_prev_raw" in pmd_dr_state:
            gear_raw_prev = bool(pmd_dr_state.get("hotas_gear_handler_prev_raw", False))
        else:
            gear_raw_prev = bool(gear_raw_prev_global)
            pmd_dr_state["hotas_gear_handler_prev_raw"] = bool(gear_raw_now)
        gear_raw_changed = bool(gear_raw_now != gear_raw_prev)
        gear_mode = str(pmd_dr_state.get("hotas_ldg_gear_mode", "TOGGLE")).upper()
        if gear_mode not in {"MOMENTARY", "TOGGLE"}:
            gear_mode = "TOGGLE"
        # In MOMENTARY mode, only the ON/pressed edge acts like pressing G.
        # This prevents refocus/dropout release edges from lowering gear.
        hotas_gear_event = bool(gear_hotas_bound and gear_raw_changed and (gear_mode != "MOMENTARY" or gear_raw_now))
        gear_debug_state = (bool(gear_hotas_bound), bool(gear_raw_now), bool(gear_live_down), bool(gear_raw_changed), str(gear_mode), bool(gear_raw_prev), bool(gear_raw_prev_global))
        prev_gear_debug_state = tuple(pmd_dr_state.get("hotas_gear_debug_state", (None, None, None, None, None, None, None)))
        if prev_gear_debug_state != gear_debug_state:
            pmd_dr_state["hotas_gear_debug_state"] = gear_debug_state
            print(
                "[HOTAS][GEAR] "
                f"bound={int(bool(gear_hotas_bound))} raw={int(gear_raw_now)} live={int(gear_live_down)} "
                f"prev={int(gear_raw_prev)} global_prev={int(gear_raw_prev_global)} "
                f"changed={int(gear_raw_changed)} mode={gear_mode}"
            )
            try:
                prev_debug_raw_known = isinstance(prev_gear_debug_state, tuple) and len(prev_gear_debug_state) >= 2 and prev_gear_debug_state[1] is not None
                prev_debug_raw = bool(prev_gear_debug_state[1]) if prev_debug_raw_known else bool(gear_raw_now)
            except Exception:
                prev_debug_raw_known = False
                prev_debug_raw = bool(gear_raw_now)
            if (
                gear_hotas_bound
                and prev_debug_raw_known
                and bool(gear_raw_now) != bool(prev_debug_raw)
                and (gear_mode != "MOMENTARY" or bool(gear_raw_now))
            ):
                try:
                    focus_inhibit_until_ms_dbg = int(pmd_dr_state.get("input_focus_inhibit_until_ms", 0))
                except Exception:
                    focus_inhibit_until_ms_dbg = 0
                if int(now_ms) < int(focus_inhibit_until_ms_dbg):
                    print(
                        "[GEAR][IGNORE] "
                        f"source=hotas_as_keyboard raw={int(gear_raw_now)} prev={int(prev_debug_raw)} "
                        f"focus_inhibit_until_ms={int(focus_inhibit_until_ms_dbg)}"
                    )
                    hotas_gear_event = False
                    pmd_dr_state["hotas_gear_handler_prev_raw"] = bool(gear_raw_now)
                elif phase >= 1:
                    print(
                        "[GEAR][EDGE] "
                        f"source=hotas_as_keyboard raw={int(gear_raw_now)} prev={int(prev_debug_raw)} "
                        f"mode={gear_mode}"
                    )
                    _command_landing_gear_input("hotas_as_keyboard")
                    hotas_gear_event = False
                    pmd_dr_state["hotas_gear_handler_prev_raw"] = bool(gear_raw_now)
                else:
                    print(f"[GEAR][BLOCK] source=hotas_as_keyboard phase={phase}")
                    hotas_gear_event = False
                    pmd_dr_state["hotas_gear_handler_prev_raw"] = bool(gear_raw_now)
        gear_binding_active = bool(gear_hotas_bound or keyboard_gear_rising or hotas_gear_event or (len(_pmd_action_key_codes("ldg_gear")) > 0))
        if gear_binding_active:
            try:
                focus_inhibit_until_ms = int(pmd_dr_state.get("input_focus_inhibit_until_ms", 0))
            except Exception:
                focus_inhibit_until_ms = 0
            gear_inhibited = bool(now_ms < focus_inhibit_until_ms)
            if gear_inhibited and hotas_gear_event:
                print(
                    "[GEAR][IGNORE] "
                    f"source=hotas raw={int(gear_raw_now)} prev={int(gear_raw_prev)} "
                    f"until_ms={int(focus_inhibit_until_ms)}"
                )
                hotas_gear_event = False
            if gear_inhibited:
                pmd_dr_state["hotas_ldg_gear_prev_pressed"] = bool(hotas_now_map.get("ldg_gear", False))
                pmd_dr_state["hotas_ldg_gear_db_raw"] = bool(hotas_now_map.get("ldg_gear", False))
                pmd_dr_state["hotas_ldg_gear_db_state"] = bool(hotas_now_map.get("ldg_gear", False))
                pmd_dr_state["hotas_ldg_gear_db_since_ms"] = int(now_ms)
            else:
                if bool(pmd_dr_state.get("hotas_gear_pending_after_inhibit", False)):
                    try:
                        pending_raw = int(bool(pmd_dr_state.get("hotas_gear_pending_raw", gear_raw_now)))
                        pending_prev = int(bool(pmd_dr_state.get("hotas_gear_pending_prev", gear_raw_prev)))
                    except Exception:
                        pending_raw = int(gear_raw_now)
                        pending_prev = int(gear_raw_prev)
                    pmd_dr_state["hotas_gear_pending_after_inhibit"] = False
                    print(f"[GEAR][EDGE] source=hotas_deferred raw={pending_raw} prev={pending_prev} mode={gear_mode} bound={int(bool(gear_hotas_bound))}")
                    _command_landing_gear("hotas_deferred")
                    hotas_gear_event = False
                if keyboard_gear_rising:
                    print("[GEAR][EDGE] source=keyboard_state")
                    _command_landing_gear("keyboard_state")
                if hotas_gear_event:
                    print(
                        "[GEAR][EDGE] "
                        f"source=hotas raw={int(gear_raw_now)} prev={int(gear_raw_prev)} "
                        f"mode={gear_mode} bound={int(bool(gear_hotas_bound))}"
                    )
                    _command_landing_gear("hotas")
                pmd_dr_state["hotas_ldg_gear_prev_pressed"] = bool(hotas_now_map.get("ldg_gear", False))
            pmd_dr_state["hotas_gear_handler_prev_raw"] = bool(gear_raw_now)

        brake_binding_active = isinstance(_hotas_get_connected_binding("brake"), dict) or (len(_pmd_action_key_codes("brake")) > 0)
        if brake_binding_active:
            brake_mode = str(pmd_dr_state.get("hotas_brake_mode", "TOGGLE")).upper()
            if brake_mode not in {"MOMENTARY", "TOGGLE"}:
                brake_mode = "TOGGLE"
            brake_pressed = bool(now_map.get("brake", False))
            panel_state = _ensure_panel_button_states()
            console_left = panel_state.get("CONSOLE LEFT", {})
            if isinstance(console_left, dict):
                current_on = str(console_left.get("PARKING_BRAKE", "ON")).upper() == "ON"

                def _set_brake_on(target_on: bool) -> None:
                    target_state = "ON" if target_on else "OFF"
                    if str(console_left.get("PARKING_BRAKE", "ON")).upper() != target_state:
                        console_left["PARKING_BRAKE"] = target_state
                        play_sound_effect("SWITCH")

                if brake_mode == "TOGGLE":
                    if _rising("brake"):
                        _set_brake_on(not current_on)
                else:
                    _set_brake_on(brake_pressed)

        pmd_dr_state["hotas_prev_down"] = dict(now_map)
        pmd_dr_state["hotas_prev_down_raw"] = dict(hotas_now_map)
        pmd_dr_state["hotas_prev_key_down"] = dict(key_now_map)

    def _hotas_capture_event(event: pygame.event.Event) -> bool:
        action = str(pmd_dr_state.get("hotas_edit_action", "")).strip().lower()
        if action not in HOTAS_ACTION_ORDER:
            return False
        if not bool(pmd_dr_state.get("hotas_edit_capture_selected", False)):
            return False
        joy_idx = _hotas_event_joy_index(event)
        manual_dev = bool(pmd_dr_state.get("hotas_edit_device_manual", False))
        try:
            selected_dev = int(pmd_dr_state.get("hotas_edit_device", -1))
        except Exception:
            selected_dev = -1
        if joy_idx < 0:
            if (not manual_dev) and selected_dev in hotas_joysticks:
                joy_idx = int(selected_dev)
            else:
                return False
        if manual_dev and selected_dev >= 0 and joy_idx != selected_dev:
            return False
        if (not manual_dev) and selected_dev != joy_idx:
            pmd_dr_state["hotas_edit_device"] = joy_idx
        pmd_dr_state["hotas_edit_device_auto_lock"] = int(joy_idx)
        try:
            pmd_dr_state["hotas_edit_device_auto_lock_until_ms"] = int(pygame.time.get_ticks()) + 1500
        except Exception:
            pmd_dr_state["hotas_edit_device_auto_lock_until_ms"] = 1500
        allowed = set(_hotas_allowed_types(action))
        excluded_set = _hotas_excluded_inputs_set()
        event_type = int(getattr(event, "type", -1))

        if event_type == _JOYAXISMOTION_EVENT and "axis" in allowed:
            try:
                axis_idx = int(getattr(event, "axis"))
                axis_val = float(getattr(event, "value"))
            except Exception:
                return False
            if abs(axis_val) < 0.9:
                return False
            existing = _hotas_get_binding(action) or {}
            invert = bool(existing.get("invert", False))
            return _hotas_set_binding(action, {"type": "axis", "joy": joy_idx, "id": axis_idx, "invert": invert})

        if event_type == _JOYBUTTONDOWN_EVENT and "button" in allowed:
            try:
                btn_idx = int(getattr(event, "button"))
            except Exception:
                return False
            sig = f"button:{int(joy_idx)}:{int(btn_idx)}"
            if sig in excluded_set:
                return False
            return _hotas_set_binding(action, {"type": "button", "joy": joy_idx, "id": btn_idx})

        if event_type == _JOYHATMOTION_EVENT and "hat" in allowed:
            try:
                hat_idx = int(getattr(event, "hat"))
                hat_val = getattr(event, "value")
                x_val = int(hat_val[0]) if isinstance(hat_val, (tuple, list)) and len(hat_val) > 0 else 0
                y_val = int(hat_val[1]) if isinstance(hat_val, (tuple, list)) and len(hat_val) > 1 else 0
            except Exception:
                return False
            hat_dir = ""
            if y_val > 0:
                hat_dir = "UP"
            elif y_val < 0:
                hat_dir = "DOWN"
            elif x_val < 0:
                hat_dir = "LEFT"
            elif x_val > 0:
                hat_dir = "RIGHT"
            if hat_dir == "":
                return False
            sig = f"hat:{int(joy_idx)}:{int(hat_idx)}:{hat_dir.lower()}"
            if sig in excluded_set:
                return False
            return _hotas_set_binding(action, {"type": "hat", "joy": joy_idx, "id": hat_idx, "dir": hat_dir})
        return False

    def _hotas_update_runtime_event_state(event: pygame.event.Event) -> None:
        event_type = int(getattr(event, "type", -1))
        if event_type not in {_JOYBUTTONDOWN_EVENT, _JOYBUTTONUP_EVENT, _JOYHATMOTION_EVENT}:
            return
        joy_idx = _hotas_event_joy_index(event)
        if joy_idx < 0:
            return
        overrides_raw = pmd_dr_state.get("hotas_event_down_override", {})
        overrides: Dict[str, bool] = dict(overrides_raw) if isinstance(overrides_raw, dict) else {}
        bindings = _hotas_bindings_dict()

        def _binding_event_joy_matches(binding: Dict[str, object]) -> bool:
            resolved = _hotas_resolve_binding_joy_index(binding)
            return bool(resolved is not None and int(resolved) == int(joy_idx))

        for action_name, binding_raw in bindings.items():
            action_key = str(action_name).strip().lower()
            if action_key not in HOTAS_ACTION_ORDER or not isinstance(binding_raw, dict):
                continue
            binding = binding_raw
            if not _binding_event_joy_matches(binding):
                continue
            b_type = str(binding.get("type", "")).strip().lower()
            if event_type in {_JOYBUTTONDOWN_EVENT, _JOYBUTTONUP_EVENT} and b_type == "button":
                try:
                    btn_idx = int(getattr(event, "button"))
                    bind_btn = int(binding.get("id", -1))
                except Exception:
                    continue
                if btn_idx != bind_btn:
                    continue
                prev_down = bool(overrides.get(action_key, False))
                overrides[action_key] = bool(event_type == _JOYBUTTONDOWN_EVENT)
                if action_key in {"aprch_pwr_comp", "ldg_gear"}:
                    print(f"[HOTAS][EVENT] {action_key}={int(overrides[action_key])} joy={joy_idx} button={btn_idx}")
                if action_key == "ldg_gear" and event_type == _JOYBUTTONDOWN_EVENT and not prev_down:
                    try:
                        focus_inhibit_until_ms = int(pmd_dr_state.get("input_focus_inhibit_until_ms", 0))
                    except Exception:
                        focus_inhibit_until_ms = 0
                    now_evt = int(pygame.time.get_ticks())
                    if now_evt < focus_inhibit_until_ms:
                        print(f"[GEAR][IGNORE] source=hotas_event focus_inhibit_until_ms={focus_inhibit_until_ms}")
                    elif phase >= 1:
                        print("[GEAR][EDGE] source=hotas_event")
                        _command_landing_gear_input("hotas_event")
                    else:
                        print(f"[GEAR][BLOCK] source=hotas_event phase={phase}")
                elif action_key == "aprch_pwr_comp":
                    pass
            elif event_type == _JOYHATMOTION_EVENT and b_type == "hat":
                try:
                    hat_idx = int(getattr(event, "hat"))
                    bind_hat = int(binding.get("id", -1))
                    hat_val = getattr(event, "value")
                    x_val = int(hat_val[0]) if isinstance(hat_val, (tuple, list)) and len(hat_val) > 0 else 0
                    y_val = int(hat_val[1]) if isinstance(hat_val, (tuple, list)) and len(hat_val) > 1 else 0
                except Exception:
                    continue
                if hat_idx != bind_hat:
                    continue
                hat_dir = str(binding.get("dir", "")).upper().strip()
                down = (
                    (hat_dir == "UP" and y_val > 0)
                    or (hat_dir == "DOWN" and y_val < 0)
                    or (hat_dir == "LEFT" and x_val < 0)
                    or (hat_dir == "RIGHT" and x_val > 0)
                )
                overrides[action_key] = bool(down)
        pmd_dr_state["hotas_event_down_override"] = dict(overrides)

    def _hotas_axis_throttle_percent() -> Optional[float]:
        binding = _hotas_get_binding("throttle")
        if not isinstance(binding, dict):
            return None
        value = _hotas_axis_value(binding)
        if value is None:
            return None
        value = max(-1.0, min(1.0, float(value)))
        return max(0.0, min(150.0, ((1.0 - value) * 0.5) * 150.0))

    def _hotas_begin_edit_action(action: str) -> bool:
        action_key = str(action).strip().lower()
        if action_key not in HOTAS_ACTION_ORDER:
            return False
        _hotas_refresh_devices()
        pmd_dr_state["hotas_edit_action"] = action_key
        pmd_dr_state["hotas_edit_capture_selected"] = False
        pmd_dr_state["hotas_edit_input_text"] = ""
        pmd_dr_state["hotas_edit_status"] = ""
        pmd_dr_state["hotas_edit_device_manual"] = False
        pmd_dr_state["hotas_edit_device_auto_lock"] = -1
        pmd_dr_state["hotas_edit_device_auto_lock_until_ms"] = 0
        pmd_dr_state["hotas_edit_excluded_inputs"] = []
        binding = _hotas_get_binding(action_key)
        if isinstance(binding, dict):
            pmd_dr_state["hotas_edit_input_text"] = _hotas_binding_label(binding)
        devices_raw = pmd_dr_state.get("hotas_devices", [])
        devices = devices_raw if isinstance(devices_raw, list) else []
        valid_indices: List[int] = []
        for dev in devices:
            if not isinstance(dev, dict):
                continue
            try:
                idx = int(dev.get("index", -1))
            except Exception:
                idx = -1
            if idx >= 0 and idx not in valid_indices:
                valid_indices.append(idx)
        selected_idx = -1
        if isinstance(binding, dict):
            try:
                selected_idx = int(binding.get("joy", -1))
            except Exception:
                selected_idx = -1
        if selected_idx not in valid_indices:
            selected_idx = valid_indices[0] if len(valid_indices) > 0 else -1
        pmd_dr_state["hotas_edit_device"] = selected_idx
        return True

    def _hotas_cycle_edit_device(step: int) -> bool:
        _hotas_refresh_devices()
        devices_raw = pmd_dr_state.get("hotas_devices", [])
        devices = devices_raw if isinstance(devices_raw, list) else []
        indices: List[int] = []
        for dev in devices:
            if not isinstance(dev, dict):
                continue
            try:
                idx = int(dev.get("index", -1))
            except Exception:
                idx = -1
            if idx >= 0 and idx not in indices:
                indices.append(idx)
        if len(indices) <= 0:
            pmd_dr_state["hotas_edit_device"] = -1
            pmd_dr_state["hotas_edit_device_manual"] = True
            pmd_dr_state["hotas_edit_device_auto_lock"] = -1
            pmd_dr_state["hotas_edit_device_auto_lock_until_ms"] = 0
            return False
        try:
            current = int(pmd_dr_state.get("hotas_edit_device", indices[0]))
        except Exception:
            current = indices[0]
        if current in indices:
            pos = indices.index(current)
            next_pos = (pos + int(step)) % len(indices)
            next_idx = indices[next_pos]
        else:
            next_idx = indices[0]
        pmd_dr_state["hotas_edit_device"] = int(next_idx)
        pmd_dr_state["hotas_edit_device_manual"] = True
        pmd_dr_state["hotas_edit_device_auto_lock"] = -1
        pmd_dr_state["hotas_edit_device_auto_lock_until_ms"] = 0
        return True

    def finalize_pmd_keybind_data_entry(action: str) -> None:
        action_key = str(action).strip().lower()
        if action_key not in PMD_KEYBIND_ACTION_ORDER:
            return
        inputs_raw = pmd_dr_state.get("keybind_inputs", {})
        if not isinstance(inputs_raw, dict):
            return
        typed = str(inputs_raw.get(action_key, "")).strip()
        if typed != "":
            if _pmd_set_keybind_value(action_key, typed):
                _save_flight_keybinds_to_settings()
        inputs_raw[action_key] = ""
        if _pmd_keybind_selected_field() == action_key:
            pmd_dr_state["keybind_selected"] = None

    def select_pmd_keybind_data_entry(action: str) -> None:
        action_key = str(action).strip().lower()
        if action_key not in PMD_KEYBIND_ACTION_ORDER:
            return
        current = _pmd_keybind_selected_field()
        if current == action_key:
            finalize_pmd_keybind_data_entry(action_key)
            return
        if current is not None:
            finalize_pmd_keybind_data_entry(current)
        pmd_dr_state["keybind_selected"] = action_key
        inputs_raw = pmd_dr_state.get("keybind_inputs", {})
        if isinstance(inputs_raw, dict):
            inputs_raw[action_key] = ""

    def _pmd_keybind_type_char(ch: str) -> bool:
        action = _pmd_keybind_selected_field()
        if action is None:
            return False
        key_name = _pmd_normalize_key_name(ch)
        if key_name == "":
            return False
        if _pmd_keybind_owner_for_key(key_name, action) is not None:
            return False
        inputs_raw = pmd_dr_state.get("keybind_inputs", {})
        if not isinstance(inputs_raw, dict):
            return False
        inputs_raw[action] = key_name
        return True

    def _apply_saved_flight_keybinds() -> None:
        raw = settings.get(FLIGHT_KEYBINDS_SETTINGS_KEY, {})
        if not isinstance(raw, dict):
            return
        # Backward compatibility: migrate legacy cursor-pan bindings.
        legacy_to_pan = {
            "curs_lt": "pan_left",
            "curs_up": "pan_up",
            "curs_dn": "pan_down",
            "curs_rt": "pan_right",
        }
        for legacy_key, pan_key in legacy_to_pan.items():
            pan_val = str(raw.get(pan_key, "")).strip()
            legacy_val = str(raw.get(legacy_key, "")).strip()
            if pan_val == "" and legacy_val != "":
                raw[pan_key] = legacy_val
        for action in PMD_KEYBIND_ACTION_ORDER:
            if action not in raw:
                continue
            val = str(raw.get(action, "")).strip()
            if val == "":
                _pmd_clear_keybind_value(action)
            else:
                _pmd_set_keybind_value(action, val)

    _apply_saved_flight_keybinds()

    _DATA_LINK_FIELDS = {"flt_pos", "callsign", "msn_nbr", "net_key"}
    _DATA_LINK_FIELD_SPECS = {
        "flt_pos": {"max_len": 3, "charset": "0123456789"},
        "callsign": {"max_len": 9, "charset": "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"},
        "msn_nbr": {"max_len": 5, "charset": "0123456789"},
        "net_key": {"max_len": 16, "charset": "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"},
    }

    def _data_link_field_charset(field: str) -> str:
        key = str(field).strip().lower()
        spec = _DATA_LINK_FIELD_SPECS.get(key, {})
        charset = str(spec.get("charset", ""))
        if charset == "":
            return "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
        return charset

    def _data_link_selected_field() -> Optional[str]:
        field = str(data_link_state.get("selected_field", "")).strip().lower()
        if field in _DATA_LINK_FIELDS:
            return field
        return None

    def _data_link_max_len(field: str) -> int:
        key = str(field).strip().lower()
        spec = _DATA_LINK_FIELD_SPECS.get(key, {})
        try:
            return max(1, int(spec.get("max_len", 1)))
        except Exception:
            return 1

    def _data_link_is_valid_value(field: str, value: object) -> bool:
        key = str(field).strip().lower()
        if key not in _DATA_LINK_FIELDS:
            return False
        charset = _data_link_field_charset(key)
        max_len = _data_link_max_len(key)
        txt = str(value or "").strip().upper()
        if key == "net_key":
            if len(txt) < 1 or len(txt) > max_len:
                return False
        else:
            if len(txt) != max_len:
                return False
        return all(ch in charset for ch in txt)

    def _data_link_ready_for_msn() -> bool:
        flt_pos = str(data_link_state.get("flt_pos_value", "")).strip().upper()
        callsign = str(data_link_state.get("callsign_value", "")).strip().upper()
        return flt_pos != "" and callsign != ""

    def _data_link_runtime_value(field: str) -> str:
        key = str(field).strip().lower()
        if key not in _DATA_LINK_FIELDS:
            return ""
        committed = _data_link_clean_text(data_link_state.get(f"{key}_value", ""), key)
        selected = _data_link_selected_field()
        if selected != key:
            return committed
        inputs = data_link_state.get("inputs", {})
        if not isinstance(inputs, dict):
            return committed
        draft = _data_link_clean_text(inputs.get(key, ""), key)
        return draft if draft != "" else committed

    def _data_link_committed_value(field: str) -> str:
        key = str(field).strip().lower()
        if key not in _DATA_LINK_FIELDS:
            return ""
        return _data_link_clean_text(data_link_state.get(f"{key}_value", ""), key)

    def _data_link_ready_for_create() -> bool:
        # Use committed values only; draft input does not apply until submitted.
        callsign = _data_link_committed_value("callsign")
        net_key = _data_link_committed_value("net_key")
        return callsign != "" and _data_link_is_valid_value("net_key", net_key)

    def _data_link_clean_text(value: object, field: str) -> str:
        raw = str(value or "").upper()
        charset = _data_link_field_charset(field)
        max_len = _data_link_max_len(field)
        clean = "".join(ch for ch in raw if ch in charset)
        return clean[: max(1, int(max_len))].strip()

    def _save_data_link_settings() -> None:
        settings["data_link_flt_pos"] = str(data_link_state.get("flt_pos_value", "")).strip()
        settings["data_link_callsign"] = str(data_link_state.get("callsign_value", "")).strip()
        settings["data_link_msn_nbr"] = str(data_link_state.get("msn_nbr_value", "")).strip()
        settings["data_link_net_key"] = str(data_link_state.get("net_key_value", "")).strip()
        settings["data_link_default_net_key"] = str(data_link_state.get("default_net_key", "")).strip()
        settings["data_link_mission"] = str(data_link_state.get("mission_value", "")).strip()
        settings["data_link_image"] = str(data_link_state.get("image_value", "")).strip()
        settings["data_link_entry_id"] = str(data_link_state.get("entry_id", "")).strip()
        settings["data_link_entry_callsign"] = str(data_link_state.get("entry_callsign", "")).strip()
        settings["data_link_entry_flt_pos"] = str(data_link_state.get("entry_flt_pos", "")).strip()
        settings["udp_relay_firewall_rule_installed"] = bool(data_link_state.get("firewall_rule_installed", False))
        save_settings(settings)

    def _data_link_mark_fw_rule_installed(installed: bool) -> None:
        val = bool(installed)
        data_link_state["firewall_rule_installed"] = val
        settings["udp_relay_firewall_rule_installed"] = val
        try:
            save_settings(settings)
        except Exception:
            pass

    def _data_link_fw_rule_names() -> Tuple[str, str]:
        return ("F35 PCD Relay UDP In", "F35 PCD Relay UDP Out")

    def _data_link_fw_rule_exists(display_name: str) -> bool:
        if os.name != "nt":
            return True
        dname = str(display_name).strip()
        if dname == "":
            return False
        esc = dname.replace("'", "''")
        out = _run_powershell_capture(
            f"$r=Get-NetFirewallRule -DisplayName '{esc}' -Enabled True -ErrorAction SilentlyContinue | Select-Object -First 1; "
            "if ($null -ne $r) { '1' } else { '0' }",
            timeout_s=2.0,
        )
        return str(out).strip() == "1"

    def _data_link_fw_has_required_rules() -> bool:
        if os.name != "nt":
            return True
        if bool(data_link_state.get("firewall_rule_installed", False)):
            return True
        in_name, out_name = _data_link_fw_rule_names()
        return _data_link_fw_rule_exists(in_name) and _data_link_fw_rule_exists(out_name)

    def _data_link_request_fw_exception_uac() -> bool:
        if os.name != "nt":
            return False
        exe_path = str(Path(sys.executable).resolve())
        if exe_path == "":
            data_link_state["firewall_exception_last_status"] = "Unable to resolve EXE path for firewall exception."
            return False
        ip_txt = str(udp_relay_server_ip or "").strip() or "104.248.63.183"
        try:
            port_num = int(udp_relay_server_port)
        except Exception:
            port_num = 27015
        if port_num <= 0:
            port_num = 27015

        try:
            op = "runas"
            file = exe_path
            args = [
                "--fw-helper",
                "--fw-exe",
                exe_path,
                "--fw-ip",
                ip_txt,
                "--fw-port",
                str(int(port_num)),
            ]
            params = subprocess.list2cmdline(args)
            rc = ctypes.windll.shell32.ShellExecuteW(None, op, file, params, None, 1)
            # >32 indicates success (process launched / UAC accepted).
            ok = int(rc) > 32
            if ok:
                _data_link_mark_fw_rule_installed(True)
            data_link_state["firewall_exception_last_status"] = (
                "Firewall access prompt opened." if ok else "Firewall access prompt was canceled or failed."
            )
            return bool(ok)
        except Exception:
            data_link_state["firewall_exception_last_status"] = "Failed to request firewall exception."
            return False

    def _data_link_check_or_request_fw_exception() -> None:
        if os.name != "nt":
            return
        if bool(data_link_state.get("firewall_rule_installed", False)):
            data_link_state["firewall_exception_last_status"] = "Firewall exception marked installed."
            return
        if _data_link_fw_has_required_rules():
            _data_link_mark_fw_rule_installed(True)
            data_link_state["firewall_exception_last_status"] = "Firewall exception present."
            return
        # Request elevation every JOIN attempt while the rules are still missing.
        _data_link_request_fw_exception_uac()

    def _data_link_default_net_key() -> str:
        from_state = str(data_link_state.get("default_net_key", "")).strip().upper()
        if _data_link_is_valid_value("net_key", from_state):
            return from_state
        env_key = str(os.environ.get("F35_DATALINK_DEFAULT_NET_KEY", "")).strip().upper()
        if _data_link_is_valid_value("net_key", env_key):
            data_link_state["default_net_key"] = env_key
            _save_data_link_settings()
            return env_key
        return ""

    def _data_link_current_net_key() -> str:
        committed_key = _data_link_committed_value("net_key")
        if _data_link_is_valid_value("net_key", committed_key):
            return committed_key
        return _data_link_default_net_key()

    def _finalize_data_link_data_entry(field: str) -> None:
        key = str(field).strip().lower()
        if key not in _DATA_LINK_FIELDS:
            return
        if key == "msn_nbr" and not _data_link_ready_for_msn():
            data_link_state["selected_field"] = None
            return
        inputs = data_link_state.get("inputs", {})
        if not isinstance(inputs, dict):
            inputs = {}
            data_link_state["inputs"] = inputs
        raw = str(inputs.get(key, ""))
        cleaned = _data_link_clean_text(raw, key)
        if key == "net_key" and cleaned != "" and not _data_link_is_valid_value("net_key", cleaned):
            cleaned = ""
        if cleaned != "":
            prev_val = str(data_link_state.get(f"{key}_value", "")).strip().upper()
            data_link_state[f"{key}_value"] = cleaned
            if key == "net_key" and cleaned != prev_val:
                data_link_state["entry_id"] = ""
                data_link_state["active_net_exists"] = False
                data_link_state["active_net_payload"] = {}
                data_link_state["next_create_retry_ms"] = 0
                data_link_state["next_all_ms"] = 0
        inputs[key] = ""
        if _data_link_selected_field() == key:
            data_link_state["selected_field"] = None
        _save_data_link_settings()

    def _select_data_link_data_entry(field: str) -> None:
        key = str(field).strip().lower()
        if key not in _DATA_LINK_FIELDS:
            return
        current = _data_link_selected_field()
        if current == key:
            _finalize_data_link_data_entry(key)
            return
        if current is not None:
            _finalize_data_link_data_entry(current)
        if key == "msn_nbr" and not _data_link_ready_for_msn():
            return
        inputs = data_link_state.get("inputs", {})
        if not isinstance(inputs, dict):
            inputs = {}
            data_link_state["inputs"] = inputs
        inputs[key] = ""
        data_link_state["selected_field"] = key
        data_link_state["keypad_last_group"] = ""
        data_link_state["keypad_last_group_ms"] = 0

    def _data_link_type_char(ch: str) -> bool:
        field = _data_link_selected_field()
        if field is None:
            return False
        if field == "msn_nbr" and not _data_link_ready_for_msn():
            return False
        txt = str(ch or "").upper()
        charset = _data_link_field_charset(field)
        if len(txt) != 1 or txt not in charset:
            return False
        inputs = data_link_state.get("inputs", {})
        if not isinstance(inputs, dict):
            return False
        current = str(inputs.get(field, ""))
        limit = _data_link_max_len(field)
        if len(current) < limit:
            inputs[field] = current + txt
        else:
            inputs[field] = current[:-1] + txt
        return True

    def _data_link_keypad_press(token: str) -> None:
        field = _data_link_selected_field()
        if field is None:
            return
        if field == "msn_nbr" and not _data_link_ready_for_msn():
            return
        inputs = data_link_state.get("inputs", {})
        if not isinstance(inputs, dict):
            return
        key = str(token).strip().upper()
        current = str(inputs.get(field, ""))
        limit = _data_link_max_len(field)
        group_map = {
            "DATA_LINK_KP_A4": "ABC2",
            "DATA_LINK_KP_B4": "DEF3",
            "DATA_LINK_KP_C4": "GHI4",
            "DATA_LINK_KP_A5": "JKL5",
            "DATA_LINK_KP_B5": "MNO6",
            "DATA_LINK_KP_C5": "PQRS7",
            "DATA_LINK_KP_A6": "TUV8",
            "DATA_LINK_KP_B6": "WXYZ9",
            "DATA_LINK_KP_C6": "1",
        }
        charset = _data_link_field_charset(field)
        if key in group_map:
            group = "".join(ch for ch in group_map[key] if ch in charset)
            if group == "":
                return
            now_ms = int(pygame.time.get_ticks())
            prev_group = str(data_link_state.get("keypad_last_group", ""))
            prev_ms = int(data_link_state.get("keypad_last_group_ms", 0) or 0)
            if current != "" and prev_group == key and (now_ms - prev_ms) <= 1200:
                last_char = current[-1]
                idx = group.find(last_char)
                if idx < 0:
                    next_ch = group[0]
                else:
                    next_ch = group[(idx + 1) % len(group)]
                current = current[:-1] + next_ch
            else:
                if len(current) < limit:
                    current = current + group[0]
            data_link_state["keypad_last_group"] = key
            data_link_state["keypad_last_group_ms"] = now_ms
            inputs[field] = current
            return
        if key == "DATA_LINK_KP_B7":
            if " " in charset and len(current) < limit:
                inputs[field] = current + " "
            data_link_state["keypad_last_group"] = ""
            return
        if key == "DATA_LINK_KP_C7":
            inputs[field] = current[:-1]
            data_link_state["keypad_last_group"] = ""
            return
        if key in {"DATA_LINK_KP_A7", "DATA_LINK_KP_A8"}:
            if charset == "":
                return
            if current == "":
                inputs[field] = charset[0] if key == "DATA_LINK_KP_A7" else charset[-1]
                return
            idx = charset.find(current[-1])
            if idx < 0:
                idx = 0
            if key == "DATA_LINK_KP_A7":
                idx = (idx + 1) % len(charset)
            else:
                idx = (idx - 1) % len(charset)
            inputs[field] = current[:-1] + charset[idx]
            data_link_state["keypad_last_group"] = ""
            return

    def _data_link_build_ownship_table() -> Dict[str, object]:
        lat_val = None
        lon_val = None
        try:
            with adsb_runtime_lock:
                lat_val = adsb_runtime.get("lat")
                lon_val = adsb_runtime.get("lon")
        except Exception:
            lat_val = None
            lon_val = None
        try:
            lat = float(lat_val) if lat_val is not None else None
        except Exception:
            lat = None
        try:
            lon = float(lon_val) if lon_val is not None else None
        except Exception:
            lon = None
        try:
            heading = float(getattr(formats, "TWD_STATE", {}).get("heading_deg", 0.0)) % 360.0
        except Exception:
            heading = 0.0
        altitude_ft = 0.0
        airspeed_kts = 0.0
        vertical_fpm = 0.0
        ground_kts = 0.0
        try:
            panel = _ensure_panel_button_states()
            throttle = panel.get("THROTTLE", {})
            aircraft = throttle.get("AIRCRAFT", {}) if isinstance(throttle, dict) else {}
            if isinstance(aircraft, dict):
                altitude_ft = float(aircraft.get("ALTITUDE_FT", aircraft.get("ALTITUDE_TARGET_FT", 0.0)) or 0.0)
                airspeed_kts = float(aircraft.get("AIRSPEED_KTS", 0.0) or 0.0)
                vertical_fpm = float(aircraft.get("VERTICAL_SPEED_FPM", 0.0) or 0.0)
                try:
                    ground_kts = float(max(0.0, (max(0.0, airspeed_kts) ** 2 - (max(0.0, vertical_fpm / 101.2686) ** 2)) ** 0.5))
                except Exception:
                    ground_kts = max(0.0, airspeed_kts)
        except Exception:
            pass
        toi_state = getattr(formats, "TSD_TOI_STATE", {})
        toi_payload: Dict[str, object] = {
            "active": bool(isinstance(toi_state, dict) and toi_state.get("active", False)),
            "lat": None,
            "lon": None,
        }
        if isinstance(toi_state, dict) and bool(toi_state.get("active", False)):
            try:
                toi_payload["lat"] = float(toi_state.get("lat"))
                toi_payload["lon"] = float(toi_state.get("lon"))
            except Exception:
                toi_payload["lat"] = None
                toi_payload["lon"] = None
        mission_payload: object = str(data_link_state.get("mission_value", "")).strip()
        image_payload: str = str(data_link_state.get("image_value", "")).strip()
        if isinstance(mission_payload, str):
            mission_text = mission_payload.strip()
            if mission_text != "" and mission_text[:1] in {"{", "["}:
                try:
                    mission_payload = json.loads(mission_text)
                except Exception:
                    mission_payload = mission_text
        fuel_snapshot: Dict[str, object] = {}
        try:
            fuel_snapshot = dict(get_status_fuel_snapshot())
        except Exception:
            fuel_snapshot = {}
        stores_payload: Dict[str, object] = {}
        try:
            sms = getattr(formats, "SMS_STATE", {})
            if isinstance(sms, dict):
                stores_payload = {
                    "live_train_idx": int(sms.get("live_train_idx", 0) or 0),
                    "store_loads": dict(sms.get("store_loads", {})) if isinstance(sms.get("store_loads", {}), dict) else {},
                    "training_store_loads": dict(sms.get("training_store_loads", {})) if isinstance(sms.get("training_store_loads", {}), dict) else {},
                }
        except Exception:
            stores_payload = {}
        seclvl_payload: Dict[str, object] = {
            "logged_in": bool(seclvl_state.get("logged_in", False)),
            "level_idx": int(seclvl_state.get("level_idx", 0) or 0),
            "mode_idx": int(seclvl_state.get("mode_idx", 0) or 0),
        }
        return {
            "schema": 1,
            "session_id": str(data_link_state.get("session_id", "")).strip(),
            "callsign": str(data_link_state.get("callsign_value", "")).strip(),
            "flt_pos": str(data_link_state.get("flt_pos_value", "")).strip(),
            "msn_nbr": str(data_link_state.get("msn_nbr_value", "")).strip(),
            "lat": lat,
            "lon": lon,
            "heading_deg": heading,
            "altitude_ft": altitude_ft,
            "airspeed_kts": airspeed_kts,
            "ground_speed_kts": ground_kts,
            "vertical_speed_fpm": vertical_fpm,
            "toi": toi_payload,
            "image": image_payload,
            "mission": mission_payload,
            "fuel": fuel_snapshot,
            "stores": stores_payload,
            "seclvl": seclvl_payload,
            "updated_ms": int(pygame.time.get_ticks()),
        }

    def _data_link_collect_dim_missions() -> Dict[str, object]:
        out: Dict[str, object] = {}
        try:
            cls = getattr(formats, "DimV2Format", None)
            if cls is None:
                return {}
            raw_store = getattr(cls, "_shared_mission_store", {})
            own_ids = list(getattr(cls, "_shared_inbox_own_ids", []))
            flt_ids = list(getattr(cls, "_shared_inbox_flt_ids", []))
            outbox_ids = list(getattr(cls, "_shared_outbox_ids", []))
            if isinstance(raw_store, dict):
                mission_store: Dict[str, object] = {}
                for k, v in raw_store.items():
                    sid = str(k).strip()
                    if sid == "" or not isinstance(v, dict):
                        continue
                    mission_store[sid] = dict(v)
                out["store"] = mission_store
                out["inbox_own_ids"] = [str(x) for x in own_ids if str(x).strip() != ""]
                out["inbox_flt_ids"] = [str(x) for x in flt_ids if str(x).strip() != ""]
                out["outbox_ids"] = [str(x) for x in outbox_ids if str(x).strip() != ""]
        except Exception:
            return {}
        return out

    def _data_link_apply_net_missions(
        missions_blob: object,
        images_blob: object = None,
        local_session_id: str = "",
    ) -> None:
        if isinstance(missions_blob, str):
            try:
                missions_blob = json.loads(missions_blob)
            except Exception:
                missions_blob = {}
        if isinstance(images_blob, str):
            try:
                images_blob = json.loads(images_blob)
            except Exception:
                images_blob = {}
        if not isinstance(missions_blob, dict):
            return
        try:
            cls = getattr(formats, "DimV2Format", None)
            if cls is None:
                return
            existing_store_raw = getattr(cls, "_shared_mission_store", {})
            existing_store: Dict[str, Dict[str, object]] = {}
            if isinstance(existing_store_raw, dict):
                for k, v in existing_store_raw.items():
                    mid = str(k).strip()
                    if mid == "" or not isinstance(v, dict):
                        continue
                    existing_store[mid] = dict(v)
            existing_outbox_raw = getattr(cls, "_shared_outbox_ids", [])
            existing_outbox = [str(x) for x in existing_outbox_raw if str(x).strip() != ""] if isinstance(existing_outbox_raw, list) else []
            raw_store = missions_blob.get("store", {})
            normalized_store: Dict[str, Dict[str, object]] = {}
            if isinstance(raw_store, dict):
                for k, v in raw_store.items():
                    mission_id = str(k).strip()
                    if mission_id == "" or not isinstance(v, dict):
                        continue
                    mission = dict(v)
                    origin_sid = str(mission.get("origin_session_id", "")).strip()
                    if local_session_id != "":
                        if origin_sid == "":
                            # Heuristic fallback for legacy missions with no origin marker.
                            if str(mission.get("local", "")).strip().upper() == "V" and mission_id in existing_outbox:
                                origin_sid = local_session_id
                            mission["origin_session_id"] = origin_sid
                        mission["local"] = "V" if origin_sid == local_session_id else "L"
                    # Merge by updated timestamp so local edits (response/assign/etc)
                    # are not immediately clobbered by an older remote snapshot.
                    prev_mission = existing_store.get(mission_id)
                    if isinstance(prev_mission, dict):
                        try:
                            prev_ms = int(prev_mission.get("updated_unix_ms", 0) or 0)
                        except Exception:
                            prev_ms = 0
                        try:
                            new_ms = int(mission.get("updated_unix_ms", 0) or 0)
                        except Exception:
                            new_ms = 0
                        if prev_ms > new_ms:
                            mission = dict(prev_mission)
                    normalized_store[mission_id] = mission
            own_ids_raw = missions_blob.get("inbox_own_ids", [])
            flt_ids_raw = missions_blob.get("inbox_flt_ids", [])
            # Outbox is local-only; do not trust network outbox list directly.
            own_ids = [str(x) for x in own_ids_raw if str(x).strip() != ""] if isinstance(own_ids_raw, list) else []
            flt_ids = [str(x) for x in flt_ids_raw if str(x).strip() != ""] if isinstance(flt_ids_raw, list) else []
            # OWN assignment is local per client; preserve local selection across sync.
            if isinstance(existing_store_raw, dict):
                existing_own_raw = getattr(cls, "_shared_inbox_own_ids", [])
                if isinstance(existing_own_raw, list):
                    existing_own = [str(x) for x in existing_own_raw if str(x).strip() != ""]
                    keep_own: List[str] = []
                    for mid in existing_own:
                        mission = normalized_store.get(mid)
                        if isinstance(mission, dict) and (not cls._mission_is_deleted(mission)):  # type: ignore[attr-defined]
                            if mid not in keep_own:
                                keep_own.append(mid)
                    own_ids = keep_own
            # Ensure FLT section always has missions present in the store.
            if len(flt_ids) <= 0:
                for mid, mission in normalized_store.items():
                    if not isinstance(mission, dict):
                        continue
                    if bool(mission.get("deleted", False)):
                        continue
                    flt_ids.append(str(mid))
            outbox_ids: List[str] = []
            if local_session_id != "":
                for mid, mission in normalized_store.items():
                    if not isinstance(mission, dict):
                        continue
                    if str(mission.get("origin_session_id", "")).strip() == local_session_id:
                        if bool(mission.get("deleted", False)):
                            continue
                        outbox_ids.append(str(mid))
                # Preserve local unsent missions so periodic ALL polling does not wipe
                # a mission before the next write publishes it to the net.
                for mid, mission in existing_store.items():
                    if mid in normalized_store:
                        continue
                    origin_sid = str(mission.get("origin_session_id", "")).strip()
                    is_local = origin_sid == local_session_id
                    if (not is_local) and origin_sid == "":
                        is_local = str(mission.get("local", "")).strip().upper() == "V" and mid in existing_outbox
                    if not is_local:
                        continue
                    keep = dict(mission)
                    keep["origin_session_id"] = local_session_id
                    keep["local"] = "V"
                    normalized_store[mid] = keep
                    if mid not in flt_ids:
                        flt_ids.append(mid)
                    if mid not in outbox_ids:
                        outbox_ids.append(mid)
            setattr(cls, "_shared_mission_store", normalized_store)
            setattr(cls, "_shared_inbox_own_ids", own_ids)
            setattr(cls, "_shared_inbox_flt_ids", flt_ids)
            setattr(cls, "_shared_outbox_ids", outbox_ids)
            existing_images_raw = getattr(cls, "_shared_image_data", {})
            images_map: Dict[str, Dict[str, object]] = {}
            if isinstance(existing_images_raw, dict):
                for k, v in existing_images_raw.items():
                    kk = str(k).strip()
                    if kk == "" or not isinstance(v, dict):
                        continue
                    images_map[kk] = dict(v)
            if isinstance(images_blob, dict):
                for token, raw in images_blob.items():
                    key = str(token).strip()
                    if key == "":
                        continue
                    if isinstance(raw, str):
                        try:
                            raw = json.loads(raw)
                        except Exception:
                            raw = {}
                    if isinstance(raw, dict):
                        b64 = str(raw.get("data_b64", "")).strip()
                        if b64 == "":
                            continue
                        images_map[key] = dict(raw)
            setattr(cls, "_shared_image_data", images_map)
        except Exception:
            pass

    def _data_link_build_net_payload(base_payload: object, ownship_data: Dict[str, object], now_ms: int) -> Dict[str, object]:
        payload: Dict[str, object] = {}
        if isinstance(base_payload, dict):
            payload = dict(base_payload)
        payload["schema"] = 1
        payload["updated_unix_ms"] = int(now_ms)
        session_id = str(data_link_state.get("session_id", "")).strip()
        if session_id == "":
            session_id = str(uuid.uuid4())
            data_link_state["session_id"] = session_id
        aircraft_raw = payload.get("aircraft", {})
        aircraft_map: Dict[str, object] = dict(aircraft_raw) if isinstance(aircraft_raw, dict) else {}
        own_copy = dict(ownship_data)
        own_copy["last_seen_unix_ms"] = int(now_ms)
        own_copy["session_id"] = session_id
        aircraft_map[session_id] = own_copy
        # Remove stale aircraft entries to keep nets clean.
        stale_cutoff = int(now_ms) - 15000
        stale_ids: List[str] = []
        for sid, raw in aircraft_map.items():
            if not isinstance(raw, dict):
                stale_ids.append(str(sid))
                continue
            try:
                seen_ms = int(raw.get("last_seen_unix_ms", 0) or 0)
            except Exception:
                seen_ms = 0
            if seen_ms > 0 and seen_ms < stale_cutoff:
                stale_ids.append(str(sid))
        for sid in stale_ids:
            aircraft_map.pop(sid, None)
        payload["aircraft"] = aircraft_map
        missions_blob = _data_link_collect_dim_missions()
        try:
            outbox_ids = missions_blob.get("outbox_ids", []) if isinstance(missions_blob, dict) else []
            if isinstance(outbox_ids, list):
                store = missions_blob.get("store", {}) if isinstance(missions_blob, dict) else {}
                if isinstance(store, dict):
                    for raw_mid in outbox_ids:
                        mid = str(raw_mid).strip()
                        mission = store.get(mid)
                        if isinstance(mission, dict):
                            mission["origin_session_id"] = session_id
                            mission["local"] = "V"
        except Exception:
            pass
        payload["missions"] = missions_blob
        # Shared image map (manifest only): token -> {mime, bytes, name, sha1}
        images_blob: Dict[str, object] = {}
        try:
            existing_images = payload.get("images", {})
            if isinstance(existing_images, dict):
                for token, raw in existing_images.items():
                    key = str(token).strip()
                    if key == "" or not isinstance(raw, dict):
                        continue
                    manifest: Dict[str, object] = {}
                    mime = str(raw.get("mime", "")).strip()
                    if mime != "":
                        manifest["mime"] = mime
                    name = str(raw.get("name", "")).strip()
                    if name != "":
                        manifest["name"] = name
                    sha1 = str(raw.get("sha1", "")).strip().lower()
                    if sha1 != "":
                        manifest["sha1"] = sha1
                    try:
                        size_b = int(raw.get("bytes", 0) or 0)
                    except Exception:
                        size_b = 0
                    if size_b > 0:
                        manifest["bytes"] = int(size_b)
                    if manifest:
                        images_blob[key] = manifest
        except Exception:
            images_blob = {}
        # Include local DIM cached image manifests.
        try:
            cls = getattr(formats, "DimV2Format", None)
            local_images = getattr(cls, "_shared_image_data", {}) if cls is not None else {}
            if isinstance(local_images, dict):
                for token, raw in local_images.items():
                    key = str(token).strip()
                    if key == "" or not isinstance(raw, dict):
                        continue
                    b64 = str(raw.get("data_b64", raw.get("data", raw.get("b64", "")))).strip()
                    raw_bytes: bytes = b""
                    if b64 != "":
                        try:
                            if "," in b64 and b64.lower().startswith("data:"):
                                b64 = b64.split(",", 1)[1].strip()
                            raw_bytes = base64.b64decode(b64, validate=False)
                        except Exception:
                            raw_bytes = b""
                    manifest: Dict[str, object] = {}
                    mime = str(raw.get("mime", "")).strip() or "image/png"
                    manifest["mime"] = mime
                    name = str(raw.get("name", "")).strip()
                    if name != "":
                        manifest["name"] = name
                    if len(raw_bytes) > 0:
                        manifest["bytes"] = int(len(raw_bytes))
                        try:
                            manifest["sha1"] = hashlib.sha1(raw_bytes).hexdigest()
                        except Exception:
                            pass
                    else:
                        try:
                            size_b = int(raw.get("bytes", 0) or 0)
                        except Exception:
                            size_b = 0
                        if size_b > 0:
                            manifest["bytes"] = int(size_b)
                        sha1 = str(raw.get("sha1", "")).strip().lower()
                        if sha1 != "":
                            manifest["sha1"] = sha1
                    images_blob[key] = manifest
        except Exception:
            pass
        # Ensure all referenced mission image tokens have a manifest key.
        try:
            cls = getattr(formats, "DimV2Format", None)
            store = missions_blob.get("store", {}) if isinstance(missions_blob, dict) else {}
            if isinstance(store, dict):
                for _mid, mraw in store.items():
                    if not isinstance(mraw, dict):
                        continue
                    imgs = mraw.get("images", [])
                    if not isinstance(imgs, list):
                        continue
                    for raw_token in imgs:
                        token = str(raw_token).strip()
                        if token == "":
                            continue
                        if token not in images_blob:
                            images_blob[token] = {}
                        # Backward compatibility: if token is a local file path, cache
                        # the raw bytes locally so chunked UDP transfer can publish it.
                        if cls is not None:
                            try:
                                local_images_raw = getattr(cls, "_shared_image_data", {})
                                local_images = local_images_raw if isinstance(local_images_raw, dict) else {}
                                if token not in local_images:
                                    p = Path(token)
                                    if p.exists() and p.is_file():
                                        data = p.read_bytes()
                                        if len(data) > 0:
                                            local_images[token] = {
                                                "mime": "image/png",
                                                "data_b64": base64.b64encode(data).decode("ascii"),
                                                "bytes": int(len(data)),
                                                "name": str(p.name),
                                            }
                                            setattr(cls, "_shared_image_data", local_images)
                            except Exception:
                                pass
        except Exception:
            images_blob = {}
        payload["images"] = images_blob
        try:
            targets_blob: Dict[str, object] = {}
            toi_state = getattr(formats, "TSD_TOI_STATE", {})
            if isinstance(toi_state, dict):
                targets_blob["toi"] = dict(toi_state)
            sim_targets_raw = getattr(formats, "PMD_SIM_TARGETS", [])
            sim_targets: List[Dict[str, object]] = []
            if isinstance(sim_targets_raw, list):
                send_global = bool(getattr(formats, "PMD_SIM_TARGETS_SEND_OVER_DATALINK", False))
                for row in sim_targets_raw:
                    if not isinstance(row, dict):
                        continue
                    if (not send_global) or (not bool(row.get("send_datalink", True))):
                        continue
                    try:
                        sim_targets.append(
                            {
                                "id": str(row.get("id", "")).strip(),
                                "lat": float(row.get("lat")),
                                "lon": float(row.get("lon")),
                                "heading": float(row.get("heading", 0.0) or 0.0),
                                "speed_kts": max(0.0, float(row.get("speed_kts", 0.0) or 0.0)),
                                "affiliation": str(row.get("affiliation", "UNKNOWN")).strip().upper() or "UNKNOWN",
                                "domain": str(row.get("domain", "AIR")).strip().upper() or "AIR",
                                "category": str(row.get("category", "B1")).strip().upper() or "B1",
                                "_link16": True,
                                "_sim": True,
                            }
                        )
                    except Exception:
                        continue
            if len(sim_targets) > 0:
                targets_blob["sim_targets"] = sim_targets
            if len(targets_blob) > 0:
                payload["targets"] = targets_blob
        except Exception:
            pass
        return payload

    def _data_link_payload_sig(net_payload: object) -> str:
        if not isinstance(net_payload, dict):
            return ""
        subset = {
            "missions": net_payload.get("missions", {}),
            "images": net_payload.get("images", {}),
            "targets": net_payload.get("targets", {}),
        }
        try:
            text = json.dumps(subset, sort_keys=True, ensure_ascii=True, separators=(",", ":"))
        except Exception:
            text = str(subset)
        try:
            return hashlib.sha1(text.encode("utf-8", errors="ignore")).hexdigest()
        except Exception:
            return str(abs(hash(text)))

    def _dim_mission_blob_sig(missions_blob: object) -> str:
        if not isinstance(missions_blob, dict):
            return ""
        try:
            text = json.dumps(missions_blob, sort_keys=True, ensure_ascii=True, separators=(",", ":"))
        except Exception:
            text = str(missions_blob)
        try:
            return hashlib.sha1(text.encode("utf-8", errors="ignore")).hexdigest()
        except Exception:
            return str(abs(hash(text)))

    def _dim_mission_blob_counts(missions_blob: object) -> Tuple[int, int, int, int]:
        if not isinstance(missions_blob, dict):
            return (0, 0, 0, 0)
        store = missions_blob.get("store", {})
        store_count = 0
        if isinstance(store, dict):
            for _mid, raw in store.items():
                if isinstance(raw, dict):
                    store_count += 1
        own_raw = missions_blob.get("inbox_own_ids", [])
        flt_raw = missions_blob.get("inbox_flt_ids", [])
        out_raw = missions_blob.get("outbox_ids", [])
        own_count = len([x for x in own_raw if str(x).strip() != ""]) if isinstance(own_raw, list) else 0
        flt_count = len([x for x in flt_raw if str(x).strip() != ""]) if isinstance(flt_raw, list) else 0
        out_count = len([x for x in out_raw if str(x).strip() != ""]) if isinstance(out_raw, list) else 0
        return (store_count, own_count, flt_count, out_count)

    def _udp_relay_local_image_source(token: str) -> Optional[Dict[str, object]]:
        key = str(token).strip()
        if key == "":
            return None
        try:
            cls = getattr(formats, "DimV2Format", None)
            if cls is None:
                return None
            images_raw = getattr(cls, "_shared_image_data", {})
            if not isinstance(images_raw, dict):
                return None
            raw = images_raw.get(key)
            if isinstance(raw, dict):
                return dict(raw)
        except Exception:
            return None
        return None

    def _udp_relay_image_bytes_from_entry(raw: object) -> Tuple[bytes, str, str]:
        return _udp_relay_image_bytes_from_entry_impl(raw)

    def _udp_relay_referenced_image_tokens(net_payload: object) -> List[str]:
        return _udp_relay_referenced_image_tokens_impl(net_payload)

    def _udp_relay_refresh_image_tx_tokens(net_payload: object, now_ms: int) -> None:
        nonlocal udp_relay_img_tx_refresh_ms
        if int(now_ms) < int(udp_relay_img_tx_refresh_ms):
            return
        udp_relay_img_tx_refresh_ms = int(now_ms) + 1500
        wanted_tokens = _udp_relay_referenced_image_tokens(net_payload)
        wanted_set = set(wanted_tokens)
        for tk in list(udp_relay_img_tx_state.keys()):
            if tk not in wanted_set:
                udp_relay_img_tx_state.pop(tk, None)
        chunk_raw = max(600, int(udp_relay_img_chunk_raw_bytes))
        for token in wanted_tokens:
            src = _udp_relay_local_image_source(token)
            if not isinstance(src, dict):
                continue
            raw_bytes, mime, name = _udp_relay_image_bytes_from_entry(src)
            if len(raw_bytes) <= 0:
                continue
            try:
                sha1 = hashlib.sha1(raw_bytes).hexdigest()
            except Exception:
                sha1 = ""
            existing = udp_relay_img_tx_state.get(token, {})
            if isinstance(existing, dict):
                same = (
                    str(existing.get("sha1", "")).strip().lower() == str(sha1).strip().lower()
                    and int(existing.get("bytes", -1) or -1) == int(len(raw_bytes))
                )
                if same:
                    continue
            chunks: List[str] = []
            for start in range(0, len(raw_bytes), chunk_raw):
                piece = raw_bytes[start : start + chunk_raw]
                if piece:
                    chunks.append(base64.b64encode(piece).decode("ascii"))
            if not chunks:
                continue
            udp_relay_img_tx_state[token] = {
                "token": token,
                "mime": mime,
                "name": name,
                "sha1": sha1,
                "bytes": int(len(raw_bytes)),
                "chunks": chunks,
                "chunk_count": int(len(chunks)),
                "phase": "start",
                "next_idx": 0,
                "next_send_ms": int(now_ms),
                "last_round_ms": 0,
            }

    def _udp_relay_pump_image_tx(net_key: str, net_payload: object, now_ms: int) -> None:
        nonlocal udp_relay_img_tx_next_ms
        if not udp_relay_enabled:
            return
        joined = str(net_key).strip().upper()
        if joined == "":
            return
        if int(now_ms) < int(udp_relay_img_tx_next_ms):
            return
        _udp_relay_refresh_image_tx_tokens(net_payload, now_ms)
        resend_ms = 2500
        sent = 0
        for token in sorted(list(udp_relay_img_tx_state.keys())):
            if sent >= 8:
                break
            entry_raw = udp_relay_img_tx_state.get(token, {})
            if not isinstance(entry_raw, dict):
                continue
            phase = str(entry_raw.get("phase", "idle")).strip().lower() or "idle"
            try:
                next_send_ms = int(entry_raw.get("next_send_ms", 0) or 0)
            except Exception:
                next_send_ms = 0
            if int(now_ms) < next_send_ms:
                continue
            if phase == "idle":
                try:
                    last_round = int(entry_raw.get("last_round_ms", 0) or 0)
                except Exception:
                    last_round = 0
                if last_round > 0 and (int(now_ms) - last_round) < resend_ms:
                    continue
                entry_raw["phase"] = "start"
                entry_raw["next_idx"] = 0
                phase = "start"
            img_id = str(entry_raw.get("token", token)).strip()
            if img_id == "":
                continue
            mime = str(entry_raw.get("mime", "image/png")).strip() or "image/png"
            name = str(entry_raw.get("name", "")).strip()
            sha1 = str(entry_raw.get("sha1", "")).strip().lower()
            try:
                size_b = int(entry_raw.get("bytes", 0) or 0)
            except Exception:
                size_b = 0
            try:
                chunk_count = int(entry_raw.get("chunk_count", 0) or 0)
            except Exception:
                chunk_count = 0
            chunks = entry_raw.get("chunks", [])
            if not isinstance(chunks, list) or chunk_count <= 0:
                continue
            sent_ok = False
            if phase == "start":
                sent_ok = _udp_relay_send_packet(
                    {
                        "type": "dl_img_start",
                        "net_key": joined,
                        "image_id": img_id,
                        "mime": mime,
                        "name": name,
                        "bytes": int(size_b),
                        "sha1": sha1,
                        "chunks": int(chunk_count),
                    }
                )
                if sent_ok:
                    entry_raw["phase"] = "chunks"
                    entry_raw["next_idx"] = 0
            elif phase == "chunks":
                try:
                    next_idx = int(entry_raw.get("next_idx", 0) or 0)
                except Exception:
                    next_idx = 0
                if next_idx >= chunk_count:
                    entry_raw["phase"] = "end"
                    phase = "end"
                else:
                    data_b64 = str(chunks[next_idx]).strip()
                    if data_b64 != "":
                        sent_ok = _udp_relay_send_packet(
                            {
                                "type": "dl_img_chunk",
                                "net_key": joined,
                                "image_id": img_id,
                                "index": int(next_idx),
                                "data": data_b64,
                            }
                        )
                    if sent_ok:
                        entry_raw["next_idx"] = int(next_idx) + 1
                        if int(entry_raw.get("next_idx", 0) or 0) >= chunk_count:
                            entry_raw["phase"] = "end"
            if phase == "end":
                sent_ok = _udp_relay_send_packet(
                    {
                        "type": "dl_img_end",
                        "net_key": joined,
                        "image_id": img_id,
                        "sha1": sha1,
                        "chunks": int(chunk_count),
                    }
                )
                if sent_ok:
                    entry_raw["phase"] = "idle"
                    entry_raw["last_round_ms"] = int(now_ms)
            if sent_ok:
                sent += 1
                entry_raw["next_send_ms"] = int(now_ms) + 2
            else:
                entry_raw["next_send_ms"] = int(now_ms) + 40
                try:
                    print(f"[DIM][IMG_TX_RETRY] token={img_id} phase={str(entry_raw.get('phase', '-'))}")
                except Exception:
                    pass
            udp_relay_img_tx_state[token] = entry_raw
        udp_relay_img_tx_next_ms = int(now_ms) + (2 if sent > 0 else 15)

    def _udp_relay_store_received_image(token: str, mime: str, raw_bytes: bytes, name: str = "") -> None:
        key = str(token).strip()
        if key == "" or len(raw_bytes) <= 0:
            return
        try:
            cls = getattr(formats, "DimV2Format", None)
            if cls is None:
                return
            images_raw = getattr(cls, "_shared_image_data", {})
            images_map = dict(images_raw) if isinstance(images_raw, dict) else {}
            images_map[key] = {
                "mime": str(mime).strip() or "image/png",
                "data_b64": base64.b64encode(raw_bytes).decode("ascii"),
                "bytes": int(len(raw_bytes)),
                "name": str(name).strip(),
                "sha1": hashlib.sha1(raw_bytes).hexdigest(),
            }
            setattr(cls, "_shared_image_data", images_map)
            try:
                print(f"[DIM][IMG_RX] token={key} bytes={int(len(raw_bytes))} name={str(name).strip() or '-'}")
            except Exception:
                pass
        except Exception:
            return

    def _udp_relay_handle_image_packet(msg: Dict[str, object], sender_id: str, now_ms: int) -> bool:
        joined = _udp_relay_joined_net_key()
        if joined == "":
            return True
        net_key = str(msg.get("net_key", "")).strip().upper()
        if net_key == "" or net_key != joined:
            return True
        mtype = str(msg.get("type", "")).strip().lower()
        image_id = str(msg.get("image_id", msg.get("token", ""))).strip()
        if image_id == "":
            return True
        rx_key = f"{str(sender_id).strip()}::{image_id}"
        if mtype == "dl_img_start":
            try:
                chunk_count = int(msg.get("chunks", 0) or 0)
            except Exception:
                chunk_count = 0
            try:
                total_b = int(msg.get("bytes", 0) or 0)
            except Exception:
                total_b = 0
            new_sha1 = str(msg.get("sha1", "")).strip().lower()
            existing = udp_relay_img_rx_state.get(rx_key)
            if isinstance(existing, dict):
                old_sha1 = str(existing.get("sha1", "")).strip().lower()
                try:
                    old_expected = int(existing.get("chunks_expected", 0) or 0)
                except Exception:
                    old_expected = 0
                same_stream = (
                    old_sha1 != ""
                    and new_sha1 != ""
                    and old_sha1 == new_sha1
                    and int(old_expected) == int(max(0, int(chunk_count)))
                )
                if same_stream:
                    existing["last_ms"] = int(now_ms)
                    udp_relay_img_rx_state[rx_key] = existing
                    return True
            udp_relay_img_rx_state[rx_key] = {
                "token": image_id,
                "mime": str(msg.get("mime", "image/png")).strip() or "image/png",
                "name": str(msg.get("name", "")).strip(),
                "sha1": new_sha1,
                "chunks_expected": max(0, int(chunk_count)),
                "bytes_expected": max(0, int(total_b)),
                "chunks": {},
                "started_ms": int(now_ms),
                "last_ms": int(now_ms),
            }
            return True
        if mtype == "dl_img_chunk":
            row = udp_relay_img_rx_state.get(rx_key)
            if not isinstance(row, dict):
                row = {
                    "token": image_id,
                    "mime": "image/png",
                    "name": "",
                    "sha1": "",
                    "chunks_expected": 0,
                    "bytes_expected": 0,
                    "chunks": {},
                    "started_ms": int(now_ms),
                    "last_ms": int(now_ms),
                }
            chunks_raw = row.get("chunks", {})
            chunks = chunks_raw if isinstance(chunks_raw, dict) else {}
            try:
                idx = int(msg.get("index", 0) or 0)
            except Exception:
                idx = 0
            data_b64 = str(msg.get("data", "")).strip()
            if data_b64 == "":
                return True
            try:
                chunks[int(idx)] = base64.b64decode(data_b64, validate=False)
            except Exception:
                return True
            row["chunks"] = chunks
            row["last_ms"] = int(now_ms)
            udp_relay_img_rx_state[rx_key] = row
            return True
        if mtype == "dl_img_end":
            row = udp_relay_img_rx_state.get(rx_key)
            if not isinstance(row, dict):
                return True
            chunks_raw = row.get("chunks", {})
            chunks = chunks_raw if isinstance(chunks_raw, dict) else {}
            try:
                expected = int(msg.get("chunks", row.get("chunks_expected", 0)) or 0)
            except Exception:
                expected = 0
            if expected <= 0:
                expected = max(chunks.keys(), default=-1) + 1
            if expected <= 0:
                udp_relay_img_rx_state.pop(rx_key, None)
                return True
            if len(chunks) < expected:
                row["last_ms"] = int(now_ms)
                udp_relay_img_rx_state[rx_key] = row
                try:
                    print(f"[DIM][IMG_RX_PROGRESS] token={image_id} chunks={len(chunks)}/{expected}")
                except Exception:
                    pass
                return True
            data = bytearray()
            for i in range(expected):
                part = chunks.get(i)
                if not isinstance(part, (bytes, bytearray)):
                    return True
                data.extend(part)
            raw_bytes = bytes(data)
            try:
                bytes_expected = int(row.get("bytes_expected", 0) or 0)
            except Exception:
                bytes_expected = 0
            if bytes_expected > 0 and len(raw_bytes) != bytes_expected:
                return True
            sha1_expected = str(row.get("sha1", msg.get("sha1", ""))).strip().lower()
            if sha1_expected != "":
                try:
                    if hashlib.sha1(raw_bytes).hexdigest() != sha1_expected:
                        return True
                except Exception:
                    return True
            _udp_relay_store_received_image(
                str(row.get("token", image_id)),
                str(row.get("mime", "image/png")),
                raw_bytes,
                str(row.get("name", "")),
            )
            udp_relay_img_rx_state.pop(rx_key, None)
            return True
        return False

    def _udp_relay_cleanup_image_rx(now_ms: int) -> None:
        stale: List[str] = []
        for key, row in udp_relay_img_rx_state.items():
            if not isinstance(row, dict):
                stale.append(key)
                continue
            try:
                last_ms = int(row.get("last_ms", row.get("started_ms", 0)) or 0)
            except Exception:
                last_ms = 0
            if last_ms <= 0 or (int(now_ms) - last_ms) > int(udp_relay_img_rx_timeout_ms):
                stale.append(key)
        for key in stale:
            udp_relay_img_rx_state.pop(key, None)

    def _udp_relay_pack_datalink_payload_blob(payload: object) -> Tuple[Dict[str, object], bool]:
        return _udp_relay_pack_datalink_payload_blob_impl(payload)

    def _udp_relay_unpack_datalink_payload_blob(dl_obj: object) -> Dict[str, object]:
        return _udp_relay_unpack_datalink_payload_blob_impl(dl_obj)

    def _udp_relay_send_packet(packet: Dict[str, object]) -> bool:
        if not udp_relay_enabled or udp_relay_sock is None:
            return False
        if not isinstance(packet, dict):
            return False
        out = dict(packet)
        out["callsign"] = str(_data_link_runtime_value("callsign")).strip().upper() or "UNKNOWN"
        out["session"] = str(udp_relay_session).strip() or "F35_PCD_GLOBAL"
        out["client_id"] = str(udp_relay_client_id).strip()
        try:
            payload = json.dumps(out, separators=(",", ":"), ensure_ascii=True).encode("utf-8")
        except Exception:
            return False
        if len(payload) > 7600:
            try:
                ptype = str(packet.get("type", "")).strip().lower()
                print(f"[UDP][TX_DROP] type={ptype if ptype != '' else '-'} oversized={len(payload)} bytes")
            except Exception:
                pass
            return False
        try:
            udp_relay_sock.sendto(payload, (udp_relay_server_ip, int(udp_relay_server_port)))
            return True
        except Exception:
            return False

    def _udp_relay_send_heartbeat(now_ms: int) -> None:
        nonlocal udp_relay_last_hb_send_ms, udp_relay_hb_nonce
        if not udp_relay_enabled:
            return
        if int(now_ms) < int(udp_relay_last_hb_send_ms) + int(udp_relay_hb_interval_ms):
            return
        udp_relay_hb_nonce = int(udp_relay_hb_nonce) + 1
        pkt = {
            "type": "hb_ping",
            "nonce": int(udp_relay_hb_nonce),
            "time": time.time(),
        }
        if _udp_relay_send_packet(pkt):
            udp_relay_last_hb_send_ms = int(now_ms)

    def _udp_relay_joined_net_key() -> str:
        joined = str(data_link_state.get("entry_id", "")).strip().upper()
        return joined

    def _udp_relay_comm_net_key() -> str:
        # For secure voice, allow either actively joined net or the currently
        # configured NET KEY field (without requiring datalink join state).
        joined = _udp_relay_joined_net_key()
        if joined != "":
            return joined
        configured = str(data_link_state.get("net_key_value", "")).strip().upper()
        return configured

    def _udp_relay_radio_secure(radio: str) -> bool:
        prof = _comm_profile_for(str(radio).strip().lower())
        return bool(prof.get("secure_on", False))

    comm_audio_debug_lock = threading.Lock()
    comm_audio_debug_state: Dict[str, object] = {
        "next_flush_ms": 0,
        "rows": {},
    }

    def _comm_audio_debug_event(kind: str, radio: str, bytes_len: int = 0, detail: str = "") -> None:
        try:
            now_ms = int(time.monotonic() * 1000)
        except Exception:
            now_ms = 0
        key = f"{str(kind).strip().upper()}|{str(radio).strip().lower()}"
        try:
            with comm_audio_debug_lock:
                rows_raw = comm_audio_debug_state.get("rows", {})
                rows = rows_raw if isinstance(rows_raw, dict) else {}
                row_raw = rows.get(key, {})
                row = row_raw if isinstance(row_raw, dict) else {}
                row["kind"] = str(kind).strip().upper()
                row["radio"] = str(radio).strip().lower()
                row["count"] = int(row.get("count", 0) or 0) + 1
                row["bytes"] = int(row.get("bytes", 0) or 0) + max(0, int(bytes_len))
                if str(detail).strip() != "":
                    row["detail"] = str(detail).strip()
                rows[key] = row
                comm_audio_debug_state["rows"] = rows
                try:
                    next_flush_ms = int(comm_audio_debug_state.get("next_flush_ms", 0) or 0)
                except Exception:
                    next_flush_ms = 0
                if now_ms < next_flush_ms:
                    return
                comm_audio_debug_state["next_flush_ms"] = now_ms + 1000
                for _k, data_raw in list(rows.items()):
                    if not isinstance(data_raw, dict):
                        continue
                    kind_txt = str(data_raw.get("kind", "")).strip().upper()
                    radio_txt = str(data_raw.get("radio", "")).strip().lower()
                    count = int(data_raw.get("count", 0) or 0)
                    total_bytes = int(data_raw.get("bytes", 0) or 0)
                    detail_txt = str(data_raw.get("detail", "")).strip()
                    if detail_txt != "":
                        print(f"[COMM AUDIO][{kind_txt}] {radio_txt} chunks={count} bytes={total_bytes} {detail_txt}")
                    else:
                        print(f"[COMM AUDIO][{kind_txt}] {radio_txt} chunks={count} bytes={total_bytes}")
                comm_audio_debug_state["rows"] = {}
        except Exception:
            pass

    def _udp_relay_poll_incoming(now_ms: int, accept_state: bool = True) -> None:
        nonlocal udp_relay_last_hb_recv_ms
        if not udp_relay_enabled or udp_relay_sock is None:
            return
        max_msgs = 96
        for _ in range(max_msgs):
            try:
                raw, _addr = udp_relay_sock.recvfrom(8192)
            except BlockingIOError:
                break
            except Exception:
                break
            try:
                msg = json.loads(raw.decode("utf-8", errors="ignore"))
            except Exception:
                continue
            if not isinstance(msg, dict):
                continue
            mtype = str(msg.get("type", "")).strip().lower()
            if mtype in {"hb_pong", "relay_hb"}:
                udp_relay_last_hb_recv_ms = int(now_ms)
                continue
            sender_id = str(msg.get("client_id", "")).strip()
            if sender_id == "" or sender_id == udp_relay_client_id:
                continue
            if mtype == "state":
                if not bool(accept_state):
                    continue
                rec = dict(msg)
                try:
                    dl_obj = rec.get("datalink", {})
                    if isinstance(dl_obj, dict):
                        unpacked = _udp_relay_unpack_datalink_payload_blob(dl_obj)
                        if isinstance(unpacked, dict) and len(unpacked) > 0:
                            dl_obj["payload"] = unpacked
                            rec["datalink"] = dl_obj
                except Exception:
                    pass
                # Preserve last known datalink payload when sender publishes a
                # lightweight state tick with empty payload.
                try:
                    prev = udp_relay_peers.get(sender_id, {})
                    prev_dl = prev.get("datalink", {}) if isinstance(prev, dict) else {}
                    prev_payload = prev_dl.get("payload", {}) if isinstance(prev_dl, dict) else {}
                    dl = rec.get("datalink", {})
                    if not isinstance(dl, dict):
                        dl = {}
                    new_payload = dl.get("payload", {})
                    if (not isinstance(new_payload, dict)) or len(new_payload) <= 0:
                        if isinstance(prev_payload, dict) and len(prev_payload) > 0:
                            dl["payload"] = dict(prev_payload)
                            rec["datalink"] = dl
                except Exception:
                    pass
                try:
                    dl_dbg = rec.get("datalink", {})
                    if isinstance(dl_dbg, dict):
                        pl_dbg = dl_dbg.get("payload", {})
                        ms_dbg = pl_dbg.get("missions", {}) if isinstance(pl_dbg, dict) else {}
                        ms_sig = _dim_mission_blob_sig(ms_dbg)
                        old_sig = str(dim_peer_debug_sigs.get(sender_id, "")).strip()
                        if ms_sig != old_sig:
                            m_store, m_own, m_flt, m_out = _dim_mission_blob_counts(ms_dbg)
                            print(
                                f"[DIM][PEER_STATE] from={sender_id[:8]} net={str(dl_dbg.get('net_key', '')).strip().upper() or '-'} "
                                f"store={m_store} own={m_own} flt={m_flt} out={m_out}"
                            )
                            dim_peer_debug_sigs[sender_id] = ms_sig
                except Exception:
                    pass
                rec["_last_seen_ms"] = int(now_ms)
                udp_relay_peers[sender_id] = rec
                continue
            if mtype in {"dl_img_start", "dl_img_chunk", "dl_img_end"}:
                _udp_relay_handle_image_packet(msg, sender_id, now_ms)
                continue
            if mtype != "voice":
                continue
            radio = str(msg.get("radio", "")).strip().lower()
            freq = str(msg.get("freq", "")).strip()
            payload = str(msg.get("audio", msg.get("payload", ""))).strip()
            if radio not in {"coma", "comb", "comc"} or payload == "" or freq == "":
                continue
            try:
                chunk = base64.b64decode(payload)
            except Exception:
                continue
            if not chunk:
                continue
            remote_secure = bool(msg.get("secure", False))
            remote_net = str(msg.get("net_key", "")).strip().upper()
            local_net = _udp_relay_comm_net_key()
            _comm_audio_debug_event(
                "RX_PKT",
                radio,
                len(chunk),
                f"freq={freq} secure={'1' if remote_secure else '0'} net={remote_net if remote_net != '' else '-'}",
            )
            matched: List[str] = []
            drop_reason = "no local radio match"
            for local_radio in ("coma", "comb", "comc"):
                if not bool(comm_state.get(f"{local_radio}_on", False)):
                    drop_reason = f"{local_radio}:off"
                    continue
                local_freq = str(comm_state.get(f"{local_radio}_freq", "")).strip()
                if local_freq == "" or local_freq != freq:
                    drop_reason = f"{local_radio}:freq_mismatch"
                    continue
                local_secure = _udp_relay_radio_secure(local_radio)
                if local_secure != remote_secure:
                    drop_reason = f"{local_radio}:secure_mismatch local={1 if local_secure else 0} remote={1 if remote_secure else 0}"
                    continue
                if local_secure and remote_secure:
                    if local_net == "" or remote_net == "" or local_net != remote_net:
                        drop_reason = f"{local_radio}:net_mismatch local={local_net if local_net != '' else '-'} remote={remote_net if remote_net != '' else '-'}"
                        continue
                matched.append(local_radio)
            if not matched:
                _comm_audio_debug_event("RX_DROP", radio, len(chunk), drop_reason)
                continue
            rx_gain = 0.0
            for lr in matched:
                try:
                    rx_gain = max(float(rx_gain), float(_comm_rx_gain_for_radio(lr)))
                except Exception:
                    continue
            out_chunk = _comm_apply_rx_gain(chunk, rx_gain)
            if rx_gain <= 0.0001:
                _comm_audio_debug_event("RX_DROP", ",".join(matched), len(chunk), "muted_or_zero_volume")
            else:
                _comm_audio_debug_event("RX_OK", ",".join(matched), len(chunk), f"freq={freq} gain={rx_gain:.2f}")
                if len(audio_output_chunks) >= audio_output_chunks.maxlen:
                    audio_output_chunks.popleft()
                audio_output_chunks.append(out_chunk)
            with frame_state.audio_lock:
                if len(frame_state.audio_rx_queue) >= frame_state.audio_rx_queue.maxlen:
                    frame_state.audio_rx_queue.popleft()
                payload_out = payload
                try:
                    if out_chunk != chunk:
                        payload_out = base64.b64encode(out_chunk).decode("ascii")
                except Exception:
                    payload_out = payload
                frame_state.audio_rx_queue.append({"radio": matched[0], "sample_rate": int(msg.get("rate", msg.get("sample_rate", audio_sample_rate)) or audio_sample_rate), "payload": payload_out})
            rx_until = comm_state.get("rx_until")
            if not isinstance(rx_until, dict):
                rx_until = {"coma": 0, "comb": 0, "comc": 0}
                comm_state["rx_until"] = rx_until
            for lr in matched:
                rx_until[lr] = max(int(rx_until.get(lr, 0) or 0), int(now_ms) + 900)

    def _udp_relay_cleanup_peers(now_ms: int) -> None:
        stale: List[str] = []
        for sid, row in udp_relay_peers.items():
            if not isinstance(row, dict):
                stale.append(sid)
                continue
            try:
                seen = int(row.get("_last_seen_ms", 0) or 0)
            except Exception:
                seen = 0
            if seen <= 0 or (int(now_ms) - seen) > int(udp_relay_timeout_ms):
                stale.append(sid)
        for sid in stale:
            udp_relay_peers.pop(sid, None)

    def _udp_relay_send_state(now_ms: int) -> None:
        nonlocal udp_relay_last_state_ms, udp_relay_last_payload_ms, udp_relay_last_payload_sig
        if not udp_relay_enabled:
            return
        net_key = _udp_relay_joined_net_key()
        if net_key == "":
            return
        if int(now_ms) < int(udp_relay_last_state_ms) + 250:
            return
        ownship_data = _data_link_build_ownship_table()
        comm_payload = {
            "coma_on": bool(comm_state.get("coma_on", False)),
            "comb_on": bool(comm_state.get("comb_on", False)),
            "comc_on": bool(comm_state.get("comc_on", False)),
            "coma_freq": str(comm_state.get("coma_freq", "000.000")),
            "comb_freq": str(comm_state.get("comb_freq", "000.000")),
            "comc_freq": str(comm_state.get("comc_freq", "000.000")),
            "coma_secure": bool(_udp_relay_radio_secure("coma")),
            "comb_secure": bool(_udp_relay_radio_secure("comb")),
            "comc_secure": bool(_udp_relay_radio_secure("comc")),
            "ptt": str(comm_state.get("ptt_radio", "") or "").strip().lower(),
        }
        payload_blob: Dict[str, object] = {}
        payload_transport: Dict[str, object] = {"payload": {}}
        payload_compressed = False
        if net_key != "":
            refresh_due = int(now_ms) >= int(udp_relay_last_payload_ms) + 1200
            candidate_payload = _data_link_build_net_payload(data_link_net_payload_cache.get(net_key, {}), ownship_data, int(time.time() * 1000))
            candidate_sig = _data_link_payload_sig(candidate_payload)
            try:
                missions_dbg = candidate_payload.get("missions", {}) if isinstance(candidate_payload, dict) else {}
                m_store, m_own, m_flt, m_out = _dim_mission_blob_counts(missions_dbg)
                tx_m_sig = _dim_mission_blob_sig(missions_dbg)
                last_tx_sig = str(dim_debug_state.get("tx_sig", "")).strip()
                next_tx_ms = int(dim_debug_state.get("next_tx_ms", 0) or 0)
                if tx_m_sig != last_tx_sig or int(now_ms) >= next_tx_ms:
                    print(
                        f"[DIM][TX] net={net_key if net_key != '' else '-'} store={m_store} own={m_own} flt={m_flt} out={m_out} "
                        f"payload={'full' if (refresh_due or candidate_sig != str(udp_relay_last_payload_sig)) else 'tick'}"
                    )
                    dim_debug_state["tx_sig"] = tx_m_sig
                    dim_debug_state["next_tx_ms"] = int(now_ms) + 3000
            except Exception:
                pass
            if refresh_due or candidate_sig != str(udp_relay_last_payload_sig):
                payload_blob = candidate_payload
                udp_relay_last_payload_ms = int(now_ms)
                udp_relay_last_payload_sig = str(candidate_sig)
                data_link_net_payload_cache[net_key] = dict(payload_blob)
                meta = data_link_net_meta.get(net_key, {})
                if not isinstance(meta, dict):
                    meta = {}
                now_unix_ms = int(time.time() * 1000)
                meta["last_payload_ms"] = max(int(meta.get("last_payload_ms", 0) or 0), int(now_unix_ms))
                meta["last_active_ms"] = max(int(meta.get("last_active_ms", 0) or 0), int(now_unix_ms))
                data_link_net_meta[net_key] = meta
        try:
            payload_transport, payload_compressed = _udp_relay_pack_datalink_payload_blob(payload_blob)
        except Exception:
            payload_transport, payload_compressed = ({"payload": payload_blob if isinstance(payload_blob, dict) else {}}, False)
        pkt = {
            "type": "state",
            "time": time.time(),
            "aircraft": ownship_data,
            "comm": comm_payload,
            "datalink": {
                "joined": bool(net_key != ""),
                "net_key": net_key,
                **payload_transport,
            },
        }
        sent_ok = _udp_relay_send_packet(pkt)
        if (not sent_ok) and isinstance(pkt.get("datalink", {}), dict):
            # Fallback to a lightweight tick if a full payload packet is too large.
            dl_light = dict(pkt.get("datalink", {}))
            dl_light["payload"] = {}
            dl_light.pop("payload_z", None)
            dl_light.pop("payload_codec", None)
            dl_light.pop("payload_raw_bytes", None)
            lite_pkt = dict(pkt)
            lite_pkt["datalink"] = dl_light
            if _udp_relay_send_packet(lite_pkt):
                try:
                    if bool(payload_compressed):
                        print("[UDP][STATE_TX] fallback=tick_after_oversize payload=compressed")
                    else:
                        print("[UDP][STATE_TX] fallback=tick_after_oversize payload=raw")
                except Exception:
                    pass
        udp_relay_last_state_ms = int(now_ms)

    def _udp_relay_send_voice(radio: str, payload_b64: str, sample_rate_hz: int) -> None:
        if not udp_relay_enabled:
            return
        rr = str(radio).strip().lower()
        if rr not in {"coma", "comb", "comc"}:
            return
        freq = str(comm_state.get(f"{rr}_freq", "")).strip()
        if freq == "":
            return
        try:
            b_est = max(0, int((len(str(payload_b64)) * 3) // 4))
        except Exception:
            b_est = 0
        _comm_audio_debug_event(
            "TX_REQ",
            rr,
            b_est,
            f"freq={freq} secure={'1' if _udp_relay_radio_secure(rr) else '0'} net={_udp_relay_comm_net_key() if _udp_relay_comm_net_key() != '' else '-'}",
        )
        _udp_relay_send_packet(
            {
                "type": "voice",
                "radio": rr,
                "freq": freq,
                "secure": bool(_udp_relay_radio_secure(rr)),
                "net_key": _udp_relay_comm_net_key(),
                "rate": int(sample_rate_hz),
                "channels": 1,
                "format": "pcm_s16le",
                "audio": str(payload_b64),
            }
        )

    def _udp_relay_debug_status(now_ms: int) -> None:
        nonlocal udp_relay_hb_state, udp_relay_hb_next_log_ms
        if not udp_relay_enabled:
            data_link_state["relay_hb_ok"] = False
            data_link_state["relay_hb_last_ms"] = 0
            data_link_state["relay_hb_state"] = "DISABLED"
            return
        last_rx = int(udp_relay_last_hb_recv_ms or 0)
        if last_rx <= 0:
            state = "WAITING"
            hb_ok = False
            age_ms = 0
        else:
            age_ms = max(0, int(now_ms) - int(last_rx))
            hb_ok = age_ms <= int(udp_relay_hb_timeout_ms)
            state = "OK" if hb_ok else "TIMEOUT"
        data_link_state["relay_hb_ok"] = bool(hb_ok)
        data_link_state["relay_hb_last_ms"] = int(last_rx)
        data_link_state["relay_hb_state"] = str(state)
        if str(state) != str(udp_relay_hb_state):
            udp_relay_hb_state = str(state)
            if int(now_ms) >= int(udp_relay_hb_next_log_ms):
                if state == "TIMEOUT":
                    print("[UDP][HEARTBEAT] timeout: no relay pulse (relay down or inbound blocked)")
                elif state == "OK":
                    print("[UDP][HEARTBEAT] relay pulse restored")
                elif state == "WAITING":
                    print("[UDP][HEARTBEAT] waiting for relay pulse")
                udp_relay_hb_next_log_ms = int(now_ms) + 3000

    def _data_link_publish_remote_contacts() -> None:
        contacts_raw = data_link_state.get("remote_contacts", [])
        contacts = contacts_raw if isinstance(contacts_raw, list) else []
        merged: List[Dict[str, object]] = []
        if isinstance(contacts, list):
            for row in contacts:
                if isinstance(row, dict):
                    merged.append(dict(row))
        try:
            setattr(formats, "TSD_LINK16_CONTACTS", list(merged))
        except Exception:
            pass

    def _data_link_realtime_ws_url() -> str:
        base = _supabase_url()
        key = _supabase_api_key()
        if base == "" or key == "":
            return ""
        parsed = urllib_parse.urlparse(base)
        if parsed.scheme not in {"http", "https"} or parsed.netloc == "":
            return ""
        ws_scheme = "wss" if parsed.scheme == "https" else "ws"
        apikey = urllib_parse.quote(key, safe="")
        return f"{ws_scheme}://{parsed.netloc}/realtime/v1/websocket?apikey={apikey}&vsn=1.0.0"

    def _data_link_realtime_worker() -> None:
        warned_no_ws = False
        while not data_link_realtime_stop_event.is_set():
            ws_url = _data_link_realtime_ws_url()
            table = _supabase_table_name()
            if ws_url == "" or table == "":
                data_link_realtime_stop_event.wait(2.0)
                continue
            if websocket_client is None:
                if not warned_no_ws:
                    print("[DATALINK] Realtime disabled: websocket-client module not installed.")
                    warned_no_ws = True
                data_link_realtime_stop_event.wait(5.0)
                continue
            ws = None
            try:
                ws = websocket_client.create_connection(ws_url, timeout=10)  # type: ignore[attr-defined]
                topic = f"realtime:public:{table}"
                ws.send(
                    json.dumps(
                        {
                            "topic": topic,
                            "event": "phx_join",
                            "payload": {
                                "config": {
                                    "broadcast": {"self": False},
                                    "presence": {"key": ""},
                                    "postgres_changes": [{"event": "*", "schema": "public", "table": table}],
                                }
                            },
                            "ref": "1",
                        },
                        separators=(",", ":"),
                    )
                )
                data_link_state["realtime_connected"] = True
                data_link_realtime_refresh_event.set()
                hb_ref = 2
                next_heartbeat = time.time() + 20.0
                while not data_link_realtime_stop_event.is_set():
                    now_s = time.time()
                    if now_s >= next_heartbeat:
                        ws.send(
                            json.dumps(
                                {
                                    "topic": "phoenix",
                                    "event": "heartbeat",
                                    "payload": {},
                                    "ref": str(hb_ref),
                                },
                                separators=(",", ":"),
                            )
                        )
                        hb_ref += 1
                        next_heartbeat = now_s + 20.0
                    try:
                        ws.settimeout(0.25)
                        raw_msg = ws.recv()
                    except Exception as exc:
                        text = str(exc).lower()
                        if "timed out" in text or "timeout" in text:
                            continue
                        raise
                    if not isinstance(raw_msg, str) or raw_msg.strip() == "":
                        continue
                    try:
                        msg = json.loads(raw_msg)
                    except Exception:
                        continue
                    if not isinstance(msg, dict):
                        continue
                    event_name = str(msg.get("event", "")).strip().lower()
                    if event_name in {"postgres_changes", "broadcast"}:
                        data_link_realtime_refresh_event.set()
                        continue
                    if event_name == "system":
                        payload = msg.get("payload", {})
                        if isinstance(payload, dict) and str(payload.get("status", "")).strip().lower() == "ok":
                            data_link_realtime_refresh_event.set()
            except Exception as exc:
                data_link_state["realtime_connected"] = False
                print(f"[DATALINK] Realtime reconnect: {exc}")
                data_link_realtime_stop_event.wait(2.0)
            finally:
                data_link_state["realtime_connected"] = False
                if ws is not None:
                    try:
                        ws.close()
                    except Exception:
                        pass

    def _data_link_start_api_request(kind: str, payload: Dict[str, object]) -> bool:
        req_kind = str(kind).strip().lower()
        if req_kind == "":
            return False
        with data_link_api_lock:
            if bool(data_link_api_runtime.get("inflight", False)):
                return False
            data_link_api_runtime["inflight"] = True
            data_link_api_runtime["kind"] = req_kind
            data_link_api_runtime["pending"] = None
        should_log_dispatch = bool(payload.get("_log_io", req_kind in {"create", "delete"}))
        if should_log_dispatch:
            try:
                debug_payload = dict(payload)
                if "key" in debug_payload:
                    raw_key = str(debug_payload.get("key", "")).strip()
                    if len(raw_key) > 8:
                        debug_payload["key"] = f"{raw_key[:4]}...{raw_key[-4:]}"
                    elif raw_key != "":
                        debug_payload["key"] = "***"
                if "value" in debug_payload:
                    raw_val = str(debug_payload.get("value", ""))
                    if len(raw_val) > 400:
                        debug_payload["value"] = f"{raw_val[:200]}...<{len(raw_val)} chars>...{raw_val[-120:]}"
                if "net_payload" in debug_payload:
                    raw_val = str(debug_payload.get("net_payload", ""))
                    if len(raw_val) > 500:
                        debug_payload["net_payload"] = f"{raw_val[:240]}...<{len(raw_val)} chars>...{raw_val[-120:]}"
                print(f"[DATALINK] DISPATCH {req_kind.upper()} {json.dumps(debug_payload, ensure_ascii=True)}")
            except Exception:
                print(f"[DATALINK] DISPATCH {req_kind.upper()} <payload unavailable>")

        def _worker() -> None:
            resp, err = _data_link_api_request(req_kind, payload, timeout_s=8.0)
            with data_link_api_lock:
                data_link_api_runtime["inflight"] = False
                data_link_api_runtime["kind"] = ""
                data_link_api_runtime["pending"] = {
                    "kind": req_kind,
                    "resp": resp,
                    "err": err,
                }

        threading.Thread(target=_worker, name=f"DataLink-{req_kind}", daemon=True).start()
        return True

    def _data_link_process_api_response(now_ms: int) -> None:
        pending = None
        with data_link_api_lock:
            pending = data_link_api_runtime.get("pending")
            data_link_api_runtime["pending"] = None
        if not isinstance(pending, dict):
            return
        kind = str(pending.get("kind", "")).strip().lower()
        err = str(pending.get("err", "")).strip()
        resp = pending.get("resp")
        if err != "":
            err_l = err.lower()
            if kind in {"write", "all"} and (
                "http 409" in err_l
                or "error code: 1001" in err_l
                or "timed out" in err_l
                or "timeout" in err_l
            ):
                if kind == "write":
                    data_link_state["next_write_ms"] = max(
                        int(data_link_state.get("next_write_ms", 0) or 0),
                        int(now_ms) + 3000,
                    )
                if kind == "all":
                    data_link_state["next_all_ms"] = max(
                        int(data_link_state.get("next_all_ms", 0) or 0),
                        int(now_ms) + 3000,
                    )
                data_link_state["status"] = "SYNC RETRY"
                return
            data_link_state["status"] = f"{kind.upper()} ERR: {err[:48]}"
            if kind == "create":
                data_link_state["next_create_retry_ms"] = int(now_ms) + 5000
            return
        if not isinstance(resp, dict):
            data_link_state["status"] = f"{kind.upper()} ERR: invalid response"
            if kind == "create":
                data_link_state["next_create_retry_ms"] = int(now_ms) + 5000
            return
        result_text = str(resp.get("result", "")).strip().lower()
        if result_text != "success":
            if kind in {"write", "delete"} and result_text in {"error_invalid_id", "invalid_id"}:
                data_link_state["entry_id"] = ""
                data_link_state["entry_callsign"] = ""
                data_link_state["entry_flt_pos"] = ""
                data_link_state["create_req_callsign"] = ""
                data_link_state["create_req_flt_pos"] = ""
                data_link_state["pending_recreate"] = False
                data_link_state["active_net_exists"] = False
                data_link_state["active_net_payload"] = {}
                data_link_state["next_create_retry_ms"] = 0
                _save_data_link_settings()
                data_link_state["status"] = "INVALID ID - RECREATE"
                return
            data_link_state["status"] = f"{kind.upper()} ERR: {str(resp.get('result', 'failed'))[:40]}"
            if kind == "create":
                data_link_state["next_create_retry_ms"] = int(now_ms) + 5000
            return
        if kind == "create":
            entry_id = str(resp.get("id", "")).strip()
            if entry_id == "":
                data_link_state["status"] = "CREATE ERR: missing id"
                data_link_state["next_create_retry_ms"] = int(now_ms) + 5000
                return
            data_link_state["entry_id"] = entry_id
            data_link_state["entry_callsign"] = str(data_link_state.get("create_req_callsign", "")).strip().upper()
            data_link_state["entry_flt_pos"] = str(data_link_state.get("create_req_flt_pos", "")).strip().upper()
            data_link_state["create_req_callsign"] = ""
            data_link_state["create_req_flt_pos"] = ""
            data_link_state["pending_recreate"] = False
            data_link_state["active_net_exists"] = True
            _save_data_link_settings()
            data_link_state["status"] = f"JOINED NET {entry_id}"
            return
        if kind == "delete":
            data_link_state["entry_id"] = ""
            data_link_state["entry_callsign"] = ""
            data_link_state["entry_flt_pos"] = ""
            data_link_state["create_req_callsign"] = ""
            data_link_state["create_req_flt_pos"] = ""
            data_link_state["active_net_exists"] = False
            data_link_state["active_net_payload"] = {}
            if bool(data_link_state.get("pending_recreate", False)):
                data_link_state["next_create_retry_ms"] = 0
                data_link_state["status"] = "RECREATE..."
            else:
                data_link_state["status"] = "DELETED"
            data_link_state["pending_recreate"] = False
            _save_data_link_settings()
            return
        if kind == "all":
            rows = resp.get("rows", [])
            if not isinstance(rows, list):
                rows = []
            now_unix_ms = int(time.time() * 1000)
            nets_map: Dict[str, Dict[str, object]] = {}
            nets_list: List[Dict[str, object]] = []
            for row in rows:
                if not isinstance(row, dict):
                    continue
                net_key = str(row.get("id", "")).strip().upper()
                if net_key == "":
                    continue
                payload_obj: Dict[str, object] = {}
                aircraft_col = row.get("aircraft", {})
                missions_col = row.get("missions", {})
                images_col = row.get("images", {})
                targets_col = row.get("targets", {})
                if isinstance(aircraft_col, str):
                    try:
                        aircraft_col = json.loads(aircraft_col)
                    except Exception:
                        aircraft_col = {}
                if isinstance(missions_col, str):
                    try:
                        missions_col = json.loads(missions_col)
                    except Exception:
                        missions_col = {}
                if isinstance(images_col, str):
                    try:
                        images_col = json.loads(images_col)
                    except Exception:
                        images_col = {}
                if isinstance(targets_col, str):
                    try:
                        targets_col = json.loads(targets_col)
                    except Exception:
                        targets_col = {}
                if isinstance(aircraft_col, dict) or isinstance(missions_col, dict) or isinstance(images_col, dict) or isinstance(targets_col, dict):
                    payload_obj = {
                        "schema": 1,
                        "aircraft": aircraft_col if isinstance(aircraft_col, dict) else {},
                        "missions": missions_col if isinstance(missions_col, dict) else {},
                        "images": images_col if isinstance(images_col, dict) else {},
                        "targets": targets_col if isinstance(targets_col, dict) else {},
                    }
                    try:
                        payload_obj["updated_unix_ms"] = int(row.get("updated_unix_ms", 0) or 0)
                    except Exception:
                        payload_obj["updated_unix_ms"] = 0
                else:
                    legacy_payload = row.get("mission", {})
                    if isinstance(legacy_payload, str):
                        txt = legacy_payload.strip()
                        if txt != "":
                            try:
                                legacy_payload = json.loads(txt)
                            except Exception:
                                legacy_payload = {}
                    if isinstance(legacy_payload, dict):
                        payload_obj = dict(legacy_payload)
                    else:
                        payload_obj = {}
                aircraft_raw = payload_obj.get("aircraft", {})
                active_count = 0
                if isinstance(aircraft_raw, dict):
                    for _sid, raw_air in aircraft_raw.items():
                        if not isinstance(raw_air, dict):
                            continue
                        try:
                            seen_ms = int(raw_air.get("last_seen_unix_ms", 0) or 0)
                        except Exception:
                            seen_ms = 0
                        if seen_ms <= 0 or (now_unix_ms - seen_ms) <= 15000:
                            active_count += 1
                nets_map[net_key] = {
                    "payload": payload_obj,
                    "name": str(row.get("net_name", row.get("image", ""))).strip(),
                    "active": int(active_count),
                }
                nets_list.append({"key": net_key, "active": int(active_count)})
            # Show only the 4 largest nets by currently active aircraft count.
            nets_list.sort(key=lambda x: (-int(x.get("active", 0) or 0), str(x.get("key", ""))))
            data_link_state["nets_list"] = nets_list[:4]
            data_link_state["nets_snapshot"] = nets_list

            selected_net = str(_data_link_current_net_key()).strip().upper()
            my_session = str(data_link_state.get("session_id", "")).strip()
            out_contacts: List[Dict[str, object]] = []
            out_missions: Dict[str, object] = {}
            out_images: Dict[str, object] = {}
            if selected_net != "" and selected_net in nets_map:
                selected_payload = nets_map[selected_net]["payload"]
                data_link_state["active_net_exists"] = True
                data_link_state["active_net_payload"] = selected_payload if isinstance(selected_payload, dict) else {}
                if str(data_link_state.get("entry_id", "")).strip().upper() != selected_net:
                    data_link_state["entry_id"] = selected_net
                    _save_data_link_settings()
                aircraft_map = data_link_state["active_net_payload"].get("aircraft", {})
                if isinstance(aircraft_map, dict):
                    for sid, raw_air in aircraft_map.items():
                        sid_str = str(sid).strip()
                        if sid_str == "" or sid_str == my_session:
                            continue
                        if not isinstance(raw_air, dict):
                            continue
                        try:
                            seen_ms = int(raw_air.get("last_seen_unix_ms", 0) or 0)
                        except Exception:
                            seen_ms = 0
                        if seen_ms > 0 and (now_unix_ms - seen_ms) > 15000:
                            continue
                        try:
                            lat = float(raw_air.get("lat"))
                            lon = float(raw_air.get("lon"))
                        except Exception:
                            continue
                        try:
                            heading = float(raw_air.get("heading_deg", 0.0)) % 360.0
                        except Exception:
                            heading = 0.0
                        try:
                            speed = float(raw_air.get("ground_speed_kts", raw_air.get("airspeed_kts", 0.0)) or 0.0)
                        except Exception:
                            speed = 0.0
                        out_contacts.append(
                            {
                                "id": sid_str,
                                "lat": lat,
                                "lon": lon,
                                "heading": heading,
                                "speed_kts": max(0.0, speed),
                                "affiliation": "FRIENDLY",
                                "domain": "AIR",
                                "category": "B1",
                                "_link16": True,
                                "mission": raw_air.get("mission"),
                                "image": raw_air.get("image"),
                                "toi": raw_air.get("toi"),
                            }
                        )
                targets_blob = data_link_state["active_net_payload"].get("targets", {})
                if isinstance(targets_blob, dict):
                    sim_targets = targets_blob.get("sim_targets", [])
                    if isinstance(sim_targets, list):
                        for raw_sim in sim_targets:
                            if not isinstance(raw_sim, dict):
                                continue
                            try:
                                lat = float(raw_sim.get("lat"))
                                lon = float(raw_sim.get("lon"))
                            except Exception:
                                continue
                            try:
                                heading = float(raw_sim.get("heading", 0.0) or 0.0) % 360.0
                            except Exception:
                                heading = 0.0
                            try:
                                speed = float(raw_sim.get("speed_kts", 0.0) or 0.0)
                            except Exception:
                                speed = 0.0
                            out_contacts.append(
                                {
                                    "id": str(raw_sim.get("id", "SIM")).strip() or "SIM",
                                    "lat": lat,
                                    "lon": lon,
                                    "heading": heading,
                                    "speed_kts": max(0.0, speed),
                                    "affiliation": str(raw_sim.get("affiliation", "UNKNOWN")).strip().upper() or "UNKNOWN",
                                    "domain": str(raw_sim.get("domain", "AIR")).strip().upper() or "AIR",
                                    "category": str(raw_sim.get("category", "B1")).strip().upper() or "B1",
                                    "_link16": True,
                                    "_sim": True,
                                }
                            )
                missions_blob = data_link_state["active_net_payload"].get("missions", {})
                if isinstance(missions_blob, dict):
                    out_missions = dict(missions_blob)
                    _data_link_apply_net_missions(
                        missions_blob,
                        data_link_state["active_net_payload"].get("images", {}),
                        my_session,
                    )
                images_blob = data_link_state["active_net_payload"].get("images", {})
                if isinstance(images_blob, dict):
                    out_images = dict(images_blob)
                data_link_state["status"] = f"NET {selected_net} ACFT {int(nets_map[selected_net].get('active', 0))}"
            else:
                data_link_state["active_net_exists"] = False
                data_link_state["active_net_payload"] = {}
                if selected_net == "":
                    data_link_state["entry_id"] = ""
                data_link_state["status"] = f"NETS {len(nets_list)}"
            data_link_state["remote_contacts"] = out_contacts
            data_link_state["remote_missions"] = out_missions
            data_link_state["remote_images"] = out_images
            _data_link_publish_remote_contacts()
            return
        data_link_state["status"] = kind.upper()

    def _data_link_update_runtime(now_ms: int) -> None:
        joined_key = _udp_relay_joined_net_key()
        _udp_relay_send_heartbeat(now_ms)
        _udp_relay_poll_incoming(now_ms, accept_state=bool(joined_key != ""))
        _udp_relay_cleanup_image_rx(now_ms)
        _udp_relay_cleanup_peers(now_ms)
        if joined_key != "":
            _udp_relay_send_state(now_ms)
            _udp_relay_pump_image_tx(joined_key, data_link_net_payload_cache.get(joined_key, {}), now_ms)
        _udp_relay_debug_status(now_ms)

        if bool(data_link_state.get("cni_fail_l16_ipf_active", False)):
            data_link_state["status"] = "L16 IPF FAIL"
            data_link_state["remote_contacts"] = []
            _data_link_publish_remote_contacts()
            return

        callsign = _data_link_runtime_value("callsign")
        if callsign == "":
            data_link_state["status"] = "WAIT CALLSGN"
            data_link_state["remote_contacts"] = []
            _data_link_publish_remote_contacts()
            return

        now_unix_ms = int(time.time() * 1000)
        net_counts: Dict[str, int] = {}
        for _sid, rec in udp_relay_peers.items():
            if not isinstance(rec, dict):
                continue
            dl = rec.get("datalink", {})
            if not isinstance(dl, dict) or not bool(dl.get("joined", False)):
                continue
            nk = str(dl.get("net_key", "")).strip().upper()
            if nk == "":
                continue
            net_counts[nk] = int(net_counts.get(nk, 0)) + 1
            meta = data_link_net_meta.get(nk, {})
            if not isinstance(meta, dict):
                meta = {}
            meta["last_active_ms"] = int(now_unix_ms)
            rp = dl.get("payload", {})
            if isinstance(rp, dict):
                prev = data_link_net_payload_cache.get(nk, {})
                try:
                    prev_ms = int(prev.get("updated_unix_ms", 0) or 0)
                except Exception:
                    prev_ms = 0
                try:
                    new_ms = int(rp.get("updated_unix_ms", 0) or 0)
                except Exception:
                    new_ms = 0
                if (not isinstance(prev, dict)) or new_ms >= prev_ms:
                    data_link_net_payload_cache[nk] = dict(rp)
                if new_ms > 0:
                    meta["last_payload_ms"] = max(int(meta.get("last_payload_ms", 0) or 0), int(new_ms))
            data_link_net_meta[nk] = meta

        if joined_key != "":
            net_counts[joined_key] = int(net_counts.get(joined_key, 0)) + 1
            meta = data_link_net_meta.get(joined_key, {})
            if not isinstance(meta, dict):
                meta = {}
            meta["last_active_ms"] = int(now_unix_ms)
            data_link_net_meta[joined_key] = meta

        # Auto-close idle nets after 10 minutes with no active members.
        idle_close_ms = 10 * 60 * 1000
        for nk, meta_raw in list(data_link_net_meta.items()):
            if not isinstance(meta_raw, dict):
                data_link_net_meta.pop(nk, None)
                data_link_net_payload_cache.pop(nk, None)
                continue
            if nk == joined_key:
                continue
            if int(net_counts.get(nk, 0) or 0) > 0:
                continue
            try:
                last_active = int(meta_raw.get("last_active_ms", 0) or 0)
            except Exception:
                last_active = 0
            try:
                last_payload = int(meta_raw.get("last_payload_ms", 0) or 0)
            except Exception:
                last_payload = 0
            last_seen = max(last_active, last_payload)
            if last_seen > 0 and (int(now_unix_ms) - int(last_seen)) >= int(idle_close_ms):
                data_link_net_meta.pop(nk, None)
                data_link_net_payload_cache.pop(nk, None)

        nets_list = [{"key": k, "active": int(v)} for k, v in net_counts.items() if str(k).strip() != ""]
        nets_list.sort(key=lambda row: (-int(row.get("active", 0) or 0), str(row.get("key", ""))))
        data_link_state["nets_list"] = nets_list[:4]
        data_link_state["nets_snapshot"] = nets_list

        if joined_key == "":
            udp_relay_img_tx_state.clear()
            dim_peer_debug_sigs.clear()
            data_link_state["active_net_exists"] = False
            data_link_state["active_net_payload"] = {}
            data_link_state["remote_contacts"] = []
            data_link_state["remote_missions"] = {}
            data_link_state["remote_images"] = {}
            data_link_state["status"] = f"NETS {len(nets_list)}"
            _data_link_publish_remote_contacts()
            return

        base_payload = data_link_net_payload_cache.get(joined_key, {})
        ownship_data = _data_link_build_ownship_table()
        active_payload = _data_link_build_net_payload(base_payload, ownship_data, now_unix_ms)
        aircraft_map = active_payload.get("aircraft", {})
        if not isinstance(aircraft_map, dict):
            aircraft_map = {}

        out_contacts: List[Dict[str, object]] = []
        out_missions: Dict[str, object] = {}
        out_images: Dict[str, object] = {}
        for sid, rec in udp_relay_peers.items():
            if not isinstance(rec, dict):
                continue
            dl = rec.get("datalink", {})
            if not isinstance(dl, dict) or not bool(dl.get("joined", False)):
                continue
            nk = str(dl.get("net_key", "")).strip().upper()
            if nk != joined_key:
                continue
            remote_air = rec.get("aircraft", {})
            if isinstance(remote_air, dict):
                copy_air = dict(remote_air)
                copy_air["last_seen_unix_ms"] = int(now_unix_ms)
                aircraft_map[str(sid)] = copy_air
                try:
                    lat = float(copy_air.get("lat"))
                    lon = float(copy_air.get("lon"))
                except Exception:
                    lat = None
                    lon = None
                if lat is not None and lon is not None:
                    try:
                        heading = float(copy_air.get("heading_deg", 0.0)) % 360.0
                    except Exception:
                        heading = 0.0
                    try:
                        speed = float(copy_air.get("ground_speed_kts", copy_air.get("airspeed_kts", 0.0)) or 0.0)
                    except Exception:
                        speed = 0.0
                    out_contacts.append(
                        {
                            "id": str(sid),
                            "lat": lat,
                            "lon": lon,
                            "heading": heading,
                            "speed_kts": max(0.0, speed),
                            "affiliation": "FRIENDLY",
                            "domain": "AIR",
                            "category": "B1",
                            "_link16": True,
                            "mission": copy_air.get("mission"),
                            "image": copy_air.get("image"),
                            "toi": copy_air.get("toi"),
                        }
                    )
            rp = dl.get("payload", {})
            if isinstance(rp, dict):
                rms = rp.get("missions", {})
                if isinstance(rms, dict):
                    out_missions = dict(rms)
                rim = rp.get("images", {})
                if isinstance(rim, dict):
                    out_images.update(dict(rim))
                targets_blob = rp.get("targets", {})
                if isinstance(targets_blob, dict):
                    sim_targets = targets_blob.get("sim_targets", [])
                    if isinstance(sim_targets, list):
                        for raw_sim in sim_targets:
                            if not isinstance(raw_sim, dict):
                                continue
                            try:
                                lat = float(raw_sim.get("lat"))
                                lon = float(raw_sim.get("lon"))
                            except Exception:
                                continue
                            try:
                                heading = float(raw_sim.get("heading", 0.0) or 0.0) % 360.0
                            except Exception:
                                heading = 0.0
                            try:
                                speed = float(raw_sim.get("speed_kts", 0.0) or 0.0)
                            except Exception:
                                speed = 0.0
                            out_contacts.append(
                                {
                                    "id": str(raw_sim.get("id", "SIM")).strip() or "SIM",
                                    "lat": lat,
                                    "lon": lon,
                                    "heading": heading,
                                    "speed_kts": max(0.0, speed),
                                    "affiliation": str(raw_sim.get("affiliation", "UNKNOWN")).strip().upper() or "UNKNOWN",
                                    "domain": str(raw_sim.get("domain", "AIR")).strip().upper() or "AIR",
                                    "category": str(raw_sim.get("category", "B1")).strip().upper() or "B1",
                                    "_link16": True,
                                    "_sim": True,
                                }
                            )

        my_session = str(data_link_state.get("session_id", "")).strip()
        aircraft_map.pop(my_session, None)
        active_payload["aircraft"] = aircraft_map
        data_link_net_payload_cache[joined_key] = dict(active_payload)
        data_link_state["active_net_exists"] = True
        data_link_state["active_net_payload"] = active_payload
        data_link_state["remote_contacts"] = out_contacts
        data_link_state["remote_missions"] = out_missions
        data_link_state["remote_images"] = out_images
        try:
            rx_sig = _dim_mission_blob_sig(out_missions)
            last_rx_sig = str(dim_debug_state.get("rx_sig", "")).strip()
            next_rx_ms = int(dim_debug_state.get("next_rx_ms", 0) or 0)
            m_store, m_own, m_flt, m_out = _dim_mission_blob_counts(out_missions)
            if rx_sig != last_rx_sig or int(now_ms) >= next_rx_ms:
                print(
                    f"[DIM][RX] net={joined_key if joined_key != '' else '-'} store={m_store} own={m_own} flt={m_flt} out={m_out} peers={len(out_contacts)}"
                )
                dim_debug_state["rx_sig"] = rx_sig
                dim_debug_state["next_rx_ms"] = int(now_ms) + 3000
        except Exception:
            pass
        missions_for_dim = out_missions if isinstance(out_missions, dict) else {}
        images_for_dim = out_images if isinstance(out_images, dict) else {}
        if not isinstance(missions_for_dim, dict) or len(missions_for_dim) <= 0:
            missions_for_dim = active_payload.get("missions", {})
            images_for_dim = active_payload.get("images", {})
        if isinstance(missions_for_dim, dict):
            _data_link_apply_net_missions(
                missions_for_dim,
                images_for_dim,
                my_session,
            )
        _data_link_publish_remote_contacts()
        data_link_state["status"] = f"NET {joined_key} ACFT {len(out_contacts)}"

    def _data_link_delete_remote_entry_on_shutdown() -> None:
        entry_id = str(data_link_state.get("entry_id", "")).strip().upper()
        data_link_state["entry_id"] = ""
        data_link_state["entry_callsign"] = ""
        data_link_state["entry_flt_pos"] = ""
        data_link_state["pending_recreate"] = False
        data_link_state["create_req_callsign"] = ""
        data_link_state["create_req_flt_pos"] = ""
        data_link_state["active_net_exists"] = False
        data_link_state["active_net_payload"] = {}
        data_link_state["nets_list"] = []
        data_link_state["remote_contacts"] = []
        data_link_state["remote_missions"] = {}
        data_link_state["remote_images"] = {}
        data_link_net_payload_cache.clear()
        data_link_net_meta.clear()
        udp_relay_img_tx_state.clear()
        udp_relay_img_rx_state.clear()
        dim_peer_debug_sigs.clear()
        # Preserve UDP comm peer visibility but clear stale datalink payload state.
        for _sid, _peer in list(udp_relay_peers.items()):
            if not isinstance(_peer, dict):
                continue
            dl = _peer.get("datalink", {})
            if isinstance(dl, dict):
                dl["joined"] = False
                dl["net_key"] = ""
                dl["payload"] = {}
                _peer["datalink"] = dl
        if entry_id != "":
            data_link_state["status"] = f"LEFT {entry_id}"
        _save_data_link_settings()
        _data_link_publish_remote_contacts()

    def _pmd_svc_selected_field() -> Optional[str]:
        value = pmd_dr_state.get("svc_selected")
        if not value:
            return None
        s = str(value)
        if s in {"BOS_QTY", "ENG_OIL", "HYD_A", "HYD_B", "PAO", "28V_BAT"}:
            return s
        return None

    def finalize_pmd_svc_data_entry(field: str) -> None:
        inputs = pmd_dr_state.get("svc_inputs", {})
        values = pmd_dr_state.get("svc_values", {})
        if not isinstance(inputs, dict) or not isinstance(values, dict):
            return
        raw = str(inputs.get(field, "")).strip()
        if raw != "":
            try:
                if field == "PAO":
                    v = float(raw)
                    v = max(0.0, min(11.0, v))
                elif field == "BOS_QTY":
                    v = float(max(0, min(400, int(float(raw)))))
                elif field == "ENG_OIL":
                    v = float(max(0, min(12, int(float(raw)))))
                elif field == "HYD_A":
                    v = float(max(0, min(500, int(float(raw)))))
                elif field == "HYD_B":
                    v = float(max(450, min(600, int(float(raw)))))
                elif field == "28V_BAT":
                    v = max(0.0, min(100.0, float(raw)))
                    v = round(v, 1)
                else:
                    v = float(raw)
                values[field] = v
                if field == "BOS_QTY":
                    pmd_dr_state["bos_live_qty"] = float(v)
            except Exception:
                pass
        inputs[field] = ""
        if _pmd_svc_selected_field() == field:
            pmd_dr_state["svc_selected"] = None

    def select_pmd_svc_data_entry(field: str) -> None:
        current = _pmd_svc_selected_field()
        if current == field:
            finalize_pmd_svc_data_entry(field)
            return
        if current is not None:
            finalize_pmd_svc_data_entry(current)
        pmd_dr_state["svc_selected"] = field
        inputs = pmd_dr_state.get("svc_inputs", {})
        if isinstance(inputs, dict):
            inputs[field] = ""

    def pmd_svc_keypad_press(key: str) -> None:
        field = _pmd_svc_selected_field()
        if field is None:
            return
        inputs = pmd_dr_state.get("svc_inputs", {})
        values = pmd_dr_state.get("svc_values", {})
        if not isinstance(inputs, dict) or not isinstance(values, dict):
            return
        current = str(inputs.get(field, ""))
        if key in {"KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9"}:
            d = key.split("_", 1)[1]
            if field == "PAO":
                # Left-to-right PAO entry:
                # first key "5" => "5.0"; second key can become "5.3" or "10.0".
                if current == "":
                    inputs[field] = f"{d}.0"
                    return
                left, _, right = current.partition(".")
                if right == "":
                    right = "0"
                if right == "0":
                    can_extend_int = left in {"0", "1"} and len(left) < 2
                    if can_extend_int:
                        try:
                            candidate = int(left + d)
                        except Exception:
                            candidate = 99
                        if candidate <= 11:
                            inputs[field] = f"{candidate}.0"
                        else:
                            inputs[field] = f"{left}.{d}"
                    else:
                        inputs[field] = f"{left}.{d}"
                else:
                    inputs[field] = f"{left}.{d}"
            elif field == "28V_BAT":
                left = current.split(".", 1)[0] if "." in current else current
                digits = "".join(ch for ch in left if ch.isdigit())
                next_digits = (digits + d)[-3:]
                try:
                    intval = int(next_digits) if next_digits != "" else 0
                except Exception:
                    intval = 0
                intval = max(0, min(100, intval))
                inputs[field] = f"{intval}.0"
            else:
                width = 3 if field in {"BOS_QTY", "HYD_A", "HYD_B"} else 2
                digits = "".join(ch for ch in current if ch.isdigit())
                inputs[field] = (digits + d)[-width:]
            return
        if key == "KP_BACK":
            if field == "PAO":
                if current == "":
                    return
                left, _, right = current.partition(".")
                if right not in {"", "0"}:
                    inputs[field] = f"{left}.0"
                elif len(left) > 1:
                    inputs[field] = f"{left[:-1]}.0"
                else:
                    inputs[field] = ""
            elif field == "28V_BAT":
                left = current.split(".", 1)[0] if "." in current else current
                digits = "".join(ch for ch in left if ch.isdigit())
                if len(digits) <= 1:
                    inputs[field] = ""
                else:
                    inputs[field] = f"{int(digits[:-1])}.0"
            else:
                inputs[field] = "".join(ch for ch in current if ch.isdigit())[:-1]
            return
        if key in {"KP_UP", "KP_DOWN"}:
            base = str(inputs.get(field, "")) if str(inputs.get(field, "")) != "" else str(values.get(field, "0"))
            try:
                val = float(base)
            except Exception:
                val = float(values.get(field, 0.0))
            step = 0.1 if field in {"PAO", "28V_BAT"} else 1.0
            val = val + step if key == "KP_UP" else val - step
            if field == "BOS_QTY":
                val = max(0.0, min(400.0, val))
            elif field == "ENG_OIL":
                val = max(0.0, min(12.0, val))
            elif field == "HYD_A":
                val = max(0.0, min(500.0, val))
            elif field == "HYD_B":
                val = max(450.0, min(600.0, val))
            elif field == "PAO":
                val = max(0.0, min(11.0, val))
            elif field == "28V_BAT":
                val = max(0.0, min(100.0, val))
            if field in {"PAO", "28V_BAT"}:
                inputs[field] = f"{val:.1f}"
            else:
                inputs[field] = str(int(round(val)))

    def _term_input_selected() -> bool:
        return bool(pmd_dr_state.get("term_input_selected", False))

    def _set_term_input_selected(selected: bool) -> None:
        pmd_dr_state["term_input_selected"] = bool(selected)

    def _term_input_text() -> str:
        return str(pmd_dr_state.get("term_input", ""))

    def _set_term_input_text(text: str) -> None:
        pmd_dr_state["term_input"] = str(text)

    def _term_reset_history_nav() -> None:
        pmd_dr_state["term_history_nav"] = -1
        pmd_dr_state["term_history_unsent"] = _term_input_text()

    def _term_append_text(text: str) -> None:
        if text == "":
            return
        chars: List[str] = []
        for ch in str(text):
            if ch in {"\r", "\n", "\t"}:
                chars.append(" ")
            elif ch.isprintable():
                chars.append(ch)
        if len(chars) <= 0:
            return
        _set_term_input_text(_term_input_text() + "".join(chars))
        _term_reset_history_nav()

    def _term_append_char(ch: str) -> None:
        _term_append_text(ch)

    def _term_backspace() -> None:
        cur = _term_input_text()
        if cur != "":
            _set_term_input_text(cur[:-1])
            _term_reset_history_nav()

    def _term_history_entries() -> List[str]:
        raw = pmd_dr_state.get("term_history", [])
        if isinstance(raw, list):
            return [str(item) for item in raw]
        return []

    def _term_push_history_entry(command: str) -> None:
        cmd = str(command)
        if cmd.strip() == "":
            return
        history = _term_history_entries()
        if len(history) <= 0 or history[-1] != cmd:
            history.append(cmd)
        if len(history) > TERM_HISTORY_MAX:
            history = history[-TERM_HISTORY_MAX:]
        pmd_dr_state["term_history"] = history
        pmd_dr_state["term_history_nav"] = -1
        pmd_dr_state["term_history_unsent"] = ""

    def _term_history_step(direction: int) -> None:
        history = _term_history_entries()
        if len(history) <= 0:
            return
        try:
            nav = int(pmd_dr_state.get("term_history_nav", -1))
        except Exception:
            nav = -1
        if direction < 0:
            if nav == -1:
                pmd_dr_state["term_history_unsent"] = _term_input_text()
                nav = len(history) - 1
            elif nav > 0:
                nav -= 1
            _set_term_input_text(history[nav])
            pmd_dr_state["term_history_nav"] = nav
            return
        if nav == -1:
            return
        if nav < len(history) - 1:
            nav += 1
            _set_term_input_text(history[nav])
            pmd_dr_state["term_history_nav"] = nav
            return
        _set_term_input_text(str(pmd_dr_state.get("term_history_unsent", "")))
        pmd_dr_state["term_history_nav"] = -1

    def _term_read_clipboard_text() -> str:
        out = ""
        try:
            pygame.scrap.init()
            raw = pygame.scrap.get(pygame.SCRAP_TEXT)
            if isinstance(raw, (bytes, bytearray)):
                out = raw.decode("utf-8", errors="ignore")
            elif raw is not None:
                out = str(raw)
        except Exception:
            out = ""
        out = out.replace("\x00", "")
        if out == "" and os.name == "nt":
            try:
                startupinfo = None
                if hasattr(subprocess, "STARTUPINFO"):
                    startupinfo = subprocess.STARTUPINFO()
                    startupinfo.dwFlags |= subprocess.STARTF_USESHOWWINDOW
                    startupinfo.wShowWindow = 0
                proc = subprocess.run(
                    ["powershell", "-NoProfile", "-Command", "Get-Clipboard"],
                    check=False,
                    capture_output=True,
                    text=True,
                    timeout=1.5,
                    startupinfo=startupinfo,
                    creationflags=getattr(subprocess, "CREATE_NO_WINDOW", 0),
                )
                out = str(proc.stdout or "")
            except Exception:
                out = ""
        return out

    def _term_paste_clipboard() -> bool:
        payload = _term_read_clipboard_text()
        if payload == "":
            return False
        before = _term_input_text()
        _term_append_text(payload)
        return _term_input_text() != before

    def _term_scroll_by_lines(delta_lines: int) -> None:
        delta = int(delta_lines)
        if delta == 0:
            return
        try:
            max_lines = max(1, int(pmd_dr_state.get("term_log_max_lines", 1)))
        except Exception:
            max_lines = 1
        try:
            max_chars = max(1, int(pmd_dr_state.get("term_log_max_chars", 1)))
        except Exception:
            max_chars = 1
        wrapped = _term_wrapped_snapshot(pmd_dr_state, max_chars)
        max_scroll = max(0, len(wrapped) - max_lines)
        try:
            current = int(pmd_dr_state.get("term_scroll_lines", 0))
        except Exception:
            current = 0
        pmd_dr_state["term_scroll_lines"] = max(0, min(max_scroll, current + delta))

