    setattr(engine_sfx_track, "_engine_pitch_band", _ENGINE_PITCH_BASE_SOUND_KEY)
    setattr(engine_sfx_track, "_engine_pitch_ratio", float(ENGINE_LOOP_PITCH_MIN))
    setattr(engine_sfx_track, "_engine_pitch_target_ratio", float(ENGINE_LOOP_PITCH_MIN))
    setattr(engine_sfx_track, "_engine_pitch_applied_ratio", float(ENGINE_LOOP_PITCH_MIN))
    setattr(engine_sfx_track, "_engine_pitch_last_ms", 0)
    setattr(engine_sfx_track, "_engine_pitch_last_apply_ms", 0)
    setattr(engine_sfx_track, "_engine_pitch_next_key", "")
    panel_touch_swipe: Optional[Dict[str, int]] = None
    panel_touch_active_button = 1
    startup_external_panels_button_win_rect: Optional[pygame.Rect] = None

    def _panel_popup_touch_button_from_pos(pos: Tuple[int, int]) -> int:
        for hit in reversed(_PANEL_RUNTIME_BUTTON_HITS):
            rect = hit.get("rect")
            if not isinstance(rect, pygame.Rect):
                continue
            if rect.collidepoint(pos):
                return 1 if int(pos[0]) <= int(rect.centerx) else 3
        return 1

    def _commit_start_mode(mode_value: str, now_ms: Optional[int] = None) -> None:
        nonlocal start_mode, cold_start_active, start_mode_pending, startup_start
        nonlocal cockpit_panels_popup_active, cold_display_mode, cold_prev_ipp_on, cold_ipp_on_since_ms
        nonlocal hot_start_engine_on_pending, cold_batt_wait_start_ms, cold_left_loading_start_ms
        nonlocal cold_full_loading_start_ms, cold_ipp_repower_lockout, cold_half_hold_on_batt

        mode_norm = "cold" if str(mode_value).strip().lower() == "cold" else "hot"
        start_mode = mode_norm
        cold_start_active = mode_norm == "cold"
        try:
            formats.set_engine_cold_start(cold_start_active)
        except Exception:
            pass
        try:
            apply_start_mode_panel_presets(start_mode)
        except Exception:
            pass
        start_mode_pending = False
        startup_start = int(now_ms) if isinstance(now_ms, (int, float)) else int(pygame.time.get_ticks())
        if start_mode == "hot":
            cockpit_panels_popup_active = False
            cold_display_mode = "full_on"
            cold_prev_ipp_on = True
            cold_ipp_on_since_ms = int(startup_start - IPP_DISPLAY_POWER_DELAY_MS)
            hot_start_engine_on_pending = True
        else:
            cockpit_panels_popup_active = True
            cold_display_mode = "off"
            cold_prev_ipp_on = False
            cold_ipp_on_since_ms = None
            hot_start_engine_on_pending = False
        cold_batt_wait_start_ms = None
        cold_left_loading_start_ms = 0
        cold_full_loading_start_ms = 0
        cold_ipp_repower_lockout = False
        cold_half_hold_on_batt = (start_mode == "hot")

    prev_icaws_cw_keys: Set[str] = set()
    slow_frame_watchdog = create_slow_frame_watchdog("PCD")

    while running:
        slow_frame_watchdog.begin_frame("main_loop")
        now = pygame.time.get_ticks()
        wall_now_ms = int(time.time() * 1000)
        sync_panel_text_lites_tint()
        try:
            with frame_state.lock:
                frame_state.show_video_rates = bool(pmd_dr_state.get("show_video_rates", False))
        except Exception:
            pass
        try:
            formats.update_sms_door_transitions(now)
        except Exception:
            pass
        try:
            # Load a small number of queued graphics assets each frame.
            formats.pump_graphics_asset_loading(3)
        except Exception:
            pass
        dt_sec = max(0.0, min(0.2, (now - prev_sim_ms) / 1000.0))
        prev_sim_ms = now
        try:
            _hotas_update_runtime_inputs()
        except Exception:
            pass
        try:
            _update_panel_runtime(now, dt_sec, held_keys, pmd_dr_state)
        except Exception:
            pass
        try:
            _pmd_tick_plugins(dt_sec, now)
        except Exception:
            traceback.print_exc()
        if SOUND_ENABLED:
            try:
                panel_state = _ensure_panel_button_states()
                power_state = panel_state.get("POWER PANEL", {})
                throttle_state = panel_state.get("THROTTLE", {})
                if isinstance(power_state, dict):
                    batt_switch_on = str(power_state.get("BAT", "OFF")).upper() == "ON"
                    start_seq_end = int(power_state.get("IPP_START_SEQ_END_MS", 0))
                    start_seq_success = bool(power_state.get("IPP_START_SEQ_SUCCESS", False))
                    ipp_starting = bool(start_seq_success and start_seq_end > now)
                    ipp_on = bool(power_state.get("IPP_ON", False))
                    shutdown_seq_end = int(power_state.get("IPP_SHUTDOWN_SEQ_END_MS", 0))
                    ipp_shutting = bool(shutdown_seq_end > now)
                    if isinstance(throttle_state, dict):
                        engine_cmd = str(throttle_state.get("ENGINE", "OFF")).upper()
                    else:
                        engine_cmd = "OFF"
                    if engine_cmd not in {"OFF", "MOTOR", "RUN"}:
                        engine_cmd = "OFF"
                    try:
                        batt_28v = float(power_state.get("BATT_28V", 0.0))
                    except Exception:
                        batt_28v = 0.0
                    batt_ready = bool(power_state.get("BAT_ACTIVE", False)) and batt_28v > 0.0
                    icc1_on = str(power_state.get("ICC1", "OFF")).upper() == "ON"
                    icc2_on = str(power_state.get("ICC2", "OFF")).upper() == "ON"
                    icc3_on = str(power_state.get("ICC3", "OFF")).upper() == "ON"
                    fuel_ready = bool(_fuel_feed_available())
                    try:
                        engine_spool = float(throttle_state.get("ENGINE_SPOOL", 0.0)) if isinstance(throttle_state, dict) else 0.0
                    except Exception:
                        engine_spool = 0.0
                    engine_spool_mode = str(throttle_state.get("ENGINE_SPOOL_MODE", "OFF")).upper() if isinstance(throttle_state, dict) else "OFF"
                    engine_runtime_on = bool(engine_spool_mode == "RUN" and engine_spool > 0.001)
                    try:
                        throttle_pos_audio = float(throttle_state.get("THROTTLE_POS", 0.0)) if isinstance(throttle_state, dict) else 0.0
                    except Exception:
                        throttle_pos_audio = 0.0
                    throttle_idle_ready = bool(throttle_pos_audio <= 1.0 or engine_runtime_on)
                    engine_prereqs_ready = bool(
                        batt_ready and icc1_on and icc2_on and icc3_on and ipp_on and fuel_ready and throttle_idle_ready
                    )
                    engine_cmd_for_audio = str(engine_cmd)
                    if engine_cmd_for_audio == "RUN" and (not engine_prereqs_ready) and (not engine_runtime_on):
                        engine_cmd_for_audio = "OFF"

                    if hot_start_engine_on_pending:
                        batt_sfx_track.desired_on = False
                        ipp_sfx_track.desired_on = False
                        engine_sfx_track.desired_on = False
                        _reset_crossfade_track(batt_sfx_track)
                        _reset_crossfade_track(ipp_sfx_track)
                        stop_sound_channel(SFX_CH_ENGINE_OFF)
                        _start_track_with_loop_sound(engine_sfx_track, now)
                        engine_sfx_track.desired_on = True
                        ipp_to_engine_crossfade_active = False
                        ipp_to_engine_crossfade_from_channels = []
                        engine_to_off_crossfade_active = False
                        engine_to_off_crossfade_from_channels = []
                        prev_batt_switch_on = batt_switch_on
                        prev_ipp_starting = ipp_starting
                        prev_ipp_on = ipp_on
                        prev_ipp_shutting = ipp_shutting
                        prev_engine_cmd = engine_cmd_for_audio
                        sfx_power_state_initialized = True
                        hot_start_engine_on_pending = False
                        continue

                    if not sfx_power_state_initialized:
                        prev_batt_switch_on = batt_switch_on
                        prev_ipp_starting = ipp_starting
                        prev_ipp_on = ipp_on
                        prev_ipp_shutting = ipp_shutting
                        prev_engine_cmd = engine_cmd_for_audio
                        sfx_power_state_initialized = True
                    else:
                        engine_start_edge = bool(engine_cmd_for_audio == "RUN" and prev_engine_cmd != "RUN")
                        engine_off_edge = bool(engine_cmd_for_audio == "OFF" and prev_engine_cmd != "OFF")
                        if engine_start_edge and engine_to_off_crossfade_active:
                            stop_sound_channel(SFX_CH_ENGINE_OFF)
                            engine_to_off_crossfade_active = False
                            engine_to_off_crossfade_from_channels = []
                        if engine_start_edge:
                            ipp_channels = []
                            for ch in (ipp_sfx_track.start_channel, ipp_sfx_track.loop_ch_a, ipp_sfx_track.loop_ch_b):
                                if is_sound_channel_busy(ch):
                                    ipp_channels.append(int(ch))
                            start_volume = 0.0 if len(ipp_channels) > 0 else float(_engine_ipp_volume())
                            _start_track_with_start_sound(engine_sfx_track, now, start_volume=start_volume)
                            engine_sfx_track.desired_on = True
                            ipp_to_engine_crossfade_active = len(ipp_channels) > 0
                            ipp_to_engine_crossfade_start_ms = int(now)
                            ipp_to_engine_crossfade_from_channels = ipp_channels
                            ipp_sfx_track.desired_on = False
                        if engine_off_edge:
                            from_channels: List[int] = []
                            for ch in (engine_sfx_track.start_channel, engine_sfx_track.loop_ch_a, engine_sfx_track.loop_ch_b):
                                if is_sound_channel_busy(ch):
                                    from_channels.append(int(ch))
                            off_start_volume = 0.0 if len(from_channels) > 0 else float(_engine_ipp_volume())
                            played_off = play_sound_effect_on_channel(
                                "ENGINE OFF",
                                SFX_CH_ENGINE_OFF,
                                loops=0,
                                volume=off_start_volume,
                                web_fade_in_ms=int(SFX_CROSSFADE_MS) if len(from_channels) > 0 else 0,
                                web_fade_out_ms=0,
                            )
                            if played_off and len(from_channels) > 0:
                                engine_to_off_crossfade_active = True
                                engine_to_off_crossfade_start_ms = int(now)
                                engine_to_off_crossfade_from_channels = from_channels
                            else:
                                engine_to_off_crossfade_active = False
                                engine_to_off_crossfade_from_channels = []
                                engine_sfx_track.desired_on = False
                                _reset_crossfade_track(engine_sfx_track)

                        # BATT audio starts only on real OFF->ON transitions.
                        if batt_switch_on and (not prev_batt_switch_on):
                            _start_track_with_start_sound(batt_sfx_track, now)
                            batt_sfx_track.desired_on = True
                        if batt_sfx_track.desired_on and (not batt_switch_on):
                            batt_sfx_track.desired_on = False
                        _update_crossfade_track(batt_sfx_track, now)

                        # IPP audio starts on startup edge and runs until shutdown begins.
                        if ipp_starting and (not prev_ipp_starting):
                            _start_track_with_start_sound(ipp_sfx_track, now)
                            ipp_sfx_track.desired_on = True
                        ipp_runtime_on = bool((ipp_starting or ipp_on) and (not ipp_shutting))
                        if ipp_sfx_track.desired_on and (not ipp_runtime_on):
                            ipp_sfx_track.desired_on = False
                        if ipp_to_engine_crossfade_active:
                            fade_ms = max(1, int(SFX_CROSSFADE_MS))
                            progress = max(0.0, min(1.0, (now - ipp_to_engine_crossfade_start_ms) / float(fade_ms)))
                            set_sound_channel_volume(engine_sfx_track.start_channel, float(_engine_ipp_volume()) * progress)
                            for ch in ipp_to_engine_crossfade_from_channels:
                                set_sound_channel_volume(ch, float(_engine_ipp_volume()) * (1.0 - progress))
                            if progress >= 1.0:
                                for ch in ipp_to_engine_crossfade_from_channels:
                                    stop_sound_channel(ch)
                                set_sound_channel_volume(engine_sfx_track.start_channel, float(_engine_ipp_volume()))
                                ipp_to_engine_crossfade_active = False
                                ipp_to_engine_crossfade_from_channels = []
                                _reset_crossfade_track(ipp_sfx_track)
                        else:
                            _update_crossfade_track(ipp_sfx_track, now)

                        # Engine audio: START -> ON loop while commanded RUN.
                        if engine_to_off_crossfade_active:
                            fade_ms = max(1, int(SFX_CROSSFADE_MS))
                            progress = max(0.0, min(1.0, (now - engine_to_off_crossfade_start_ms) / float(fade_ms)))
                            set_sound_channel_volume(SFX_CH_ENGINE_OFF, float(_engine_ipp_volume()) * progress)
                            for ch in engine_to_off_crossfade_from_channels:
                                set_sound_channel_volume(ch, float(_engine_ipp_volume()) * (1.0 - progress))
                            if progress >= 1.0:
                                for ch in engine_to_off_crossfade_from_channels:
                                    stop_sound_channel(ch)
                                set_sound_channel_volume(SFX_CH_ENGINE_OFF, float(_engine_ipp_volume()))
                                engine_to_off_crossfade_active = False
                                engine_to_off_crossfade_from_channels = []
                                engine_sfx_track.desired_on = False
                                _reset_crossfade_track(engine_sfx_track)
                        else:
                            if engine_sfx_track.desired_on and engine_cmd_for_audio != "RUN":
                                engine_sfx_track.desired_on = False
                            elif (engine_cmd_for_audio == "RUN") and (not engine_sfx_track.desired_on) and (not engine_start_edge):
                                _start_track_with_loop_sound(engine_sfx_track, now)
                                engine_sfx_track.desired_on = True
                            _update_crossfade_track(engine_sfx_track, now)

                        prev_batt_switch_on = batt_switch_on
                        prev_ipp_starting = ipp_starting
                        prev_ipp_on = ipp_on
                        prev_ipp_shutting = ipp_shutting
                        prev_engine_cmd = engine_cmd_for_audio
            except Exception:
                pass
        pressed = pygame.key.get_pressed()
        hotas_raw_down = pmd_dr_state.get("hotas_action_down_raw", {})
        hotas_raw_map = hotas_raw_down if isinstance(hotas_raw_down, dict) else {}
        # HOTAS COM A/B/C are direct PTT-by-radio actions.
        if bool(hotas_raw_map.get("com_a", False) or hotas_raw_map.get("comm_ctl_left", False)):
            local_ptt_radio = "coma"
        elif bool(hotas_raw_map.get("com_b", False) or hotas_raw_map.get("comm_ctl_right", False)):
            local_ptt_radio = "comb"
        elif bool(hotas_raw_map.get("com_c", False) or hotas_raw_map.get("comm_ctl_aft", False) or hotas_raw_map.get("comm_ctl_down", False)):
            local_ptt_radio = "comc"
        elif _pmd_is_action_down("tx", pressed):
            assigned = str(comm_state.get("asgn_radio", "comb")).strip().lower()
            local_ptt_radio = {"coma": "coma", "comb": "comb", "comc": "comc"}.get(assigned, None)
        else:
            local_ptt_radio = None
        # Keep capture/send nearly realtime:
        # - capture only while PTT is active
        # - keep a brief release grace so tail audio is not cut off
        ptt_intent = local_ptt_radio if local_ptt_radio in {"coma", "comb", "comc"} else None
        prev_cap_radio = str(comm_state.get("_ptt_capture_radio", "")).strip().lower()
        if prev_cap_radio not in {"coma", "comb", "comc"}:
            prev_cap_radio = ""
        try:
            cap_until = int(comm_state.get("_ptt_capture_until_ms", 0) or 0)
        except Exception:
            cap_until = 0
        if ptt_intent in {"coma", "comb", "comc"} and bool(comm_state.get(f"{ptt_intent}_on", False)):
            local_ptt_radio = ptt_intent
            comm_state["_ptt_capture_radio"] = str(ptt_intent)
            comm_state["_ptt_capture_until_ms"] = int(now) + int(ptt_capture_grace_ms)
            comm_state["_ptt_capture_on"] = True
        elif prev_cap_radio in {"coma", "comb", "comc"} and int(now) <= int(cap_until) and bool(comm_state.get(f"{prev_cap_radio}_on", False)):
            local_ptt_radio = prev_cap_radio
            comm_state["_ptt_capture_on"] = True
        else:
            local_ptt_radio = None
            comm_state["_ptt_capture_on"] = False
            if int(now) > int(cap_until):
                comm_state["_ptt_capture_radio"] = ""
                comm_state["_ptt_capture_until_ms"] = 0
            if len(audio_input_chunks) > 0:
                audio_input_chunks.clear()
        if audio_worker_running:
            _set_audio_worker_local_ptt(local_ptt_radio)
        term_string_input_active = bool(
            status_menu_popup_active
            and status_menu_active_submenu == "PMD_DR_TERM"
            and _term_input_selected()
        )
        ap_speed_mode_active = False
        try:
            ap_state_live = _autopilot_state()
            ap_speed_mode_active = bool(ap_state_live.get("speed_hold", False) or ap_state_live.get("speed_sel", False))
        except Exception:
            ap_speed_mode_active = False
        if (not term_string_input_active) and (not ap_speed_mode_active):
            hotas_throttle = _hotas_axis_throttle_percent()
            if hotas_throttle is not None:
                try:
                    panel = _ensure_panel_button_states()
                    throttle_state = panel.get("THROTTLE", {})
                    if isinstance(throttle_state, dict):
                        engine_switch_mode = str(throttle_state.get("ENGINE", "OFF")).upper()
                        # Disable HOTAS throttle-axis input when ENGINE switch is OFF.
                        # Keyboard throttle keys remain active.
                        if engine_switch_mode != "OFF":
                            current_thr = float(throttle_state.get("THROTTLE_POS", 0.0))
                            adjust_engine_thrust(float(hotas_throttle) - current_thr, source="hotas_axis")
                except Exception:
                    pass
        throttle_delta = 0.0
        if (not term_string_input_active) and (not ap_speed_mode_active):
            if _pmd_is_action_down("throt_plus"):
                throttle_delta += throttle_rate_per_sec * dt_sec
            if _pmd_is_action_down("throt_minus"):
                throttle_delta -= throttle_rate_per_sec * dt_sec
        if abs(throttle_delta) > 1e-9:
            adjust_engine_thrust(throttle_delta, source="keyboard")
        update_engine_runtime(dt_sec)
        try:
            # Keep formats module state references live for TFLIR/DAS pose extraction.
            setattr(formats, "ins_gps_state", ins_gps_state)
            setattr(formats, "PANEL_BUTTON_STATES", _ensure_panel_button_states())
        except Exception:
            pass
        try:
            _push_pose_to_3dworld(
                now,
                ins_gps_state if isinstance(ins_gps_state, dict) else {},
                portal_formats if isinstance(portal_formats, list) else None,
            )
        except Exception:
            pass
        try:
            _apply_engine_pitch_from_thrust(engine_sfx_track, get_status_engine_thrust(), now)
        except Exception:
            pass
        update_fuel_burn_from_ff(dt_sec)
        update_fuel_dump(dt_sec)
        try:
            panel_state = _ensure_panel_button_states()
            master_arm_state = panel_state.get("MASTER ARM", {})
            if isinstance(master_arm_state, dict):
                prev_vols = (
                    int(comm_state.get("vola", 5) or 5),
                    int(comm_state.get("volb", 5) or 5),
                    int(comm_state.get("volc", 5) or 5),
                )
                comm_state["vola"] = max(0, min(10, int(master_arm_state.get("DIAL_A", comm_state.get("vola", 5)))))
                comm_state["volb"] = max(0, min(10, int(master_arm_state.get("DIAL_B", comm_state.get("volb", 5)))))
                comm_state["volc"] = max(0, min(10, int(master_arm_state.get("DIAL_C", comm_state.get("volc", 5)))))
                if prev_vols != (
                    int(comm_state.get("vola", 5) or 5),
                    int(comm_state.get("volb", 5) or 5),
                    int(comm_state.get("volc", 5) or 5),
                ):
                    _comm_persist_audio_settings()
        except Exception:
            pass
        _comm_enforce_cni_linkage(now)
        _comm_sync_a123_from_asgn()
        bus_rx_active = {"coma": False, "comb": False, "comc": False}
        overlay_rx = {}
        if AUDIO_STREAM_ENABLED:
            # Keep local PTT valid only while the assigned radio is powered on.
            if local_ptt_radio is not None and not bool(comm_state.get(f"{local_ptt_radio}_on", False)):
                local_ptt_radio = None
            runtime_comm_state["coma_on"] = bool(comm_state.get("coma_on", False))
            runtime_comm_state["comb_on"] = bool(comm_state.get("comb_on", False))
            runtime_comm_state["comc_on"] = bool(comm_state.get("comc_on", False))
            runtime_comm_state["coma_freq"] = str(comm_state.get("coma_freq", "000.000"))
            runtime_comm_state["comb_freq"] = str(comm_state.get("comb_freq", "000.000"))
            runtime_comm_state["comc_freq"] = str(comm_state.get("comc_freq", "000.000"))
            try:
                runtime_comm_state["vola"] = int(comm_state.get("vola", 5))
            except Exception:
                runtime_comm_state["vola"] = 5
            try:
                runtime_comm_state["volb"] = int(comm_state.get("volb", 5))
            except Exception:
                runtime_comm_state["volb"] = 5
            try:
                runtime_comm_state["volc"] = int(comm_state.get("volc", 5))
            except Exception:
                runtime_comm_state["volc"] = 5
            profiles = comm_state.get("radio_profiles", {})
            runtime_comm_state["radio_profiles"] = profiles if isinstance(profiles, dict) else {}
            overlay_ptt = None
            if WEB_COMM_STREAM_ENABLED:
                with comm_overlay_lock:
                    overlay_ptt = comm_overlay_state.get("ptt_radio")
                    overlay_rx = comm_overlay_state.get("rx_active", {})
            overlay_ptt_val = overlay_ptt if overlay_ptt in {"coma", "comb", "comc"} else None
            effective_ptt = local_ptt_radio if local_ptt_radio in {"coma", "comb", "comc"} else overlay_ptt_val
            comm_state["ptt_radio"] = effective_ptt
            if audio_worker_running:
                worker_rx = _get_audio_worker_bus_rx_active()
                bus_rx_active["coma"] = bool(worker_rx.get("coma", False))
                bus_rx_active["comb"] = bool(worker_rx.get("comb", False))
                bus_rx_active["comc"] = bool(worker_rx.get("comc", False))
            if not audio_worker_running:
                injected = []
                with frame_state.audio_lock:
                    while frame_state.audio_inject_queue:
                        injected.append(frame_state.audio_inject_queue.popleft())
                for inj in injected:
                    try:
                        radio = str(inj.get("radio", "")).strip().lower()
                        payload = str(inj.get("payload", ""))
                        sr = int(inj.get("sample_rate", audio_sample_rate))
                    except Exception:
                        continue
                    if radio not in {"coma", "comb", "comc"} or payload == "":
                        continue
                    cid = f"{comm_bus_instance_id}-{wall_now_ms}-W-{random.randint(100000, 999999)}"
                    if local_comm_bus_enabled:
                        audio_bus_write({"id": cid, "from": comm_bus_instance_id, "ts": wall_now_ms, "radio": radio, "sample_rate": sr, "payload": payload})
                # Publish local standalone mic chunks while transmitting.
                if local_ptt_radio in {"coma", "comb", "comc"} and bool(comm_state.get(f"{local_ptt_radio}_on", False)):
                    if audio_input_chunks:
                        raw = audio_input_chunks.popleft()
                        try:
                            _recording_audio_add_chunk(raw, audio_sample_rate, 1)
                            payload = base64.b64encode(raw).decode("ascii")
                            cid = f"{comm_bus_instance_id}-{wall_now_ms}-S-{random.randint(100000, 999999)}"
                            if local_comm_bus_enabled:
                                audio_bus_write({"id": cid, "from": comm_bus_instance_id, "ts": wall_now_ms, "radio": local_ptt_radio, "sample_rate": audio_sample_rate, "payload": payload})
                            _udp_relay_send_voice(local_ptt_radio, payload, audio_sample_rate)
                            audio_last_tx_ms = now
                        except Exception:
                            pass
                    else:
                        _comm_audio_debug_event("TX_WAIT", local_ptt_radio, 0, "ptt active, no mic chunk")
            if local_comm_bus_enabled and not audio_worker_running and now - comm_bus_last_sync_ms >= COMM_BUS_SYNC_INTERVAL_MS:
                snapshot = read_comm_bus_snapshot()
                snapshot = {sid: info for sid, info in snapshot.items() if isinstance(info, dict) and int(info.get("seen", 0)) >= (wall_now_ms - 1200)}
                local_payload = {
                    "id": comm_bus_instance_id,
                    "seen": wall_now_ms,
                    "ptt": effective_ptt,
                    "net_key": _udp_relay_joined_net_key(),
                    "radios": {
                        "coma_on": bool(comm_state.get("coma_on", False)),
                        "comb_on": bool(comm_state.get("comb_on", False)),
                        "comc_on": bool(comm_state.get("comc_on", False)),
                        "coma_freq": str(comm_state.get("coma_freq", "000.000")),
                        "comb_freq": str(comm_state.get("comb_freq", "000.000")),
                        "comc_freq": str(comm_state.get("comc_freq", "000.000")),
                        "coma_secure": bool(_udp_relay_radio_secure("coma")),
                        "comb_secure": bool(_udp_relay_radio_secure("comb")),
                        "comc_secure": bool(_udp_relay_radio_secure("comc")),
                    },
                }
                write_comm_bus_local(comm_bus_instance_id, local_payload)
                snapshot[comm_bus_instance_id] = local_payload
                for sid, info in snapshot.items():
                    if sid == comm_bus_instance_id or not isinstance(info, dict):
                        continue
                    ptt = str(info.get("ptt", ""))
                    if ptt not in {"coma", "comb", "comc"}:
                        continue
                    radios = info.get("radios", {})
                    if not isinstance(radios, dict):
                        continue
                    if not bool(radios.get(f"{ptt}_on", False)) or not bool(comm_state.get(f"{ptt}_on", False)):
                        continue
                    local_freq = str(comm_state.get(f"{ptt}_freq", "")).strip()
                    remote_freq = str(radios.get(f"{ptt}_freq", "")).strip()
                    if local_freq == "" or local_freq != remote_freq:
                        continue
                    local_secure = bool(_udp_relay_radio_secure(ptt))
                    remote_secure = bool(radios.get(f"{ptt}_secure", False))
                    if local_secure or remote_secure:
                        if not (local_secure and remote_secure):
                            continue
                        local_net = _udp_relay_comm_net_key()
                        remote_net = str(info.get("net_key", "")).strip().upper()
                        if local_net == "" or remote_net == "" or local_net != remote_net:
                            continue
                    bus_rx_active[ptt] = True
                comm_bus_last_sync_ms = now
            if local_comm_bus_enabled and not audio_worker_running and now - last_comm_bus_cleanup_ms >= COMM_BUS_CLEAN_INTERVAL_MS:
                last_comm_bus_cleanup_ms = now
                try:
                    if COMM_BUS_DIR.exists():
                        for p in COMM_BUS_DIR.glob("*.json"):
                            try:
                                if wall_now_ms - int(p.stat().st_mtime * 1000) > COMM_BUS_RETENTION_MS:
                                    p.unlink(missing_ok=True)
                            except Exception:
                                continue
                except Exception:
                    pass
            if local_comm_bus_enabled and not audio_worker_running and now - audio_last_scan_ms >= AUDIO_BUS_SCAN_INTERVAL_MS:
                audio_last_scan_ms = now
                try:
                    if AUDIO_BUS_DIR.exists():
                        comm_snapshot = read_comm_bus_snapshot()
                        scanned_files = 0
                        for p in AUDIO_BUS_DIR.glob("*.json"):
                            scanned_files += 1
                            if scanned_files > AUDIO_BUS_SCAN_MAX_FILES:
                                break
                            try:
                                if wall_now_ms - int(p.stat().st_mtime * 1000) > AUDIO_BUS_RETENTION_MS:
                                    p.unlink(missing_ok=True)
                                    continue
                            except Exception:
                                pass
                            # Chunk ids are used as file stems; skip files we already consumed.
                            if p.stem in audio_seen_set:
                                continue
                            try:
                                raw = json.loads(p.read_text(encoding="utf-8"))
                            except Exception:
                                continue
                            if not isinstance(raw, dict):
                                continue
                            cid = str(raw.get("id", ""))
                            if cid == "" or cid in audio_seen_set:
                                continue
                            audio_seen_set.add(cid)
                            audio_seen_ids.append(cid)
                            while len(audio_seen_ids) > audio_seen_ids.maxlen:
                                old = audio_seen_ids.popleft()
                                audio_seen_set.discard(old)
                            src = str(raw.get("from", ""))
                            ts = int(raw.get("ts", 0))
                            if src == comm_bus_instance_id or ts < (wall_now_ms - AUDIO_CHUNK_TTL_MS):
                                continue
                            radio = str(raw.get("radio", "")).strip().lower()
                            if radio not in {"coma", "comb", "comc"} or not bool(comm_state.get(f"{radio}_on", False)):
                                continue
                            sender_info = comm_snapshot.get(src, {})
                            srad = sender_info.get("radios", {}) if isinstance(sender_info, dict) else {}
                            if not isinstance(srad, dict) or not bool(srad.get(f"{radio}_on", False)):
                                continue
                            lf = str(comm_state.get(f"{radio}_freq", "")).strip()
                            rf = str(srad.get(f"{radio}_freq", "")).strip()
                            if lf == "" or lf != rf:
                                continue
                            local_secure = bool(_udp_relay_radio_secure(radio))
                            remote_secure = bool(srad.get(f"{radio}_secure", False))
                            if local_secure or remote_secure:
                                if not (local_secure and remote_secure):
                                    continue
                                local_net = _udp_relay_comm_net_key()
                                remote_net = str(sender_info.get("net_key", "")).strip().upper()
                                if local_net == "" or remote_net == "" or local_net != remote_net:
                                    continue
                            sr = int(raw.get("sample_rate", audio_sample_rate))
                            payload = str(raw.get("payload", ""))
                            if payload == "":
                                continue
                            try:
                                chunk = base64.b64decode(payload)
                                if chunk:
                                    rx_gain = _comm_rx_gain_for_radio(radio)
                                    out_chunk = _comm_apply_rx_gain(chunk, rx_gain)
                                    _recording_audio_add_chunk(out_chunk, sr, 1)
                                    if rx_gain > 0.0001:
                                        if len(audio_output_chunks) >= audio_output_chunks.maxlen:
                                            audio_output_chunks.popleft()
                                        audio_output_chunks.append(out_chunk)
                                    with frame_state.audio_lock:
                                        if len(frame_state.audio_rx_queue) >= frame_state.audio_rx_queue.maxlen:
                                            frame_state.audio_rx_queue.popleft()
                                        payload_out = payload
                                        if rx_gain > 0.0001 and out_chunk != chunk:
                                            try:
                                                payload_out = base64.b64encode(out_chunk).decode("ascii")
                                            except Exception:
                                                payload_out = payload
                                        frame_state.audio_rx_queue.append({"radio": radio, "sample_rate": sr, "payload": payload_out})
                            except Exception:
                                pass
                except Exception:
                    pass
            rx_until = comm_state.get("rx_until")
            if not isinstance(rx_until, dict):
                rx_until = {"coma": 0, "comb": 0, "comc": 0}
                comm_state["rx_until"] = rx_until
            for r in ("coma", "comb", "comc"):
                active_overlay = bool(overlay_rx.get(r, False)) if isinstance(overlay_rx, dict) else False
                active = active_overlay or bool(bus_rx_active.get(r, False))
                if active:
                    rx_until[r] = int(now + 800)
        else:
            comm_state["ptt_radio"] = local_ptt_radio if local_ptt_radio in {"coma", "comb", "comc"} else None
        # BOS live quantity fluctuates around BOS reference (+/-1..2) continuously.
        if now >= next_bos_flux_ms:
            svc_vals = pmd_dr_state.get("svc_values", {})
            svc_sel = _pmd_svc_selected_field()
            if isinstance(svc_vals, dict) and svc_sel != "BOS_QTY":
                bos_ref = float(svc_vals.get("BOS_QTY", 330.0))
                delta = float(random.choice([-2, -1, 1, 2]))
                pmd_dr_state["bos_live_qty"] = max(0.0, min(400.0, bos_ref + delta))
            next_bos_flux_ms = now + random.randint(700, 1300)
        _sync_fuel_degrd_runtime()
        sync_shared_fuel_total()
        sync_svc_debug_outputs()
        comm_state["now_ms"] = now
        _autopilot_state()["now_ms"] = now
        iff_state["now_ms"] = now
        # Drive IFF degradation state from active ICAWs.
        try:
            icaw_alerts = list(getattr(formats, "get_current_icaws_alerts", lambda: [])())
        except Exception:
            icaw_alerts = []
        current_icaws_cw_keys: Set[str] = set()
        new_warning = False
        new_caution = False
        active_icaw_names: set[str] = set()
        for item in icaw_alerts:
            if not isinstance(item, (list, tuple)) or len(item) < 2:
                continue
            name = str(item[0]).strip().upper()
            if name == "":
                continue
            active_icaw_names.add(name)
            sev = str(item[1]).strip().lower()
            if sev in {"warning", "caution"}:
                key = f"{name}|{sev}"
                current_icaws_cw_keys.add(key)
                if key not in prev_icaws_cw_keys:
                    if sev == "warning":
                        new_warning = True
                    elif sev == "caution":
                        new_caution = True
        if new_warning:
            play_sound_effect_on_channel(
                "warning",
                SFX_CH_ICAWS_WARNING,
                volume=float(_icaws_alert_volume()),
            )
        if new_caution:
            play_sound_effect_on_channel(
                "caution",
                SFX_CH_ICAWS_CAUTION,
                volume=float(_icaws_alert_volume()),
            )
        prev_icaws_cw_keys = set(current_icaws_cw_keys)
        mode_c_degd_active = "IFF DEGD MODE C" in active_icaw_names
        cm_fail_iff_active = "CM FAIL - IFF" in active_icaw_names
        iff_state["mode_c_degd_active"] = bool(mode_c_degd_active)
        iff_state["cm_fail_iff_active"] = bool(cm_fail_iff_active)
        iff_state["degrade_flag"] = bool(mode_c_degd_active or cm_fail_iff_active)
        iff_state["degrade_mode"] = "C" if mode_c_degd_active else ""
        comm_state["bur_degd_active"] = bool("BUR DEGD" in active_icaw_names)
        comm_state["bur_fail_active"] = bool("BUR FAIL" in active_icaw_names)
        if bool(comm_state.get("bur_fail_active", False)):
            field = _comm_selected_field()
            if field in {"vold", "comd"}:
                finalize_comm_data_entry(field)
        nav_state["cni_fail_tacan_active"] = bool("CNI FAIL - TACAN" in active_icaw_names)
        nav_state["cni_fail_ils_active"] = bool("CNI FAIL ILS" in active_icaw_names)
        if bool(nav_state.get("cni_fail_tacan_active", False)) and bool(nav_state.get("c3_menu_open", False)):
            nav_state["c3_menu_open"] = False
        if bool(nav_state.get("cni_fail_ils_active", False)) and _nav_selected_field() == "b1":
            finalize_nav_data_entry("b1")
        data_link_state["cni_fail_l16_ipf_active"] = bool("CNI FAIL L16 IPF" in active_icaw_names)
        ecs_state["cabin_press_active"] = bool("CABIN PRESS" in active_icaw_names)
        ins_gps_state["gps_degd_active"] = bool("GPS DEGD" in active_icaw_names)
        ins_gps_state["gps_fail_active"] = bool("GPS FAIL" in active_icaw_names)
        ins_gps_state["gps_no_keys_active"] = bool("GPS NO KEYS" in active_icaw_names)
        ins_gps_state["ins_degd_active"] = bool("INS DEGD" in active_icaw_names)
        ins_gps_state["nav_degd_active"] = bool("NAV DEGD" in active_icaw_names)
        ins_gps_state["ins_fail_active"] = bool("INS FAIL" in active_icaw_names)
        _update_ins_gps_runtime(dt_sec)
        _update_ownship_geo_from_motion(dt_sec)
        _sync_ins_gps_from_adsb_runtime()
        _data_link_update_runtime(now)
        _update_on_off_and_phm_runtime(now)
        if bool(ins_gps_state.get("ins_fail_active", False)) and status_menu_active_submenu == "INS_GPS_A1_GOL":
            status_menu_active_submenu = "INS_GPS"
        display_degd_side = _active_icaw_display_degd_side()
        try:
            panel_state = _ensure_panel_button_states()
            phm_state = panel_state.get("PHM STATUS", {})
            if isinstance(phm_state, dict):
                phm_state["display_degd_side"] = display_degd_side
        except Exception:
            pass
        if cm_fail_iff_active:
            # Hard-disable IFF popup interaction paths while CM FAIL - IFF is active.
            iff_state["a1_menu_open"] = False
            iff_state["a2_menu_open"] = False
            iff_state["e7_subpage_open"] = False
            sel_field = _iff_selected_field()
            if sel_field is not None:
                finalize_iff_data_entry(sel_field, now)
        altitude_state["now_ms"] = now
        nav_state["now_ms"] = now
        try:
            altitude_state["cab"] = str(int(ecs_state.get("b1_alt", 800)))
        except Exception:
            altitude_state["cab"] = "800"
        flash_map = comm_state.get("flash_until")
        if isinstance(flash_map, dict):
            comm_state["flash_until"] = {
                k: v for k, v in flash_map.items() if isinstance(v, (int, float)) and int(v) > now
            }
        iff_flash = iff_state.get("flash_until")
        if isinstance(iff_flash, dict):
            iff_state["flash_until"] = {
                k: v for k, v in iff_flash.items() if isinstance(v, (int, float)) and int(v) > now
            }
        alt_flash = altitude_state.get("flash_until")
        if isinstance(alt_flash, dict):
            altitude_state["flash_until"] = {
                k: v for k, v in alt_flash.items() if isinstance(v, (int, float)) and int(v) > now
            }
        nav_flash = nav_state.get("flash_until")
        if isinstance(nav_flash, dict):
            nav_state["flash_until"] = {
                k: v for k, v in nav_flash.items() if isinstance(v, (int, float)) and int(v) > now
            }
        try:
            mode_options = iff_state.get("mode_options", ["OFF", "STBY", "MAN", "AUTO"])
            if not isinstance(mode_options, list) or len(mode_options) == 0:
                mode_options = ["OFF", "STBY", "MAN", "AUTO"]
            mode_idx = int(iff_state.get("mode_idx", 0))
            mode_idx = max(0, min(len(mode_options) - 1, mode_idx))
            master_mode = str(mode_options[mode_idx]).upper()
            if bool(iff_state.get("emergency_on", False)) and bool(iff_state.get("iff_on", False)):
                master_mode = "EMER"
            if master_mode in {"AUTO", "MAN"} and bool(iff_state.get("iff_on", False)):
                next_check = int(iff_state.get("interrogator_next_check_ms", 0))
                if now >= next_check:
                    iff_state["interrogator_next_check_ms"] = now + random.randint(2500, 6000)
                    if random.random() < 0.3:
                        iff_state["mode3_highlight_until_ms"] = now + 1000
            else:
                iff_state["interrogator_next_check_ms"] = now + random.randint(2500, 6000)
        except Exception:
            pass
        nav_pending = nav_state.get("pending_action")
        if (
            isinstance(nav_pending, tuple)
            and len(nav_pending) == 3
            and str(nav_pending[0]) == "submenu"
            and isinstance(nav_pending[2], (int, float))
            and int(nav_pending[2]) <= now
        ):
            nav_state["submenu"] = nav_pending[1]
            nav_state["pending_action"] = None
        status_flash = iff_state.get("status_flash_until")
        if not isinstance(status_flash, dict):
            status_flash = {}
            iff_state["status_flash_until"] = status_flash
        else:
            iff_state["status_flash_until"] = {
                k: v for k, v in status_flash.items() if isinstance(v, (int, float)) and int(v) > now
            }
            status_flash = iff_state["status_flash_until"]
        try:
            curr_mode_idx = int(iff_state.get("mode_idx", 0))
        except Exception:
            curr_mode_idx = 0
        curr_mode1 = str(iff_state.get("mode1", ""))
        curr_mode3 = str(iff_state.get("mode3a", ""))
        if int(iff_state.get("_last_mode_idx", curr_mode_idx)) != curr_mode_idx:
            status_flash["mode"] = now + 1000
            iff_state["_last_mode_idx"] = curr_mode_idx
        if str(iff_state.get("_last_mode1", curr_mode1)) != curr_mode1:
            status_flash["mode1"] = now + 1000
            iff_state["_last_mode1"] = curr_mode1
        if str(iff_state.get("_last_mode3", curr_mode3)) != curr_mode3:
            status_flash["mode3"] = now + 1000
            iff_state["_last_mode3"] = curr_mode3
        pending_asgn_due = comm_state.get("pending_asgn_open_due")
        if isinstance(pending_asgn_due, (int, float)) and int(pending_asgn_due) <= now:
            comm_state["asgn_menu_open"] = True
            comm_state["gol_menu"] = "D4"
            comm_state["pending_asgn_open_due"] = None
        pending_asgn_close_due = comm_state.get("pending_asgn_close_due")
        if isinstance(pending_asgn_close_due, (int, float)) and int(pending_asgn_close_due) <= now:
            comm_state["asgn_menu_open"] = False
            if str(comm_state.get("gol_menu", "")).upper().strip() == "D4":
                comm_state["gol_menu"] = ""
            comm_state["pending_asgn_close_due"] = None
        if now >= next_recordings_cleanup_ms:
            cleanup_old_recordings(recordings_dir)
            next_recordings_cleanup_ms = now + RECORDINGS_CLEANUP_INTERVAL_MS
        if now >= next_formats_mtime_check_ms:
            next_formats_mtime_check_ms = now + FORMATS_MTIME_CHECK_INTERVAL_MS
            if formats_path is not None and last_formats_mtime is not None:
                try:
                    if formats_path.exists():
                        current_mtime = formats_path.stat().st_mtime
                        if current_mtime != last_formats_mtime:
                            rebuild_formats()
                            last_formats_mtime = current_mtime
                except Exception as exc:
                    print(f"Auto-reload formats failed: {exc}")
        elapsed = now - startup_start
        if status_menu_pending_action is not None:
            action, value, due_ms = status_menu_pending_action
            if now >= due_ms:
                if action == "back":
                    status_menu_active_submenu = None
                elif action == "open":
                    status_menu_active_submenu = value
                status_menu_pending_action = None
        if screen_dbg_pending_record_start:
            if not record_active:
                start_recording_session(_screen_debug_initial_record_rect(), source="screen_debug")
            screen_dbg_pending_record_start = False
        if len(pending_osb_actions) > 0:
            still_pending: List[Tuple[int, str, Optional[str], int]] = []
            for portal_idx, label, popup_name, due_ms in pending_osb_actions:
                try:
                    if int(now) >= int(due_ms):
                        _execute_osb_action(int(portal_idx), str(label), popup_name)
                    else:
                        still_pending.append((int(portal_idx), str(label), popup_name, int(due_ms)))
                except Exception:
                    continue
            pending_osb_actions = still_pending
        if pending_nav_menu_action is not None:
            pending_nav = pending_nav_menu_action if isinstance(pending_nav_menu_action, (tuple, list)) else None
            if pending_nav is not None and len(pending_nav) >= 2:
                try:
                    portal_idx = int(pending_nav[0])
                    due_ms = int(pending_nav[1])
                except Exception:
                    pending_nav_menu_action = None
                else:
                    if now >= due_ms:
                        if (not status_menu_popup_active) or (portal_idx != int(status_menu_popup_portal_index)):
                            request_vded(portal_idx, "MENU")
                        pending_nav_menu_action = None
        if pending_vded_action is not None:
            pending_vded = pending_vded_action if isinstance(pending_vded_action, (tuple, list)) else None
            if pending_vded is not None and len(pending_vded) >= 4:
                try:
                    portal_idx = int(pending_vded[0])
                    action = pending_vded[1]
                    value = pending_vded[2]
                    due_ms = int(pending_vded[3])
                    target_portal_idx = int(pending_vded[4]) if len(pending_vded) >= 5 else int(portal_idx)
                except Exception:
                    pending_vded_action = None
                else:
                    if now >= due_ms:
                        if action == "set_format" and value is not None:
                            set_format(target_portal_idx, value)
                        close_vded(portal_idx)
                        pending_vded_action = None
        vded_flash_until = {
            key: until for key, until in vded_flash_until.items() if until > now
        }
        osb_flash_until = {
            key: until for key, until in osb_flash_until.items() if until > now
        }
        status_menu_item_flash_until = {
            key: until for key, until in status_menu_item_flash_until.items() if until > now
        }
        cold_display_phase = -2
        if not start_mode_pending:
            panel_state = _ensure_panel_button_states()
            power_state = panel_state.get("POWER PANEL", {})
            throttle_state = panel_state.get("THROTTLE", {})
            if not isinstance(power_state, dict):
                power_state = {}
            if not isinstance(throttle_state, dict):
                throttle_state = {}
            batt_on = bool(power_state.get("BAT_ACTIVE", str(power_state.get("BAT", "OFF")).upper() == "ON"))
            icc3_on = str(power_state.get("ICC3", "OFF")).upper() == "ON"
            ipp_on = bool(power_state.get("IPP_ON", False))
            engine_mode = str(throttle_state.get("ENGINE", "OFF")).upper()
            engine_spool_mode = str(throttle_state.get("ENGINE_SPOOL_MODE", "OFF")).upper()
            try:
                engine_spool = float(throttle_state.get("ENGINE_SPOOL", 0.0))
            except Exception:
                engine_spool = 0.0
            engine_off = engine_mode == "OFF"
            engine_running = bool(engine_mode == "RUN" and engine_spool_mode == "RUN" and engine_spool > 0.001)
            if ipp_on:
                if cold_ipp_on_since_ms is None:
                    cold_ipp_on_since_ms = now
            else:
                cold_ipp_on_since_ms = None
            ipp_ready = bool(ipp_on and cold_ipp_on_since_ms is not None and (now - int(cold_ipp_on_since_ms)) >= IPP_DISPLAY_POWER_DELAY_MS)

            if not batt_on:
                cold_half_hold_on_batt = False
            if cold_ipp_repower_lockout and not batt_on:
                cold_ipp_repower_lockout = False

            # If IPP drops while the engine is not running, keep only the left side
            # alive on battery if a full-power display session already occurred.
            # Full repower still follows the lockout/battery-cycle behavior.
            if cold_prev_ipp_on and (not ipp_on) and (not engine_running):
                if batt_on and cold_half_hold_on_batt:
                    cold_display_mode = "left_on"
                    cold_left_loading_start_ms = 0
                else:
                    cold_display_mode = "off"
                cold_batt_wait_start_ms = None
                cold_full_loading_start_ms = 0
                cold_ipp_repower_lockout = True

            # Engine RUN keeps displays powered continuously.
            # Do not force an IPP warm-up blackout while already airborne/running.
            if engine_running:
                cold_display_mode = "full_on"
                cold_batt_wait_start_ms = None
                cold_left_loading_start_ms = 0
                cold_full_loading_start_ms = 0
                cold_half_hold_on_batt = True
            elif cold_ipp_repower_lockout and batt_on:
                if cold_half_hold_on_batt:
                    cold_display_mode = "left_on"
                    cold_batt_wait_start_ms = None
                    cold_left_loading_start_ms = 0
                    cold_full_loading_start_ms = 0
                else:
                    cold_display_mode = "off"
                    cold_batt_wait_start_ms = None
                    cold_left_loading_start_ms = 0
                    cold_full_loading_start_ms = 0
            else:
                if ipp_ready:
                    if cold_display_mode == "left_on":
                        # Left side already powered by BATT path; bring right online immediately.
                        cold_display_mode = "full_on"
                        cold_full_loading_start_ms = 0
                        cold_half_hold_on_batt = True
                    elif cold_display_mode != "full_on":
                        if cold_display_mode != "full_loading":
                            cold_display_mode = "full_loading"
                            cold_full_loading_start_ms = now
                            cold_batt_wait_start_ms = None
                            cold_left_loading_start_ms = 0
                        elif (now - cold_full_loading_start_ms) >= (PHASE0_MS + PHASE1_MS):
                            cold_display_mode = "full_on"
                            cold_half_hold_on_batt = True
                else:
                    if cold_display_mode in {"full_loading", "full_on"}:
                        if batt_on and cold_half_hold_on_batt:
                            cold_display_mode = "left_on"
                        else:
                            cold_display_mode = "off"
                        cold_batt_wait_start_ms = None
                        cold_left_loading_start_ms = 0
                        cold_full_loading_start_ms = 0

                    prepower_eligible = batt_on and icc3_on and engine_off and (not cold_ipp_repower_lockout)
                    if prepower_eligible:
                        if cold_display_mode == "off":
                            if cold_batt_wait_start_ms is None:
                                cold_batt_wait_start_ms = now
                            if (now - cold_batt_wait_start_ms) >= COLD_BATT_LEFT_POWER_DELAY_MS:
                                cold_display_mode = "left_loading"
                                cold_left_loading_start_ms = now
                        elif cold_display_mode == "left_loading":
                            if (now - cold_left_loading_start_ms) >= PHASE0_MS:
                                cold_display_mode = "left_on"
                    else:
                        if cold_display_mode in {"left_loading", "left_on", "off"}:
                            cold_display_mode = "off"
                        cold_batt_wait_start_ms = None
                        cold_left_loading_start_ms = 0

            cold_prev_ipp_on = ipp_on

            if cold_display_mode == "off":
                cold_display_phase = -2
            elif cold_display_mode == "left_loading":
                cold_display_phase = 0
            elif cold_display_mode == "left_on":
                cold_display_phase = 1
            elif cold_display_mode == "full_loading":
                full_elapsed = max(0, now - cold_full_loading_start_ms)
                if full_elapsed < PHASE0_MS:
                    cold_display_phase = 0
                elif full_elapsed < PHASE0_MS + PHASE1_MS:
                    cold_display_phase = 1
                else:
                    cold_display_mode = "full_on"
                    cold_display_phase = 2
            else:
                cold_display_phase = 2
        if start_mode_pending:
            phase = -1
        elif DEBUG_SHOW_ZONES:
            phase = 2
        else:
            phase = cold_display_phase

        screen.fill(BG_COLOR)
        osb_zones: List[OsbZone] = []
        control_zones: List[ControlZone] = []
        subportal_zones: List[SubPortalZone] = []
        vded_zones: List[VdedZone] = []
        status_menu_button_rect = None
        eng_popup_button_rect = None
        fuel_popup_button_rect = None
        sms_popup_button_rect = None
        fcs_popup_button_rect = None
        icaws_popup_button_rect = None
        autopilot_popup_button_rect = None
        nav_popup_button_rect = None
        iff_popup_button_rect = None
        altitude_popup_button_rect = None
        time_popup_button_rect = None
        record_button_rect = None
        comm_popup_button_rect = None
        swap_button_rect = None
        status_menu_popup_zones = {}
        start_prompt_zones: Dict[str, pygame.Rect] = {}
        status_menu_popup_portal_index = 3 if not status_bar_swapped else 1
        active_status_popups_by_portal = _compute_active_status_popups(status_bar_swapped)
        active_status_popup_name: Optional[str] = None
        active_status_popup_portal_index: Optional[int] = None
        if len(active_status_popups_by_portal) > 0:
            try:
                first_popup_portal = sorted(int(idx) for idx in active_status_popups_by_portal.keys())[0]
                active_status_popup_portal_index = int(first_popup_portal)
                active_status_popup_name = str(active_status_popups_by_portal.get(first_popup_portal, ""))
                if active_status_popup_name == "":
                    active_status_popup_name = None
            except Exception:
                active_status_popup_name = None
                active_status_popup_portal_index = None
        event_q_depth_before = 0
        with frame_state.event_lock:
            event_q_depth_before = len(frame_state.event_queue)
            while frame_state.event_queue:
                evt = frame_state.event_queue.popleft()
                try:
                    if isinstance(evt, pygame.event.EventType):
                        pygame.event.post(evt)
                except Exception:
                    traceback.print_exc()
        if poi_on_screen:
            poi_sub_index = _clamp_poi_sub_index(poi_sub_index)
            if int(poi_sub_index) >= 0 and (not _poi_subportal_selectable(poi_portal_index, poi_sub_index)):
                poi_sub_index = -1
            if int(poi_sub_index) < 0:
                poi_portal_index = normalize_poi_index(poi_portal_index)
        debug_overlay_active = bool(cockpit_panels_popup_active)
        try:
            _hotas_apply_edge_actions(debug_overlay_active, dt_sec)
        except Exception:
            pass
        _apply_poi_tsd_keyboard_pan_zoom(dt_sec, active_status_popup_name, debug_overlay_active)
        _apply_poi_asr_keyboard_pan_zoom(dt_sec, debug_overlay_active)
        _apply_poi_tflir_keyboard_slew(dt_sec, debug_overlay_active)
        _auto_follow_tracked_tsd_states()
        _update_adsb_fetch_activity(
            active_status_popups_by_portal,
            debug_overlay_active,
        )
        _update_adsb_query_radius_from_tsd()
        display_record_seconds = int(record_accumulated_seconds + (max(0.0, (now - record_session_start_ms) / 1000.0) if (record_active and record_session_start_ms is not None) else 0.0))
        status_record_mode_name = "PICTURE" if _screen_dbg_mode_idx() == 1 else "RECORD"
        status_record_area_label = _screen_dbg_area_status_label()
        pmd_dr_state["screen_dbg_record_active"] = bool(record_active)
        status_show_fps_debug = bool(pmd_dr_state.get("show_fps_counter", False))
        dist_state["menu_access"] = _dist_menu_access_allowed()
        dist_state["require_user_key"] = bool(dist_runtime_metadata.get("require_user_key", True))
        if bool(dist_state.get("distributor_locked", False)):
            dist_state["distributor_selected"] = False
            dist_state["distributor_value"] = _dist_sanitize_distributor(dist_runtime_metadata.get("distributor", dist_state.get("distributor_value", "")))
        if status_menu_active_submenu == "DIST_CONFIG":
            dist_state["distributor_selected"] = False
            dist_state["distributor_input"] = str(dist_state.get("distributor_value", ""))
        if status_menu_active_submenu in {"DIST_CONFIG", "DIST_USER_GOL"} and not bool(dist_state.get("menu_access", False)):
            status_menu_active_submenu = None
            status_menu_pending_action = None
        try:
            _apply_gun_trigger_fire(dt_sec)
        except Exception:
            pass
        try:
            _sync_stores_to_sms_state()
        except Exception:
            pass

        raw_slew_pos = pmd_dr_state.get("hotas_slew_cursor_logical", (WINDOW_WIDTH // 2, WINDOW_HEIGHT // 2))
        if isinstance(raw_slew_pos, (tuple, list)) and len(raw_slew_pos) >= 2:
            try:
                slew_x = int(raw_slew_pos[0])
                slew_y = int(raw_slew_pos[1])
            except Exception:
                slew_x = WINDOW_WIDTH // 2
                slew_y = WINDOW_HEIGHT // 2
        else:
            slew_x = WINDOW_WIDTH // 2
            slew_y = WINDOW_HEIGHT // 2
        slew_x = max(0, min(WINDOW_WIDTH - 1, slew_x))
        slew_y = max(0, min(WINDOW_HEIGHT - 1, slew_y))
        try:
            formats.set_display_cursor_logical((slew_x, slew_y))
        except Exception:
            pass

        if phase == -1:
            start_prompt_zones = draw_start_mode_prompt(screen)
        elif phase == -2:
            # Display unpowered.
            screen.fill(BG_COLOR)
        elif phase == 0:
            left_rect = pygame.Rect(0, 0, WINDOW_WIDTH // 2, WINDOW_HEIGHT)
            draw_loading_half(screen, loading_font, left_rect, text="DISPLAY LOADING")
        elif phase == 1:
            left_rect = pygame.Rect(0, 0, WINDOW_WIDTH // 2, WINDOW_HEIGHT)
            screen.set_clip(left_rect)
            osb_zones, control_zones, subportal_zones, status_menu_popup_zones = draw_layout(
                screen,
                font,
                portal_states,
                portal_formats,
                status_formats,
                system_mode,
                pair_owner,
                request_vded,
                set_format,
                close_vded,
                osb_flash_until,
                now,
                status_menu_popup_active,
                set_status_menu_rect,
                set_eng_popup_rect,
                set_fuel_popup_rect,
                set_sms_popup_rect,
                set_fcs_popup_rect,
                set_icaws_popup_rect,
                set_autopilot_popup_rect,
                set_nav_popup_rect,
                set_iff_popup_rect,
                set_altitude_popup_rect,
                set_time_popup_rect,
                set_record_button_rect,
                set_comm_popup_rect,
                set_swap_button_rect,
                get_status_fuel_values,
                get_status_fuel_snapshot,
                get_status_engine_thrust,
                get_status_fps,
                status_show_fps_debug,
                get_comm_state,
                status_menu_button_flash_until > now,
                status_menu_active_submenu,
                status_menu_item_flash_until,
                crus_state,
                lites_state,
                data_link_state,
                ecs_state,
                seclvl_state,
                hmd_state,
                ins_gps_state,
                pmd_dr_state,
                dist_state,
                eng_popup_active,
                fuel_popup_active,
                sms_popup_active,
                fcs_popup_active,
                icaws_popup_active,
                autopilot_popup_active,
                nav_popup_active,
                iff_popup_active,
                altitude_popup_active,
                time_popup_active,
                record_active,
                record_started,
                display_record_seconds,
                status_record_mode_name,
                status_record_area_label,
                comm_popup_active,
                status_bar_swapped,
                status_menu_popup_portal_index,
                active_status_popups_by_portal,
                poi_portal_index,
                poi_sub_index,
                poi_on_screen,
                _pmd_collect_status_menu_buttons(status_menu_active_submenu),
            )
            vded_zones = draw_vded_overlays(left_rect)
            screen.set_clip(None)
            right_rect = pygame.Rect(WINDOW_WIDTH // 2, 0, WINDOW_WIDTH // 2, WINDOW_HEIGHT)
            draw_loading_half(screen, loading_font, right_rect, text="")
        else:
            osb_zones, control_zones, subportal_zones, status_menu_popup_zones = draw_layout(
                screen,
                font,
                portal_states,
                portal_formats,
                status_formats,
                system_mode,
                pair_owner,
                request_vded,
                set_format,
                close_vded,
                osb_flash_until,
                now,
                status_menu_popup_active,
                set_status_menu_rect,
                set_eng_popup_rect,
                set_fuel_popup_rect,
                set_sms_popup_rect,
                set_fcs_popup_rect,
                set_icaws_popup_rect,
                set_autopilot_popup_rect,
                set_nav_popup_rect,
                set_iff_popup_rect,
                set_altitude_popup_rect,
                set_time_popup_rect,
                set_record_button_rect,
                set_comm_popup_rect,
                set_swap_button_rect,
                get_status_fuel_values,
                get_status_fuel_snapshot,
                get_status_engine_thrust,
                get_status_fps,
                status_show_fps_debug,
                get_comm_state,
                status_menu_button_flash_until > now,
                status_menu_active_submenu,
                status_menu_item_flash_until,
                crus_state,
                lites_state,
                data_link_state,
                ecs_state,
                seclvl_state,
                hmd_state,
                ins_gps_state,
                pmd_dr_state,
                dist_state,
                eng_popup_active,
                fuel_popup_active,
                sms_popup_active,
                fcs_popup_active,
                icaws_popup_active,
                autopilot_popup_active,
                nav_popup_active,
                iff_popup_active,
                altitude_popup_active,
                time_popup_active,
                record_active,
                record_started,
                display_record_seconds,
                status_record_mode_name,
                status_record_area_label,
                comm_popup_active,
                status_bar_swapped,
                status_menu_popup_portal_index,
                active_status_popups_by_portal,
                poi_portal_index,
                poi_sub_index,
                poi_on_screen,
                _pmd_collect_status_menu_buttons(status_menu_active_submenu),
            )
            vded_zones = draw_vded_overlays()

        if phase >= 1:
            brightness_mult = _display_control_brightness_multiplier()
            if brightness_mult <= 0.001:
                screen.fill(BG_COLOR)
            elif brightness_mult < 0.999:
                dim_alpha = max(0, min(255, int(round((1.0 - brightness_mult) * 255.0))))
                if dim_alpha > 0:
                    dim_layer = pygame.Surface((WINDOW_WIDTH, WINDOW_HEIGHT), pygame.SRCALPHA)
                    dim_layer.fill((0, 0, 0, dim_alpha))
                    screen.blit(dim_layer, (0, 0))

        if phase >= 1:
            if display_degd_side in {"LEFT", "BOTH"}:
                screen.fill(BG_COLOR, pygame.Rect(0, 0, WINDOW_WIDTH // 2, WINDOW_HEIGHT))
            if display_degd_side in {"RIGHT", "BOTH"}:
                screen.fill(BG_COLOR, pygame.Rect(WINDOW_WIDTH // 2, 0, WINDOW_WIDTH - (WINDOW_WIDTH // 2), WINDOW_HEIGHT))

        debug_popup_rect: Optional[pygame.Rect] = None
        if debug_overlay_active:
            debug_popup_rect, cockpit_panels_total_pages = draw_backtick_popup(screen, cockpit_panels_page_index)
            if cockpit_panels_total_pages > 0:
                cockpit_panels_page_index %= cockpit_panels_total_pages

        if screen_dbg_pending_picture_capture:
            if phase >= 1:
                capture_screen_debug_picture(screen)
            screen_dbg_pending_picture_capture = False

        term_active_for_repeat = bool(
            status_menu_popup_active
            and status_menu_active_submenu == "PMD_DR_TERM"
            and _term_input_selected()
        )
        if not term_active_for_repeat:
            pmd_dr_state["term_backspace_held"] = False
        elif bool(pmd_dr_state.get("term_backspace_held", False)):
            keys_now = pygame.key.get_pressed()
            if not bool(keys_now[pygame.K_BACKSPACE]):
                pmd_dr_state["term_backspace_held"] = False
            else:
                next_ms = int(pmd_dr_state.get("term_backspace_next_ms", 0))
                if int(now) >= next_ms:
                    _term_backspace()
                    pmd_dr_state["term_backspace_next_ms"] = int(now) + 35

        if mouse_down:
            draw_crosshair(screen, crosshair_pos)

        def _display_degd_blocks_pos(pos: Tuple[int, int]) -> bool:
            if phase < 1 or debug_overlay_active:
                return False
            if display_degd_side == "LEFT":
                return int(pos[0]) < (WINDOW_WIDTH // 2)
            if display_degd_side == "RIGHT":
                return int(pos[0]) >= (WINDOW_WIDTH // 2)
            if display_degd_side == "BOTH":
                return True
            return False

        try:
            _event_queue = pygame.event.get()
        except Exception:
            traceback.print_exc()
            _event_queue = []
        for event in _event_queue:
            if event.type == pygame.VIDEORESIZE and not _fullscreen_mode:
                try:
                    _windowed_size = (max(320, int(event.w)), max(240, int(event.h)))
                    _window_surface = _set_mode_windowed(_windowed_size, _window_flags, _windowed_display_index)
                except Exception:
                    pass
                _viewport_rect, _viewport_scale = _recompute_window_viewport()
                _capture_windowed_geometry()
                continue
            if _WINDOWRESIZED_EVENT != -1 and event.type == _WINDOWRESIZED_EVENT:
                if not _fullscreen_mode:
                    try:
                        _windowed_size = (
                            max(320, int(getattr(event, "x", _window_surface.get_width()))),
                            max(240, int(getattr(event, "y", _window_surface.get_height()))),
                        )
                    except Exception:
                        pass
                _viewport_rect, _viewport_scale = _recompute_window_viewport()
                if not _fullscreen_mode:
                    _capture_windowed_geometry()
                continue
            if _WINDOWMOVED_EVENT != -1 and event.type == _WINDOWMOVED_EVENT:
                if not _fullscreen_mode:
                    _capture_windowed_geometry()
                _capture_active_display_index()
                continue
            if hasattr(event, "pos"):
                mapped = _logical_from_window_pos(event.pos)
                if mapped is None:
                    if (
                        event.type == pygame.MOUSEBUTTONUP
                        and int(getattr(event, "button", 0)) == 1
                        and isinstance(startup_external_panels_button_win_rect, pygame.Rect)
                        and startup_external_panels_button_win_rect.collidepoint(event.pos)
                    ):
                        cockpit_panels_popup_active = not cockpit_panels_popup_active
                        if not cockpit_panels_popup_active:
                            _release_panel_popup_holds()
                        mouse_down = False
                        continue
                    if event.type == pygame.MOUSEBUTTONUP:
                        mouse_down = False
                    if event.type in {pygame.MOUSEBUTTONDOWN, pygame.MOUSEBUTTONUP, pygame.MOUSEMOTION}:
                        continue
                if mapped is not None:
                    try:
                        event.pos = mapped
                    except Exception:
                        pass
            focus_event = event.type in {_WINDOWFOCUSGAINED_EVENT, _WINDOWFOCUSLOST_EVENT}
            if (not focus_event) and event.type == _ACTIVEEVENT_EVENT:
                try:
                    focus_event = bool(int(getattr(event, "state", 0)) & 2)
                except Exception:
                    focus_event = False
            if focus_event:
                held_keys.clear()
                raw_hotas = pmd_dr_state.get("hotas_action_down_raw", {})
                hotas_now = dict(raw_hotas) if isinstance(raw_hotas, dict) else {}
                pmd_dr_state["hotas_event_down_override"] = dict(hotas_now)
                pmd_dr_state["hotas_prev_down_raw"] = dict(hotas_now)
                pmd_dr_state["hotas_prev_down"] = dict(hotas_now)
                pmd_dr_state["hotas_prev_key_down"] = {}
                gear_now = bool(hotas_now.get("ldg_gear", False))
                pmd_dr_state["hotas_gear_handler_prev_raw"] = bool(gear_now)
                pmd_dr_state["hotas_gear_debug_state"] = (
                    bool(_hotas_get_connected_binding("ldg_gear")),
                    bool(gear_now),
                    bool(gear_now),
                    False,
                    str(pmd_dr_state.get("hotas_ldg_gear_mode", "TOGGLE")).upper(),
                    bool(gear_now),
                    bool(gear_now),
                )
                pmd_dr_state["hotas_ldg_gear_prev_pressed"] = gear_now
                pmd_dr_state["hotas_ldg_gear_db_raw"] = gear_now
                pmd_dr_state["hotas_ldg_gear_db_state"] = gear_now
                pmd_dr_state["hotas_ldg_gear_db_since_ms"] = int(now)
                pmd_dr_state["apc_hold_start_ms"] = 0
                pmd_dr_state["apc_hold_fired"] = False
                pmd_dr_state["apc_prev_held"] = False
                pmd_dr_state["apc_last_down_ms"] = 0
                pmd_dr_state["input_focus_inhibit_until_ms"] = int(now + 800)
                continue
            if event.type in {_JOYDEVICEADDED_EVENT, _JOYDEVICEREMOVED_EVENT}:
                # Joystick enumeration can briefly stall SDL/DirectInput.
                # Schedule it outside the event dispatch path.
                pmd_dr_state["hotas_refresh_next_ms"] = int(now + 100)
                continue
            if event.type in {_JOYAXISMOTION_EVENT, _JOYBUTTONDOWN_EVENT, _JOYHATMOTION_EVENT}:
                _hotas_update_runtime_event_state(event)
                if _hotas_capture_event(event):
                    pmd_dr_state["hotas_edit_capture_selected"] = False
                    pmd_dr_state["hotas_edit_status"] = "Captured."
                    continue
            if event.type == _JOYBUTTONUP_EVENT:
                _hotas_update_runtime_event_state(event)
            if event.type == pygame.KEYDOWN and _pmd_event_matches_landing_gear(event.key):
                # Gear is a flight-control keybind, not a text/data-entry key.
                # Handle it before generic data-entry paths so a focused popup
                # cannot consume the press and make gear appear dead.
                if phase >= 1:
                    _command_landing_gear_input("keyboard_event")
                else:
                    print(f"[GEAR][BLOCK] source=keyboard_event phase={phase}")
                continue
            if event.type == pygame.KEYDOWN and _handle_keyboard_data_entry(event):
                continue
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN and event.key == pygame.K_ESCAPE:
                running = False
            elif event.type == pygame.KEYDOWN and (
                _pmd_event_matches_action(event.key, "ful_scrn")
                or (event.key == pygame.K_RETURN and (event.mod & pygame.KMOD_ALT))
            ):
                _set_window_mode(not _fullscreen_mode)
                continue
            elif start_mode_pending and event.type == pygame.KEYDOWN:
                if event.key == pygame.K_h:
                    _commit_start_mode("hot", now)
                    continue
                elif event.key == pygame.K_c:
                    _commit_start_mode("cold", now)
                    continue
                elif event.key == pygame.K_TAB:
                    cockpit_panels_popup_active = not cockpit_panels_popup_active
                    if not cockpit_panels_popup_active:
                        _release_panel_popup_holds()
                    continue
                elif cockpit_panels_popup_active and event.key in {pygame.K_LEFT, pygame.K_RIGHT}:
                    total = max(1, len(_discover_panel_pages()))
                    if event.key == pygame.K_LEFT:
                        cockpit_panels_page_index = (cockpit_panels_page_index - 1) % total
                    else:
                        cockpit_panels_page_index = (cockpit_panels_page_index + 1) % total
                    continue
                else:
                    continue
            elif event.type == pygame.KEYDOWN and event.key == pygame.K_TAB:
                cockpit_panels_popup_active = not cockpit_panels_popup_active
                if not cockpit_panels_popup_active:
                    _release_panel_popup_holds()
                continue
            elif event.type == pygame.KEYDOWN and cockpit_panels_popup_active and event.key in {pygame.K_LEFT, pygame.K_RIGHT}:
                total = max(1, len(_discover_panel_pages()))
                if event.key == pygame.K_LEFT:
                    cockpit_panels_page_index = (cockpit_panels_page_index - 1) % total
                else:
                    cockpit_panels_page_index = (cockpit_panels_page_index + 1) % total
                continue
            elif event.type == pygame.KEYDOWN and _pmd_is_hold_action_key(event.key):
                term_string_input_active_evt = bool(
                    status_menu_popup_active
                    and status_menu_active_submenu == "PMD_DR_TERM"
                    and _term_input_selected()
                )
                is_throttle_mod = _pmd_event_matches_action(event.key, "throt_plus") or _pmd_event_matches_action(event.key, "throt_minus")
                if not (term_string_input_active_evt and is_throttle_mod):
                    held_keys.add(int(event.key))
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "restart"):
                _restart_all_python_scripts()
                continue
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "rec_cap"):
                if phase >= 1:
                    mode_idx = _screen_dbg_mode_idx()
                    pmd_dr_state["screen_dbg_mode_idx"] = 1 if mode_idx == 0 else 0
                continue
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "strt_rec"):
                if phase >= 1:
                    _screen_debug_trigger_action(screen, close_menu=False)
                continue
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "cap_area"):
                if not record_active:
                    opts = _screen_dbg_area_options()
                    if len(opts) > 0:
                        idx = _screen_dbg_area_idx()
                        pmd_dr_state["screen_dbg_area_idx"] = (idx + 1) % len(opts)
                continue
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "poi_lt"):
                if debug_overlay_active:
                    total = max(1, len(_discover_panel_pages()))
                    cockpit_panels_page_index = (cockpit_panels_page_index - 1) % total
                elif phase >= 1 and poi_on_screen:
                    poi_portal_index = step_poi_index(poi_portal_index, -1)
                    _center_hotas_cursor_on_portal(poi_portal_index, make_visible=True)
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "poi_rt"):
                if debug_overlay_active:
                    total = max(1, len(_discover_panel_pages()))
                    cockpit_panels_page_index = (cockpit_panels_page_index + 1) % total
                elif phase >= 1 and poi_on_screen:
                    poi_portal_index = step_poi_index(poi_portal_index, 1)
                    _center_hotas_cursor_on_portal(poi_portal_index, make_visible=True)
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "poi_up"):
                if phase >= 1:
                    poi_on_screen = False
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "poi_dn"):
                if phase >= 1:
                    poi_on_screen = True
                    _center_hotas_cursor_on_portal(poi_portal_index, make_visible=True)
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "toi"):
                _toggle_toi_at_cursor()
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "com_a"):
                comm_state["asgn_radio"] = "coma"
                comm_state["asgn_mode"] = "HIGH VHF"
                mode_map = comm_state.get("radio_modes", {})
                if not isinstance(mode_map, dict):
                    mode_map = {}
                    comm_state["radio_modes"] = mode_map
                mode_map["coma"] = "HIGH VHF"
                _comm_sync_a123_from_asgn()
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "com_b"):
                comm_state["asgn_radio"] = "comb"
                comm_state["asgn_mode"] = "LOW VHF"
                mode_map = comm_state.get("radio_modes", {})
                if not isinstance(mode_map, dict):
                    mode_map = {}
                    comm_state["radio_modes"] = mode_map
                mode_map["comb"] = "LOW VHF"
                _comm_sync_a123_from_asgn()
            elif event.type == pygame.KEYDOWN and _pmd_event_matches_action(event.key, "com_c"):
                comm_state["asgn_radio"] = "comc"
                comm_state["asgn_mode"] = "UHF"
                mode_map = comm_state.get("radio_modes", {})
                if not isinstance(mode_map, dict):
                    mode_map = {}
                    comm_state["radio_modes"] = mode_map
                mode_map["comc"] = "UHF"
                _comm_sync_a123_from_asgn()
            elif event.type == pygame.KEYUP:
                try:
                    held_keys.discard(int(event.key))
                except Exception:
                    pass
                try:
                    if int(event.key) == pygame.K_BACKSPACE:
                        pmd_dr_state["term_backspace_held"] = False
                except Exception:
                    pass
            elif event.type == pygame.MOUSEWHEEL:
                hover_window = pygame.mouse.get_pos()
                hover_pos = _logical_from_window_pos(hover_window)
                if (
                    hover_pos is not None
                    and status_menu_popup_active
                    and status_menu_active_submenu == "PMD_DR_TERM"
                ):
                    menu_rect = get_portal_rect(status_menu_popup_portal_index)
                    if menu_rect.collidepoint(hover_pos):
                        wheel_y = int(getattr(event, "y", 0))
                        if wheel_y != 0:
                            _term_scroll_by_lines(wheel_y * TERM_SCROLL_STEP_LINES)
                        continue
            elif event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
                if (phase == 1 and (not debug_overlay_active) and event.pos[0] >= (WINDOW_WIDTH // 2)) or _display_degd_blocks_pos(event.pos):
                    # Left-half-only mode: ignore right-half touch input.
                    continue
                is_touch_event = bool(getattr(event, "touch", False)) and (not bool(getattr(event, "hotas_virtual", False)))
                if not bool(getattr(event, "hotas_virtual", False)):
                    pmd_dr_state["hotas_slew_cursor_visible"] = False
                mouse_down = True
                crosshair_pos = event.pos
                mouse_down_at_ms = pygame.time.get_ticks()
                mouse_down_popup_key = None
                if debug_overlay_active:
                    if isinstance(debug_popup_rect, pygame.Rect):
                        left_page_rect, right_page_rect = cockpit_panel_page_arrow_rects(debug_popup_rect)
                        if left_page_rect.collidepoint(event.pos) or right_page_rect.collidepoint(event.pos):
                            total = max(1, len(_discover_panel_pages()))
                            if left_page_rect.collidepoint(event.pos):
                                cockpit_panels_page_index = (cockpit_panels_page_index - 1) % total
                            else:
                                cockpit_panels_page_index = (cockpit_panels_page_index + 1) % total
                            mouse_down = False
                            panel_touch_swipe = None
                            panel_touch_active_button = 1
                            continue
                    if is_touch_event:
                        panel_touch_active_button = _panel_popup_touch_button_from_pos(event.pos)
                        panel_touch_swipe = {
                            "sx": int(event.pos[0]),
                            "sy": int(event.pos[1]),
                            "lx": int(event.pos[0]),
                            "ly": int(event.pos[1]),
                        }
                    else:
                        panel_touch_active_button = 1
                        panel_touch_swipe = None
                    _handle_panel_popup_mouse_down(event.pos, int(panel_touch_active_button))
                if phase >= 1 and status_menu_popup_active:
                    for key, zone_rect in status_menu_popup_zones.items():
                        if zone_rect.collidepoint(event.pos):
                            mouse_down_popup_key = key
                            break
                # TWD SEP hold is a true press-and-hold behavior: start on LMB down.
                try:
                    twd_sep_down = False
                    for zone in osb_zones:
                        if zone.label != "L4":
                            continue
                        if not zone.rect.collidepoint(event.pos):
                            continue
                        popup_name = active_status_popups_by_portal.get(zone.portal_index)
                        if popup_name is not None:
                            portal_format = create_format(str(popup_name))
                        else:
                            portal_format = portal_formats[zone.portal_index].primary
                        fmt_name = str(getattr(portal_format, "name", "")).upper().strip()
                        if fmt_name == "TWD":
                            twd_sep_down = True
                            break
                    if hasattr(formats, "TWD_STATE") and isinstance(formats.TWD_STATE, dict):
                        formats.TWD_STATE["sep_hold_mouse"] = bool(twd_sep_down)
                except Exception:
                    pass
            elif event.type == pygame.MOUSEBUTTONDOWN and event.button == 3:
                if (phase == 1 and (not debug_overlay_active) and event.pos[0] >= (WINDOW_WIDTH // 2)) or _display_degd_blocks_pos(event.pos):
                    # Left-half-only mode: ignore right-half touch input.
                    continue
                if debug_overlay_active:
                    _handle_panel_popup_mouse_down(event.pos, 3)
            elif event.type == pygame.MOUSEBUTTONDOWN and event.button == 2:
                if (phase == 1 and (not debug_overlay_active) and event.pos[0] >= (WINDOW_WIDTH // 2)) or _display_degd_blocks_pos(event.pos):
                    # Left-half-only mode: ignore right-half touch input.
                    continue
                if debug_overlay_active:
                    _handle_panel_popup_mouse_down(event.pos, 2)
            elif event.type == pygame.MOUSEMOTION:
                drag_buttons = 0
                try:
                    if isinstance(event.buttons, (tuple, list)):
                        if len(event.buttons) > 0 and bool(event.buttons[0]):
                            drag_buttons |= 1
                        if len(event.buttons) > 2 and bool(event.buttons[2]):
                            drag_buttons |= 2
                    else:
                        drag_buttons = int(event.buttons)
                except Exception:
                    drag_buttons = 0
                if bool(getattr(event, "touch", False)) and isinstance(panel_touch_swipe, dict):
                    panel_touch_swipe["lx"] = int(event.pos[0])
                    panel_touch_swipe["ly"] = int(event.pos[1])
                if debug_overlay_active and drag_buttons:
                    if bool(getattr(event, "touch", False)) and int(panel_touch_active_button) == 3 and (drag_buttons & 1):
                        drag_buttons |= 2
                    _handle_panel_popup_mouse_drag(event.pos, int(drag_buttons))
                if mouse_down:
                    if not _display_degd_blocks_pos(event.pos):
                        crosshair_pos = event.pos
            elif event.type == pygame.MOUSEBUTTONUP and event.button == 3:
                if (phase == 1 and (not debug_overlay_active) and event.pos[0] >= (WINDOW_WIDTH // 2)) or _display_degd_blocks_pos(event.pos):
                    # Left-half-only mode: ignore right-half touch input.
                    continue
                if debug_overlay_active:
                    _handle_panel_popup_mouse_up(3)
                handled_right = False
                if phase >= 1 and not debug_overlay_active:
                    # Active status popups consume clicks in their portal so
                    # underlying primary formats (e.g. TSD) do not receive them.
                    for popup_portal_idx in active_status_popups_by_portal.keys():
                        popup_click_rect = get_portal_rect(int(popup_portal_idx))
                        if popup_click_rect.collidepoint(event.pos):
                            handled_right = True
                            break
                    if not handled_right:
                        for portal_idx in range(4):
                            pair_idx = portal_idx // 2
                            if pair_owner[pair_idx] is not None and portal_idx != pair_owner[pair_idx]:
                                continue
                            fmt = portal_formats[portal_idx].primary
                            if fmt is None or not hasattr(fmt, "on_right_click"):
                                continue
                            portal_rect = get_portal_rect(portal_idx)
                            click_rect = portal_rect.copy()
                            suppress_subportals = False
                            if hasattr(fmt, "suppress_subportals"):
                                try:
                                    suppress_subportals = bool(fmt.suppress_subportals())
                                except Exception:
                                    suppress_subportals = False
                            owner_idx = pair_owner[pair_idx]
                            if owner_idx is not None and portal_idx == owner_idx:
                                pair_start = pair_idx * 2
                                use_full_height = bool(portal_states[owner_idx].expanded_vertical) or suppress_subportals
                                click_rect = pygame.Rect(
                                    pair_start * PORTAL_WIDTH,
                                    ICAWS_HEIGHT,
                                    PORTAL_WIDTH * 2,
                                    PORTAL_HEIGHT if use_full_height else MAIN_PORTAL_HEIGHT,
                                )
                            elif not bool(portal_states[portal_idx].expanded_vertical):
                                click_rect = pygame.Rect(
                                    portal_rect.x,
                                    portal_rect.y,
                                    portal_rect.width,
                                    PORTAL_HEIGHT if suppress_subportals else MAIN_PORTAL_HEIGHT,
                                )
                            if not click_rect.collidepoint(event.pos):
                                continue
                            click_context = FormatContext(
                                portal_idx,
                                request_vded,
                                set_format,
                                close_vded,
                                is_osb_flashing=lambda label, idx=portal_idx: osb_flash_until.get((idx, label), 0) > now,
                            )
                            try:
                                if bool(fmt.on_right_click(event.pos, click_rect, click_context)):
                                    handled_right = True
                                    break
                            except Exception:
                                pass
            elif event.type == pygame.MOUSEBUTTONUP and event.button == 1:
                if (phase == 1 and (not debug_overlay_active) and event.pos[0] >= (WINDOW_WIDTH // 2)) or _display_degd_blocks_pos(event.pos):
                    # Left-half-only mode: ignore right-half touch input.
                    mouse_down = False
                    continue
                try:
                    if hasattr(formats, "TWD_STATE") and isinstance(formats.TWD_STATE, dict):
                        formats.TWD_STATE["sep_hold_mouse"] = False
                except Exception:
                    pass
                is_touch_event = bool(getattr(event, "touch", False)) and (not bool(getattr(event, "hotas_virtual", False)))
                mouse_down = False
                crosshair_pos = event.pos
                held_ms = pygame.time.get_ticks() - mouse_down_at_ms
                handled = False
                # Touch swipe gesture: left/right on cockpit popup changes page.
                if is_touch_event and debug_overlay_active and isinstance(panel_touch_swipe, dict):
                    sx = int(panel_touch_swipe.get("sx", int(event.pos[0])))
                    sy = int(panel_touch_swipe.get("sy", int(event.pos[1])))
                    ex = int(event.pos[0])
                    ey = int(event.pos[1])
                    dx = ex - sx
                    dy = ey - sy
                    if abs(dx) >= 80 and abs(dx) > int(abs(dy) * 1.3):
                        total = max(1, len(_discover_panel_pages()))
                        if dx < 0:
                            cockpit_panels_page_index = (cockpit_panels_page_index + 1) % total
                        else:
                            cockpit_panels_page_index = (cockpit_panels_page_index - 1) % total
                        handled = True
                if start_mode_pending and phase == -1 and not handled:
                    hot_rect = start_prompt_zones.get("hot")
                    cold_rect = start_prompt_zones.get("cold")
                    if isinstance(hot_rect, pygame.Rect) and hot_rect.collidepoint(event.pos):
                        _commit_start_mode("hot", now)
                        handled = True
                    elif isinstance(cold_rect, pygame.Rect) and cold_rect.collidepoint(event.pos):
                        _commit_start_mode("cold", now)
                        handled = True
                if debug_overlay_active:
                    panel_up_button = int(panel_touch_active_button) if is_touch_event else 1
                    if panel_up_button not in {1, 3}:
                        panel_up_button = 1
                    _handle_panel_popup_mouse_up(panel_up_button)
                panel_touch_swipe = None
                panel_touch_active_button = 1
                if debug_overlay_active and not start_mode_pending:
                    # While cockpit panels popup is shown (outside start page), it captures click input.
                    handled = True
                elif phase < 1:
                    # Display is still unpowered/loading.
                    handled = True
                if phase >= 1:
                    clicked_status_popup_name: Optional[str] = None
                    clicked_status_popup_portal_index: Optional[int] = None
                    for popup_portal_idx, popup_name in active_status_popups_by_portal.items():
                        popup_rect = get_portal_rect(int(popup_portal_idx))
                        if popup_rect.collidepoint(event.pos):
                            clicked_status_popup_name = str(popup_name)
                            clicked_status_popup_portal_index = int(popup_portal_idx)
                            break
                    if not handled and swap_button_rect is not None and swap_button_rect.collidepoint(event.pos):
                        status_bar_swapped = not status_bar_swapped
                        handled = True
                    if not handled and record_button_rect is not None and record_button_rect.collidepoint(event.pos):
                        # Match F2 behavior: use the active SCREEN DEBUG mode/area selection.
                        _screen_debug_trigger_action(screen, close_menu=False)
                        handled = True
                    if phase == 1:
                        active_rect = pygame.Rect(0, 0, WINDOW_WIDTH // 2, WINDOW_HEIGHT)
                        if not active_rect.collidepoint(event.pos):
                            handled = True
                    status_popup_btn_hit = any(
                        isinstance(r, pygame.Rect) and r.collidepoint(event.pos)
                        for r in (
                            eng_popup_button_rect,
                            fuel_popup_button_rect,
                            sms_popup_button_rect,
                            fcs_popup_button_rect,
                            icaws_popup_button_rect,
                            autopilot_popup_button_rect,
                            nav_popup_button_rect,
                            iff_popup_button_rect,
                            altitude_popup_button_rect,
                            time_popup_button_rect,
                            comm_popup_button_rect,
                        )
                    )
                    status_group_portals = _status_popup_group_portals(status_bar_swapped)
                    if (
                        not handled
                        and (not status_popup_btn_hit)
                        and status_menu_button_rect is not None
                        and status_menu_button_rect.collidepoint(event.pos)
                    ):
                        menu_click = ButtonState(
                            button_id="STATUS_MENU",
                            button_type=ButtonType.MOMENTARY_SINGLE,
                            text="MENU",
                            flash_until_ms=status_menu_button_flash_until,
                        )
                        activate_button(menu_click, now, OSB_FLASH_MS)
                        status_menu_button_flash_until = menu_click.flash_until_ms
                        if bool(status_menu_popup_active):
                            _close_status_menu_popup()
                        else:
                            _close_status_popups_for_portal(status_menu_popup_portal_index)
                            status_menu_popup_active = True
                            close_vded_for_portal(status_menu_popup_portal_index)
                        handled = True
                    if not handled and eng_popup_button_rect is not None and eng_popup_button_rect.collidepoint(event.pos):
                        if eng_popup_active:
                            _set_status_group_a_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("A", -1)))
                            _set_status_group_a_popup("ENG")
                        handled = True
                    if not handled and fuel_popup_button_rect is not None and fuel_popup_button_rect.collidepoint(event.pos):
                        if fuel_popup_active:
                            _set_status_group_a_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("A", -1)))
                            _set_status_group_a_popup("FUEL")
                        handled = True
                    if not handled and sms_popup_button_rect is not None and sms_popup_button_rect.collidepoint(event.pos):
                        if sms_popup_active:
                            _set_status_group_a_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("A", -1)))
                            _set_status_group_a_popup("SMS")
                        handled = True
                    if not handled and fcs_popup_button_rect is not None and fcs_popup_button_rect.collidepoint(event.pos):
                        if fcs_popup_active:
                            _set_status_group_a_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("A", -1)))
                            _set_status_group_a_popup("FCS")
                        handled = True
                    if not handled and icaws_popup_button_rect is not None and icaws_popup_button_rect.collidepoint(event.pos):
                        right_half_ack_rect = pygame.Rect(
                            icaws_popup_button_rect.centerx,
                            icaws_popup_button_rect.top,
                            icaws_popup_button_rect.width // 2,
                            icaws_popup_button_rect.height,
                        )
                        if (not icaws_popup_active) and bool(getattr(formats, "ICAWS_STATE", {}).get("ack_pending", False)) and right_half_ack_rect.collidepoint(event.pos):
                            try:
                                formats.ICAWS_STATE["ack_pending"] = False
                                formats.ICAWS_STATE["unacked_cw"] = []
                            except Exception:
                                pass
                            handled = True
                        elif icaws_popup_active:
                            _set_status_group_b_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("B", -1)))
                            _set_status_group_b_popup("ICAWS")
                        handled = True
                    if not handled and autopilot_popup_button_rect is not None and autopilot_popup_button_rect.collidepoint(event.pos):
                        if autopilot_popup_active:
                            _set_status_group_b_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("B", -1)))
                            _set_status_group_b_popup("AUTOPILOT")
                        handled = True
                    if not handled and nav_popup_button_rect is not None and nav_popup_button_rect.collidepoint(event.pos):
                        if nav_popup_active:
                            _set_status_group_c_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("C", -1)))
                            _set_status_group_c_popup("NAVMENU")
                        handled = True
                    if not handled and iff_popup_button_rect is not None and iff_popup_button_rect.collidepoint(event.pos):
                        if iff_popup_active:
                            _set_status_group_d_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("D", -1)))
                            _set_status_group_d_popup("IFF")
                            iff_state["a1_menu_open"] = False
                            iff_state["a2_menu_open"] = False
                            iff_state["e7_subpage_open"] = False
                            sel = _iff_selected_field()
                            if sel is not None:
                                finalize_iff_data_entry(sel)
                        handled = True
                    if not handled and altitude_popup_button_rect is not None and altitude_popup_button_rect.collidepoint(event.pos):
                        if altitude_popup_active:
                            _set_status_group_d_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("D", -1)))
                            _set_status_group_d_popup("ALTITUDE")
                        handled = True
                    if not handled and time_popup_button_rect is not None and time_popup_button_rect.collidepoint(event.pos):
                        if time_popup_active:
                            _set_status_group_d_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("D", -1)))
                            _set_status_group_d_popup("WIND")
                        handled = True
                    if not handled and comm_popup_button_rect is not None and comm_popup_button_rect.collidepoint(event.pos):
                        if comm_popup_active:
                            _set_status_group_c_popup(None)
                        else:
                            _close_status_menu_if_portal_conflicts(int(status_group_portals.get("C", -1)))
                            _set_status_group_c_popup("COMM")
                        handled = True
                    if not handled and status_menu_popup_active:
                        menu_portal_rect = get_portal_rect(status_menu_popup_portal_index)
                        if menu_portal_rect.collidepoint(event.pos):
                            for key, zone_rect in status_menu_popup_zones.items():
                                if zone_rect.collidepoint(event.pos):
                                    if key in {"ECS_E1_E2", "PMD_SCREENDBG_E1_E2"}:
                                        continue
                                    if key == "ECS_C2":
                                        handled = True
                                        break
                                    disabled_status_zone = False
                                    if key == "DATA_LINK_E2" and bool(data_link_state.get("cni_fail_l16_ipf_active", False)):
                                        disabled_status_zone = True
                                    elif key == "INS_GPS_A1" and bool(ins_gps_state.get("ins_fail_active", False)):
                                        disabled_status_zone = True
                                    elif key == "INS_GPS_D8" and bool(ins_gps_state.get("gps_fail_active", False)):
                                        disabled_status_zone = True
                                    if disabled_status_zone:
                                        handled = True
                                        break
                                    if key in pmd_status_menu_button_defs:
                                        btype_raw = str(pmd_status_menu_button_defs.get(key, {}).get("button_type", "MOMENTARY_SINGLE")).upper().strip()
                                        if btype_raw == "PAGE_ACCESS":
                                            click_type = ButtonType.PAGE_ACCESS
                                        elif btype_raw == "GROUP_OPTION_LIST":
                                            click_type = ButtonType.GROUP_OPTION_LIST
                                        elif btype_raw == "DATA_ENTRY":
                                            click_type = ButtonType.DATA_ENTRY
                                        elif btype_raw == "STATUS_LABEL":
                                            click_type = ButtonType.STATUS_LABEL
                                        else:
                                            click_type = ButtonType.MOMENTARY_SINGLE
                                    else:
                                        click_type = ButtonType.PAGE_ACCESS if key in {"BACK", "PMD_STORES_INV_E8_BACK"} else ButtonType.MOMENTARY_SINGLE
                                    click_state = ButtonState(
                                        button_id=key,
                                        button_type=click_type,
                                        text=key,
                                        flash_until_ms=status_menu_item_flash_until.get(key, 0),
                                    )
                                    activate_button(click_state, now, OSB_FLASH_MS)
                                    status_menu_item_flash_until[key] = click_state.flash_until_ms
                                    ecs_edit_keys = {
                                        "ECS_D1",
                                        "KP_0", "KP_1", "KP_2", "KP_3", "KP_4",
                                        "KP_5", "KP_6", "KP_7", "KP_8", "KP_9",
                                        "KP_BACK", "KP_UP", "KP_DOWN",
                                    }
                                    if (
                                        status_menu_active_submenu == "ECS"
                                        and bool(ecs_state["d1_selected"])
                                        and key not in ecs_edit_keys
                                    ):
                                        finalize_ecs_data_entry()
                                    seclvl_edit_keys = {
                                        "SECLVL_USER",
                                        "SECLVL_PASS",
                                        "KP_0", "KP_1",
                                        "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9",
                                        "KP_BACK",
                                        "KP_RIGHT",
                                    }
                                    if (
                                        status_menu_active_submenu in {"SECLVL", "SECLVL_MODE_GOL"}
                                        and _seclvl_field_prefix() is not None
                                        and key not in seclvl_edit_keys
                                    ):
                                        finalize_all_seclvl_fields()
                                    hmd_edit_keys = {
                                        "HMD_E6",
                                        "KP_0", "KP_1", "KP_2", "KP_3", "KP_4",
                                        "KP_5", "KP_6", "KP_7", "KP_8", "KP_9",
                                        "KP_BACK",
                                    }
                                    if (
                                        status_menu_active_submenu == "HMD"
                                        and bool(hmd_state["e6_selected"])
                                        and key not in hmd_edit_keys
                                    ):
                                        finalize_hmd_data_entry()
                                    hmd_video_edit_keys = {
                                        "HMD_VIDEO_E4",
                                        "HMD_VIDEO_E5",
                                        "KP_0", "KP_1", "KP_2", "KP_3", "KP_4",
                                        "KP_5", "KP_6", "KP_7", "KP_8", "KP_9",
                                        "KP_BACK", "KP_UP", "KP_DOWN",
                                    }
                                    if (
                                        status_menu_active_submenu == "HMD_VIDEO"
                                        and (bool(hmd_state["video_e4_selected"]) or bool(hmd_state["video_e5_selected"]))
                                        and key not in hmd_video_edit_keys
                                    ):
                                        finalize_all_hmd_video_data_entries()
                                    pmd_dr_edit_keys = {
                                        "PMD_DR_D1", "PMD_DR_E1", "PMD_DR_D2", "PMD_DR_E2", "PMD_DR_D3", "PMD_DR_E3",
                                        "PMD_DR_D4", "PMD_DR_E4", "PMD_DR_D5", "PMD_DR_E5", "PMD_DR_D6", "PMD_DR_E6",
                                        "KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9",
                                        "KP_BACK", "KP_UP", "KP_DOWN",
                                    }
                                    if (
                                        status_menu_active_submenu == "PMD_DR_FUEL_DEBUG"
                                        and _pmd_dr_selected_field() is not None
                                        and key not in pmd_dr_edit_keys
                                    ):
                                        finalize_pmd_dr_data_entry(str(_pmd_dr_selected_field()))
                                    pmd_svc_edit_keys = {
                                        "PMD_SVC_A1", "PMD_SVC_E1", "PMD_SVC_E2", "PMD_SVC_E3", "PMD_SVC_E4", "PMD_SVC_E5", "PMD_SVC_E6",
                                        "KP_0", "KP_1", "KP_2", "KP_3", "KP_4", "KP_5", "KP_6", "KP_7", "KP_8", "KP_9",
                                        "KP_BACK", "KP_UP", "KP_DOWN",
                                    }
